0点。						\n    --\"杰出草药师的笔记\",						--使用： 研究以使你的卡兹阿加草药学知识提高15点。						\n    --\"杰出矿工的笔记\",						    --使用： 研究以使你的卡兹阿加采矿知识提高15点。						\n    --\"杰出剥皮师的笔记\",						--使用： 研究以使你的卡兹阿加剥皮知识提高15点。						\n    --\"无瑕铁匠的图表\",						    --使用： 研究以使你的卡兹阿加锻造知识提高10点。						\n    --\"无瑕铭文师的符文图案\",					    --使用： 研究以使你的卡兹阿加铭文知识提高10点。						\n    --\"无瑕炼金师的研究\",						--使用： 研究以使你的卡兹阿加炼金知识提高10点。						\n    --\"无瑕裁缝的图表\",						    --使用： 研究以使你的卡兹阿加裁缝知识提高10点。						\n    --\"无瑕附魔师的研究\",						--使用： 研究以使你的卡兹阿加附魔知识提高10点。						\n    --\"无瑕工程师的草稿\",						--使用： 研究以使你的卡兹阿加工程学知识提高10点。						\n    --\"无瑕珠宝匠的插图\",						--使用： 研究以使你的卡兹阿加珠宝加工知识提高10点。						\n    --\"无瑕制皮匠的图表\",						--使用： 研究以使你的卡兹阿加制皮知识提高10点。						\n    --\"无瑕草药师的笔记\",						--使用： 研究以使你的卡兹阿加草药学知识提高15点。						\n    --\"无瑕矿工的笔记\",						    --使用： 研究以使你的卡兹阿加采矿知识提高15点。						\n    --\"无瑕剥皮师的笔记\",						--使用： 研究以使你的卡兹阿加剥皮知识提高15点。						\n\n\n}\nif _G._MFF and _G._MFF.GetText and _G._MFF:GetText() == \"捐献\" and _G._MFF:IsEnabled() then\n    _G._MFF:Click()\n    return\nend\nfor i, v in ipairs(vars[\"专业物品和箱子\"]) do\n    if sv:GetItemCount(v) > 0 then\n        A[\"使用背包物品\"]:SetItem(v)\n        return A[\"使用背包物品\"]:Cast()\n    end\nend\n",
            ["使用饰品"] = "--全职业-全专精-使用饰品\n\n--如果饰品可用,则立即使用\n--用法 v = run(\"使用饰品\", \"饰品名\") if v then return v end\n--或者 v = run(\"使用饰品\", \"饰品名\", 额外条件, 目标) if v then return v end\nlocal name, condition, castTo, leadCd = ...\nif condition == false then\n	return\nend\nlocal v\nif SwitchIsOn(\"饰品1\") and A[\"饰品1\"]:IsItem(name) then\n	v = A[\"饰品1\"]:Cast(nil, castTo) if v then return v end\nelseif SwitchIsOn(\"饰品2\") and A[\"饰品2\"]:IsItem(name) then\n	v = A[\"饰品2\"]:Cast(nil, castTo) if v then return v end\nend\n",
            ["保命"] = "--全职业-全专精-保命\nreturn",
            ["军团神器技能"] = "--全职业-全专精-军团神器技能\nlocal v = A[\"魔刺\"]:IsActiveSpell() and player.MyBuff[\"扭曲的远征\"]:GetTimeLeft() < 3 and A[\"魔刺\"]:Cast() if v then return v end\nif not SwitchIsOn(\"神器技能\") then return end\nv = A[\"扭曲的远征\"]:IsActiveSpell() and A[\"扭曲的远征\"]:Cast() if v then return v end\nv = A[\"守备官的审判\"]:IsActiveSpell() and A[\"守备官的审判\"]:Cast() if v then return v end\nv = A[\"投身战场\"]:IsActiveSpell() and A[\"投身战场\"]:Cast() if v then return v end\nv = A[\"光缚通道\"]:IsActiveSpell() and A[\"光缚通道\"]:Cast() if v then return v end\nv = A[\"纳兰的永恒圆盘\"]:IsActiveSpell() and A[\"纳兰的永恒圆盘\"]:Cast() if v then return v end\nv = A[\"森林的召唤\"]:IsActiveSpell() and A[\"森林的召唤\"]:Cast() if v then return v end\nv = A[\"怒雷风暴\"]:IsActiveSpell() and A[\"怒雷风暴\"]:Cast() if v then return v end\n",
            ["发送按键"] = "--全职业-全专精-发送按键\n--用法：创建一个宏，内容是： /jaa 发送按键 key interval\n--x为你想要发送的按键, 数字和字母直接写, 如果要发送F1-F12， 需要写 KEY_F1 \n--例如： /jaa 发送按键 P 60         会每隔60秒发送一个P按键\nlocal key, interval = ...\nif tonumber(interval) then\n    if not vars[\"上次发送按键时间\"] or (GetTime() - vars[\"上次发送按键时间\"] > tonumber(interval)) then\n        vars[\"上次发送按键时间\"] = GetTime()\n        return key \n    end\nelse\n    return key \nend\n",
            ["取得嗜血剩余时间"] = "--全职业-全专精-取得嗜血剩余时间\nlocal v\nv = player.AllBuff[\"嗜血\"]\nif v.SpellID == 2825 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"远古狂乱\"]\nif v.SpellID == 90355 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"英勇\"]\nif v.SpellID == 32182 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"时间扭曲\"]\nif v.SpellID == 80353 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"虚空之风\"]\nif v.SpellID == 160452 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"原始暴怒\"]\nif v.SpellID == 264667 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"死亡凶蛮战鼓\"]\nif v.SpellID == 309658 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nvars[\"嗜血剩余时间\"] = 0\n",
            ["取得爆发强度"] = "--全职业-全专精-取得爆发强度\nif boss.Exists and not boss.InCombat then\n    --print(\"boss存在但不在战斗\")\n    return 0 --不爆发\nend\nif target.IsTrainDummy then\n    return 99\nend\nif inPvpCombat then\n	if target.IsPlayer then\n		return target.HealthPercent <= (vars[\"PVP爆发阈值\"] or 0.5) and 5 or 1\n	else\n		return 0\n	end\nend\n\nif boss.Exists then -- boss战\n    if boss.IsTarget then\n        if inRaid then --团本boss\n            return 98\n        elseif inParty then --5人本boss\n            if target:TimeToDie() > 15 then\n                return 88\n            else\n                return target.Health / (player.HealthBaseline * 5)\n            end\n        else --野外boss\n            if target:TimeToDie() > 15 then\n                return 50\n            else\n                return target.Health / (player.HealthBaseline * 20)\n            end\n        end\n    elseif inPVE then\n        return target.Health / (player.HealthBaseline * (inParty and 10 or 50))\n    end\nelseif inRaid then -- 团本小怪,无boss\n	return vars[\"敌方目标总血量\"] / (player.HealthBaseline * 20)\nelseif battleType == \"小队\" then -- 小队小怪,无boss\n	return vars[\"敌方目标总血量\"] / (player.HealthBaseline * 3)\nelse --野外\n	return vars[\"敌方目标总血量\"] / (player.HealthBaseline * 0.7)\nend\nreturn 0\n\n",
            ["取得目标强度"] = "--全职业-全专精-取得目标强度\nlocal unit = ... or target\nif unit.IsTrainDummy then\n    return 99\nend\nif inPvpCombat then\n	if unit.IsPlayer then\n		return unit.HealthPercent <= (vars[\"PVP爆发阈值\"] or 0.5) and 5 or 2\n	else\n		return 0\n	end\nend\n--if unit.IsBoss then\n--    return inParty and 4.1 or 5\n--end\n\nif inRaid then -- 团本小怪,无boss\n	return unit.Health / (player.HealthBaseline * 10)\nelseif battleType == \"小队\" then -- 小队小怪,无boss\n	return unit.Health / (player.HealthBaseline * 3)\nelse --野外\n	return unit.Health / (player.HealthBaseline * 0.7)\nend\nreturn 0\n\n",
            ["在巨龙群岛"] = "--全职业-全专精-在巨龙群岛\n\nlocal mapInfo = C_Map.GetMapInfo(C_Map.GetBestMapForUnit(\"player\"))\nwhile mapInfo do\n    if mapInfo.mapID == 1978 then\n        return true\n    end\n    mapInfo = C_Map.GetMapInfo(mapInfo.parentMapID)\nend\n",
            ["基本检查"] = "--全职业-全专精-基本检查\nif IsMounted() then --在坐骑上\n    return\nend\nif UnitIsDeadOrGhost(\"player\") then --已死亡\n    return\nend\nif run(\"正在引导法术\") then --正在引导法术\n    return\nend\nif inCombat and IsForceStart() then\n    return true\nend\nif  player.MyBuff:Has(\"灵魂变形\") then \n    return\nend\nif ... then --附加check\n    return\nend\nreturn true",
            ["安全嘲讽"] = "--全职业-全专精-安全嘲讽\nif player.TauntSpell then\n    return player.TauntSpell:Cast()\nend\n",
            ["安全引导"] = "--全职业-全专精-安全引导\n--local actionName, castTo = ...\n--local v\n--if A[actionName]:IsReady() then\n--	A[actionName]:Protect(3)\n--	--print(1, A[actionName]:Cast(nil, castTo) or 0, GetTime())\n--	return A[actionName]:Cast(nil, castTo) or 0\n--elseif A[actionName]:IsProtected() then\n--	v = A[actionName]:GetCooldown()\n--	if v > 10 and v < select(2, GetSpellCooldown(actionName)) - 2 then\n--		--print(3, v, GetTime())\n--		return\n--	else\n--		--print(2, A[actionName]:Cast(nil, castTo) or 0, GetTime())\n--		return A[actionName]:Cast(nil, castTo) or 0\n--	end\n--else\n--	--print(4, v, GetTime())\n--end\n\nlocal actionName, castTo, params = ...\nlocal v = A[actionName]:Cast(nil, castTo, params)\nif v then\n	A[actionName]:Protect(1.5)\n	--print(1, A[actionName]:Cast(nil, castTo) or 0, GetTime())\n	return v\nelseif A[actionName]:IsProtected() then\n	v = A[actionName]:GetCooldown()\n	if v > 10 and v < select(2, sv:GetSpellCooldown(actionName)) - 2 then\n		--print(\"安全引导1\", actionName, GetTime())\n		return\n	else\n		--print(\"安全引导2\", actionName, GetTime())\n		return 0\n	end\nelse\n	--print(4, v, GetTime())\nend\n\n\n\n",
            ["强制执行"] = "--全职业-全专精-强制执行\nreturn",
            ["打断"] = "--全职业-全专精-打断\nif player.InterruptSpell then\n    return player.InterruptSpell:Cast(nil, ...)\nend\n",
            ["打爆炸物"] = "--全职业-全专精-打爆炸物\n--用于打爆炸物的技能，各专精需要自定义，否则将使用输出流程\nreturn run(\"输出\")",
            ["智能上马"] = "--全职业-全专精-智能上马\nif player:IsCasting() then\n    return -1 ----停止优先宏\nend\n--if A[\"全局保护\"]:IsProtected() then\n--    return\n--end\n--A[\"全局保护\"]:Protect(2.5)/script VehicleExit()/dump UnitInVehicle(\"player\")\n\nif A[\"全局保护\"]:IsProtected() then\n    return -1 ----停止优先宏\nend\nif UnitInVehicle(\"player\") then\n    return VehicleExit() ----离开载具\nend\n\nlocal v = A[\"幽魂缰绳\"]:Cast() if v then return v end \nv = A[\"噬渊鼠缰绳\"]:Cast() if v then return v end \nlocal cls = UnitClass(\"player\")\nif cls == \"德鲁伊\" then\n    if IsSwimming() then\n        if player.MyBuff:Has(\"旅行形态\") then\n            A[\"全局保护\"]:Protect(1, 0)\n            return A[\"取消旅行形态\"]:Cast()\n        else\n            return A[\"旅行形态\"]:Cast()\n        end\n    elseif IsIndoors() then\n--        if A[\"全局保护\"]:IsProtected() then\n--            return 0 --防止瞬间取消\n--        end\n        if player.MyBuff:Has(\"猎豹形态\") then\n            A[\"全局保护\"]:Protect(1, 0)\n            return A[\"取消猎豹形态\"]:Cast()\n        else\n            return A[\"猎豹形态\"]:Cast()\n        end\n    end\n    if player.MyBuff:Has(\"旅行形态\") then\n        A[\"全局保护\"]:Protect(1, 0)\n        return A[\"取消旅行形态\"]:Cast()\n    end\n    if not IsMounted() and (inCombat or player:IsMoving() or player.MyBuff:Has(\"猎豹形态\") or player.MyBuff:Has(\"熊形态\") or player.MyBuff:Has(\"枭兽形态\")) then\n        --A[\"全局保护\"]:Protect(1)\n        return A[\"旅行形态\"]:Cast()\n    end\nelseif cls == \"萨满祭司\" then\n    if IsIndoors() then\n        if not player.MyBuff:Has(\"幽魂之狼\") then\n            A[\"全局保护\"]:Protect(1, 0)\n            return A[\"幽魂之狼\"]:Cast()\n        else\n--            A[\"全局保护\"]:Protect(1, 0)\n            return A[\"取消幽魂之狼\"]:Cast()\n        end\n    end\nend\n--if not IsMounted() and not IsIndoors() and not player:IsMoving() then -- and run(\"在巨龙群岛\")\n--    return A[\"召唤随机坐骑\"]:Cast()\n--end\n\nif IsMounted() and not player.MyBuff:Has(\"神圣马驹\") then\n    --A[\"全局保护\"]:Protect(1.5)\n    Dismount()\n    return -1\nend\nif C_Map.GetBestMapForUnit(\"player\")==1543 then \n    C_MountJournal.SummonByID(1442)\nelse\n    C_MountJournal.SummonByID(0)\n    --return A[\"召唤随机坐骑\"]:Cast()\nend\nreturn -1\n",
            ["暗影折磨宝珠"] = "--全职业-全专精-暗影折磨宝珠\nreturn player.Health > 38000 and run(\"使用饰品\", \"暗影折磨宝珠\")",
            ["更新治疗饰品"] = "--全职业-全专精-更新治疗饰品\nvars[\"可用治疗饰品\"] = vars[\"可用治疗饰品\"] or {\"流水脉动之心\", \"焖燃飞羽绒簇\"}\nvars[\"治疗饰品1\"] = false\nvars[\"治疗饰品2\"] = false\n\nfor _, v in pairs(vars[\"可用治疗饰品\"]) do\n    if A[\"饰品1\"]:IsItem(v) then\n        vars[\"治疗饰品1\"] = A[\"饰品1\"]\n    elseif A[\"饰品2\"]:IsItem(v) then\n        vars[\"治疗饰品2\"] = A[\"饰品2\"]\n    end\nend\n",
            ["更新爆发饰品"] = "--全职业-全专精-更新爆发饰品\nif not vars[\"无效饰品\"] then\n    vars[\"无效饰品\"] = \n    {\n        [\"帕库冠羽\"] = true,\n        [\"噩兆多彩精华\"] = true,\n        [\"索·莉亚的究极秘术\"] = true,\n        [\"焕新羁绊之鼓\"] = true,\n    }\n    if vars[\"可用治疗饰品\"] then\n        for _, v in pairs(vars[\"可用治疗饰品\"]) do\n           vars[\"无效饰品\"][v] = true\n        end\n    end\n    vars[\"忽略施法时间饰品\"] = \n    {\n        [\"被诅咒的岩石雕像\"] = true,\n    }\nend\nvars[\"爆发饰品1\"] = A[\"饰品1\"]:CanBeUsedInBurstMacro(vars[\"无效饰品\"], vars[\"忽略施法时间饰品\"]) and A[\"饰品1\"]\nvars[\"爆发饰品2\"] = A[\"饰品2\"]:CanBeUsedInBurstMacro(vars[\"无效饰品\"], vars[\"忽略施法时间饰品\"]) and A[\"饰品2\"]\n\n--for _, v in pairs(vars[\"无效饰品\"]) do\n--    if A[\"饰品1\"]:IsItem(v) then\n--        vars[\"爆发饰品1\"] = false\n--    elseif A[\"饰品2\"]:IsItem(v) then\n--        vars[\"爆发饰品2\"] = false\n--    end\n--end\n",
            ["正在引导法术"] = "--全职业-全专精-正在引导法术\n--可重载\nreturn player:GetChannelingSpell() --正在引导法术\n",
            ["治疗"] = "--全职业-全专精-治疗\nreturn",
            ["治疗石"] = "--全职业-全专精-治疗石\nif not SwitchIsOn(\"治疗石\") then\n    return\nend\nif player.HealthPercent > (battleType == \"野外\" and 0.55 or 0.45) then\n    return\nend\nif A[\"治疗石\"]:GetCount() == 0 then\n    return\nend\nif A[\"治疗石\"]:FailedIn(10, \"物品还没有准备好\") then\n    return\nend\nif A[\"治疗石\"]:FailedIn(10, \"不能在变形状态下使用物品\") then\n    return\nend\nreturn A[\"治疗石\"]:Cast()\n",
            ["治疗药水"] = "--全职业-全专精-治疗药水\nif player.HealthPercent > 0.45 then\n    return\nend\nif SwitchIsOn(\"低星红瓶\") then\n    if A[\"一星治疗药水\"]:GetCount() > 0 then\n        if A[\"一星治疗药水\"]:FailedIn(10, \"物品还没有准备好\") then\n            return\n        end\n        if A[\"一星治疗药水\"]:FailedIn(10, \"不能在变形状态下使用物品\") then\n            return\n        end\n        return A[\"一星治疗药水\"]:Cast()\n    end\n    if A[\"二星治疗药水\"]:GetCount() > 0 then\n        if A[\"二星治疗药水\"]:FailedIn(10, \"物品还没有准备好\") then\n            return\n        end\n        if A[\"二星治疗药水\"]:FailedIn(10, \"不能在变形状态下使用物品\") then\n            return\n        end\n        return A[\"二星治疗药水\"]:Cast()\n    end\nelseif SwitchIsOn(\"高星红瓶\") then\n    if A[\"二星治疗药水\"]:GetCount() > 0 then\n        if A[\"二星治疗药水\"]:FailedIn(10, \"物品还没有准备好\") then\n            return\n        end\n        if A[\"二星治疗药水\"]:FailedIn(10, \"不能在变形状态下使用物品\") then\n            return\n        end\n        return A[\"二星治疗药水\"]:Cast()\n    end\n    if A[\"一星治疗药水\"]:GetCount() > 0 then\n        if A[\"一星治疗药水\"]:FailedIn(10, \"物品还没有准备好\") then\n            return\n        end\n        if A[\"一星治疗药水\"]:FailedIn(10, \"不能在变形状态下使用物品\") then\n            return\n        end\n        return A[\"一星治疗药水\"]:Cast()\n    end\nend\n\n",
            ["爆发技能"] = "--全职业-全专精-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n	return\nend\nreturn run(\"一键爆发\")\n",
            ["目标已无敌"] = "--全职业-全专精-目标已无敌\nlocal v\nif target.AllBuff:Has(\"圣盾术\") or target.AllBuff:Has(\"寒冰屏障\") or target.AllBuff:Has(\"灵龟守护\") then\n    return 0\nend\n",
            ["碎裂精华"] = "--全职业-全专精-碎裂精华\nreturn A[\"附魔_碎裂精华\"]:Cast()\n",
            ["立即一键爆发"] = "--全职业-全专精-立即一键爆发\nreturn A[\"一键爆发\"]:Cast(true)\n",
            ["紫瓶药水"] = "--全职业-全专精-紫瓶药水\nif player.HealthPercent > 0.45 then\n    return\nend\nif SwitchIsOn(\"低星紫瓶\") then\n    if A[\"一星紫瓶\"]:GetCount() > 0 then\n        if A[\"一星紫瓶\"]:FailedIn(10, \"物品还没有准备好\") then\n            return\n        end\n        if A[\"一星紫瓶\"]:FailedIn(10, \"不能在变形状态下使用物品\") then\n            return\n        end\n        return A[\"一星紫瓶\"]:Cast()\n    end\n    if A[\"二星紫瓶\"]:GetCount() > 0 then\n        if A[\"二星紫瓶\"]:FailedIn(10, \"物品还没有准备好\") then\n            return\n        end\n        if A[\"二星紫瓶\"]:FailedIn(10, \"不能在变形状态下使用物品\") then\n            return\n        end\n        return A[\"二星紫瓶\"]:Cast()\n    end\nelseif SwitchIsOn(\"高星紫瓶\") then\n    if A[\"二星紫瓶\"]:GetCount() > 0 then\n        if A[\"二星紫瓶\"]:FailedIn(10, \"物品还没有准备好\") then\n            return\n        end\n        if A[\"二星紫瓶\"]:FailedIn(10, \"不能在变形状态下使用物品\") then\n            return\n        end\n        return A[\"二星紫瓶\"]:Cast()\n    end\n    if A[\"一星紫瓶\"]:GetCount() > 0 then\n        if A[\"一星紫瓶\"]:FailedIn(10, \"物品还没有准备好\") then\n            return\n        end\n        if A[\"一星紫瓶\"]:FailedIn(10, \"不能在变形状态下使用物品\") then\n            return\n        end\n        return A[\"一星紫瓶\"]:Cast()\n    end\nend\n\n",
            ["自动道标"] = "--全职业-全专精-自动道标\nlocal spell, noPlayer = ...\nif not spell or not SwitchIsOn(spell) then\n    return\nend\nif A[spell]:IsProtected() then\n    return\nend\nif friends:GetMyBuffCount(spell, 60) > 0  then\n    return\nend\nlocal v = friends:GetTank()\nif v then\n    v = A[spell]:Cast(nil, v) if v then A[spell]:Protect(3, 0.8) return v end\nend\nif inParty or inRaid then\n    if focus.IsFriend then\n        v = A[spell]:Cast(nil, focus) if v then A[spell]:Protect(3, 0.8) return v end\n    elseif not noPlayer then\n        v = A[spell]:Cast(nil, player) if v then A[spell]:Protect(3, 0.8) return v end\n    end\nend\n",
            ["菲莱拉兹，梦境之瞑"] = "--全职业-全专精-菲莱拉兹，梦境之瞑\n\nreturn A[\"菲莱拉兹，梦境之瞑\"]:Cast()\n",
            ["补刀"] = "--全职业-全专精-补刀\nreturn\n",
            ["输出"] = "--全职业-全专精-输出\n--Print(\"当前专精没有内置输出脚本, 请打开Hekili开关\")\nPrint(\"当前专精没有内置输出脚本, 请打开【内置一键】开关\")\nreturn",
            ["输出初始化"] = "--全职业-全专精-输出初始化\nlocal unit, rangeLimit = ...\nvars[\"敌方目标\"] = enemies:GetNearbyInfo(unit or target, rangeLimit or 8)\nvars[\"敌方目标数量\"] = SwitchIsOn(\"仅单体\") and 1 or vars[\"敌方目标\"][\"数量\"] or 0\nvars[\"敌方不动目标数量\"] = SwitchIsOn(\"仅单体\") and 1 or vars[\"敌方目标\"][\"不动数量\"]\nvars[\"敌方目标总血量\"] = vars[\"敌方目标\"][\"总剩余血量\"]\nvars[\"爆发强度\"] = run(\"取得爆发强度\")\nvars[\"目标强度\"] = run(\"取得目标强度\")\nvars[\"目标死亡时间\"] = target:TimeToDie()\nrun(\"取得嗜血剩余时间\")\n\n",
            ["输出前"] = "--全职业-全专精-输出前\nreturn",
            ["输出流程"] = "--全职业-全专精-输出流程\"\nlocal v\n--v = (battleType == \"小队\") and A[\"打爆炸物\"]:Cast() if v then return v end --\n--v = run(\"远程拾取器\") if v then return v end\n--v = A[\"打爆炸物\"]:Cast() if v then return v end --\n--v = A[\"虚体生物\"]:Cast() if v then return v end --\n--print(SwitchIsOn(\"切换敌方\") and inCombat and not target.IsEnemy)\nif inCombat and not target.IsEnemy then --SwitchIsOn(\"切换敌方\") and \n	return A[\"选择目标\"]:TargetFrontEnemy()\nend\n\nif not target.IsEnemy then\n	return A[\"停止攻击\"]:Cast()\nend\nif not IsForceStart() then\n    if not inCombat then\n        Debug(\"防止误开怪\")\n        --pauseHekili()\n		return A[\"停止攻击\"]:Cast()\n        --return 0\n    end\n    if not target.NeedAttack then\n        Debug(\"目标不在战斗中\")\n		return A[\"停止攻击\"]:Cast()\n        --return 0\n    end\nend\nv = SwitchIsOn(\"打断焦点\") and focus.IsEnemy and run(\"打断\", focus) if v then return v end\nv = SwitchIsOn(\"打断目标\") and run(\"打断\") if v then return v end\n--目标已无敌\nif target.IsPlayer and target.PhysicalReduce == 1 and target.MagicReduce == 1 then \n	return 0\nend\n\nif sv:UnitName(target.UnitId) == \"扬升宝珠\" then --SwitchIsOn(\"切换敌方\") and \n	return 0\nend\n--v = not inInstance and SwitchIsOn(\"狩猎陷阱\") and A[\"已解除的陷阱\"]:Cast() if v then return v end\nv = A[\"宠物攻击\"]:Cast() if v then return v end\n--local isAoe, count = run(\"取得目标数\", battleType)\n--v = run(battleType .. \"输出\" .. (isAoe and \"AOE\" or \"单体\"), count) if v then return v end\n--v = run(\"Simc\") if v then return v end\n--run(\"输出初始化\")\nv = run(\"输出初始化\") if v then return v end\n--v = A[\"自动攻击\"]:Cast() if v then return v end\nv = vars[\"敌方目标数量\"] == 1 and run(\"补刀\") if v then return v end\nv = run(\"输出前\") if v then return v end\n--v = JWow.IsJTRemix and run(\"军团神器技能\") if v then return v end\nv = run(\"Hekili输出或内置输出\") if v then return v end\n--if inCombat then\n--    return A[\"自动攻击\"]:Cast()\n--end\n",
            ["远程拾取器"] = "--全职业-全专精-远程拾取器\nlocal v\nif inInstance or not SwitchIsOn(\"远程拾取器\") then\n    return\nend\nif not A[\"远程拾取器\"]:IsReady() then\n    return\nend\nif A[\"远程拾取器\"]:IsProtected() then\n    return\nend\nA[\"远程拾取器\"]:Protect(60)\nError(\"警告:长时间使用[远程拾取器]自动挂机有可能导致封号, 使用此功能后果自负!!!\")\nreturn A[\"远程拾取器\"]:Cast()\n",
            ["选择治疗目标"] = "--全职业-全专精-选择治疗目标\nlocal v = friends:GetMinHealthPercentUnit()\n--if v and v.UnitId then\n	--print(\"选择治疗目标\", sv:UnitName(v.UnitId), v.HealthPercent)\n--end\nreturn v\n",
            ["防暂离"] = "--全职业-全专精-防暂离\nlocal t = GetTime() - (vars[\"上次时间\"] or 0)\nif t > 10 then\n    if t > 15 then\n        vars[\"上次时间\"] = GetTime()\n    end\n    return \"A\"\nend",
            ["预铺Buff"] = "--全职业-全专精-预铺Buff\nlocal action, rangeLimit, angleLimit, excludeBuff, excludeDebuff = ...\nlocal condi = \"预铺Buff条件\" .. action.ActionName\nvars[condi] = vars[condi] or\n	function(cachedUnit, unit, ...)\n		if action:Cast(nil, unit) then\n			if excludeBuff and unit.MyBuff:Has(excludeBuff) then\n				return false\n			end\n			if excludeDebuff and unit.AllDebuff:Has(excludeDebuff) then\n				return false\n			end\n			if not cachedUnit then\n				return true\n			else\n				local hp1 = unit.HealthPercent\n				if unit:GetDuty() == \"TANK\" then\n					hp1 = hp1 - 0.2\n				elseif sv:UnitIsUnit(unit.UnitId, \"player\") then\n					hp1 = hp1 - 0.1\n				end\n				local hp2 = cachedUnit.HealthPercent\n				if cachedUnit:GetDuty() == \"TANK\" then\n					hp2 = hp2 - 0.2\n				elseif sv:UnitIsUnit(cachedUnit.UnitId, \"player\") then\n					hp2 = hp2 - 0.1\n				end\n				if hp1 > hp2 then\n					return false\n				end\n			end\n			if inRaid then\n				return UnitInRaid(unit.UnitId) and (UnitIsPlayer(unit.UnitId) or select(3, GetInstanceInfo()) == 205)\n			elseif inParty then\n				return UnitInParty(unit.UnitId) and (UnitIsPlayer(unit.UnitId) or select(3, GetInstanceInfo()) == 205)\n			else--野外给宠物\n				return UnitIsPlayer(unit.UnitId) or sv:UnitIsUnit(unit.UnitId, \"pet\")\n			end\n			return true\n		end\n	end\nreturn action:CastOnUnitByCondition(nil, rangeLimit or 40, angleLimit, vars[condi], friends)\n",
            ["饰品治疗"] = "--全职业-全专精-饰品治疗\nlocal castTo = ...\nlocal v\nv = vars[\"治疗饰品1\"] and vars[\"治疗饰品1\"]:Cast(nil, castTo) if v then return v end \nv = vars[\"治疗饰品2\"] and vars[\"治疗饰品2\"]:Cast(nil, castTo) if v then return v end \n",
            ["驱散友方"] = "--全职业-全专精-驱散友方\nlocal v\nif not SwitchIsOn(\"驱散友方\") then\n	return\nend\nlocal boss1 = boss:GetBoss1()\nif not boss1 then\n	return DispelFriend()\nend\n--11.0 boss\nlocal name = sv:UnitName(boss1.UnitId)\nif name == \"缚霜者纳尔佐\" then -- 通灵战潮\n	v = DispelFriend()\n	if v then\n		local tm = v.CastTo.AllDebuff[\"冻结之缚\"]:GetTimeLeft()\n		if tm == 0 then\n			return v\n		elseif tm < 11 then\n			local count = friends:GetNearbyInfo(v.CastTo, 17)[\"数量\"]\n			if count == 1 then\n				return v\n			end\n		end\n	end\n\nelseif name == \"布隆特\" or name == \"齐扎·迅索\" then -- 水闸行动\n	v = DispelFriend()\n	if v then\n		local tm = v.CastTo.AllDebuff[\"动能胶质炸药\"]:GetTimeLeft()\n		if tm == 0 then\n			return v\n		--这个buff持续12秒，9的意思就是3秒后驱散，tm就是buff剩余的时间\n		elseif tm < 9 and not v.CastTo:IsMoving() then\n			return v\n		end\n	end\n\nelseif name == \"维克戈斯\" then --围攻伯拉勒斯\n	v = DispelFriend()\n	if v then\n		local tm = v.CastTo.AllDebuff[\"腐败之水\"]:GetTimeLeft()\n		if tm == 0 then\n			return v\n		else\n			local count = friends:GetNearbyInfo(v.CastTo, 4.5)[\"数量\"]\n			if count == 1 then\n				return v\n			end\n		end\n	end\n\nelseif name == \"E.D.N.A.\" then --矶石宝库\n	if boss1:GetCastingSpell() == \"震地猛击\" then\n		v = DispelFriend()\n		if v then\n			if v.CastTo.AllDebuff:Has(\"震地回响\") then\n				return v\n			end\n			local t = friends:GetTank()\n			if t.AllDebuff:Has(\"震地回响\") then\n				v.CastTo = t\n				return v\n			end\n--			print(\"震地猛击\", UnitName(v.CastTo.UnitId))\n			return v\n		end\n	else\n		local t = friends:GetTank()\n		if t then\n			local tm = t.AllDebuff[\"震地回响\"]:GetTimeLeft()\n			if tm > 0 and tm < 3.5 then\n				v = DispelFriend()\n				v.CastTo = t\n				return v\n			end\n--			v = DispelFriend()\n--			if v then\n--				print(UnitName(v.CastTo.UnitId), v.CastTo.AllDebuff[\"震地回响\"]:GetTimeLeft())\n--			end\n		end\n	end\n\nelse\n	return DispelFriend()\nend\n",
            ["默认"] = "--全职业-全专精-默认\n--通过run函数执行子脚本的时候，如果存在当前执行主脚本的名字作为前缀的脚本，则会优先执行\n--例如在执行主脚本【默认】时，如果存在子脚本【默认初始化】，则该脚本会优先被执行\nreturn run(\"默认流程\")",
            ["默认流程"] = "--全职业-全专精-默认流程\nlocal v\n--if SwitchIsOn(\"强制驱散\") then\n--	--优先驱散列表中的debuff\n--    v = ForceDispelFriend() if v then return v end --\"优先驱散友方\" \n--end\n\nv = run(\"治疗石\") if v then return v end\n\n--自己保命\nhealTarget = player --保命内脚本应该是直接使用player, 此处为了保险起见, 设置为player\nv = run(\"保命\") if v then return v end\n\nif SwitchIndex(\"治疗药水\") < SwitchIndex(\"紫瓶药水\") then\n	v = run(\"治疗药水\") if v then return v end\n	v = run(\"紫瓶药水\") if v then return v end\nelse\n	v = run(\"紫瓶药水\") if v then return v end\n	v = run(\"治疗药水\") if v then return v end\nend\n--v = A[\"驱散受难\"]:Cast() if v then return v end --\n\n--v = SwitchIsOn(\"驱散友方\") and DispelFriend() if v then return v end\nv = run(\"驱散友方\") if v then return v end\n--治疗目标\nif target.IsFriend and target.HealReduce < 0.9 then\n	healTarget = target\n	--healTarget:UpdateReduceV3()\n	--healTarget:UpdateDamageReduceV10()\n    v = run(\"治疗\") if v then return v end\nend\n\nif player.IsHealer then\n	--v = (battleType == \"小队\") and A[\"打爆炸物\"]:Cast() if v then return v end --\n	--治疗专精\n	if focus.IsFriend and focus.HealReduce < 0.9 then\n		healTarget = focus\n		--healTarget:UpdateReduceV3()\n		--healTarget:UpdateDamageReduceV10()\n		v = run(\"治疗\") if v then return v end\n	end\n    if SwitchIsOn(\"切换友方\") then\n        healTarget = run(\"选择治疗目标\") or false\n		if healTarget then\n			--healTarget:UpdateReduceV3()\n			--healTarget:UpdateDamageReduceV10()\n			v = run(\"治疗\") if v then return v end\n		end\n    end\n--	yeild(1)\n	v = SwitchIsOn(\"打断焦点\") and focus.IsEnemy and run(\"打断\", focus) if v then return v end\n	v = SwitchIsOn(\"打断目标\") and run(\"打断\") if v then return v end\n    if not target.IsFriend and SwitchIsOn(\"攻击敌方\") then\n--		yeild(2)\n        v = run(\"输出流程\") if v then return v end\n    end\nelseif not target.IsFriend then\n	--非治疗专精\n--	yeild(3)\n    v = run(\"输出流程\") if v then return v end\nend\n",
        },
    },
    ["唤魔师"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--唤魔师-全专精-_专精初始化\nvars[\"最大蓄力\"] = talent[\"魔法之泉\"] and 4 or 3\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["正在引导法术"] = "--唤魔师-全专精-正在引导法术\nif _G.___jPlayerEmpoweringSpell then\n    return\nend\nreturn player:GetChannelingSpell() --正在引导法术\n",
            ["输出初始化"] = "--唤魔师-全专精-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", target, 12)\n\n",
            ["输出前"] = "--唤魔师-全专精-输出前\nreturn A[\"蓄力法术\"]:Cast() \n",
        },
        ["增辉"] = {
            ["_先知先觉"] = "--唤魔师-增辉-_先知先觉\nif not SwitchIsOn(\"先知先觉\") then\n    return\nend\nif not A[\"先知先觉\"]:IsReady() then\n    return\nend\nif UnitExists(\"focus\") and focus.IsFriend and focus.MyBuff[\"先知先觉\"]:GetTimeLeft() < 3 then\n    v = A[\"先知先觉\"]:Cast(nil, focus) if v then return v end\nend\nif (inParty or inRaid) then\n    v = friends:GetUnitByCondition(player, 25, false, false,\n        function(cachedUnit, unit)\n            if unit.IsFriend and not sv:UnitIsUnit(unit.UnitId, \"player\") and A[\"先知先觉\"]:Cast(nil, unit) then\n                return true, unit:GetDuty() == \"DAMAGER\"\n            end\n        end\n    )\n    if v then\n        v = A[\"先知先觉\"]:Cast(nil, v) if v then return v end\n    end\nelse\n    v = A[\"先知先觉\"]:Cast(nil, player) if v then return v end\nend\n\n",
            ["_炽火龙鳞"] = "--唤魔师-增辉-_炽火龙鳞\nif not SwitchIsOn(\"炽火龙鳞\") then\n    return\nend\nif friends:GetMyBuffCount(\"炽火龙鳞\", 60) > 0 then\n    return\nend\nlocal v\n--if UnitIsUnit(healTarget.UnitId, \"focus\") then\n--    if not healTarget.MyBuff:Has(\"炽火龙鳞\") then\n--        v = A[\"炽火龙鳞\"]:Cast(nil, healTarget) if v then return v end\n--    end\n--end\nif inParty or inRaid then\n    v = friends:GetTank()\n    if v then\n        --print(UnitName(healTarget.UnitId), healTarget:GetDuty())\n        v = A[\"炽火龙鳞\"]:Cast(nil, v) if v then return v end\n    end\nelse\n    v = A[\"炽火龙鳞\"]:Cast(nil, player) if v then return v end\nend\n",
            ["_魔力之源"] = "--唤魔师-增辉-_魔力之源\nif not SwitchIsOn(\"魔力之源\") then\n    return\nend\nif friends:GetMyBuffCount(\"魔力之源\", 60) > 0 then\n    return\nend\nlocal v\n--if UnitIsUnit(healTarget.UnitId, \"focus\") then\n--    if not healTarget.MyBuff:Has(\"魔力之源\") then\n--        v = A[\"魔力之源\"]:Cast(nil, healTarget) if v then return v end\n--    end\n--end\nif inParty or inRaid then\n    v = friends:GetHealer()\n    if v then\n        --print(UnitName(healTarget.UnitId), healTarget:GetDuty())\n        v = A[\"魔力之源\"]:Cast(nil, v) if v then return v end\n    end\n--else\n--    v = A[\"魔力之源\"]:Cast(nil, player) if v then return v end\nend\n",
            ["保命"] = "--唤魔师-增辉-保命\nlocal v\nif inCombat then\n    v = A[\"青翠之拥\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n    v = A[\"翡翠之花\"]:ForceCast(healTarget.HealthPercent < 0.5, player) if v then return v end\n    v = A[\"黑曜鳞片\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"活焰自疗\") and A[\"活化烈焰\"]:Cast(player.HealthPercent < (inPVE and 0.3 or 0.4), player) if v then return v end\n    v = run(\"_先知先觉\") if v then return v end\nelse\n    if SwitchIsOn(\"活焰自疗\") and healTarget.HealthPercent < 0.8 and battleType == \"野外\" then\n        v = A[\"活化烈焰\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n        v = A[\"活化烈焰\"]:CastSafely(player.HealthPercent < 0.85, player) if v then return v end\n    end\n    v = A[\"青铜龙的祝福\"]:Cast() if v then return v end\nend\nv = run(\"_炽火龙鳞\") if v then return v end\nv = run(\"_魔力之源\") if v then return v end\n",
            ["爆发技能."] = "--唤魔师-增辉-爆发技能.\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nv = A[\"黑檀之力\"]:Cast() if v then return run(\"一键爆发\") end\n",
            ["输出"] = "--唤魔师-增辉-输出前\nlocal v\nvars[\"精华迸发\"] = player.MyBuff[\"精华迸发\"].Count\nv = A[\"亘古吐息\"]:Cast() if v then return v end\nv = A[\"深呼吸\"]:Cast() if v then return v end\nv = A[\"火焰吐息\"]:Cast(nil, target) if v then return v end\nv = vars[\"精华迸发\"] > 1 and A[\"喷发\"]:Cast() if v then return v end\nv = A[\"地壳激变\"]:Cast() if v then return v end\nv = A[\"喷发\"]:Cast() if v then return v end\nv = vars[\"敌方目标数量\"] > 1 and A[\"碧蓝打击\"]:Cast() if v then return v end\nv = A[\"活化烈焰\"]:Cast() if v then return v end --飞扑烈焰\n",
            ["输出前"] = "--唤魔师-增辉-输出前\nlocal v\nv = A[\"黑檀之力\"]:Cast() if v then return v end\nreturn A[\"蓄力法术\"]:Cast() \n",
        },
        ["恩护"] = {
            ["_专精初始化"] = "--唤魔师-恩护-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--唤魔师-恩护-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--唤魔师-恩护-保命\nvars[\"精华数\"] = player:GetPower(P[\"精华\"])\nvars[\"精华差值\"] = player:GetPowerDeficit(P[\"精华\"])\n\nlocal v\nif inCombat then\n    v = A[\"青翠之拥\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n    v = SwitchIsOn(\"黑曜鳞片\") and A[\"黑曜鳞片\"]:Cast() if v then return v end\nend\n\nv = A[\"青铜龙的祝福\"]:Cast() if v then return v end\n",
            ["打爆炸物"] = "--唤魔师-恩护-打爆炸物\nlocal v\nv = A[\"碧蓝打击\"]:Cast() if v then return v end\n",
            ["治疗"] = "--唤魔师-恩护-治疗\nlocal v\nif inCombat then\n    v = SwitchIsOn(\"取消施法\") and A[\"活化烈焰\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    v = A[\"时间膨胀\"]:Cast() if v then return v end\n    v = A[\"回溯\"]:Cast() if v then return v end\n    v = A[\"静滞\"]:Cast() if v then return v end\n    v = A[\"梦境吐息\"]:Cast() if v then return A[\"扭转天平\"]:Cast() or v end\n    v = A[\"时空畸体\"]:Cast() if v then return v end\n    v = A[\"梦境飞行\"]:Cast() if v then return v end\nend\nv = A[\"回响\"]:Cast(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\nv = A[\"青翠之拥\"]:Cast(healTarget.HealthPercent < 0.7 and (sv:UnitIsUnit(\"player\", healTarget.UnitId) or healTarget.MyBuff:Has(\"回响\")), player) if v then return v end\nv = A[\"翡翠之花\"]:Cast(healTarget.HealthPercent < 0.85, healTarget) if v then return v end\nv = A[\"逆转\"]:Cast(healTarget.HealthPercent < 0.88, healTarget) if v then return v end\nv = A[\"活化烈焰\"]:Cast(healTarget.HealthPercent < 0.7, healTarget) if v then return v end\nv = A[\"活化烈焰\"]:CastSafely(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\nv = SwitchIsOn(\"预铺回响\") and run(\"预铺Buff\", A[\"回响\"]) if v then return v end\n\n",
            ["输出"] = "--唤魔师-恩护-输出\nlocal v\nif not inCombat then\n    v = A[\"活化烈焰\"]:CastSafely() if v then return v end\nend\nv = SwitchIsOn(\"深呼吸\") and vars[\"敌方目标数量\"] > 1 and A[\"深呼吸\"]:Cast() if v then return v end\n\nv = SwitchIsOn(\"拆解\") and A[\"拆解\"]:Cast() if v then return v end\n\nv = A[\"火焰吐息\"]:Cast(nil, target) if v then return v end\n--v = A[\"焚身\"]:Cast(target.MyDebuff:Has(\"火焰吐息\")) if v then return v end\nv = vars[\"精华差值\"] == 0 and A[\"裂解\"]:Cast() if v then return v end\nv = vars[\"敌方目标数量\"] > 1 and A[\"碧蓝打击\"]:Cast() if v then return v end\nv = A[\"活化烈焰\"]:Cast() if v then return v end --飞扑烈焰\n",
        },
        ["湮灭"] = {
            ["_专精初始化"] = "--唤魔师-湮灭-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["保命"] = "--唤魔师-湮灭-保命\nlocal v\nif inCombat then\n    v = A[\"青翠之拥\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n    v = A[\"翡翠之花\"]:ForceCast(healTarget.HealthPercent < (battleType == \"野外\" and 0.75 or 0.5), player) if v then return v end\n    v = A[\"黑曜鳞片\"]:Cast() if v then return v end\n    if SwitchIsOn(\"活焰自疗\") then\n        v = A[\"活化烈焰\"]:Cast(player.HealthPercent < (battleType == \"野外\" and 0.5 or (inPVE and 0.3 or 0.4)), player) if v then return v end\n    end\nelse\n    if SwitchIsOn(\"活焰自疗\") and healTarget.HealthPercent < 0.8 and battleType == \"野外\" then\n        v = A[\"活化烈焰\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n        v = A[\"活化烈焰\"]:CastSafely(player.HealthPercent < 0.85, player) if v then return v end\n    end\n    v = A[\"青铜龙的祝福\"]:Cast() if v then return v end\nend\n",
            ["打爆炸物"] = "--唤魔师-湮灭-打爆炸物\nlocal v\nv = A[\"碧蓝打击\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--唤魔师-湮灭-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\n--if A[\"永恒之涌\"]:GetCooldown() <= (player.MyBuff[\"狂龙之怒\"].Duration + 6) and (A[\"火焰吐息\"]:GetCooldown() <= 2 * gcdmax or not talent[\"火上浇油\"]) then\nv = A[\"狂龙之怒\"]:Cast() if v then return run(\"一键爆发\") end\n--end\n",
            ["补刀"] = "--唤魔师-湮灭-补刀\nlocal v\nv = A[\"碧蓝打击\"]:Cast(A[\"碧蓝打击\"]:GetDamage() > target.Health) if v then return v end\n",
            ["输出"] = "--唤魔师-湮灭-输出\nlocal v\nif not inCombat then\n    --v = A[\"活化烈焰\"]:CastSafely() if v then return v end\nend\nv = SwitchIsOn(\"拆解\") and A[\"拆解\"]:Cast() if v then return v end\nvars[\"狂龙之怒时间\"] = player.MyBuff[\"狂龙之怒\"]:GetTimeLeft()\nv = SwitchIsOn(\"深呼吸\") and vars[\"敌方目标数量\"] > 1 and vars[\"狂龙之怒时间\"] == 0 and A[\"深呼吸\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\nv = A[\"碧蓝打击\"]:IsActiveSpellName(\"碧蓝横扫\") and A[\"碧蓝打击\"]:Cast() if v then return v end\nif vars[\"敌方目标数量\"] > 2 then\n    v = player.MyBuff:Has(\"飞扑烈焰\") and A[\"活化烈焰\"]:Cast() if v then return v end\n    v = A[\"火焰吐息\"]:Cast(nil, target) if v then return A[\"火焰吐息\"]:GetEmpowerStage() >= vars[\"最大蓄力\"] and A[\"扭转天平\"]:Cast() or v end\n    v = A[\"永恒之涌\"]:Cast() if v then return A[\"永恒之涌\"]:GetEmpowerStage() >= vars[\"最大蓄力\"] and A[\"扭转天平\"]:Cast() or v end\n    v = player.MyBuff:Has(\"群体裂解\") and A[\"裂解\"]:Cast() if v then return v end\n    v = A[\"葬火\"]:Cast() if v then return v end\nelse\n    v = vars[\"敌方目标数量\"] > 1 and player.MyBuff:Has(\"飞扑烈焰\") and A[\"活化烈焰\"]:Cast() if v then return v end\n    v = A[\"火焰吐息\"]:Cast(nil, target) if v then return vars[\"敌方目标数量\"] == (talent[\"飞扑烈焰\"] and 2 or 1) and A[\"扭转天平\"]:Cast() or v end\n    v = A[\"永恒之涌\"]:Cast() if v then return vars[\"敌方目标数量\"] > 1 and A[\"扭转天平\"]:Cast() or v end\n    v = A[\"裂解\"]:Cast() if v then return v end\nend\nv = vars[\"敌方目标数量\"] > 1 and A[\"碧蓝打击\"]:Cast() if v then return v end\nv = A[\"活化烈焰\"]:Cast() if v then return v end --飞扑烈焰\nv = A[\"碧蓝打击\"]:Cast(player:IsMoving()) if v then return v end\n",
        },
    },
    ["圣骑士"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--圣骑士-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["基本检查"] = "--圣骑士-全专精-基本检查\nif IsMounted() and not player.MyBuff:Has(\"神圣马驹\") then --在坐骑上\n    return\nend\nif UnitIsDeadOrGhost(\"player\") then --已死亡\n    return\nend\nif run(\"正在引导法术\") then --正在引导法术\n    return\nend\nif inCombat and IsForceStart() then\n    return true\nend\nif  player.MyBuff:Has(\"灵魂变形\") then \n    return\nend\nif ... then --附加check\n    return\nend\nreturn true",
            ["输出初始化"] = "--圣骑士-全专精-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["惩戒"] = {
            ["_专精初始化"] = "--圣骑士-惩戒-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"神圣风暴\"] = talent[\"神圣烈焰\"] and talent[\"旭日再升\"] and not talent[\"神圣仲裁者\"]-- and not talent[\"最终审判\"] and not talent[\"审判官复仇\"]\n\n\n",
            ["保命"] = "--圣骑士-惩戒-保命\nlocal v\nvars[\"神圣能量\"] = UnitLevel(\"player\") < 10 and 0 or player:GetPower(P[\"神圣能量\"])\nvars[\"神圣能量差\"] = player:GetPowerMax(P[\"神圣能量\"]) - vars[\"神圣能量\"]\nv = A[\"圣光闪现\"]:Cast(A[\"圣光闪现\"]:GetCurrentCastingTime() == 0 and player.HealthPercent < (battleType == \"野外\" and 0.85 or 0.5), player) if v then return v end\nlocal sds = player.MyBuff:Has(\"圣盾术\")\nv = A[\"圣光闪现\"]:Cast(sds and SwitchIsOn(\"无敌闪现\") and player.HealthPercent < 0.85, player) if v then return v end\n\nif not inCombat and battleType == \"野外\" then\n    v = A[\"圣光闪现\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n    v = A[\"圣光闪现\"]:CastSafely(player.HealthPercent < 0.8, player) if v then return v end\n    return\nend\nv = A[\"荣耀圣令\"]:Cast(player.HealthPercent < (battleType == \"野外\" and 0.6 or 0.35), player) if v then return v end\nif sds then\n    return \nend\nlocal fczd = (player.MyDebuff[\"复仇之盾\"].Absorb) / player.HealthBaseline\n--if fczd > 0 then\n--    player:AddAllReduce(fczd)\n--end\nv = A[\"圣佑术\"]:Cast() if v then return v end\nv = A[\"圣盾术\"]:Cast() if v then return v end\nv = A[\"圣疗术\"]:Cast((player.HealthPercent + fczd) < ((player.AllReduce > 0.2) and 0.2 or 0.25), player) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n\n",
            ["光辉荣耀"] = "--圣骑士-惩戒-光辉荣耀\nif vars[\"爆发强度\"] < 1 or not SwitchIsOn(\"输出爆发\") or target.RangeToPlayer > 8 then\n    return\nend\nlocal v\n\nif talent[\"处决宣判\"] then \n    local cd = A[\"处决宣判\"]:GetCooldown()\n    --v = A[\"处决宣判\"]:Cast() if v then return v end\n    v = (cd < 0.3 or cd > 22) and A[\"灰烬觉醒\"]:IsActiveSpell() and vars[\"神圣能量差\"] > 2 and A[\"灰烬觉醒\"]:Cast() if v then return A[\"处决宣判\"]:Cast() or run(\"一键爆发\") end\nelse\n    v = A[\"灰烬觉醒\"]:IsActiveSpell() and vars[\"神圣能量差\"] > 2 and A[\"灰烬觉醒\"]:Cast() if v then return run(\"一键爆发\") end\nend\nv = vars[\"神圣能量差\"] > 1 and player.MyBuff:Has(\"复仇之怒\") and A[\"圣洁鸣钟\"]:Cast(nil, target, {LeadCd=1}) if v then return v end\n",
            ["打爆炸物"] = "--圣骑士-惩戒-打爆炸物\nlocal v\nv = A[\"十字军打击\"]:Cast() if v then return v end\nv = A[\"审判\"]:Cast() if v then return v end\nv = A[\"愤怒之锤\"]:IsActiveSpell() and A[\"愤怒之锤\"]:Cast() if v then return v end\nv = A[\"公正之剑\"]:Cast() if v then return v end\n",
            ["普通技能"] = "--圣骑士-惩戒-普通技能\nif vars[\"神圣能量差\"] == 0 then\n    return\nend\nlocal v\nif not talent[\"光辉荣耀\"] and vars[\"爆发强度\"] > 0.4 and target.RangeToPlayer < 8 then\n    v = A[\"处决宣判\"]:Cast() if v then return v end\n    v = A[\"灰烬觉醒\"]:IsActiveSpell() and vars[\"神圣能量差\"] > 2 and A[\"灰烬觉醒\"]:Cast() if v then return v end\n    v = vars[\"神圣能量差\"] > 1 and A[\"圣洁鸣钟\"]:Cast(nil, target, {LeadCd=1}) if v then return v end\nend\nif talent[\"圣殿骑士之击\"] then\n    v = A[\"圣殿骑士斩击\"]:IsActiveSpell() and A[\"圣殿骑士斩击\"]:Cast() if v then return v end\n    v = A[\"圣殿骑士打击\"]:IsActiveSpell() and A[\"圣殿骑士打击\"]:Cast() if v then return v end\nend\n--v = A[\"驱邪术\"]:Cast() if v then return v end\nv = A[\"审判\"]:Cast() if v then return v end\n--v = A[\"愤怒之锤\"]:IsActiveSpell() and A[\"愤怒之锤\"]:Cast() if v then return v end\nv = A[\"公正之剑\"]:Cast(vars[\"神圣能量差\"] > (talent[\"神圣之刃\"] and 1 or 0)) if v then return v end\nv = A[\"奉献\"]:Cast(target.RangeToPlayer < 2) if v then return v end\nv = A[\"十字军打击\"]:Cast(nil, nil, {LeadCd=0.2}) if v then return v end\n--v = A[\"愤怒之锤\"]:IsActiveSpell() and A[\"愤怒之锤\"]:Cast() if v then return v end\n\n                --self:Add(CAutoActionSpell(\"圣殿骑士斩击\", CSTAutoAttack(), CSTToEnemy()))\n                --self:Add(CAutoActionSpell(\"圣殿骑士打击\", CSTAutoAttack(), CSTToEnemy()))\n",
            ["治疗"] = "--圣骑士-惩戒-治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\nv = A[\"圣疗术\"]:Cast(target.HealthPercent < 0.2, target) if v then return v end\nv = A[\"圣光闪现\"]:Cast(target.HealthPercent < 0.8 and (A[\"圣光闪现\"]:GetCurrentCastingTime() == 0), target) if v then return v end\nv = A[\"荣耀圣令\"]:Cast(player.HealthPercent < 0.3, target) if v then return v end\nv = A[\"圣光闪现\"]:Cast(target.HealthPercent < 0.7, target) if v then return v end\nv = A[\"圣光闪现\"]:CastSafely(target.HealthPercent < 0.85, target) if v then return v end\n",
            ["爆发技能"] = "--圣骑士-惩戒-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nv = run(\"复仇征伐\") if v then return v end\nlocal cd = A[\"复仇之怒\"]:GetCooldown()\nif cd > 4 * gcdmax then\n    return \nend\nif cd < 0.6 and vars[\"神圣能量差\"] < 2 then\n    return run(\"一键爆发\")--A[\"复仇之怒\"]\nend\nreturn run(\"普通技能\") or 0 --攒神圣能量\n",
            ["终结技"] = "--圣骑士-惩戒-终结技\nlocal v\n--if A[\"圣光之锤\"]:IsActiveSpell()  then return A[\"圣光之锤\"]:ForceCast() end\nif A[\"圣光之锤\"]:IsActiveSpell() then\n    v = A[\"圣光之锤\"]:Cast() if v then return v end\n    return run(\"普通技能\") or 0\nend\n\nv = player.MyBuff:Has(\"苍穹之力\") and A[\"神圣风暴\"]:Cast() if v then return v end\nlocal cd = A[\"复仇之怒\"]:GetCooldown()\n\nif player.MyBuff:Has(\"苍穹之遗\") then\n    if talent[\"最终审判\"] then\n        v = A[\"最终审判\"]:Cast() if v then return v end\n    else\n        v = A[\"圣殿骑士的裁决\"]:Cast() if v then return v end\n    end\nend\nif vars[\"神圣风暴\"] then\n    v = A[\"神圣风暴\"]:Cast() if v then return v end\nelse\n    v = not SwitchIsOn(\"仅单体\") and A[\"神圣风暴\"]:Cast(enemies:GetNearbyCount(player, 12) > 1) if v then return v end\nend\nif talent[\"最终审判\"] then\n    v = A[\"最终审判\"]:Cast() if v then return v end\nelse\n    v = A[\"圣殿骑士的裁决\"]:Cast() if v then return v end\nend\nv = A[\"正义盾击\"]:Cast() if v then return v end\n\n",
            ["输出"] = "--圣骑士-惩戒-输出\nlocal v\n--v = vars[\"爆发强度\"] > 0.4 and A[\"处决宣判\"]:Cast() if v then return v end\n\n--v = player.MyBuff:Has(\"苍穹之力\") and A[\"神圣风暴\"]:Cast() if v then return v end\nv = vars[\"神圣能量差\"] > (talent[\"神圣之刃\"] and 1 or 0) and (A[\"公正之剑\"]:GetChargeInfo():IsReachedOrSoon() or player.MyBuff:Has(\"战争艺术\")) and A[\"公正之剑\"]:Cast() if v then return v end\nv = A[\"愤怒之锤\"]:IsActiveSpell() and A[\"愤怒之锤\"]:Cast(vars[\"神圣能量差\"] > 0) if v then return v end\nif talent[\"光辉荣耀\"] then\n    v = run(\"光辉荣耀\") if v then return v end\nelse\n    v = run(\"爆发技能\") if v then return v end\nend\n--v = A[\"审判\"]:Cast(vars[\"神圣能量差\"] > 0) if v then return v end\nv = run(\"终结技\") if v then return v end\nv = run(\"普通技能\") if v then return v end\n\n\n",
        },
        ["神圣"] = {
            ["_专精初始化"] = "--圣骑士-神圣-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--圣骑士-神圣-_脚本初始化\nrun(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--圣骑士-神圣-保命\nlocal v\nvars[\"神圣能量\"] = UnitLevel(\"player\") < 10 and 0 or player:GetPower(P[\"神圣能量\"])\nvars[\"神圣能量差\"] = player:GetPowerMax(P[\"神圣能量\"]) - vars[\"神圣能量\"]\nlocal sds = player.MyBuff:Has(\"圣盾术\")\nif sds or not inCombat then\n    v = A[\"荣耀圣令\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n    v = A[\"圣光闪现\"]:Cast(player.HealthPercent < 0.6, player) if v then return v end\n    v = A[\"圣光闪现\"]:CastSafely(player.HealthPercent < 0.8, player) if v then return v end\n    return \nend\nif not target.IsFriend then\n    v = player.MyBuff[\"苍穹之遗\"]:GetTimeLeft()\n    v = A[\"荣耀圣令\"]:Cast(v > 0 and (v < 5 or player.HealthPercent < 0.7), player) if v then return v end\n	v = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nend\n\nv = A[\"圣佑术\"]:Cast() if v then return v end\nv = A[\"圣盾术\"]:Cast() if v then return v end\nv = A[\"圣疗术\"]:Cast(player.HealthPercent < ((player.AllReduce > 0.2) and 0.2 or 0.25), player) if v then return v end\nv = A[\"神圣壁垒\"]:IsActiveSpell() and A[\"神圣壁垒\"]:Cast(player.HealthPercent < 0.5, player) if v then return v end\n\n\n\n\n\n\n",
            ["十字军之力"] = "--圣骑士-神圣-十字军之力\n--local zjCd = A[\"神圣震击\"]:GetCooldown()\n--local lmCd = A[\"黎明之光\"]:GetCooldown()\n--if (zjCd < gcdmax + 0.4) and (lmCd < gcdmax + 0.4) then --2者都快好了\n--    return\n--end\n--if (zjCd > 3 * gcdmax + 0.4) and (lmCd < 3 * gcdmax + 0.4) then --2者都差3gcd以上\n--    return A[\"十字军打击\"]:Cast()\n--end\n--if A[\"十字军打击\"]:GetChargeInfo():TimeToCharges() < (2 * gcdmax + 0.4) then --2gcd以内充满\n--    return A[\"十字军打击\"]:Cast()\n--end\n",
            ["复仇十字军_"] = "--圣骑士-神圣-复仇十字军_\nlocal v\nv = A[\"审判\"]:Cast() if v then return v end\nv = A[\"复仇十字军\"]:Cast() if v then return v end --十字军打击\nv = A[\"神圣震击\"]:Cast() if v then return v end\nv = A[\"愤怒之锤\"]:IsActiveSpell() and A[\"愤怒之锤\"]:Cast() if v then return v end\nv = A[\"正义盾击\"]:Cast(vars[\"神圣能量差\"] == 0) if v then return v end\n",
            ["安全输出"] = "--圣骑士-神圣-安全输出\nlocal v\nv = A[\"愤怒之锤\"]:IsActiveSpell() and A[\"愤怒之锤\"]:Cast() if v then return v end\nv = A[\"奉献\"]:Cast(target.RangeToPlayer < 2 and enemies:GetMyDebuffCount(\"奉献\") == 0) if v then return v end\nv = A[\"正义盾击\"]:Cast(vars[\"神圣能量差\"] == 0) if v then return v end\nv = SwitchIsOn(\"输出震击\") and A[\"神圣震击\"]:Cast() if v then return v end\n--v = A[\"十字军打击\"]:Cast(A[\"神圣震击\"]:GetCooldown() > 1.5) if v then return v end\nv = A[\"审判\"]:Cast() if v then return v end\n--v = A[\"十字军打击\"]:Cast(A[\"十字军打击\"]:GetChargeInfo():TimeToCharges() < 0.4) if v then return v end\n\n\n\n",
            ["打爆炸物"] = "--圣骑士-神圣-打爆炸物\nlocal v\nv = A[\"审判\"]:Cast() if v then return v end\n--v = A[\"十字军打击\"]:Cast() if v then return v end\nv = SwitchIsOn(\"输出震击\") and A[\"神圣震击\"]:Cast() if v then return v end\nv = A[\"愤怒之锤\"]:IsActiveSpell() and A[\"愤怒之锤\"]:Cast() if v then return v end\n",
            ["提尔的拯救_"] = "--圣骑士-神圣-提尔的拯救_\nlocal v\nif sv:UnitIsUnit(healTarget.UnitId, \"player\") then\n    v = healTarget.MyBuff[200654]:GetTimeLeft() --提尔的拯救 附带buff\nelse\n    v = healTarget.MyBuff[\"提尔的拯救\"]:GetTimeLeft()\nend\nif healTarget.HealthPercent > 0.4 or not SwitchIsOn(\"圣光闪现\") then\n    v = v > A[\"圣光术\"]:GetCurrentCastingTime() + 0.3 and A[\"圣光术\"]:Cast(nil, healTarget) if v then return v end\nelse\n    v = v > A[\"圣光闪现\"]:GetCurrentCastingTime() + 0.3 and A[\"圣光闪现\"]:Cast(nil, healTarget) if v then return v end\nend\n",
            ["治疗"] = "--圣骑士-神圣-治疗\nlocal v\nif inCombat then\n    v = SwitchIsOn(\"取消施法\") and A[\"圣光闪现\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    v = SwitchIsOn(\"取消施法\") and A[\"圣光术\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    if SwitchIsOn(\"攻击敌方\") and target.IsEnemy and player.MyBuff:Has(\"复仇十字军\") then\n        v = run(\"复仇十字军_\") if v then return v end\n    end\n\n    v = A[\"圣疗术\"]:Cast(healTarget.HealthPercent < 0.2, healTarget) if v then return v end\n    --v = run(\"使用饰品\", \"释魂红玉\", target.IsEnemy and hoe:Need(), target) if v then return v end\n    v = A[\"圣洁鸣钟\"]:Cast(nil, healTarget) if v then return v end\n    vars[\"苍穹之遗时间\"] = player.MyBuff[\"苍穹之遗\"]:GetTimeLeft()\n    v = healTarget.HealthPercent < 0.7 and (player.MyBuff:Has(\"神性之手\") or player.MyBuff:Has(\"神恩术\")) and A[\"圣光术\"]:Cast(nil, healTarget) if v then return v end\n    v = A[\"黎明之光\"]:Cast()\n    if v then\n	    if vars[\"苍穹之遗时间\"] > 0 and SwitchIsOn(talent[\"永恒之火\"] and \"永恒之火\" or \"荣耀圣令\") then\n		    v = healTarget.HealthPercent < 0.7 and A[\"荣耀圣令\"]:Cast(nil, healTarget) if v then return v end\n	    elseif healTarget.HealthPercent > 0.5 then\n		    return v\n	    end\n    end\n    v = SwitchIsOn(\"圣光闪现\") and healTarget.HealthPercent < 0.85 and player.MyBuff:Has(\"圣光灌注\") and A[\"圣光闪现\"]:CastSafely(nil, healTarget) if v then return v end\n    v = A[\"荣耀圣令\"]:Cast(healTarget.HealthPercent < 0.5 or (healTarget.HealthPercent < 0.85 and vars[\"神圣能量差\"] == 0) or (vars[\"苍穹之遗时间\"] > 0 and (vars[\"苍穹之遗时间\"] < 5 or healTarget.HealthPercent < 0.7)), healTarget) if v then return v end\n    v = A[\"神圣震击\"]:Cast(healTarget.HealthPercent < 0.5, healTarget) if v then return v end\n    v = A[\"复仇之怒\"]:Cast() if v then return v end\n    vars[\"无敌中\"] = player.MyBuff:Has(\"圣盾术\")\n    if healTarget.HealthPercent < 0.5 then\n        v = A[\"神圣壁垒\"]:IsActiveSpell() and A[\"神圣壁垒\"]:Cast(healTarget.HealthPercent < 0.5, healTarget) if v then return v end\n        v = A[\"圣洁武器\"]:IsActiveSpell() and A[\"圣洁武器\"]:Cast(nil, healTarget) if v then return v end\n        --v = A[\"信仰屏障\"]:Cast(nil, healTarget) if v then return v end\n        --v = SwitchIsOn(\"神恩术\") and A[\"神恩术\"]:IsReady() and A[\"神恩术宏\"]:Cast(nil, healTarget) if v then return v end\n        v = run(\"饰品治疗\", healTarget) if v then return v end\n        v = healTarget.HealthPercent > 0.3 and talent[\"提尔的拯救\"] and run(\"提尔的拯救_\") if v then return v end\n        --v = A[\"神性之手\"]:Cast() if v then return v end\n        v = A[\"神圣棱镜\"]:Cast(nil, healTarget) if v then return v end\n        --v = A[\"赋予信仰\"]:Cast(nil, healTarget) if v then return v end\n    else\n        v = healTarget.HealthPercent < 0.8 and talent[\"提尔的拯救\"] and run(\"提尔的拯救_\") if v then return v end\n    end\n    v = A[\"牺牲祝福\"]:Cast(inPVE and healTarget.HealthPercent < 0.4 and not sv:UnitIsUnit(healTarget.UnitId, \"player\") and (player.HealthPercent > 0.6 or vars[\"无敌中\"]), healTarget) if v then return v end\n\n    v = A[\"光环掌握\"]:Cast() if v then return v end\n    v = A[\"美德道标\"]:Cast(nil, healTarget) if v then return v end\n\n    if SwitchIsOn(\"攻击敌方\") and target.NeedAttack and healTarget.HealthPercent > 0.5 and target.IsEnemy then\n        v = run(\"安全输出\") if v then return v end\n    end\n\n    v = A[\"黎明之光\"]:Cast() if v then return v end\n    v = A[\"荣耀圣令\"]:Cast(healTarget.HealthPercent < 0.75, healTarget) if v then return v end\n    v = A[\"神圣震击\"]:Cast(healTarget.HealthPercent < 0.9, healTarget) if v then return v end\n    v = A[\"神圣棱镜\"]:Cast(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\nend\nif SwitchIsOn(\"圣光术\") and healTarget.HealthPercent < 0.8 then\n    v = A[\"圣光术\"]:Cast(nil, healTarget) if v then return v end\nelseif SwitchIsOn(\"圣光闪现\") and healTarget.HealthPercent < 0.5 then\n    v = A[\"圣光闪现\"]:CastSafely(nil, healTarget) if v then return v end\nend\n\n",
            ["输出"] = "--圣骑士-神圣-输出\nlocal v\n--v = A[\"十字军打击\"]:Cast(player.MyBuff:Has(\"圣眷在握\")) if v then return v end\nv = A[\"愤怒之锤\"]:IsActiveSpell() and A[\"愤怒之锤\"]:Cast() if v then return v end\nv = A[\"圣洁武器\"]:IsActiveSpell() and A[\"圣洁武器\"]:Cast(nil, healTarget) if v then return v end\nv = A[\"复仇十字军_治疗\"]:Cast(target.RangeToPlayer < 5) if v then return v end\n--v = talent[\"十字军之力\"] and run(\"十字军之力\") if v then return v end\nv = A[\"神圣棱镜\"]:Cast() if v then return v end\nv = A[\"奉献\"]:Cast(target.RangeToPlayer < 2 and enemies:GetMyDebuffCount(\"奉献\") == 0) if v then return v end\nv = A[\"审判\"]:Cast() if v then return v end\n--v = A[\"十字军打击\"]:Cast(not talent[\"十字军之力\"]) if v then return v end\nv = SwitchIsOn(\"输出震击\") and A[\"神圣震击\"]:Cast() if v then return v end\n--v = A[\"十字军打击\"]:Cast(A[\"十字军打击\"]:GetChargeInfo():TimeToCharges() < 0.4) if v then return v end\n--v = A[\"十字军打击\"]:Cast() if v then return v end\nv = A[\"正义盾击\"]:Cast(vars[\"神圣能量差\"] == 0) if v then return v end\n",
        },
        ["防护"] = {
            ["_专精初始化"] = "--圣骑士-防护-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["保命"] = "--圣骑士-防护-保命\nlocal v\nvars[\"神圣能量\"] = player:GetPower(P[\"神圣能量\"])\n\nlocal sds = player.MyBuff:Has(\"圣盾术\")\nv = A[\"圣光闪现\"]:Cast(sds and SwitchIsOn(\"无敌闪现\") and player.HealthPercent < 0.85, player) if v then return v end\n\nif not inCombat and battleType == \"野外\" then\n    v = A[\"圣光闪现\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n    v = A[\"圣光闪现\"]:CastSafely(player.HealthPercent < 0.8, player) if v then return v end\n    return \nend\n--v = player.MyBuff[\"苍穹之遗\"]:GetTimeLeft()\nv = run(\"荣耀圣令_\") if v then return v end\nv = A[\"炽热防御者\"]:Cast() if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n\nif not player.MyBuff:Has(\"炽热防御者\") then\n    --v = A[\"提尔之眼\"]:Cast() if v then return v end\n    --v = vars[\"爆发强度\"] > 1 and A[\"提尔之眼\"]:ForceCast() if v then return v end\n    v = A[\"神圣壁垒\"]:IsActiveSpell() and A[\"神圣壁垒\"]:Cast(player.HealthPercent < (A[\"神圣军备\"]:GetChargeInfo():IsReachedOrSoon() and 0.8 or 0.5), player) if v then return v end\n    --v = A[\"光荣时刻_保命\"]:Cast() if v then return v end\n    v = A[\"戒卫\"]:Cast() if v then return v end\n    v = A[\"远古列王守卫\"]:Cast() if v then return v end\n    v = A[\"圣盾术\"]:Cast() if v then return v end\n    v = A[\"圣疗术\"]:Cast(player.HealthPercent < ((player.AllReduce > 0.2) and 0.2 or 0.3), player) if v then return v end\nend\nv = A[\"正义盾击\"]:Cast(player.MyBuff[\"正义盾击\"]:GetTimeLeft() < 3) if v then return v end\n",
            ["打爆炸物"] = "--圣骑士-防护-打爆炸物\nlocal v\nv = SwitchIsOn(\"复仇者之盾\") and A[\"复仇者之盾\"]:Cast() if v then return v end\nv = A[\"正义之锤\"]:Cast(target.RangeToPlayer < 5) if v then return v end\nv = A[\"审判\"]:Cast() if v then return v end\nv = A[\"愤怒之锤\"]:IsActiveSpell() and A[\"愤怒之锤\"]:Cast() if v then return v end\n\n\n\n",
            ["治疗"] = "--圣骑士-防护-治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\nv = A[\"圣疗术\"]:Cast(target.HealthPercent < 0.2, target) if v then return v end\nv = A[\"荣耀圣令\"]:Cast(target.HealthPercent < 0.7 or (target.HealthPercent < 0.8 and player.MyBuff:Has(\"闪耀之光\")), target) if v then return v end\nv = A[\"圣光闪现\"]:Cast(target.HealthPercent < 0.7, target) if v then return v end\nv = A[\"圣光闪现\"]:CastSafely(target.HealthPercent < 0.9, target) if v then return v end\n",
            ["爆发技能"] = "--圣骑士-防护-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\n--if talent[\"炽天使\"] and player.MyBuff[\"炽天使\"]:GetTimeLeft() < 10 then\n--    return\n--end\nif player.BurstSpell then\n    v = A[player.BurstSpell]:Cast() if v then return run(\"一键爆发\") end\n    if player.MyBuff[player.BurstSpell]:GetTimeLeft() < 10 then\n        return\n    end\nelse\n    v = run(\"一键爆发\") if v then return v end\nend\n\n--v = SwitchIsOn(\"光荣时刻\") and A[\"光荣时刻\"]:Cast(A[\"复仇者之盾\"]:GetCooldown() > 5) if v then return v end\n",
            ["荣耀圣令_"] = "--圣骑士-防护-荣耀圣令_\nlocal v\nlocal sszg = player.MyBuff[327510].Count --\"闪耀之光\"\nv = A[\"荣耀圣令\"]:Cast(player.HealthPercent < 0.45 or (sszg > 0 and player.HealthPercent < (sszg > 1 and 0.8 or 0.6)), player) if v then return v end\n\nif sszg > 0 and SwitchIsOn(\"治疗友方\") and player:GetPowerPercent(P[\"法力\"]) > 0.8 then\n    local ht = friends:GetMinHealthPercentUnit()\n    v = ht and ht.HealthPercent < 0.5 and A[\"荣耀圣令\"]:Cast(nil, ht) if v then return v end\nend\n",
            ["输出"] = "--圣骑士-防护-输出\n\nlocal v\nv = vars[\"目标强度\"] > 0.4 and A[\"圣洁武器\"]:IsActiveSpell() and A[\"圣洁武器\"]:Cast(nil, player) if v then return v end\nv = vars[\"目标强度\"] > 0.4 and A[\"圣光之锤\"]:IsActiveSpell() and A[\"圣光之锤\"]:Cast() if v then return v end\nv = (vars[\"神圣能量\"] > 4 or player.MyBuff[\"正义盾击\"]:GetTimeLeft() < 3) and not (vars[\"目标强度\"] > 0.4 and A[\"圣光之锤\"]:IsActiveSpell()) and A[\"正义盾击\"]:Cast() if v then return v end\nv = A[\"愤怒之锤\"]:IsActiveSpell() and A[\"愤怒之锤\"]:Cast() if v then return v end\nv = A[\"审判\"]:Cast(not target.MyDebuff:Has(\"审判\") or A[\"审判\"]:GetChargeInfo():IsReachedOrSoon()) if v then return v end\nv = A[\"祝福之锤\"]:Cast(target.RangeToPlayer < 15 and A[\"祝福之锤\"]:GetChargeInfo():IsReachedOrSoon()) if v then return v end\nv = A[\"圣洁鸣钟\"]:Cast(target.RangeToPlayer < 15 and player.MyBuff:Has(player.BurstSpell)) if v then return v end\nv = A[\"复仇者之盾\"]:Cast() if v then return v end\nv = A[\"奉献\"]:Cast(target.RangeToPlayer < 2 and not player.MyBuff:Has(\"奉献\")) if v then return v end\nv = run(\"爆发技能\") if v then return v end\n--v = A[\"炽天使\"]:Cast() if v then return v end\n--v = vars[\"神圣能量\"] < 2 and A[\"圣光壁垒\"]:Cast() if v then return v end\n    \n--v = A[\"圣洁鸣钟\"]:Cast(target.RangeToPlayer < 8) if v then return v end\n--v = A[\"复仇者之盾\"]:Cast(not target.MyDebuff:Has(\"复仇者之盾\")) if v then return v end\n\nv = A[\"正义之锤\"]:Cast(target.RangeToPlayer < 5) if v then return v end\nv = A[\"祝福之锤\"]:Cast(target.RangeToPlayer < 15) if v then return v end\nv = A[\"奉献\"]:Cast(target.RangeToPlayer < 2) if v then return v end\nv = A[\"审判\"]:Cast() if v then return v end\n    \n--print(1, target.RangeToPlayer)\n--v = A[\"正义之锤\"]:Cast() if v then return v end\n\n",
        },
    },
    ["德鲁伊"] = {
        ["全专精"] = {
            ["Hekili输出或内置输出"] = "--德鲁伊-全专精-Hekili输出或内置输出\nlocal v\nif SwitchIsOn(\"内置一键\") and vars[\"专精形态\"]~= \"\" and player.Stance == vars[\"专精形态\"] then\n    v = gameautoaction() if v then return v end\nelse\n    v = run(\"输出\") if v then return v end\nend\n",
            ["_专精初始化"] = "--德鲁伊-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\nvars[\"月蚀结束时间\"] = 0\nvars[\"日蚀结束时间\"] = 0\nvars[\"星界能量差值\"] = 100\n",
            ["万灵之召"] = "--德鲁伊-全专精-万灵之召\nlocal castTo, params = ...\nif not castTo then \n    castTo = (UnitExists(\"target\") and target or player)\nend\nreturn run(\"安全引导\", \"万灵之召\", castTo, params)\n",
            ["保命"] = "--德鲁伊-全专精-保命\nif not inCombat then\n    v = A[\"野性印记\"]:Cast(not player.MyBuff:Has(\"潜行\")) if v then return v end\n    return \nend\nlocal v\n--v = SwitchIsOn(\"甘霖\") and A[\"甘霖\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"树皮术\") and A[\"树皮术\"]:Cast() if v then return v end\nv = A[\"野性印记\"]:Cast(not player.MyBuff:Has(\"潜行\")) if v then return v end\n",
            ["变熊狂回"] = "--德鲁伊-全专精-变熊狂回\n--local v = A[\"熊形态\"]:Cast(not player.MyBuff:Has(\"熊形态\")) if v then return v end\nlocal v = A[\"熊形态\"]:Cast() if v then return v end\nv = A[\"狂暴回复\"]:Cast(player.HealthPercent < 0.9, nil, FreeToCast) if v then return v end\n\n\n\n",
            ["基本检查"] = "--德鲁伊-全专精-基本检查\nreturn run(\"全职业-全专精-基本检查\", player.MyBuff:Has(\"旅行形态\"))\n",
            ["打爆炸物"] = "--德鲁伊-全专精-打爆炸物\nlocal v = A[\"月火术\"]:ForceCast() if v then return v end\n",
            ["旅行形态保命"] = "--德鲁伊-全专精-旅行形态保命\nif not inCombat then\n    v = A[\"野性印记\"]:Cast() if v then return v end\n    return\nend\nif player.HealthPercent > 0.6 then\n    return \nend\nlocal v\n--v = A[\"甘霖\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A:Has(\"生存本能\") and A[\"生存本能\"]:Cast() if v then return v end\nv = A[\"树皮术\"]:Cast() if v then return v end\nv = A[\"野性印记\"]:Cast() if v then return v end\n",
            ["枭兽形态保命"] = "--德鲁伊-全专精-枭兽形态保命\nlocal v\nif not inCombat then\n	v = SwitchIsOn(\"保命愈合\") and A[\"愈合\"]:ForceCast(player.HealthPercent < 0.4) if v then return v end\n    v = A[\"野性印记\"]:Cast() if v then return v end\n    return \nend\nlocal v\n--v = SwitchIsOn(\"甘霖\") and A[\"甘霖\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"树皮术\") and A[\"树皮术\"]:Cast() if v then return v end\nif SwitchIsOn(\"保命愈合\") then\n	v = A[\"愈合\"]:ForceCast(player.HealthPercent < 0.2) if v then return v end\n	v = A[\"愈合\"]:CastSafely(player.HealthPercent < 0.3) if v then return v end\nend\nv = A[\"野性印记\"]:Cast() if v then return v end\n",
            ["枭兽形态治疗"] = "--德鲁伊-全专精-枭兽形态治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\n--愈合可在枭首形态下使用\n--v = A[\"愈合\"]:CastSafely(healTarget.HealthPercent < 0.85, healTarget) if v then return v end\nv = A[\"愈合\"]:ForceCast(target.HealthPercent < 0.6, target) if v then return v end\nif target.HealthPercent < 0.9 then\n    if IsForceStart() then\n        v = A[\"愈合\"]:ForceCast(nil, target) if v then return v end\n    else\n        v = A[\"愈合\"]:CastSafely(nil, target) if v then return v end\n    end\nend\n\n--血量过低时，会尝试使用恢复亲和，此时会切换到人形态\n--if target.HealthPercent < 0.7 then\n--    v = run(\"恢复亲和\") if v then return v end\n--end\n\n",
            ["治疗"] = "--德鲁伊-全专精-治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\n--v = run(\"恢复亲和\") if v then return v end\nv = A[\"愈合\"]:Cast(target.HealthPercent < 0.6 or ((target.HealthPercent < 0.9 or IsForceStart()) and A[\"愈合\"]:IsSafeToCast() and not target.MyBuff:Has(\"愈合\")), target)\n--if SwitchIsOn(\"切换友方\") then\n--    v = run(\"切换治疗目标\") if v then return v end\n--end\n",
            ["熊形态保命"] = "--德鲁伊-全专精-熊形态保命\nlocal v\nif not inCombat then\n    v = A[\"野性印记\"]:Cast() if v then return v end\n    return \nend\nlocal v\n--v = A[\"甘霖\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"树皮术\"]:Cast() if v then return v end\nv = A:Has(\"狂暴回复\") and A[\"狂暴回复\"]:Cast(player.HealthPercent < 0.7) if v then return v end\nv = A[\"铁鬃\"]:Cast(nil, nil, player.MyBuff:Has(\"野性之心\") and {MaxCount=(player.HealthPercent < 0.75 and 5 or 1),RefillTime=10} ) if v then return v end\nv = A[\"野性印记\"]:Cast() if v then return v end\n",
            ["熊形态治疗"] = "--德鲁伊-全专精-熊形态治疗\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\n--if target.HealthPercent < 0.9 then\n--    return run(\"恢复亲和\")\n--end\n",
            ["熊形态输出"] = "--德鲁伊-全专精-熊形态输出\nlocal v\nv = SwitchIsOn(\"野性之心\") and A[\"野性之心\"]:Cast() if v then return v end\nv = A[\"裂伤\"]:Cast() if v then return v end\nlocal count = SwitchIsOn(\"仅单体\") and 1 or enemies:GetNearbyCount(player, 6)\n--print(A[\"痛击\"].ActionName, A[\"痛击\"].ID, A[\"痛击\"]:IsReady(), A[\"痛击\"].IsValid, A[\"痛击\"]:Cast(vars[\"目标数\"] > 0, nil, {MaxCount=3}))\nv = A[\"痛击\"]:Cast(count > 0, nil, {MaxCount=3}) if v then return v end\n--v = A[\"月火术\"]:Cast() if v then return v end\nv = A[\"横扫\"]:Cast(count > 0) if v then return v end\nv = A[\"痛击\"]:Cast(count > 0, nil, {MaxCount=10}) if v then return v end\n\nv = SwitchIsOn(\"野性冲锋\") and A[\"野性冲锋\"]:Cast() if v then return v end\n--v = A[\"月火术\"]:ForceCast() if v then return v end\n",
            ["猎豹形态保命"] = "--德鲁伊-全专精-猎豹形态保命\nif not inCombat then\n    v = A[\"野性印记\"]:Cast() if v then return v end\n    return \nend\nlocal v\n--v = A[\"甘霖\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A:Has(\"生存本能\") and A[\"生存本能\"]:Cast() if v then return v end\nv = A[\"树皮术\"]:Cast() if v then return v end\nv = A[\"野性印记\"]:Cast() if v then return v end\n",
            ["猎豹形态治疗"] = "--德鲁伊-全专精-猎豹形态治疗\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\n--if target.HealthPercent < 0.7 then\n--    return run(\"恢复亲和\")\n--end\n",
            ["猎豹形态输出"] = "--德鲁伊-全专精-猎豹形态输出\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nvars[\"能量\"] = player:GetPower(P[\"能量\"])\n\nlocal v\nv = A[\"野性之心\"]:Cast() if v then return v end\nif vars[\"连击点\"] > 3 then\n    v = A[\"割裂\"]:Cast() if v then return v end\n    v = A[\"凶猛撕咬\"]:Cast() if v then return v end\nelse\n    local count = SwitchIsOn(\"仅单体\") and 1 or enemies:GetNearbyCount(player, 6)\n--print(A[\"痛击_豹\"].ActionName, A[\"痛击_豹\"].ID, A[\"痛击_豹\"]:IsReady(), A[\"痛击_豹\"].IsValid, count, A[\"痛击_豹\"]:Cast(count > 0))\n    v = A[\"横扫\"]:Cast(count > 2 and vars[\"能量\"] > 50) if v then return v end\n    v = A[\"斜掠\"]:Cast() if v then return v end\n    v = A[\"撕碎\"]:Cast(vars[\"能量\"] > 60) if v then return v end\nend\nv = A[\"野性冲锋\"]:Cast() if v then return v end\n\n",
            ["输出"] = "--德鲁伊-全专精-输出\nreturn\n",
            ["输出前"] = "--德鲁伊-全专精-输出前\nif vars[\"专精形态\"] ~= \"\" and player.Stance == \"\" and A[vars[\"专精形态\"]].IsValid and player.Stance ~= vars[\"专精形态\"] then\n    return A[vars[\"专精形态\"]]:Cast()\nend\nv = A[\"安抚\"]:Cast(target:HasEnrageBuff()) if v then return v end\n\n",
        },
        ["守护"] = {
