            ["打爆炸物"] = "--德鲁伊-守护-打爆炸物\nlocal v\nv = A[\"月火术\"]:ForceCast() if v then return v end\n\n\n\n",
            ["熊形态保命"] = "--德鲁伊-守护-熊形态保命\nvars[\"怒气\"] = player:GetPower(P[\"怒气\"])\nif not inCombat then\n    v = A[\"野性印记\"]:Cast() if v then return v end\n    return\nend\n\nlocal v\n--v = A[\"甘霖\"]:Cast(player.HealthPercent < 0.25) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"狂暴化身\") and A[\"狂暴\"]:Cast() if v then return v end\nv = A[\"生存本能\"]:Cast(not player.MyBuff:Has(A[\"狂暴\"].Name) or player.HealthPercent < 0.25) if v then return v end\nv = A[\"树皮术\"]:Cast() if v then return v end\nv = SwitchIsOn(\"万灵之召\") and player.HealthPercent < 0.4 and run(\"万灵之召\", player) if v then return v end\n--v = A[\"鬃毛倒竖\"]:Cast(vars[\"怒气\"] < 30 or (player.AllInjure > 0.06 and vars[\"怒气\"] < 70)) if v then return v end\nv = A[\"鬃毛倒竖\"]:Cast(vars[\"怒气\"] < 30 or (vars[\"怒气\"] < 70)) if v then return v end --player.AllInjure > 0.06 and \nv = A[\"狂暴回复\"]:Cast(player.HealthPercent < 0.65, nil, A[\"狂暴回复\"]:GetChargeInfo():TimeToCharges() < 6 and {SafeHealthPercent=0.65}) if v then return v end\nvars[\"铁鬃\"] = player.MyBuff[\"铁鬃\"].Count\nv = vars[\"怒气\"] > (A[\"毁灭\"]:IsActiveSpell() and 99 or 69) and (vars[\"铁鬃\"] < 3 or player.HealthPercent < 0.75) and A[\"铁鬃\"]:Cast() if v then return v end\n--v = A[\"明月普照\"]:Cast(player.AllInjure > 0.1 and player.HealthPercent < 0.5) if v then return v end\nv = A[\"明月普照\"]:Cast(player.HealthPercent < 0.5) if v then return v end --player.AllInjure > 0.1 and \nv = A[\"野性印记\"]:Cast() if v then return v end\n\n\n\n",
            ["熊形态治疗"] = "--德鲁伊-守护-熊形态治疗\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\n--if target.HealthPercent < 0.7 then\n--    return run(\"恢复亲和\")\n--end\n",
            ["熊形态输出"] = "--德鲁伊-守护-熊形态输出\nlocal v\n--v = vars[\"无脑痛击\"] and A[\"痛击\"]:Cast() if v then return v end\nvars[\"怒气\"] = player:GetPower(P[\"怒气\"])\n\nv = vars[\"敌方目标数量\"] > 0 and A[\"痛击\"]:ForceCast() if v then return v end\nv = vars[\"爆发强度\"] > 0.6 and A[\"碎甲咆哮\"]:Cast() if v then return v end\n\n --print(vars[\"敌方目标数量\"])\n--vars[\"无脑痛击\"] = player.MyBuff:Has(A[\"狂暴\"].Name)\n--if not vars[\"无脑痛击\"] then\n	--v = player.MyBuff[\"尖牙与利爪\"].Count\n	--if v > 1 or (v == 1 and not target.MyDebuff:Has(\"尖牙与利爪\")) then\n	--	v = A[\"摧折\"]:Cast() if v then return v end\n	--	v = A[\"重殴\"]:Cast() if v then return v end\n	--end\n	--v = SwitchIsOn(\"铁鬃\") and A[\"铁鬃\"]:Cast(nil, nil,{MaxCount=((player.HealthPercent < 0.75 or inInstance or inTraining or UnitIsPlayer(\"target\")) and 8 or 1)} ) if v then return v end\n--end\n\nv = (not talent[\"致命一击\"] or vars[\"怒气\"] >= 60) and A[\"毁灭\"]:IsActiveSpell() and A[\"毁灭\"]:Cast() if v then return v end\nv = vars[\"怒气\"] > 70 and A[\"摧折\"]:Cast() if v then return v end\nv = A[\"明月普照\"]:Cast(talent[\"朔望\"] and target.RangeToPlayer < 3) if v then return v end\nv = A[\"月火术\"]:ForceCast(vars[\"怒气\"] < 93 and player.MyBuff:Has(\"星河守护者\")) if v then return v end\n\nif vars[\"敌方目标数量\"] > 0 then\n--    v = A[\"痛击\"]:ForceCast() if v then return v end\n    v = A[\"裂伤\"]:Cast() if v then return v end\n    v = A[\"月火术\"]:Cast() if v then return v end\n    v = A[\"重殴\"]:Cast(vars[\"敌方目标数量\"] < 4 and vars[\"怒气\"] > 80 and player.HealthPercent > 0.7) if v then return v end\n    v = not talent[\"朔望\"] and A[\"横扫\"]:Cast() if v then return v end\nend\nv = A[\"月火术\"]:Cast() if v then return v end\nv = A[\"野性冲锋\"]:Cast() if v then return v end\nv = A[\"月火术\"]:CastOnMinTime(nil, 10, 140) if v then return v end\nv = A[\"月火术\"]:ForceCast(talent[\"朔望\"] or target.RangeToPlayer > 5 or not A[\"裂伤\"]:IsReady(1)) if v then return v end\n",
            ["输出初始化"] = "--德鲁伊-守护-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["平衡"] = {
            ["_专精初始化"] = "--德鲁伊-平衡-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"专精形态\"] = \"枭兽形态\"\n\n",
            ["准备日月蚀"] = "--德鲁伊-平衡-准备日月蚀\nvars[\"日蚀时间\"] = player.MyBuff[\"日蚀\"]:GetTimeLeft()\nvars[\"月蚀时间\"] = player.MyBuff[\"月蚀\"]:GetTimeLeft()\nif vars[\"日蚀时间\"] < 1 and vars[\"月蚀时间\"] < 1 and vars[\"爆发强度\"] > 0.4 then --无日月蚀 \n    if talent[\"皎月呼唤\"] then\n        v = A[\"月蚀\"]:Cast() if v then return v end\n    else\n        if vars[\"敌方目标数量\"] == 1 then\n            if A[\"月蚀\"]:IsActiveSpell() then\n                v = A[\"愤怒\"]:CastSafely() if v then return v end\n            else \n                v = A[\"日蚀\"]:Cast() if v then return v end\n            end\n        else\n            if A[\"月蚀\"]:IsActiveSpell() then\n                v = A[\"月蚀\"]:Cast() if v then return v end\n            else \n                v = A[\"星火术\"]:CastSafely() if v then return v end\n            end\n        end\n    end\nend\n",
            ["打爆炸物"] = "--德鲁伊-平衡-打爆炸物\nlocal v\nv = A[\"月火术\"]:ForceCast() if v then return v end\n\n\n\n",
            ["新半满月"] = "--德鲁伊-平衡-新半满月\nif not talent[\"新月\"] then\n    return\nend\nlocal name = UnitCastingInfo(\"player\")\nif name == \"半月\" then\n    A[\"新月\"].Name = \"满月\"\n    A[\"新月\"].Tag = 40\nelseif name == \"新月\" then\n    A[\"新月\"].Name = \"半月\"\n    A[\"新月\"].Tag = 20\nelseif name == \"满月\" then\n    A[\"新月\"].Name = \"新月\"\n    A[\"新月\"].Tag = 10\nelseif IsUsableSpell(\"满月\") then\n    A[\"新月\"].Name = \"满月\"\n    A[\"新月\"].Tag = 40\nelseif IsUsableSpell(\"半月\") then\n    A[\"新月\"].Name = \"半月\"\n    A[\"新月\"].Tag = 20\nelse--if IsUsableSpell(\"新月\") then\n    A[\"新月\"].Name = \"新月\"\n    A[\"新月\"].Tag = 10\nend\n\nif vars[\"日蚀时间\"] > 2.6 or vars[\"月蚀时间\"] > 2.6 then --日月蚀中\n    if talent[\"新月\"] and vars[\"星界能量差值\"] >= A[\"新月\"].Tag and (A[\"新月\"].Name == \"满月\" or A[\"新月\"]:GetChargeInfo():IsReachedOrSoon()) then\n        v = A[\"新月\"]:Cast() if v then return v end\n    end\nelse --无日月蚀\n    if talent[\"新月\"] and A[\"新月\"].Name ~= \"满月\" and vars[\"星界能量差值\"] >= A[\"新月\"].Tag then\n        v = A[\"新月\"]:Cast() if v then return v end\n    end\nend\n",
            ["枭兽形态治疗"] = "--德鲁伊-平衡-枭兽形态治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\n--愈合可在枭首形态下使用\n--v = A[\"愈合\"]:CastSafely(healTarget.HealthPercent < 0.85, healTarget) if v then return v end\nv = A[\"愈合\"]:ForceCast(target.HealthPercent < 0.6, target) if v then return v end\nif target.HealthPercent < 0.9 then\n    if IsForceStart() then\n        v = A[\"愈合\"]:ForceCast(nil, target) if v then return v end\n    else\n        v = A[\"愈合\"]:CastSafely(nil, target) if v then return v end\n    end\nend\n\n--血量过低时，会尝试使用恢复亲和，此时会切换到人形态\n--if target.HealthPercent < 0.7 then\n--    v = run(\"恢复亲和\") if v then return v end\n--end\n\n",
            ["枭兽形态输出"] = "--德鲁伊-平衡-枭兽形态输出\nlocal v\n--if not inCombat then\n--    if vars[\"敌方目标数量\"] > 1 then\n--        v = A[\"星火术\"]:CastSafely() if v then return v end --not A[\"星火术\"]:IsCasting()\n--    else\n--        v = A[\"愤怒\"]:CastSafely() if v then return v end -- not A[\"愤怒\"]:IsCasting()\n--    end\n--end\nvars[\"需要星辰坠落\"] = not SwitchIsOn(\"仅单体\") and SwitchIsOn(\"星辰坠落\") and (enemies:GetNearbyCount(player, 40, true) > 1)\nv = (vars[\"需要星辰坠落\"] or player.MyBuff:Has(\"织星者的经纱\")) and A[\"星辰坠落\"]:Cast() if v then return v end\nvars[\"星界能量\"] = player:GetPower(P[\"星界能量\"])\nvars[\"星界能量差值\"] = player:GetPowerDeficit(P[\"星界能量\"])\nv = vars[\"星界能量差值\"] >= 20 and A[\"艾露恩之怒\"]:Cast() if v then return v end\nv = A[\"阳炎术\"]:Cast() if v then return v end\nv = A[\"月火术\"]:Cast() if v then return v end\n\nv = SwitchIsOn(\"自然之力\") and A[\"自然之力\"]:Cast(mouseover:IsBigGuy() or enemies:GetNearbyCount(mouseover, 8) > 2) if v then return v end\nv = SwitchIsOn(\"野性蘑菇\") and vars[\"爆发强度\"] > 1 and vars[\"星界能量差值\"] > 30 and vars[\"敌方目标数量\"] > 2 and not A[\"野性蘑菇\"]:SucceededIn(6) and A[\"野性蘑菇\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\n\nv = run(\"准备日月蚀\") if v then return v end\n\nv = SwitchIsOn(\"万灵之召\") and run(\"万灵之召\") if v then return v end\n--v = vars[\"星界能量\"] < 30 and A[\"沟通星界\"]:Cast() if v then return v end\nv = SwitchIsOn(\"星涌术\") and player.MyBuff:Has(\"织星者的纬纱\") and A[\"星涌术\"]:Cast() if v then return v end\nv = SwitchIsOn(\"星涌术\") and (not vars[\"需要星辰坠落\"]) and A[\"星涌术\"]:Cast(vars[\"星界能量差值\"] <= 10) if v then return v end\n--run(\"更新日月蚀时间\")\nv = run(\"新半满月\") if v then return v end\n\nv = (talent[\"皎月呼唤\"] or vars[\"敌方目标数量\"] > 1) and vars[\"月蚀时间\"] > A[\"星火术\"]:GetCurrentCastingTime() + 0.3 and A[\"星火术\"]:Cast() if v then return v end\nv = vars[\"敌方目标数量\"] < 3 and vars[\"日蚀时间\"] > A[\"愤怒\"]:GetCurrentCastingTime() + 0.3 and A[\"愤怒\"]:Cast() if v then return v end\n\nv = SwitchIsOn(\"野性蘑菇\") and vars[\"爆发强度\"] > 1 and vars[\"星界能量差值\"] > 40 and vars[\"敌方目标数量\"] < 3 and not A[\"野性蘑菇\"]:SucceededIn(15) and A[\"野性蘑菇\"]:Cast() if v then return v end\n\nif vars[\"敌方目标数量\"] > 1 then\n    if vars[\"星界能量差值\"] > 5 then\n        v = A[\"阳炎术\"]:CastOnMinTime(nil, 40, 60) if v then return v end\n	    v = A[\"月火术\"]:CastOnMinTime(nil, 40, 60) if v then return v end\n    end\nend\n\nif talent[\"皎月呼唤\"] or vars[\"敌方目标数量\"] > 1 then\n    v = A[\"星火术\"]:Cast() if v then return v end\nelse\n    v = A[\"愤怒\"]:Cast() if v then return v end\nend\n\nv = vars[\"敌方目标数量\"] > 1 and A[\"阳炎术\"]:ForceCast() if v then return v end\nif UnitLevel(\"player\") < 20 and vars[\"专精形态\"] == \"枭兽形态\" then\n    v = A[\"愤怒\"]:Cast() if v then return v end\nend\nv = A[\"月火术\"]:ForceCast() if v then return v end\n",
            ["爆发技能"] = "--德鲁伊-平衡-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n	return\nend\nlocal v\nv = A[\"超凡之盟\"]:Cast() if v then return run(\"一键爆发\") end\n--if A[\"超凡之盟\"]:GetCooldown() < 20 then\n--   return\n--end\n--v = player.MyBuff[A[\"超凡之盟\"].ActionName]:GetTimeLeft()\n--if v > 0 and v < 3 then\n--   return\n--end\n\n",
            ["输出"] = "--德鲁伊-平衡-输出\nif not not A[vars[\"专精形态\"]].IsValid then\n    return run(\"枭兽形态输出\")\nend\n",
        },
        ["恢复"] = {
            ["_专精初始化"] = "--德鲁伊-恢复-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"专精形态\"] = \"\"\n",
            ["_脚本初始化"] = "--德鲁伊-恢复-_脚本初始化\nrun(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--德鲁伊-恢复-保命\nlocal v\nif not inCombat then\n    v = A[\"野性印记\"]:Cast() if v then return v end\n    v = run(\"自动道标\", \"共生关系\") if v then return v end\n    return\nend\nif player.HealthPercent > 0.6 then\n    return \nend\n--print(\"player.HealthPercent\", player.HealthPercent)\n\n--v = SwitchIsOn(\"甘霖\") and A[\"甘霖\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"树皮术\") and A[\"树皮术\"]:Cast() if v then return v end\nv = SwitchIsOn(\"铁木树皮\") and A[\"铁木树皮\"]:Cast(nil, player) if v then return v end\nv = A[\"野性印记\"]:Cast() if v then return v end\nv = run(\"自动道标\", \"共生关系\") if v then return v end\n",
            ["宁静"] = "--德鲁伊-恢复-宁静\nlocal castTo, params = ...\n--if not castTo then \n--    castTo = (UnitExists(\"target\") and target or player)\n--end\nreturn run(\"安全引导\", \"宁静\", castTo, params)\n\n",
            ["快速生长"] = "--德鲁伊-恢复-快速生长\nif not talent[\"快速生长\"] or not healTarget.MyBuff:Has(\"生命绽放\") then\n    return healTarget\nend\nreturn friends:GetUnitByCondition(player, 40, false, false,\n    function(cachedUnit, unit)\n		if unit.HealReduce > 0.9 then\n			--print(\"HealReduce\", unit.HealReduce, unit.UnitId)\n			return false\n		end\n		if unit.HealthPercent > 0.95 then\n			--print(\"HealReduce\", unit.HealReduce, unit.UnitId)\n			return false\n		end\n		if unit.HealthPercent > 0.3 and unit.MyBuff:Has(\"生命绽放\") then\n			--print(\"HealReduce\", unit.HealReduce, unit.UnitId)\n			return false\n		end\n		--print(unit.UnitId, unit.HealReduce)\n		if cachedUnit and unit.HealthPercent > cachedUnit.HealthPercent then\n			--print(\"HealReduce2\", unit.HealReduce, unit.UnitId)\n			return false\n		end\n		if inRaid then\n			--print(\"inRaid\", UnitInRaid(unit.UnitId), unit.UnitId)\n			return UnitInRaid(unit.UnitId) or sv:UnitIsUnit(unit.UnitId, \"player\")\n		elseif inParty then\n			--print(\"inParty\", UnitInParty(unit.UnitId), unit.UnitId)\n			return UnitInParty(unit.UnitId) or sv:UnitIsUnit(unit.UnitId, \"player\")\n		else\n			--print(\"UnitIsPlayer\", UnitIsPlayer(unit.UnitId), sv:UnitIsUnit(unit.UnitId, \"pet\"), unit.UnitId)\n			return UnitIsPlayer(unit.UnitId) or sv:UnitIsUnit(unit.UnitId, \"pet\")\n		end\n    end\n) or healTarget\n",
            ["打爆炸物"] = "--德鲁伊-恢复-打爆炸物\nlocal v\n--v = A[\"阳炎术\"]:Cast(vars[\"敌方目标数量\"] > 2) if v then return v end\nv = A[\"月火术\"]:ForceCast() if v then return v end\n\n\n\n",
            ["枭兽形态治疗"] = "--德鲁伊-恢复-枭兽形态治疗\nlocal v\nif healTarget.HealthPercent < 0.7 then\n    return run(\"德鲁伊-恢复-治疗\")\nend\n--愈合可在枭首形态下使用\nv = A[\"愈合\"]:CastSafely(healTarget.HealthPercent < 0.85, healTarget) if v then return v end\n\n",
            ["治疗"] = "--德鲁伊-恢复-治疗\nhealTarget = run(\"快速生长\")\nv = SwitchIsOn(\"取消施法\") and A[\"愈合\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n\nlocal v\n--print(\"healTarget.HealthPercent\", healTarget.HealthPercent)\nif player.MyBuff:Has(\"自然迅捷\") and healTarget.HealthPercent < 0.6 then\n    v = A[\"愈合\"]:ForceCast(nil, healTarget) if v then return v end\nend\nif inCombat then\n    --v = run(\"使用饰品\", \"流水脉动之心\", healTarget.HealthPercent < 0.55) if v then return v end\n    v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    v = SwitchIsOn(\"万灵之召\") and healTarget.HealthPercent < 0.55 and run(\"万灵之召\", healTarget) if v then return v end\n    v = A[\"安抚\"]:Cast(target.IsEnemy and target:HasEnrageBuff()) if v then return v end\n    v = SwitchIsOn(\"宁静\") and not player:IsMoving() and run(\"宁静\") if v then return v end\n    v = A[\"铁木树皮\"]:Cast(nil, healTarget) if v then return v end\n    vars[\"迅捷治愈\"] = healTarget.MyBuff[\"野性成长\"]:GetTimeLeft() > 2 or healTarget.MyBuff[\"愈合\"]:GetTimeLeft() > 2 or healTarget.MyBuff[\"回春术\"]:GetTimeLeft() > 2\n    v = vars[\"迅捷治愈\"] and A[\"迅捷治愈\"]:Cast(talent[\"森林再生\"] and healTarget.HealthPercent < 0.75, healTarget) if v then return v end\n    v = A[\"化身：生命之树\"]:Cast() if v then return run(\"一键爆发\") end\n    if SwitchIsOn(\"激活\") then\n        v = player:GetPowerPercent(P[\"法力\"])\n        if v < 0.15 then\n            v = A[\"激活\"]:ForceCast(nil, player) if v then return v end\n        elseif v < 0.75 then\n            if talent[\"化身：生命之树\"] then\n                v = A[\"激活\"]:Cast(player.MyBuff:Has(\"化身：生命之树\"), player) if v then return v end\n            else\n                v = A[\"激活\"]:Cast(nil, player) if v then return v end\n            end\n        end\n    end\n    v = vars[\"迅捷治愈\"] and healTarget.HealthPercent < 0.5 and A[\"迅捷治愈\"]:Cast(nil, healTarget) if v then return v end\n    v = A[\"自然迅捷\"]:Cast(healTarget.HealthPercent < 0.4) if v then return v end\n    v = healTarget.MyBuff[\"生命绽放\"]:GetTimeLeft()\n    v = A[\"生命绽放\"]:Cast(healTarget.HealthPercent < 0.7 and friends:GetMyBuffCount(\"生命绽放\", 60) < 1, healTarget) if v then return v end\nend\nv = A[\"愈合\"]:Cast(healTarget.HealthPercent < 0.5, healTarget) if v then return v end\nv = A[\"野性成长\"]:Cast(nil, healTarget) if v then return v end\nv = A[\"百花齐放\"]:Cast() if v then return v end\nv = A[\"回春术\"]:Cast(healTarget.HealthPercent < 0.8 and healTarget.HealthPercent > 0.45, healTarget) if v then return v end\nv = A[\"萌芽\"]:Cast(healTarget.HealthPercent < 0.8 and healTarget.HealthPercent > 0.45, healTarget) if v then return v end\nv = A[\"愈合\"]:ForceCast(healTarget.HealthPercent < 0.6, healTarget) if v then return v end\nv = A[\"愈合\"]:CastSafely(healTarget.HealthPercent < 0.85, healTarget) if v then return v end\nv = SwitchIsOn(\"预铺绽放\") and friends:GetMyBuffCount(\"生命绽放\", 60) < 1 and run(\"预铺Buff\", A[\"生命绽放\"]) if v then return v end\nv = SwitchIsOn(\"预铺回春\") and run(\"预铺Buff\", A[\"回春术\"]) if v then return v end\n",
            ["猎豹形态治疗"] = "--德鲁伊-恢复-猎豹形态治疗\nlocal v\nif healTarget.HealthPercent < 0.7 then\n    return run(\"德鲁伊-恢复-治疗\")\nend\n\n",
            ["输出"] = "--德鲁伊-恢复-输出\nlocal v\nif not inCombat then\n    if vars[\"敌方目标数量\"] == 1 then\n        v = A[\"星火术\"]:CastSafely() if v then return v end\n    end\n    v = A[\"愤怒\"]:CastSafely() if v then return v end\nend\nif vars[\"敌方目标数量\"] < 3 then\n	v = A[\"星涌术\"]:Cast() if v then return v end\nend\nif vars[\"敌方目标数量\"] > 1 then\n	v = A[\"阳炎术\"]:CastOnMinTime(nil, 40, 60) if v then return v end\n	v = A[\"月火术\"]:CastOnMinTime(nil, 40, 60) if v then return v end\n    v = A[\"星火术\"]:Cast() if v then return v end\nelse\n	v = A[\"阳炎术\"]:Cast() if v then return v end\n	v = A[\"月火术\"]:Cast() if v then return v end\nend\nv = A[\"愤怒\"]:Cast() if v then return v end\nv = A[\"月火术\"]:ForceCast() if v then return v end\n\n\n",
        },
        ["野性"] = {
            ["AOE"] = "--德鲁伊-野性-AOE\nlocal v\nv = vars[\"能量\"] >= 50 and A[\"毁灭\"]:IsActiveSpell() and A[\"毁灭\"]:Cast(vars[\"连击点\"] == 5 or player.MyBuff:Has(\"顶级捕食者的渴望\")) if v then return v end\nv = A[\"原始之怒\"]:Cast(vars[\"连击点\"] == 5) if v then return v end\nv = vars[\"能量\"] >= 50 and talent[\"野性难驯\"] and A[\"凶猛撕咬\"]:Cast(vars[\"连击点\"] == 5 or player.MyBuff:Has(\"顶级捕食者的渴望\")) if v then return v end\nv = A[\"斜掠\"]:CastOnMinTime(nil, 10, 140) if v then return v end\nv = talent[\"月之灵\"] and A[\"月火术\"]:CastOnMinTime(nil, 10, 140) if v then return v end\nv = vars[\"能量\"] >= 80 and A[\"横扫\"]:Cast() if v then return v end\n",
            ["_专精初始化"] = "--德鲁伊-野性-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"专精形态\"] = \"猎豹形态\"\n",
            ["_脚本初始化"] = "--德鲁伊-野性-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n",
            ["打爆炸物"] = "--德鲁伊-野性-打爆炸物\nlocal v\nif talent[\"月之灵\"] then\n    v = A[\"月火术\"]:ForceCast() if v then return v end\nelse\n    v = A[\"斜掠\"]:ForceCast() if v then return v end\nend\n",
            ["爆发技能"] = "--德鲁伊-野性-爆发技能\nif vars[\"爆发强度\"] < 2 or not SwitchIsOn(\"输出爆发\") then\n	return\nend\nlocal v\n\nif vars[\"爆发强度\"] > 4 and player.BurstSpell and target.RangeToPlayer < 6 and (A[\"猛虎之怒\"]:GetCooldown() < 10 or vars[\"能量差\"] < 30) then\n    v = A[player.BurstSpell]:Cast() if v then return run(\"一键爆发\") end\n    if player.MyBuff[player.BurstSpell]:GetTimeLeft() < 4 then\n       return\n    end\nend\nif vars[\"爆发强度\"] > (talent[\"阿莎曼的指引\"] and 2 or 3) then\n    v = SwitchIsOn(\"万灵之召\") and run(\"万灵之召\") if v then return v end\nend\n\n",
            ["猎豹形态保命"] = "--德鲁伊-野性-猎豹形态保命\nvars[\"掠食者的迅捷剩余时间\"] = player.MyBuff[\"掠食者的迅捷\"]:GetTimeLeft()\n--if not inCombat then\n--    return\n--end\nvars[\"潜行中\"] = player.MyBuff:Has(\"潜行\")\n\nif vars[\"掠食者的迅捷剩余时间\"] > 2 and not vars[\"潜行中\"] then\n    v = A[\"愈合\"]:ForceCast((player.HealthPercent < 0.95 and vars[\"掠食者的迅捷剩余时间\"] < 5) or player.HealthPercent < 0.6 or (player.HealthPercent < 0.85 and player.MyBuff[\"愈合\"]:GetTimeLeft() < 3), player) if v then return v end\nend\nreturn run(\"德鲁伊-全专精-猎豹形态保命\")\n\n",
            ["猎豹形态治疗"] = "--德鲁伊-野性-猎豹形态治疗\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\nif target.HealthPercent < 0.7 then\n    if vars[\"掠食者的迅捷剩余时间\"] > 0 then\n        v = A[\"愈合\"]:Cast(nil, target) if v then return v end\n    end\n    --if target.HealthPercent < 0.5 then\n    --    return run(\"恢复亲和\")\n    --end\nend\n",
            ["猎豹形态输出"] = "--德鲁伊-野性-猎豹形态输出\nlocal v\nif not inCombat then\n    return\nend\n\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nvars[\"能量\"] = player:GetPower(P[\"能量\"])\nvars[\"能量差\"] = player:GetPowerDeficit(P[\"能量\"])\n\nv = A[\"啃噬\"]:Cast() if v then return v end\nv = vars[\"能量差\"] > 70 and vars[\"爆发强度\"] > 1 and A[\"猛虎之怒\"]:Cast() if v then return v end\n\nv = run(\"爆发技能\") if v then return v end\nv = vars[\"目标强度\"] > 0.5 and A[\"野性狂乱\"]:Cast(vars[\"连击点\"] < 2) if v then return v end\n\nv = vars[\"敌方目标数量\"] > 1 and talent[\"原始之怒\"] and run(\"AOE\") if v then return v end\nv = vars[\"目标强度\"] > 0.3 and vars[\"能量\"] >= 50 and A[\"凶猛撕咬\"]:Cast(player.MyBuff:Has(\"顶级捕食者的渴望\")) if v then return v end\nif vars[\"连击点\"] >= 5 then\n    v = run(\"终结技\") if v then return v end\nend\nif vars[\"连击点\"] < 5 then\n    if player.MyBuff:Has(player.BurstSpell) then\n        v = A[\"斜掠\"]:Cast() if v then return v end\n        v = A[\"横扫\"]:Cast(vars[\"敌方目标数量\"] > 1) if v then return v end\n        v = talent[\"月之灵\"] and A[\"月火术\"]:CastOnMinTime(nil, 10, 140) if v then return v end\n        v = talent[\"月之灵\"] and A[\"月火术\"]:ForceCast() if v then return v end\n        v = talent[\"双爪斜掠\"] and vars[\"敌方目标数量\"] > 1 and A[\"斜掠\"]:ForceCast() if v then return v end\n        v = A[\"撕碎\"]:Cast() if v then return v end\n    else\n        v = player.MyBuff:Has(\"节能施法\") and run(\"节能施法\") if v then return v end\n        v = A[\"斜掠\"]:Cast() if v then return v end\n        v = talent[\"月之灵\"] and A[\"月火术\"]:Cast() if v then return v end\n        v = talent[\"月之灵\"] and A[\"月火术\"]:CastOnMinTime(nil, 10, 140) if v then return v end\n        v = A[\"横扫\"]:Cast(vars[\"敌方目标数量\"] > 1) if v then return v end\n        v = talent[\"月之灵\"] and A[\"月火术\"]:ForceCast() if v then return v end\n        v = talent[\"双爪斜掠\"] and vars[\"敌方目标数量\"] > 1 and A[\"斜掠\"]:ForceCast() if v then return v end\n        v = A[\"撕碎\"]:Cast() if v then return v end\n    end\nend\nv = A[\"野性冲锋\"]:Cast() if v then return v end\n",
            ["猎豹形态输出前"] = "--德鲁伊-野性-猎豹形态输出前\nlocal v\nif vars[\"潜行中\"] or not A[\"潜行\"].IsValid then\n    v = target.RangeToPlayer < 8 and vars[\"爆发强度\"] > 1 and not player.MyBuff:Has(\"猛虎之怒\") and A[\"猛虎之怒\"]:Cast() if v then return v end\n    v = A[\"斜掠\"]:ForceCast() if v then return v end\nelseif not inCombat then\n    v = A[\"潜行\"]:Cast(not A[\"潜行\"]:SucceededIn(2)) if v then return v end\nend\n",
            ["终结技"] = "--德鲁伊-野性-终结技\nlocal v\nv = A[\"毁灭\"]:IsActiveSpell() and A[\"毁灭\"]:Cast() if v then return v end\nif vars[\"敌方目标数量\"] > 1 then\n    if talent[\"原始之怒\"] then\n        if vars[\"敌方目标数量\"] > 2 then\n            v = vars[\"能量\"] >= 75 and A[\"原始之怒\"]:Cast() if v then return v end\n        else\n            v = A[\"割裂\"]:CastOnMinTime(nil, 10, 140) if v then return v end\n        end\n    else\n        v = A[\"割裂\"]:CastOnMinTime(nil, 10, 140) if v then return v end\n    end\nelse\n    v = A[\"割裂\"]:Cast() if v then return v end\nend\nv = vars[\"能量\"] >= 50 and A[\"凶猛撕咬\"]:Cast() if v then return v end\n",
            ["节能施法"] = "--德鲁伊-野性-节能施法\nlocal v\nv = A[\"横扫\"]:Cast(vars[\"敌方目标数量\"] > 1) if v then return v end\nv = A[\"撕碎\"]:Cast() if v then return v end",
            ["输出初始化"] = "--德鲁伊-野性-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
    },
    ["恶魔猎手"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--恶魔猎手-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["输出初始化"] = "--恶魔猎手-全专精-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["噬灭"] = {
            ["_专精初始化"] = "--恶魔猎手-噬灭-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--恶魔猎手-噬灭-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--恶魔猎手-噬灭-保命\nif not inCombat then\n    return\nend\nlocal v\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"疾影\") and A[\"疾影\"]:Cast() if v then return v end\nv = SwitchIsOn(\"黑暗\") and A[\"黑暗\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--恶魔猎手-噬灭-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nif target.RangeToPlayer > 25 then\n    return\nend\nif player:GetPower(P[\"恶魔之怒\"]) < 100 then\n    return\nend\nlocal v = GetSpellInfo(\"虚空变形\") == \"虚空变形\" and A[\"虚空变形\"]:Cast() \nif v then\n    return run(\"一键爆发\") \nend\n\n",
            ["输出"] = "--恶魔猎手-噬灭-输出\nlocal v\nv = run(\"爆发技能\") if v then return v end\nv = GetSpellInfo(\"虚空变形\") == \"坍缩之星\" and A[\"坍缩之星\"]:Cast() if v then return v end\nv = talent[\"饥渴斩击\"] and GetSpellInfo(\"虚空之刃\") == \"饥渴斩击\" and A[\"虚空之刃\"]:Cast() if v then return v end\n\nv = A[\"恶魔追击\"]:Cast() if v then return v end\nv = A[\"虚空之刃\"]:Cast() if v then return v end\n\nv = A[\"收割\"]:Cast() if v then return v end\nv = vars[\"爆发强度\"] > 0.6 and A[\"虚空射线\"]:Cast() if v then return v end\nv = A[\"吞噬\"]:Cast() if v then return v end\n									\n									\n\n",
        },
        ["复仇"] = {
            ["_专精初始化"] = "--恶魔猎手-复仇-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["保命"] = "--恶魔猎手-复仇-保命\n--vars[\"灵魂残片数\"] = player.MyBuff[\"灵魂残片\"].Count\nvars[\"恶魔之怒\"] = player:GetPower(P[\"恶魔之怒\"])\nvars[\"恶魔之怒差值\"] = player:GetPowerDeficit(P[\"恶魔之怒\"])\nvars[\"灵魂残片数\"] = player.MyBuff[\"灵魂残片\"].Count\nif not inCombat then\n    return\nend\n\nlocal v\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = player.HealthPercent < 0.9 and SwitchIsOn(\"恶魔尖刺\") and A[\"恶魔尖刺\"]:GetChargeInfo():IsReachedOrSoon() and A[\"恶魔尖刺\"]:Cast(nil, nil, {SafeHealthPercent=0.9}) if v then return v end\nv = SwitchIsOn(\"烈火烙印\") and A[\"烈火烙印\"]:Cast((not boss.InCombat or boss.IsTarget) and target:IsBigGuy()) if v then return v end\nv = SwitchIsOn(\"邪能毁灭\") and A[\"邪能毁灭\"]:Cast(player.HealthPercent < 0.9) if v then return v end\nv = SwitchIsOn(\"恶魔尖刺\") and A[\"恶魔尖刺\"]:Cast() if v then return v end\nv = SwitchIsOn(\"恶魔变形\") and A[\"恶魔变形\"]:Cast() if v then return v end\n",
            ["打爆炸物"] = "--恶魔猎手-复仇-打爆炸物\nlocal v\nv = SwitchIsOn(\"邪能之刃\") and A[\"邪能之刃\"]:Cast() if v then return v end\nv = A[\"破裂\"]:Cast(target.RangeToPlayer < 5) if v then return v end\nv = SwitchIsOn(\"投掷利刃\") and A[\"投掷利刃\"]:Cast() if v then return v end\n",
            ["输出"] = "--恶魔猎手-复仇-输出\nlocal v\nv = talent[\"战刃绝技\"] and A[\"收割者战刃\"]:IsActiveSpell() and A[\"收割者战刃\"]:Cast() if v then return v end\nv = player.MyBuff:Has(\"无羁邪怒\") and A[\"恶魔变形\"]:ForceCast() if v then return v end\nv = SwitchIsOn(\"灵魂切削\") and vars[\"灵魂残片数\"] < 2 and A[\"灵魂切削\"]:Cast() if v then return v end\nif A[\"幽魂炸弹\"].IsValid and A[\"幽魂炸弹\"]:GetCooldown() < 4 then\n	v = inCombat and SwitchIsOn(\"幽魂炸弹\") and vars[\"灵魂残片数\"] > 4 and A[\"幽魂炸弹\"]:Cast() if v then return v end\n	v = ((vars[\"恶魔之怒\"] >= 85 and vars[\"灵魂残片数\"] > 7) or (vars[\"恶魔之怒差值\"] < 21 and vars[\"灵魂残片数\"] > 1 and player.HealthPercent < 0.6)) and A[\"灵魂裂劈\"]:Cast() if v then return v end\nelseif vars[\"灵魂残片数\"] > 1 then\n	v = (player.HealthPercent < 0.4 or vars[\"恶魔之怒差值\"] < 21 or (vars[\"恶魔之怒\"] >= 85 and player.HealthPercent < 0.8)) and A[\"灵魂裂劈\"]:Cast() if v then return v end\nend\nv = A[\"献祭光环\"]:Cast(target.RangeToPlayer < 8) if v then return v end\nv = A[\"邪能之刃\"]:Cast() if v then return v end\nv = A[\"我_怨念咒符\"]:Cast() if v then return v end\nv = A[\"我_烈焰咒符\"]:Cast() if v then return v end\nv = vars[\"恶魔之怒差值\"] >= 20 and A[\"吞噬魔法\"]:Cast() if v then return v end\nv = A[\"破裂\"]:Cast(target.RangeToPlayer < 5) if v then return v end\nv = SwitchIsOn(\"地狱火撞击\") and A[\"我_地狱火撞击\"]:Cast(target.RangeToPlayer < 5 and A[\"我_地狱火撞击\"]:GetChargeInfo():IsReachedOrSoon()) if v then return v end\nv = inCombat and A[\"投掷利刃\"]:GetChargeInfo():IsReachedOrSoon() and A[\"投掷利刃\"]:Cast() if v then return v end\n",
        },
        ["浩劫"] = {
            ["_专精初始化"] = "--恶魔猎手-浩劫-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--恶魔猎手-浩劫-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--恶魔猎手-浩劫-保命\nif not inCombat then\n    return\nend\nlocal v\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"疾影\") and A[\"疾影\"]:Cast() if v then return v end\nv = SwitchIsOn(\"黑暗\") and A[\"黑暗\"]:Cast() if v then return v end\n",
            ["打爆炸物"] = "--恶魔猎手-浩劫-打爆炸物\nlocal v\nv = SwitchIsOn(\"邪能之刃\") and A[\"邪能之刃\"]:Cast() if v then return v end\nv = A[\"混乱打击\"]:Cast() if v then return v end\nv = SwitchIsOn(\"投掷利刃\") and A[\"投掷利刃\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--恶魔猎手-浩劫-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nif target.RangeToPlayer > 5 then\n    return\nend\nif talent[\"混沌变身\"] then\n    if vars[\"眼棱CD\"] < 5 then\n        return\n    end\n    if talent[\"第一滴血\"] and vars[\"刃舞CD\"] < 3 then\n        return\n    end\nend\nlocal v = A[\"我_恶魔变形\"]:Cast() \nif v then\n    return run(\"一键爆发\") \nend\n--if vars[\"恶魔变形时间\"] < 10 then\n--    return\n--end\n\n",
            ["输出"] = "--恶魔猎手-浩劫-输出\nvars[\"灵魂残片数\"] = player.MyBuff[\"灵魂残片\"].Count\nvars[\"恶魔之怒\"] = player:GetPower(P[\"恶魔之怒\"])\nvars[\"恶魔之怒差值\"] = player:GetPowerDeficit(P[\"恶魔之怒\"])\nvars[\"恶魔变形时间\"] = player.MyBuff[\"恶魔变形\"]:GetTimeLeft()\nvars[\"刃舞CD\"] = A[\"刃舞\"]:GetCooldown()\nvars[\"眼棱CD\"] = A[\"眼棱\"]:GetCooldown()--SwitchIsOn(\"眼棱\") and A[\"眼棱\"]:GetCooldown() or 999\n\nlocal v\nv = talent[\"焰由心生\"] and A[\"献祭光环\"]:Cast(target.RangeToPlayer < 8 and vars[\"恶魔之怒差值\"] > 20) if v then return v end\nv = run(\"爆发技能\") if v then return v end\nv = talent[\"战刃绝技\"] and A[\"收割者战刃\"]:IsActiveSpell() and A[\"收割者战刃\"]:Cast() if v then return v end\n--点 第一滴血 的时候，要卡cd打刃舞\nv = talent[\"第一滴血\"] and target.RangeToPlayer < 5 and A[\"刃舞\"]:Cast() if v then return v end\n\n--v = SwitchIsOn(\"极乐敕令\") and A[\"我_极乐敕令\"]:Cast() if v then return v end\nv = A[\"恶魔追击\"]:Cast(target.RangeToPlayer < 25 or UnitIsPlayer(\"target\")) if v then return v end\n--选择 混沌理论 时，在没有混沌理论buff的时候需要打刃舞\nv = vars[\"眼棱CD\"] > 5 and talent[\"混沌理论\"] and not (player.MyBuff:Has(\"混乱之刃\") or player.MyBuff:Has(\"混沌理论\")) and A[\"刃舞\"]:Cast() if v then return v end\n--死亡横扫\nv = A[\"刃舞\"]:Cast(target.RangeToPlayer < 5 and vars[\"恶魔变形时间\"] > 0.3 and vars[\"敌方目标数量\"] > 2) if v then return v end\nv = A[\"献祭光环\"]:Cast(target.RangeToPlayer < 8 and vars[\"恶魔之怒差值\"] > 20) if v then return v end\n\nif SwitchIsOn(\"眼棱\") and vars[\"爆发强度\"] > 0.3 and target.RangeToPlayer < 5 and (not talent[\"盲目之怒\"] or vars[\"恶魔之怒\"] < 60) then\n    if talent[\"第一滴血\"] then\n        v = vars[\"刃舞CD\"] > 3 and A[\"眼棱\"]:Cast() if v then return v end\n    else\n        v = A[\"眼棱\"]:Cast() if v then return v end\n    end\nend\nv = SwitchIsOn(\"精华破碎\") and A[\"精华破碎\"]:Cast(not A[\"眼棱\"]:IsReady() or player.MyBuff:Has(\"恶魔变形\")) if v then return v end\n\nif talent[\"盲目之怒\"] and target.RangeToPlayer < 5 then\n    if vars[\"眼棱CD\"] < 2 * gcdmax then\n        v = A[\"刃舞\"]:Cast(vars[\"敌方目标数量\"] > 2 and vars[\"恶魔之怒\"] >= 65) if v then return v end\n        v = A[\"混乱打击\"]:Cast(vars[\"恶魔之怒\"] >= 70) if v then return v end\n    end\nend\nv = A[\"刃舞\"]:Cast(legendary[\"混沌理论\"] or talent[\"混沌理论\"]) if v then return v end\n\nv = player.MyBuff:Has(\"混沌理论\") and A[\"混乱打击\"]:Cast() if v then return v end\nv = A[\"混乱打击\"]:Cast(vars[\"恶魔之怒\"] >= 70 or (vars[\"恶魔变形时间\"] > 0.3 and vars[\"眼棱CD\"] > 2 * gcdmax)) if v then return v end\nv = SwitchIsOn(\"邪能之刃\") and A[\"邪能之刃\"]:Cast(vars[\"恶魔之怒差值\"] >= 40 and GetLastSpell().Name ~= \"复仇回避\") if v then return v end\nv = SwitchIsOn(\"吞噬魔法\") and A[\"吞噬魔法\"]:Cast(vars[\"恶魔之怒差值\"] >= 20) if v then return v end\nv = SwitchIsOn(\"邪能冲撞\") and A[\"邪能冲撞\"]:Cast(target.RangeToPlayer > 7 and target.RangeToPlayer < 20) if v then return v end\nv = SwitchIsOn(\"投掷利刃\") and A[\"投掷利刃\"]:Cast() if v then return v end\n",
        },
    },
    ["战士"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--战士-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\nvars[\"斩杀血量\"] = talent[\"屠杀\"] and 0.35 or 0.2\n\n",
            ["崩摧"] = "--战士-全专精-崩摧\nlocal castTo, params = ...\nif not castTo then \n    castTo = (UnitExists(\"target\") and target or player)\nend\nreturn run(\"安全引导\", \"崩摧\", castTo, params)\n",
            ["无视苦痛"] = "--战士-全专精-无视苦痛\nif not A[\"无视苦痛\"]:IsReady() then\n    return\nend\nlocal wstkBuff = player.MyBuff[\"无视苦痛\"]\nlocal maxAbsorb = A[\"无视苦痛\"]:GetNumber(\"减免\", \"点\")\nlocal remainAbsorb = wstkBuff.Absorb\nif remainAbsorb < maxAbsorb * (... or 0.3) then\n    return A[\"无视苦痛\"]:Cast()\nend\nif wstkBuff:GetTimeLeft() < gcdmax + 0.4 then\n    return A[\"无视苦痛\"]:Cast()\nend\n",
            ["输出初始化"] = "--战士-全专精-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["武器"] = {
            ["_专精初始化"] = "--战士-武器-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--战士-武器-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n--vars[\"刽子手的精准\"] = azerite:IsEnabled(\"刽子手的精准\")\n--vars[\"力量的考验\"] = azerite:IsEnabled(\"力量的考验\")\n--vars[\"地震波\"] = azerite:IsEnabled(\"地震波\") or talent[\"悍勇无畏\"]\n",
            ["保命"] = "--战士-武器-保命\nlocal v\nif not inCombat then\n    v = not player.MyBuff:Has(\"防御姿态\") and A[\"战斗姿态\"]:Cast() if v then return v end\n    v = A[\"战斗怒吼\"]:Cast() if v then return v end\n    return\nend\nv = SwitchIsOn(\"盾牌格挡\") and A[\"盾牌格挡\"]:Cast() if v then return v end\nif player.HealthPercent < 0.35 then\n    v = SwitchIsOn(\"剑在人在\") and A[\"剑在人在\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"集结呐喊\") and A[\"集结呐喊\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"防御姿态\") and A[\"防御姿态\"]:Cast() if v then return v end\nend\nv = SwitchIsOn(A[\"乘胜追击\"].Name) and A[\"乘胜追击\"]:Cast(target.RangeToPlayer < 5 and player.HealthPercent < (inPVE and (boss.InCombat and 0.4 or 0.65) or (talent[\"胜利在望\"] and 0.6 or 0.8))) if v then return v end\nv = SwitchIsOn(\"无视苦痛\") and run(\"无视苦痛\") if v then return v end\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n\nv = not player.MyBuff:Has(\"防御姿态\") and A[\"战斗姿态\"]:Cast() if v then return v end\nv = SwitchIsOn(\"战斗怒吼\") and A[\"战斗怒吼\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--战士-武器-爆发技能\nif target.RangeToPlayer > 5 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nif talent[\"天神下凡\"] then\n    if vars[\"爆发强度\"] > 2 then \n        v = A[\"巨人打击\"]:GetCooldown() < 10 and A[\"天神下凡\"]:Cast() if v then return run(\"一键爆发\") end\n    end\n    --if player.MyBuff[\"天神下凡\"]:GetTimeLeft() < 10 then\n    --    return\n    --end\nelse\n    v = A[\"巨人打击\"]:Cast() if v then return run(\"一键爆发\") end\nend\n",
            ["输出"] = "--战士-武器-输出\nlocal v\nv = A[\"断筋\"]:Cast(target.RangeToPlayer < 5 and UnitIsPlayer(\"target\")) if v then return v end\nvars[\"怒气\"] = player:GetPower(P[\"怒气\"])\nvars[\"怒气百分比\"] = player:GetPowerPercent(P[\"怒气\"])\nvars[\"怒气差\"] = player:GetPowerDeficit(P[\"怒气\"])\nvars[\"巨人打击时间\"] = target.MyDebuff[\"巨人打击\"]:GetTimeLeft()\nif vars[\"巨人打击时间\"] > 5 and vars[\"爆发强度\"] > 0.7 then\n    v = SwitchIsOn(\"勇士之矛\") and not A[\"勇士之矛\"]:CastedIn(20) and not A[\"我_勇士之矛\"]:CastedIn(20) and A[\"我_勇士之矛\"]:Cast() if v then return v end\n    v = A[\"破坏者\"]:Cast() if v then return v end\n    v = A[\"剑刃风暴\"]:Cast() if v then return v end\n    v = A[\"横扫攻击\"]:Cast() if v then return v end\n    v = run(\"崩摧\") if v then return v end\nend\nif talent[\"雷霆一击\"] then\n    v = target.MyDebuff[\"撕裂\"]:GetTimeLeft() < 3 and A[\"雷霆一击\"]:Cast() if v then return v end\nelse\n    v = A[\"撕裂\"]:Cast() if v then return v end\nend\nv = A[\"震荡波\"]:Cast() if v then return v end\nv = vars[\"敌方目标数量\"] > 1 and talent[\"广域打击\"] and A[\"巨人打击\"]:GetCooldown() > 10 and A[\"横扫攻击\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\nv = talent[\"天神下凡\"] and vars[\"爆发强度\"] > 0.6 and (A[\"天神下凡\"]:GetCooldown() > 15 or player.MyBuff[\"天神下凡\"]:GetTimeLeft() > 8) and A[\"巨人打击\"]:Cast() if v then return v end\n\nif vars[\"敌方目标数量\"] > 2 then --AOE\n    v = A[\"旋风斩\"]:Cast() if v then return v end\n    v = A[\"顺劈斩\"]:Cast() if v then return v end\nend\nv = player.MyBuff[\"刽子手的精准\"].Count > 1 and A[\"致死打击\"]:Cast() if v then return v end\nv = A[\"压制\"]:GetChargeInfo():IsReachedOrSoon() and A[\"压制\"]:Cast() if v then return v end\nv = A[\"致死打击\"]:Cast() if v then return v end\nv = A[\"压制\"]:Cast() if v then return v end\nv = A[\"斩杀\"]:Cast() if v then return v end\nv = A[\"破裂投掷\"]:Cast() if v then return v end\nif vars[\"敌方目标数量\"] > 2 then --AOE\n    if talent[\"雷霆一击\"] then\n        v = A[\"雷霆一击\"]:Cast() if v then return v end\n    else\n        v = A[\"撕裂\"]:ForceCast() if v then return v end\n    end\nelse\n    v = A[\"猛击\"]:Cast() if v then return v end\nend\nv = SwitchIsOn(A[\"乘胜追击\"].Name) and A[\"乘胜追击\"]:Cast(target.RangeToPlayer < 5 and player.HealthPercent < (talent[\"胜利在望\"] and 0.6 or 0.8)) if v then return v end\nv = SwitchIsOn(\"冲锋\") and A[\"冲锋\"]:Cast(target.RangeToPlayer < 25 and target.RangeToPlayer > 8) if v then return v end\nv = A[\"盾牌猛击\"]:Cast() if v then return v end\nv = SwitchIsOn(A[\"乘胜追击\"].Name) and UnitLevel(\"player\") < 20 and A[\"乘胜追击\"]:Cast(target.RangeToPlayer < 5) if v then return v end\n\n\n",
        },
        ["狂怒"] = {
            ["_专精初始化"] = "--战士-狂怒-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["保命"] = "--战士-狂怒-保命\nlocal v\nif not inCombat then\n    v = not player.MyBuff:Has(\"防御姿态\") and A[\"狂暴姿态\"]:Cast() if v then return v end\n    v = A[\"战斗怒吼\"]:Cast() if v then return v end\n    return\nend\nv = SwitchIsOn(\"盾牌格挡\") and A[\"盾牌格挡\"]:Cast() if v then return v end\nif player.HealthPercent < 0.35 then\n    v = SwitchIsOn(\"狂怒回复\") and A[\"狂怒回复\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"集结呐喊\") and A[\"集结呐喊\"]:Cast() if v then return v end\nend\nv = SwitchIsOn(A[\"乘胜追击\"].Name) and A[\"乘胜追击\"]:Cast(target.RangeToPlayer < 5 and player.HealthPercent < (inPVE and (boss.InCombat and 0.4 or 0.6) or (talent[\"胜利在望\"] and 0.6 or 0.8))) if v then return v end\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n\nv = not player.MyBuff:Has(\"防御姿态\") and A[\"狂暴姿态\"]:Cast() if v then return v end\nv = SwitchIsOn(\"战斗怒吼\") and A[\"战斗怒吼\"]:Cast() if v then return v end\n\n",
            ["打爆炸物"] = "--战士-狂怒-打爆炸物\nlocal v\nv = SwitchIsOn(A[\"乘胜追击\"].Name) and A[\"乘胜追击\"]:Cast(target.RangeToPlayer < 5 and player.HealthPercent < (inPVE and (boss.InCombat and 0.4 or 0.6) or (talent[\"胜利在望\"] and 0.6 or 0.8))) if v then return v end\nv = A[\"英勇投掷\"]:Cast() if v then return v end \nv = A[\"嗜血\"]:Cast() if v then return v end \nv = A[\"怒击\"]:Cast() if v then return v end \n",
            ["爆发技能"] = "--战士-狂怒-爆发技能\nif vars[\"爆发强度\"] < 2 or target.RangeToPlayer > 5 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v = player.BurstSpell and (vars[\"怒气差\"] > 50 or player.BurstSpell ~= \"鲁莽\") and A[player.BurstSpell]:Cast() if v then return run(\"一键爆发\") end\n\n\n\n\n",
            ["补刀1"] = "--战士-狂怒-补刀1\n--战士-狂怒-补刀\n--local v\n--v = A[\"英勇投掷\"]:Cast(A[\"英勇投掷\"]:GetDamage() > target.Health) if v then return v end \n--v = target.RangeToPlayer < 5 and A[\"旋风斩\"]:Cast(A[\"旋风斩\"]:GetDamage() > target.Health) if v then return v end \n--v = SwitchIsOn(A[\"乘胜追击\"].Name) and A[\"乘胜追击\"]:Cast(A[\"乘胜追击\"]:GetDamage() > target.Health) if v then return v end \n--v = A[\"斩杀\"]:Cast(A[\"斩杀\"]:GetDamage() > target.Health) if v then return v end \n--v = A[\"嗜血\"]:Cast(A[\"嗜血\"]:GetDamage() > target.Health) if v then return v end \n--v = A[\"怒击\"]:Cast(A[\"怒击\"]:GetDamage() > target.Health) if v then return v end \n--v = target.Health / A[\"暴怒\"]:GetDamage() \n--v = A[\"暴怒\"]:Cast(v < 1 and v > (target.IsPlayer and 0 or 0.8)) if v then return v end \n",
            ["输出"] = "--战士-狂怒-输出\nlocal v\nv = A[\"断筋\"]:Cast(target.RangeToPlayer < 5 and UnitIsPlayer(\"target\")) if v then return v end\nvars[\"怒气\"] = player:GetPower(P[\"怒气\"])\nvars[\"怒气百分比\"] = player:GetPowerPercent(P[\"怒气\"])\nvars[\"怒气差\"] = player:GetPowerDeficit(P[\"怒气\"])\nvars[\"鲁莽时间\"] = player.MyBuff[\"鲁莽\"]:GetTimeLeft()\nvars[\"激怒时间\"] = player.MyBuff[\"激怒\"]:GetTimeLeft()\nvars[\"天神下凡时间\"] = player.MyBuff[\"天神下凡\"]:GetTimeLeft()\nvars[\"旋风斩数量\"] = player.MyBuff[\"旋风斩\"].Count\nvars[\"雷霆轰击\"] = player.MyBuff[\"雷霆轰击\"].Count\n\nif talent[\"雷霆一击\"] then\n    v = target.MyDebuff[\"撕裂\"]:GetTimeLeft() < 3 and A[\"雷霆一击\"]:Cast() if v then return v end\nelse\n    v = A[\"撕裂\"]:Cast() if v then return v end\nend\nv = A[\"震荡波\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\nv = vars[\"激怒时间\"] == 0 and A[\"奥丁之怒\"]:Cast() if v then return v end\nif vars[\"敌方目标数量\"] > 2 and vars[\"旋风斩数量\"] == 0 and talent[\"强化旋风斩\"] then\n    if talent[\"崩解闪电\"] then\n        v = A[\"雷霆一击\"]:Cast() or (not A[\"雷霆一击\"]:CastedIn(2) and not A[\"旋风斩\"]:CastedIn(2) and A[\"旋风斩\"]:Cast()) if v then return v end\n    else\n        v = not A[\"旋风斩\"]:CastedIn(2) and A[\"旋风斩\"]:Cast() if v then return v end\n    end\nend\nv = vars[\"激怒时间\"] > 3 and A[\"剑刃风暴\"]:Cast() if v then return v end\nv = (vars[\"鲁莽时间\"] > 0 or vars[\"激怒时间\"] < gcdmax or vars[\"怒气差\"] <= 20) and A[\"暴怒\"]:Cast() if v then return v end\nv = SwitchIsOn(\"勇士之矛\") and not A[\"勇士之矛\"]:CastedIn(20) and not A[\"我_勇士之矛\"]:CastedIn(20) and A[\"我_勇士之矛\"]:Cast() if v then return v end\n\nvars[\"浴血奋战\"] = A[\"浴血奋战\"]:IsActiveSpell()\nif vars[\"敌方目标数量\"] > 1 then --AOE\n    v = A[\"奥丁之怒\"]:Cast() if v then return v end\n    v = vars[\"天神下凡时间\"] > 0 and vars[\"雷霆轰击\"] > 0 and A[\"雷霆一击\"]:Cast() if v then return v end\n    v = vars[\"浴血奋战\"] and A[\"浴血奋战\"]:Cast() if v then return v end\n    v = A[\"斩杀\"]:Cast() if v then return v end\n    v = vars[\"雷霆轰击\"] > 0 and A[\"雷霆一击\"]:Cast() if v then return v end\n    v = vars[\"天神下凡时间\"] > 0 and A[\"嗜血\"]:Cast() if v then return v end\n    v = vars[\"天神下凡时间\"] > 0 and A[\"雷霆一击\"]:Cast() if v then return v end\n    v = A[\"嗜血\"]:Cast() if v then return v end\n    v = A[\"怒击\"]:Cast() if v then return v end\n    v = A[\"暴怒\"]:Cast() if v then return v end\n    v = A[\"雷霆一击\"]:Cast() if v then return v end\n    v = A[\"旋风斩\"]:Cast() if v then return v end\nelse --单体\n    vars[\"猝死Buff\"] = player.MyBuff[\"猝死\"]\n    v = A[\"奥丁之怒\"]:Cast() if v then return v end\n    v = (vars[\"猝死Buff\"].Count == 2 or vars[\"猝死Buff\"]:GetTimeLeft() < gcdmax + 0.2) and A[\"斩杀\"]:Cast() if v then return v end\n    v = vars[\"雷霆轰击\"] > 1 and A[\"雷霆一击\"]:Cast() if v then return v end\n    v = talent[\"浴血之躯\"] and vars[\"浴血奋战\"] and player.MyBuff[\"浴血之躯\"]:GetTimeLeft() < 1 and A[\"浴血奋战\"]:Cast() if v then return v end\n    v = talent[\"浴血之躯\"] and A[\"嗜血\"]:IsActiveSpell() and player.MyBuff[\"浴血之躯\"]:GetTimeLeft() < 1 and A[\"嗜血\"]:Cast() if v then return v end\n    v = A[\"怒击\"]:GetChargeInfo():IsReachedOrSoon() and A[\"怒击\"]:Cast() if v then return v end\n    v = talent[\"蛮力爆发\"] and player.MyBuff[\"蛮力爆发\"]:GetTimeLeft() < 1 and A[\"怒击\"]:Cast() if v then return v end\n    v = vars[\"浴血奋战\"] and A[\"浴血奋战\"]:Cast() if v then return v end\n    v = A[\"碎甲猛击\"]:IsActiveSpell() and A[\"碎甲猛击\"]:Cast() if v then return v end\n    v = vars[\"猝死Buff\"]:GetTimeLeft() > 0.2 and A[\"斩杀\"]:Cast() if v then return v end\n    v = A[\"嗜血\"]:Cast() if v then return v end\n    v = A[\"怒击\"]:Cast() if v then return v end\n    v = A[\"暴怒\"]:Cast() if v then return v end\n    v = vars[\"雷霆轰击\"] > 0 and A[\"雷霆一击\"]:Cast() if v then return v end\n    v = A[\"破裂投掷\"]:Cast() if v then return v end\n    v = A[\"雷霆一击\"]:Cast() if v then return v end\n    v = A[\"旋风斩\"]:Cast() if v then return v end\nend\n\nv = SwitchIsOn(A[\"乘胜追击\"].Name) and A[\"乘胜追击\"]:Cast(target.RangeToPlayer < 5 and player.HealthPercent < (talent[\"胜利在望\"] and 0.6 or 0.8)) if v then return v end\nv = SwitchIsOn(\"冲锋\") and A[\"冲锋\"]:Cast(target.RangeToPlayer < 25 and target.RangeToPlayer > 8) if v then return v end\nv = A[\"盾牌猛击\"]:Cast() if v then return v end\nv = SwitchIsOn(A[\"乘胜追击\"].Name) and UnitLevel(\"player\") < 20 and A[\"乘胜追击\"]:Cast(target.RangeToPlayer < 5) if v then return v end\n",
        },
        ["防护"] = {
            ["_专精初始化"] = "--战士-防护-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["保命"] = "--战士-防护-保命\nlocal v\nvars[\"怒气\"] = player:GetPower(P[\"怒气\"])\nvars[\"盾牌格挡时间\"] = player.MyBuff[\"盾牌格挡\"]:GetTimeLeft()\n--vars[\"盾牌格挡预留怒气\"] = (ddTm < 3 and ddCharge:TimeToCharges(1) < 3) and 30 or 0\nvars[\"盾牌格挡预留怒气\"] = 30\nif not inCombat then\n    v = not player.MyBuff:Has(\"战斗姿态\") and A[\"防御姿态\"]:Cast() if v then return v end\n    v = A[\"战斗怒吼\"]:Cast() if v then return v end\n    return\nend\n--if target.MyDebuff[\"挫志怒吼\"]:GetTimeLeft() > 0.5 then\n--    player:AddAllReduce(0.2)\n--end\nv = SwitchIsOn(\"无视苦痛\") and run(\"无视苦痛\", 3) if v then return v end\nif vars[\"盾牌格挡时间\"] == 0 and (target.RangeToPlayer < 15 or vars[\"敌方目标数量\"] > 0) and vars[\"爆发强度\"] > 0.5 then\n    v = A[\"盾牌格挡\"]:GetChargeInfo():IsReachedOrSoon() and A[\"盾牌格挡\"]:Cast() if v then A[\"盾牌冲锋\"]:Protect(2) return v end\n    v = A[\"盾牌冲锋\"]:Cast() if v then return v end\n    v = A[\"盾牌格挡\"]:Cast() if v then A[\"盾牌冲锋\"]:Protect(2) return v end\nend\n\nv = player.HealthPercent < 0.65 and A[\"挫志怒吼\"]:Cast() if v then return v end\nv = (boss.IsTarget or (not boss.Exists and vars[\"敌方目标数量\"] > 2)) and A[\"破坏者\"]:Cast() if v then return v end\nv = SwitchIsOn(A[\"乘胜追击\"].Name) and A[\"乘胜追击\"]:Cast(target.RangeToPlayer < 5 and player.HealthPercent < (inPVE and (boss.InCombat and 0.4 or 0.6) or (talent[\"胜利在望\"] and 0.6 or 0.8))) if v then return v end\nv = A[\"盾墙\"]:Cast() if v then return v end\nv = A[\"集结呐喊\"]:Cast() if v then return v end\n\nv = player.HealthPercent < 0.4 and A[\"纳鲁的赐福\"]:Cast() if v then return v end\n\nv = not player.MyBuff:Has(\"战斗姿态\") and A[\"防御姿态\"]:Cast() if v then return v end\nv = A[\"战斗怒吼\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--战士-防护-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nv = A[\"天神下凡\"]:Cast(target.RangeToPlayer < 5) if v then return run(\"一键爆发\") end\n--if player.MyBuff[\"天神下凡\"]:GetTimeLeft() < 10 then\n--    return\n--end\n",
            ["输出"] = "--战士-防护-输出\n\nlocal v\nv = A[\"断筋\"]:Cast(target.RangeToPlayer < 5 and UnitIsPlayer(\"target\")) if v then return v end\nv = A[\"法术反射\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\nvars[\"怒气差\"] = player:GetPowerDeficit(P[\"怒气\"])\nv = SwitchIsOn(\"勇士之矛\") and not A[\"勇士之矛\"]:CastedIn(20) and not A[\"我_勇士之矛\"]:CastedIn(20) and A[\"我_勇士之矛\"]:Cast() if v then return v end\nv = vars[\"爆发强度\"] > 0.7 and run(\"崩摧\") if v then return v end\nv = player.MyBuff[\"雷霆轰击\"].Count > 1 and A[\"雷霆一击\"]:Cast() if v then return v end\nv = vars[\"怒气差\"] >= 20 and player.MyBuff:Has(\"能量爆发\") and A[\"盾牌猛击\"]:Cast() if v then return v end\nv = A[\"震荡波\"]:Cast() if v then return v end\nv = A[\"撕裂\"]:Cast(not talent[\"雷霆一击\"]) if v then return v end\nif vars[\"敌方目标数量\"] > 1 then\n    v = A[\"雷霆一击\"]:Cast(vars[\"怒气差\"] >= 10 and (player.MyBuff[\"雷霆轰击\"].Count > 0 or player.MyBuff:Has(\"天神下凡\"))) if v then return v end\n    v = A[\"复仇\"]:Cast(target.RangeToPlayer < 5 and player.MyBuff:Has(\"复仇！\")) if v then return v end\n    v = A[\"雷霆一击\"]:Cast(vars[\"怒气差\"] >= 10) if v then return v end\n    v = A[\"盾牌猛击\"]:Cast(vars[\"怒气差\"] >= 20) if v then return v end\n    --v = A[\"盾牌猛击\"]:Cast(vars[\"怒气差\"] >= 20 and player.MyBuff:Has(\"抵御冲击\")) if v then return v end\nelse\n--    v = A[\"盾牌猛击\"]:Cast(vars[\"怒气差\"] >= 20 and vars[\"盾牌格挡中\"]) if v then return v end\n    v = A[\"雷霆一击\"]:Cast(vars[\"怒气差\"] >= 10 and (player.MyBuff[\"雷霆轰击\"].Count > 0 or player.MyBuff:Has(\"天神下凡\"))) if v then return v end\n    v = A[\"盾牌猛击\"]:Cast(vars[\"怒气差\"] >= 20 or not A[\"复仇\"].IsValid) if v then return v end\n    v = A[\"复仇\"]:Cast(target.RangeToPlayer < 5 and player.MyBuff:Has(\"复仇！\")) if v then return v end\n    v = A[\"雷霆一击\"]:Cast(vars[\"怒气差\"] >= 10) if v then return v end\nend\nif target.RangeToPlayer < 5 and vars[\"怒气\"] >= vars[\"盾牌格挡预留怒气\"] + 30 then\n    v = A[\"复仇\"]:Cast() if v then return v end\nend\nv = vars[\"敌方目标数量\"] < 2 and A[\"斩杀\"]:Cast(vars[\"怒气\"] >= 70 or A[\"斩杀\"]:GetDamage() > target.Health) if v then return v end\n\nv = SwitchIsOn(A[\"乘胜追击\"].Name) and A[\"乘胜追击\"]:Cast(target.RangeToPlayer < 5 and player.HealthPercent < (talent[\"胜利在望\"] and 0.6 or 0.8)) if v then return v end\nv = A[\"毁灭打击\"]:Cast() if v then return v end\nv = A[\"英勇投掷\"]:Cast() if v then return v end \nv = A[\"冲锋\"]:Cast(target.RangeToPlayer > 8 and target.RangeToPlayer < 25) if v then return v end\n",
        },
    },
    ["术士"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--术士-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["保命"] = "--术士-全专精-保命\nlocal v\nv = GetSpellInfo(\"恶魔掌控\")\nif v == \"巨斧投掷\" then\n	vars[\"宠物类型\"] = \"恶魔卫士\"\nelseif v == \"法术封锁\" then\n	vars[\"宠物类型\"] = \"地狱猎犬\"\nelseif v == \"暗影壁垒\" then\n	vars[\"宠物类型\"] = \"虚空行者\"\nelseif v == \"诱惑\" then\n	vars[\"宠物类型\"] = \"魅魔\"\nelseif v == \"烧灼驱魔\" then\n	vars[\"宠物类型\"] = \"小鬼\"\nelse\n	vars[\"宠物类型\"] = \"\"\nend\nif not inCombat then\n    vars[\"痛苦无常连发\"] = false\nend\nif not inCombat then\n    v = not talent[\"牺牲魔典\"] and run(\"召唤宠物\") if v then return v end\n    --v = SwitchIsOn(\"生命通道\") and A[\"生命通道\"]:Cast(UnitExists(\"pet\") and not UnitIsDead(\"pet\") and pet.HealthPercent < (inPVE and 0.4 or 0.6)) if v then return v end\n    v = SwitchIsOn(\"制造治疗石\") and A[\"制造治疗石\"]:Cast(battleType == \"野外\" and not inTraining and A[\"治疗石\"]:GetCount() == 0) if v then return v end\n	v = SwitchIsOn(\"灵魂石\") and A[\"灵魂石\"]:Cast(not inInstance and not inTraining, player) if v then return v end\n    return\nend\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"黑暗契约\") and A[\"黑暗契约\"]:Cast() if v then return v end\nv = SwitchIsOn(\"死亡缠绕\") and A[\"死亡缠绕\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"暗影壁垒\") and A[\"暗影壁垒\"]:Cast(vars[\"宠物类型\"] == \"虚空行者\" and not player.MyBuff:Has(\"黑暗契约\")) if v then return v end\nv = SwitchIsOn(\"不灭决心\") and A[\"不灭决心\"]:Cast(not player.MyBuff:Has(\"黑暗契约\")) if v then return v end\nv = SwitchIsOn(\"吸取生命\") and A[\"吸取生命\"]:Cast(player.HealthPercent < (inPVE and 0.25 or 0.5)) if v then return v end\nv = not talent[\"牺牲魔典\"] and run(\"召唤宠物\") if v then return v end\n--v = SwitchIsOn(\"生命通道\") and A[\"生命通道\"]:Cast(UnitExists(\"pet\") and not UnitIsDead(\"pet\") and pet.HealthPercent < (inPVE and 0.4 or 0.6)) if v then return v end\n--v = SwitchIsOn(\"灵魂石\") and A[\"灵魂石\"]:Cast(not inInstance and not inTraining, player) if v then return v end\n\n",
            ["召唤宠物"] = "--术士-全专精-召唤宠物\nlocal v\nif not A[\"召唤小鬼\"]:IsProtected() then\n	A[\"召唤小鬼\"]:Protect(4, 1.5)\n	return\nend\nif GetSpecialization() == 2 and SwitchIsOn(\"召唤卫士\") then\n    v = A[\"召唤恶魔卫士\"]:Cast()\nelseif SwitchIsOn(\"召唤小鬼\") then\n    v = A[\"召唤小鬼\"]:Cast()\nelseif SwitchIsOn(\"召唤蓝胖\") then\n    v = A[\"召唤虚空行者\"]:Cast()\nelseif SwitchIsOn(\"召唤猎犬\") then\n    v = A[\"召唤地狱猎犬\"]:Cast()\nelseif SwitchIsOn(\"召唤魅魔\") then\n    v = A[\"召唤萨亚德\"]:Cast()\nend\nif v then\n	if inCombat and SwitchIsOn(\"邪能统御\") then\n		return A[\"邪能统御\"]:Cast() or v\n	else\n		return v\n	end\nend",
            ["打断"] = "--术士-全专精-打断\nlocal v = talent[\"魔典：邪能破坏者\"] and A[\"邪能破坏者_法术封锁\"]:Cast(nil, ...) if v then return v end\nif vars[\"宠物类型\"] == \"恶魔卫士\" then\n    return A[\"巨斧投掷\"]:Cast(nil, ...)\nelseif vars[\"宠物类型\"] == \"地狱猎犬\" then\n    return A[\"法术封锁\"]:Cast(nil, ...)\nend\n",
        },
        ["恶魔学识"] = {
            ["_专精初始化"] = "--术士-恶魔学识-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["强制执行"] = "--术士-恶魔学识-强制执行\nif inCombat and UnitCastingInfo(\"player\") == \"恶魔之箭\" then\n    return A[\"取消施法\"]:Cast()\nend\n",
            ["更新灵魂碎片数量"] = "--术士-恶魔学识-更新灵魂碎片数量\nvars[\"小鬼数量\"] = player.MyBuff[\"野生小鬼\"].Count\nvars[\"灵魂碎片\"] = player:GetPower(P[\"灵魂碎片\"])\nlocal name = UnitCastingInfo(\"player\")\nif name == \"暗影箭\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] + 1\nelseif name == \"恶魔之箭\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] + 2\nelseif name == \"狱火箭\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] + 3\nelseif name == \"召唤恶魔暴君\" then   \n    if talent[\"死亡之影\"] then\n        vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] + 3\n    end\nelseif name == \"召唤恐惧猎犬\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] - 2\nelseif name == \"古尔丹之手\" or name == \"陨灭\" then\n    --if vars[\"灵魂碎片\"] > 3 then\n        vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] - 3\n		vars[\"小鬼数量\"] = vars[\"小鬼数量\"] + 3\n  --  else\n  --      vars[\"灵魂碎片\"] = 0\n		--vars[\"小鬼数量\"] = vars[\"小鬼数量\"] + vars[\"灵魂碎片\"]\n  --  end\nend\n\nif vars[\"灵魂碎片\"] > 5 then\n    vars[\"灵魂碎片\"] = 5\nelseif vars[\"灵魂碎片\"] < 0 then\n    vars[\"灵魂碎片\"] = 0\nend",
            ["爆发技能"] = "--术士-恶魔学识-爆发技能\nvars[\"需要碎片\"] = false\nif vars[\"爆发强度\"] < 2.5 then\n    vars[\"下次召唤恶魔暴君时间\"] = 999 --无需开暴君\n    return\nend\nvars[\"下次召唤恶魔暴君时间\"] = A[\"召唤恶魔暴君\"]:GetCooldown()\nif vars[\"下次召唤恶魔暴君时间\"] > 4 and vars[\"暴君时间\"] == 0 then\n    return\nend\nif not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nv = talent[\"魔典：小鬼领主\"] and A[\"魔典：小鬼领主\"]:GetCooldown() or false\nif v then\n    if v < 6 then\n        vars[\"需要碎片\"] = true\n    --elseif v < 102 then\n    --    return\n    end\nend\nv = talent[\"魔典：邪能破坏者\"] and A[\"魔典：邪能破坏者\"]:GetCooldown() or false\nif v then\n    if v < 6 then\n        vars[\"需要碎片\"] = true\n    --elseif v < 102 then\n    --    return\n    end\nend\nv = talent[\"召唤末日守卫\"] and A[\"召唤末日守卫\"]:GetCooldown() or false\nif v then\n    if v < 6 then\n        vars[\"需要碎片\"] = true\n    --elseif v < 102 and v >  then\n    --    return\n    end\nend\nvars[\"召唤恐惧猎犬CD\"] = A[\"召唤恐惧猎犬\"]:GetCooldown()\nif vars[\"暴君时间\"] > 0 then\n    if vars[\"灵魂碎片\"] > 0 then\n        v = talent[\"召唤末日守卫\"] and A[\"召唤末日守卫\"]:Cast() if v then return v end\n        v = talent[\"魔典：小鬼领主\"] and A[\"魔典：小鬼领主\"]:IsActiveSpellName() and A[\"魔典：小鬼领主\"]:Cast() if v then return v end\n        v = talent[\"魔典：邪能破坏者\"] and A[\"魔典：邪能破坏者\"]:IsActiveSpellName() and A[\"魔典：邪能破坏者\"]:Cast() if v then return v end\n    elseif vars[\"需要碎片\"] then\n        v = vars[\"恶魔之核数量\"] > 0 and (A[\"恶魔之箭\"]:CastOnMinTime(nil, 30, 120) or A[\"恶魔之箭\"]:ForceCast()) if v then return v end\n    end\nelseif vars[\"下次召唤恶魔暴君时间\"] < 4 and vars[\"小鬼数量\"] > 2 and (vars[\"猎犬时间\"] > 2 or vars[\"召唤恐惧猎犬CD\"] < 2) then\n    if vars[\"灵魂碎片\"] > 0 and vars[\"下次召唤恶魔暴君时间\"] >= 0 and (vars[\"猎犬时间\"] > 4 or vars[\"召唤恐惧猎犬CD\"] < 2) then\n        v = talent[\"魔典：小鬼领主\"] and A[\"魔典：小鬼领主\"]:IsActiveSpellName() and A[\"魔典：小鬼领主\"]:Cast() if v then return v end\n        v = talent[\"魔典：邪能破坏者\"] and A[\"魔典：邪能破坏者\"]:IsActiveSpellName() and A[\"魔典：邪能破坏者\"]:Cast() if v then return v end\n        --v = talent[\"召唤末日守卫\"] and A[\"召唤末日守卫\"]:Cast() if v then return v end\n    elseif vars[\"需要碎片\"] and vars[\"灵魂碎片\"] == 0 then\n        v = vars[\"恶魔之核数量\"] > 0 and (A[\"恶魔之箭\"]:CastOnMinTime(nil, 30, 120) or A[\"恶魔之箭\"]:ForceCast()) if v then return v end\n    end\n    if vars[\"召唤恐惧猎犬CD\"] < 2 then\n        if vars[\"灵魂碎片\"] < (2 - (talent[\"魔性征召\"] or 0)) then\n            v = vars[\"恶魔之核数量\"] > 0 and (A[\"恶魔之箭\"]:CastOnMinTime(nil, 30, 120) or A[\"恶魔之箭\"]:ForceCast()) if v then return v end\n        else\n            v = A[\"召唤恐惧猎犬\"]:Cast() if v then return v end\n        end\n    end\n    v = vars[\"猎犬时间\"] > 2 and vars[\"小鬼数量\"] > 2 and A[\"召唤恶魔暴君\"]:Cast() if v then return run(\"一键爆发\") end\nend\n\n\n",
            ["输出"] = "--术士-恶魔学识-输出\nrun(\"更新灵魂碎片数量\")\n--vars[\"召唤末日守卫CD\"] = talent[\"召唤末日守卫\"] and A[\"召唤末日守卫\"]:GetCooldown() or 999\nvars[\"魔性征召\"] = player.MyBuff:Has(\"魔性征召\")\nvars[\"暴君时间\"] = totems:GetTimeLeft(\"恶魔暴君\")\nvars[\"猎犬时间\"] = totems:GetTimeLeft(\"恐惧猎犬\")\nvars[\"恶魔之核数量\"] = A[\"恶魔之箭\"]:GetCurrentCastingTime() == 0 and player.MyBuff[\"恶魔之核\"].Count or 0\n\nlocal v\nv = run(\"爆发技能\") if v then return v end\nv = vars[\"下次召唤恶魔暴君时间\"] > 14 and vars[\"爆发强度\"] > 1.5 and talent[\"召唤末日守卫\"] and A[\"召唤末日守卫\"]:Cast() if v then return v end\nv = vars[\"下次召唤恶魔暴君时间\"] > 18 and vars[\"灵魂碎片\"] >= (2 - (talent[\"魔性征召\"] or 0)) and A[\"召唤恐惧猎犬\"]:Cast() if v then return v end\nv = A[\"古尔丹之手\"]:IsActiveSpellName(\"陨灭\") and A[\"古尔丹之手\"]:Cast() if v then return v end\nv = vars[\"恶魔之核数量\"] > 0 and vars[\"灵魂碎片\"] <= 3 and player.MyBuff[\"恶魔之核\"]:GetTimeLeft() < 4 and A[\"恶魔之箭\"]:ForceCast() if v then return v end\nv = vars[\"下次召唤恶魔暴君时间\"] > 7 and vars[\"小鬼数量\"] > 5 and A[\"内爆\"]:Cast() if v then return v end\nv = vars[\"灵魂碎片\"] > 4 and A[\"古尔丹之手\"]:Cast() if v then return v end\nv = vars[\"灵魂碎片\"] < 3 and A[\"暗影箭\"]:IsActiveSpellName(\"狱火箭\") and A[\"暗影箭\"]:Cast() if v then return v end\nv = vars[\"恶魔之核数量\"] < 3 and vars[\"小鬼数量\"] > 1 and A[\"能量虹吸\"]:Cast() if v then return v end\nv = vars[\"恶魔之核数量\"] > 1 and vars[\"灵魂碎片\"] <= 3 and A[\"恶魔之箭\"]:CastOnMinTime(nil, 30, 120) if v then return v end\nv = vars[\"恶魔之核数量\"] > 2 and vars[\"灵魂碎片\"] <= 3 and A[\"恶魔之箭\"]:ForceCast() if v then return v end\nv = vars[\"灵魂碎片\"] > 2 and (vars[\"恶魔之核数量\"] > 0 or not vars[\"需要碎片\"]) and A[\"古尔丹之手\"]:Cast() if v then return v end\nv = A[\"暗影箭\"]:Cast() if v then return v end\n\n\n\n",
        },
        ["毁灭"] = {
            ["AOE"] = "--术士-毁灭-AOE\n-- rain_of_fire,if=pet.infernal.active&(!cooldown.havoc.ready||active_enemies>3)\n-- rain_of_fire,if=pet.infernal.active and (not (cooldown.havoc.ready) or active_enemies > 3)\nv = A[\"火焰之雨\"]:Cast(vars[\"灵魂碎片\"] >= 3 and vars[\"地狱火时间\"] > 0 and (vars[\"浩劫冷却\"] > gcd + 0.4 or vars[\"敌方目标数量\"] > 3)) if v then return v end\n-- channel_demonfire,if=dot.immolate.remains>cast_time\n-- channel_demonfire,if=dot.immolate.remains > cast_time\nv = A[\"引导恶魔之火\"]:Cast(vars[\"献祭时间\"] > A[\"引导恶魔之火\"]:GetDuration()) if v then return v end\n-- immolate,cycle_targets=1,if=active_enemies<5&remains<5&(!talent.cataclysm.enabled||cooldown.cataclysm.remains>remains)\n-- immolate,if=active_enemies < 5 and remains < 5 and (not (talent.cataclysm.enabled) or cooldown.cataclysm.remains > remains)\nv = A[\"献祭\"]:Cast(vars[\"敌方目标数量\"] < 5 and (not talent[\"大灾变\"] or A[\"大灾变\"]:GetCooldown() > vars[\"献祭时间\"])) if v then return v end\n-- call_action_list,name=cds\n-- call_action_list,name=cds,if=\nv = run(\"爆发技能\") if v then return v end\n-- havoc,cycle_targets=1,if=!(target=self.target)&active_enemies<4\n-- havoc,if=not (target.unit == self.target.unit) and active_enemies < 4\nv = vars[\"敌方目标数量\"] < 4 and run(\"浩劫\") if v then return v end\n-- rain_of_fire\n-- rain_of_fire,if=\nv = A[\"火焰之雨\"]:Cast(vars[\"灵魂碎片\"] >= 3) if v then return v end\n-- havoc,cycle_targets=1,if=!(self.target=target)\n-- havoc,if=not (self.target.unit == target.unit)\nv = run(\"浩劫\") if v then return v end\n-- incinerate,if=talent.fire_and_brimstone.enabled&buff.backdraft.up&soul_shard<5-0.2*active_enemies\n-- incinerate,if=talent.fire_and_brimstone.enabled and buff.backdraft.up and soul_shard < 5 - 0.2 * active_enemies\nv = A[\"烧尽\"]:Cast(talent[\"硫磺烈火\"] and vars[\"爆燃层数\"] > 0 and vars[\"灵魂碎片\"] < 5 - 0.2 * vars[\"敌方目标数量\"]) if v then return v end\n-- soul_fire\n-- soul_fire,if=\nv = A[\"灵魂之火\"]:Cast() if v then return v end\n-- conflagrate,if=buff.backdraft.down\n-- conflagrate,if=buff.backdraft.down\nv = A[\"燃烧\"]:Cast(vars[\"爆燃层数\"] == 0) if v then return v end\n-- shadowburn,if=target.health.pct<20\n-- shadowburn,if=target.health.pct < 20\nv = target.HealthPercent < 0.2 and (not SwitchIsOn(\"暗灼打球\") or A[\"暗影灼烧\"]:GetChargeInfo():IsReachedOrSoon(nil, gcdmax - 0.4)) and A[\"暗影灼烧\"]:Cast() if v then return v end\n-- immolate,if=refreshable\n-- immolate,if=refreshable\n--v = A[\"献祭\"]:Cast() if v then return v end\nv = A[\"献祭\"]:CastOnMinTime(nil, 40, 70, false, vars[\"补献祭条件\"]) if v then return v end\n\n-- incinerate\n-- incinerate,if=\nv = A[\"烧尽\"]:Cast() if v then return v end",
            ["_专精初始化"] = "--术士-毁灭-_专精初始化\nvars[\"补献祭条件\"] = function(unit) return not unit.MyDebuff:Has(\"浩劫\") end\nrun(\"全专精-_专精初始化\")\n",
            ["打爆炸物"] = "--术士-毁灭-打爆炸物\n\nv = A[\"暗影灼烧\"]:Cast() if v then return v end\nv = A[\"燃烧\"]:Cast() if v then return v end\nv = A[\"烧尽\"]:Cast() if v then return v end\n",
            ["更新灵魂碎片数量"] = "--术士-毁灭-更新灵魂碎片数量\nif player.MyBuff:Has(\"毁灭仪式\") then\n	vars[\"灵魂碎片裂片\"] = 40\nelse\n	vars[\"灵魂碎片裂片\"] = player:GetPower(P[\"灵魂碎片裂片\"])\n	local name = UnitCastingInfo(\"player\")\n	if name == \"混乱之箭\" then\n		vars[\"灵魂碎片裂片\"] = vars[\"灵魂碎片裂片\"] - 20\n	elseif name == \"烧尽\" then\n		vars[\"灵魂碎片裂片\"] = vars[\"灵魂碎片裂片\"] + 2\n	elseif name == \"灵魂之火\" then\n		vars[\"灵魂碎片裂片\"] = vars[\"灵魂碎片裂片\"] + 10\n	end\n	if vars[\"灵魂碎片裂片\"] > 50 then\n		vars[\"灵魂碎片裂片\"] = 50\n	end\nend\nvars[\"灵魂碎片\"] = vars[\"灵魂碎片裂片\"] / 10",
            ["浩劫"] = "--术士-毁灭-浩劫\nif not SwitchIsOn(\"浩劫\") then\n    return\nend\nif A[\"浩劫\"]:GetCooldown() > gcdmax then\n    return\nend\nif vars[\"敌方目标数量\"] == 1 then\n    return\nend\nlocal castTo\nif UnitExists(\"focus\") and not sv:UnitIsUnit(\"focus\", \"target\") then \n	castTo = focus\nelseif UnitExists(\"mouseover\") and not sv:UnitIsUnit(\"mouseover\", \"target\") then \n	castTo = mouseover\nend\nif not castTo or (vars[\"敌方目标数量\"] > 2 and run(\"取得目标强度\", castTo) < 0.7) then\n	Error(\"请设置焦点或鼠标指向一个高血量敌方目标以施放《浩劫》, 并且不能是当前目标\")\n	return\nend\nif castTo then\n	v = A[\"浩劫\"]:Cast(nil, castTo) if v then return v end\nend\n\n\n\n",
            ["浩劫中"] = "--术士-毁灭-浩劫中\n-- conflagrate,if=buff.backdraft.down&soul_shard>=1&soul_shard<=4\n-- conflagrate,if=buff.backdraft.down and soul_shard >= 1 and soul_shard <= 4\nv = A[\"燃烧\"]:Cast((not player.MyBuff:Has(\"爆燃\")) and vars[\"灵魂碎片\"] >= 1 and vars[\"灵魂碎片\"] <= 4) if v then return v end\n-- soul_fire,if=cast_time<havoc_remains\n-- soul_fire,if=cast_time < havoc_remains\nv = A[\"灵魂之火\"]:Cast(A[\"灵魂之火\"]:GetCurrentCastingTime() < vars[\"浩劫剩余时间\"]) if v then return v end\n-- immolate,if=talent.internal_combustion.enabled&remains<duration*0.5||!talent.internal_combustion.enabled&refreshable\n-- immolate,if=talent.internal_combustion.enabled and remains < duration * 0.5 or not (talent.internal_combustion.enabled) and refreshable\nif talent[\"内燃\"] then\n	v = A[\"献祭\"]:Cast(nil, nil, {RefillTime = A[\"献祭\"]:GetDuration() * 0.5}) if v then return v end\nelse\n	v = A[\"献祭\"]:Cast() if v then return v end\nend\n-- chaos_bolt,if=cast_time<havoc_remains\n-- chaos_bolt,if=cast_time < havoc_remains\nif vars[\"敌方目标数量\"] < 3 and vars[\"灵魂碎片\"] >= vars[\"混乱之箭灵魂碎片\"] and A[\"混乱之箭\"]:GetCurrentCastingTime() < vars[\"浩劫剩余时间\"] then\n	v = A[\"混乱之箭\"]:Cast(vars[\"爆燃层数\"] > 0) if v then return v end\n	--if vars[\"爆燃层数\"] == 1 or vars[\"灵魂碎片裂片\"] < 40 then\n	--	v = A[\"混乱之箭\"]:CastSafely(vars[\"爆燃层数\"] > 0 and vars[\"灵魂碎片裂片\"] >= 20) if v then return v end\n	--else\n	--	v = A[\"混乱之箭\"]:Cast(vars[\"爆燃层数\"] > 0 and vars[\"灵魂碎片裂片\"] >= 20) if v then return v end\n	--end\nend\n-- shadowburn\n-- shadowburn,if=\nv = (not SwitchIsOn(\"暗灼打球\") or A[\"暗影灼烧\"]:GetChargeInfo():IsReachedOrSoon(nil, gcdmax - 0.4)) and A[\"暗影灼烧\"]:Cast() if v then return v end\n-- incinerate,if=cast_time<havoc_remains\n-- incinerate,if=cast_time < havoc_remains\n--v = A[\"烧尽\"]:Cast(A[\"烧尽\"]:GetCurrentCastingTime() < vars[\"浩劫剩余时间\"]) if v then return v end\nv = A[\"烧尽\"]:Cast() if v then return v end\n\n\n\n\n\n\n\n\n\n\n\n\n--if vars[\"爆燃层数\"] == 1 or vars[\"灵魂碎片裂片\"] < 40 then\n--    v = A[\"混乱之箭\"]:CastSafely(vars[\"爆燃层数\"] > 0 and vars[\"灵魂碎片裂片\"] >= 20) if v then return v end\n--else\n--    v = A[\"混乱之箭\"]:Cast(vars[\"爆燃层数\"] > 0 and vars[\"灵魂碎片裂片\"] >= 20) if v then return v end\n--end\n--v = A[\"燃烧\"]:Cast(vars[\"爆燃层数\"] == 0 and vars[\"灵魂碎片裂片\"] >= 15) if v then return v end\n--v = A[\"灵魂之火\"]:Cast() if v then return v end\n--v = A[\"暗影灼烧\"]:Cast() if v then return v end\n--v = A[\"烧尽\"]:Cast() if v then return v end\n--return 0\n",
            ["爆发技能"] = "--术士-毁灭-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nv = SwitchIsOn(\"召唤地狱火\") and A[\"召唤地狱火\"]:Cast() if v then return v end\nreturn run(\"一键爆发\")",
            ["输出"] = "--术士-毁灭-输出\nlocal v\nrun(\"更新灵魂碎片数量\")\nif vars[\"敌方目标数量\"] > 2 then\n	v = A[\"火焰之雨\"]:Cast(vars[\"灵魂碎片\"] >= 3) if v then return v end\nend\n\nif not inCombat then\n	v = A[\"灵魂之火\"]:Cast() if v then return v end\n	--v = not A[\"烧尽\"]:IsProtected() and A[\"烧尽\"]:Cast() if v then A[\"烧尽\"]:Protect() return v end\nend\nv = A[\"陨灭\"]:Cast() if v then return v end\n\nvars[\"爆燃层数\"] = player.MyBuff[\"爆燃\"].Count\nif vars[\"爆燃层数\"] > 0 and (A[\"混乱之箭\"]:IsCasting() or A[\"烧尽\"]:IsCasting()) then\n    vars[\"爆燃层数\"] = vars[\"爆燃层数\"] - 1\nend\nvars[\"混乱之箭灵魂碎片\"] = boss.IsTarget and 2 or (vars[\"敌方目标数量\"] > 2 and 4.5 or (inTraining and 2 or 4))\nvars[\"献祭时间\"] = target.MyDebuff[\"献祭\"]:GetTimeLeft()\n\nif vars[\"敌方目标数量\"] > 1 then\n    vars[\"枯萎数量\"], vars[\"敌方人数\"] = enemies:GetMyDebuffCount(\"枯萎\", 50)\n    v = A[\"怨毒\"]:Cast(vars[\"爆发强度\"] > 0.8 and vars[\"枯萎数量\"] >= vars[\"敌方人数\"] * 0.7) if v then return v end\nelse\n    v = A[\"怨毒\"]:Cast(vars[\"爆发强度\"] > 0.8) if v then return v end\nend\n\nv = enemies:GetMyDebuff(\"浩劫\")\nvars[\"浩劫剩余时间\"] = v and v:GetTimeLeft() or 0\nif vars[\"浩劫剩余时间\"] > 0 and vars[\"敌方目标数量\"] > 1 and vars[\"敌方目标数量\"] < 5 - (talent[\"地狱烈火\"] and 1 or 0) + ((talent[\"地狱烈火\"] and talent[\"内燃\"]) and 1 or 0) then\n	if not target.MyDebuff:Has(\"浩劫\") then\n		if vars[\"浩劫剩余时间\"] > 10 and SwitchIsOn(\"输出爆发\") and vars[\"爆发强度\"] > 4 then\n			--print(v, GetTime(), A[\"浩劫\"].LastSucceededTime)\n			v = run(\"一键爆发\") if v then return v end\n		end\n		if vars[\"敌方目标数量\"] > 2 then\n			v = run(\"AOE\") if v then return v end\n		end\n		return run(\"浩劫中\")\n	elseif vars[\"敌方目标数量\"] > 1 then\n		if SwitchIsOn(\"切换敌方\") then\n			return A[\"选择目标\"]:TargetFrontEnemy()\n		else\n			Error(\"当前目标有《浩劫》，请选中其他目标。\")\n		end\n	end\nend\n-- fleshcraft,if=soulbind.volatile_solvent,cancel_if=buff.volatile_solvent_humanoid.up\n-- fleshcraft,if=soulbind.volatile_solvent.enabled\n--v = SwitchIsOn(\"血肉铸造\") and A[\"血肉铸造\"]:Cast(soulbind[\"不稳定的溶液\"]) if v then return v end\n-- conflagrate,if=talent.roaring_blaze.enabled&debuff.roaring_blaze.remains<1.5\n-- conflagrate,if=talent.roaring_blaze.enabled and debuff.roaring_blaze.remains < 1.5\nv = A[\"燃烧\"]:Cast(talent[\"咆哮烈焰\"] and target.MyDebuff[\"燃烧\"]:GetTimeLeft() < 1.5) if v then return v end\n-- cataclysm\n-- cataclysm,if=\nv = A[\"大灾变\"]:Cast() if v then return v end\n\nvars[\"地狱火时间\"] = math.max(totems:GetTimeLeft(\"地狱火爪牙\"), player.MyBuff[\"渎神魔\"]:GetTimeLeft())\nvars[\"浩劫冷却\"] = A[\"浩劫\"]:GetCooldown()\n-- call_action_list,name=aoe,if=active_enemies>2\n-- call_action_list,name=aoe,if=active_enemies > 2\nif vars[\"敌方目标数量\"] > 2 then\n    v = run(\"AOE\") if v then return v end\nend\nif (not talent[\"大灾变\"] or A[\"大灾变\"]:GetCooldown() > vars[\"献祭时间\"]) then\n	-- soul_fire,cycle_targets=1,if=refreshable&soul_shard<=4&(!talent.cataclysm.enabled||cooldown.cataclysm.remains>remains)\n	-- soul_fire,if=refreshable and soul_shard <= 4 and (not (talent.cataclysm.enabled) or cooldown.cataclysm.remains > remains)\n	v = A[\"灵魂之火\"]:Cast(vars[\"灵魂碎片\"] <= 4) if v then return v end\n	-- immolate,cycle_targets=1,if=remains<3&(!talent.cataclysm.enabled||cooldown.cataclysm.remains>remains)\n	-- immolate,if=remains < 3 and (not (talent.cataclysm.enabled) or cooldown.cataclysm.remains > remains)\n	v = A[\"献祭\"]:Cast() if v then return v end\nend\n-- immolate,if=talent.internal_combustion.enabled&action.chaos_bolt.in_flight&remains<duration*0.5\n-- immolate,if=talent.internal_combustion.enabled and action.chaos_bolt.in_flight and remains < duration * 0.5\n--v = A[\"献祭\"]:Cast(talent[\"内燃\"] and A[\"混乱之箭\"].in_flight$ and vars[\"献祭时间\"] < target.MyDebuff[\"献祭\"].Duration * 0.5) if v then return v end\n-- chaos_bolt,if=(pet.infernal.active||pet.blasphemy.active)&soul_shard>=4\n-- chaos_bolt,if=(pet.infernal.active or pet.blasphemy.active) and soul_shard >= 4\nv = A[\"混乱之箭\"]:Cast(vars[\"敌方目标数量\"] < 3 and vars[\"地狱火时间\"] > 0 and vars[\"灵魂碎片\"] >= math.max(vars[\"混乱之箭灵魂碎片\"], 4.5)) if v then return v end\n-- call_action_list,name=cds\n-- call_action_list,name=cds,if=\nv = run(\"爆发技能\") if v then return v end\n-- channel_demonfire\n-- channel_demonfire,if=\nv = A[\"引导恶魔之火\"]:Cast() if v then return v end\n-- havoc,cycle_targets=1,if=!(target=self.target)&(dot.immolate.remains>dot.immolate.duration*0.5||!talent.internal_combustion.enabled)\n-- havoc,if=not (target.unit == self.target.unit) and (dot.immolate.remains > dot.immolate.duration * 0.5 or not (talent.internal_combustion.enabled))\nv = (vars[\"献祭时间\"] > A[\"献祭\"]:GetDuration() * 0.5 or not talent[\"内燃\"]) and run(\"浩劫\") if v then return v end\n-- havoc,if=runeforge.odr_shawl_of_the_ymirjar.equipped\n-- havoc,if=runeforge.odr_shawl_of_the_ymirjar.equipped\nv = legendary[\"奥德，伊米亚的披巾\"] and run(\"浩劫\") if v then return v end\n-- variable,name=pool_soul_shards,value=active_enemies>1&cooldown.havoc.remains<=10||buff.ritual_of_ruin.up&talent.rain_of_chaos\n-- variable,name=pool_soul_shards,if=\nvars[\"攒碎片\"] = vars[\"敌方目标数量\"] > 1 and vars[\"浩劫冷却\"] <= 10 or player.MyBuff:Has(\"毁灭仪式\") and talent[\"混乱之雨\"]\n-- conflagrate,if=buff.backdraft.down&soul_shard>=1.5-0.3*talent.flashover.enabled&!variable.pool_soul_shards\n-- conflagrate,if=buff.backdraft.down and soul_shard >= 1.5 - 0.3 * talent.flashover.enabled and not (variable.pool_soul_shards)\nv = A[\"燃烧\"]:Cast(vars[\"爆燃层数\"] == 0 and vars[\"灵魂碎片\"] >= 1.5 - 0.3 * (talent[\"爆裂之炎\"] and 1 or 0) and not vars[\"攒碎片\"]) if v then return v end\n-- chaos_bolt,if=pet.infernal.active||buff.rain_of_chaos.remains>cast_time\n-- chaos_bolt,if=pet.infernal.active or buff.rain_of_chaos.remains > cast_time\nif vars[\"灵魂碎片\"] >= vars[\"混乱之箭灵魂碎片\"] and vars[\"敌方目标数量\"] < 3 then\n	vars[\"混乱之箭施法时间\"] = A[\"混乱之箭\"]:GetCurrentCastingTime()\n	v = A[\"混乱之箭\"]:Cast(vars[\"地狱火时间\"] > 0 or player.MyBuff[\"混乱之雨\"]:GetTimeLeft() > vars[\"混乱之箭施法时间\"]) if v then return v end\n	-- chaos_bolt,if=buff.backdraft.up&!variable.pool_soul_shards\n	-- chaos_bolt,if=buff.backdraft.up and not (variable.pool_soul_shards)\n	v = A[\"混乱之箭\"]:Cast(vars[\"爆燃层数\"] > 0 and (not vars[\"攒碎片\"] or vars[\"灵魂碎片\"] >= 4)) if v then return v end\n	-- chaos_bolt,if=talent.eradication&!variable.pool_soul_shards&debuff.eradication.remains<cast_time\n	-- chaos_bolt,if=talent.eradication.enabled and not (variable.pool_soul_shards) and debuff.eradication.remains < cast_time\n	v = A[\"混乱之箭\"]:Cast(talent[\"灭杀\"] and not vars[\"攒碎片\"] and target.MyDebuff[\"灭杀\"]:GetTimeLeft() < vars[\"混乱之箭施法时间\"]) if v then return v end\nend\n-- shadowburn,if=!variable.pool_soul_shards||soul_shard>=4.5\n-- shadowburn,if=not (variable.pool_soul_shards) or soul_shard >= 4.5\nv = (not SwitchIsOn(\"暗灼打球\") or A[\"暗影灼烧\"]:GetChargeInfo():IsReachedOrSoon(nil, gcdmax - 0.4)) and A[\"暗影灼烧\"]:Cast(not vars[\"攒碎片\"] or vars[\"灵魂碎片\"] >= 4.5) if v then return v end\n-- chaos_bolt,if=soul_shard>3.5\n-- chaos_bolt,if=soul_shard > 3.5\nv = A[\"混乱之箭\"]:Cast(vars[\"敌方目标数量\"] < 3 and vars[\"灵魂碎片\"] >= vars[\"混乱之箭灵魂碎片\"]) if v then return v end\n-- chaos_bolt,if=time_to_die<5&time_to_die>cast_time+travel_time\n-- chaos_bolt,if=time_to_die < 5 and time_to_die > cast_time + travel_time\n\n--v = A[\"混乱之箭\"]:Cast(vars[\"目标死亡时间\"] < 5 and vars[\"目标死亡时间\"] > vars[\"混乱之箭施法时间\"] + A[\"混乱之箭\"]:GetTravelTime()) if v then return v end\n-- conflagrate,if=charges>1||time_to_die<gcd\n-- conflagrate,if=charges > 1 or time_to_die < gcd.execute\n--v = A[\"燃烧\"]:Cast(A[\"燃烧\"]:GetChargeInfo():IsReachedOrSoon(gcdmax) or vars[\"目标死亡时间\"] < gcd) if v then return v end\nv = A[\"燃烧\"]:Cast(A[\"燃烧\"]:GetChargeInfo():IsReachedOrSoon(gcdmax)) if v then return v end\n-- incinerate\n-- incinerate,if=\nv = A[\"烧尽\"]:Cast() if v then return v end\n\n\n",
            ["输出前"] = "--术士-毁灭-输出前\nif vars[\"敌方目标数量\"] > 1 and target.MyDebuff:Has(\"浩劫\") then\n	if SwitchIsOn(\"切换敌方\") then\n		return A[\"选择目标\"]:TargetFrontEnemy()\n	else\n		Error(\"当前目标有《浩劫》，请选中其他目标。\")\n	end\nend",
        },
        ["痛苦"] = {
            ["_专精初始化"] = "--术士-痛苦-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["取得伤害性Debuff数量"] = "--术士-痛苦-取得伤害性Debuff数量\nlocal unit = ... or target\nlocal count = 0\nif unit.MyDebuff:Has(\"腐蚀术\") then count = count + 1 end\nif unit.MyDebuff:Has(\"痛楚\") then count = count + 1 end\nif unit.MyDebuff:Has(\"痛苦无常\") then count = count + 1 end\nif unit.MyDebuff:Has(\"枯萎\") then count = count + 1 end\nreturn count",
            ["更新灵魂碎片数量"] = "--术士-痛苦-更新灵魂碎片数量\nvars[\"灵魂碎片\"] = player:GetPower(P[\"灵魂碎片\"])\nlocal name = UnitCastingInfo(\"player\")\nif name == \"腐蚀之种\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] - 1\nelseif name == \"痛苦无常\" then\n    vars[\"痛苦无常\"] = vars[\"灵魂碎片\"] - 1\nend\n",
            ["爆发技能"] = "--术士-痛苦-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v = A[\"召唤黑眼\"]:Cast() if v then return run(\"一键爆发\") end\n",
            ["输出"] = "--术士-痛苦-输出\nrun(\"更新灵魂碎片数量\")\nlocal v\nvars[\"夜幕\"] = player.MyBuff[\"夜幕\"].Count\nvars[\"暗吸灾\"] = A[\"灾难之握\"]:IsActiveSpell() and \"灾难之握\" or (talent[\"吸取灵魂\"] and \"吸取灵魂\" or \"暗影箭\")\nif vars[\"敌方目标数量\"] > 1 then\n    \n    v = (not target.MyDebuff:Has(\"腐蚀术\") or vars[\"灵魂碎片\"] == 5 or (talent[\"幽影蒙福\"] and vars[\"夜幕\"] > 1)) and A[\"腐蚀之种\"]:Cast() if v then return v end\n    v = vars[\"夜幕\"] > 1 and A[vars[\"暗吸灾\"]]:Cast() if v then return v end\n    v = A[\"痛楚\"]:CastOnMinTime(nil, 40, 60) if v then return v end\n    v = target:IsBigGuy() and A[\"鬼影缠身\"]:Cast() if v then return v end\n    v = vars[\"爆发强度\"] > 0.4 and A[\"怨毒\"]:Cast() if v then return v end\n    v = run(\"爆发技能\") if v then return v end\n    v = vars[\"爆发强度\"] > 0.4 and (not talent[\"死亡之影\"] or vars[\"灵魂碎片\"] < 3) and run(\"取得伤害性Debuff数量\") > 0 and A[\"幽冥收割\"]:Cast() if v then return v end\n    v = A[\"腐蚀之种\"]:Cast() if v then return v end\n    v = A[\"鬼影缠身\"]:Cast() if v then return v end\n    v = A[vars[\"暗吸灾\"]]:Cast() if v then return v end\nelse\n    v = A[\"痛楚\"]:Cast() if v then return v end\n    v = A[\"腐蚀术\"]:Cast() if v then return v end\n    v = vars[\"夜幕\"] > 1 and A[vars[\"暗吸灾\"]]:Cast() if v then return v end\n    v = A[\"鬼影缠身\"]:Cast() if v then return v end\n    v = vars[\"爆发强度\"] > 0.4 and (not talent[\"死亡之影\"] or vars[\"灵魂碎片\"] < 3) and run(\"取得伤害性Debuff数量\") > 0 and A[\"幽冥收割\"]:Cast() if v then return v end\n    v = vars[\"爆发强度\"] > 0.4 and A[\"怨毒\"]:Cast() if v then return v end\n    v = vars[\"灵魂碎片\"] > 2 and run(\"爆发技能\") if v then return v end\n    v = vars[\"夜幕\"] > 0 and A[vars[\"暗吸灾\"]]:Cast() if v then return v end\n    v = A[\"痛苦无常\"]:Cast() if v then return v end\n    v = A[vars[\"暗吸灾\"]]:Cast() if v then return v end\nend\n",
        },
    },
    ["武僧"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--武僧-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["正在引导法术"] = "--武僧-全专精-正在引导法术\nvars[\"正在引导的法术\"] = player:GetChannelingSpell()\n\nif not vars[\"正在引导的法术\"] then\n    return\nend\nif (vars[\"正在引导的法术\"] == \"神鹤引项踢\") then -- and UnitSpellHaste(\"player\") < 50\n    return\nend\nreturn true",
