        ["织雾"] = {
            ["_专精初始化"] = "--武僧-织雾-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--武僧-织雾-_脚本初始化\nrun(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n\n",
            ["保命"] = "--武僧-织雾-保命\nlocal v\nif not inCombat then\n    return\nend\nlocal v\n--v = talent[\"金创药\"] and A[\"金创药\"]:Cast(player.HealthPercent < 0.4 or (player.HealthPercent < 0.5 and A[\"金创药\"]:GetChargeInfo():TimeToCharges() < 5)) if v then return v end\n--v = talent[\"金创药\"] and (not A[\"金创药\"]:IsProtected()) and  A[\"金创药\"]:Cast(player.HealthPercent < 0.4 or (player.HealthPercent < 0.5 and A[\"金创药\"]:GetChargeInfo():TimeToCharges() < 5)) if v then A[\"金创药\"]:Protect(1, 0) return v end\n\n--v = A[\"散魔功\"]:Cast() if v then return v end\nv = A[\"壮胆酒\"]:Cast() if v then return v end\n--v = A[\"躯不坏\"]:Cast() if v then return v end\n--v = A[\"移花接木\"]:Cast(player.HealthPercent < 0.7) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n",
            ["强制执行"] = "--武僧-织雾-强制执行\nreturn talent[\"众神聚心\"] and A[\"众神聚心\"]:IsActiveSpell() and A[\"众神聚心\"]:Cast()\n",
            ["正在引导法术"] = "--武僧-织雾-正在引导法术\nif not run(\"武僧-全专精-正在引导法术\") then\n    return\nend\nreturn vars[\"正在引导的法术\"] ~= \"抚慰之雾\"",
            ["治疗"] = "--武僧-织雾-治疗\nlocal v\nif inCombat then\n    v = A[\"还魂术\"]:Cast() if v then return v end \n    v = A[\"天神御身\"]:Cast() if v then return v end \n    --v = A[\"神龙之赐\"]:Cast((sv:GetSpellCount(\"神龙之赐\") or 0) > 4) if v then return v end \n    v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    v = A[\"作茧缚命\"]:Cast(healTarget.HealthPercent < 0.4, healTarget) if v then return v end \n    --v = run(\"使用饰品\", \"释魂红玉\", target.IsEnemy and hoe:Need(), target) if v then return v end\n    v = SwitchIsOn(A[\"青龙下凡\"].Name) and A[\"青龙下凡\"]:Cast() if v then return v end \n    --v = A[\"碧火踏_治疗\"]:Cast() if v then return v end \n    --v = A[\"骨尘酒_治疗\"]:Cast() if v then return v end \n    v = A[\"氤氲之雾\"]:Cast(healTarget.HealthPercent < 0.7 and (player.MyBuff:Has(\"雷光聚神茶\") or player.MyBuff[\"朱鹤下凡\"].Count >= 3), healTarget) if v then return v end \n    v = A[\"活血术\"]:CastSafely(healTarget.HealthPercent < (talent[\"朱鹤下凡\"] and 0.5 or 0.7) and player.MyBuff:Has(\"活力苏醒\"), healTarget) if v then return v end \n    v = A[\"神龙之赐\"]:CastSafely(healTarget.HealthPercent < (talent[\"朱鹤下凡\"] and 0.5 or 0.7) and player.MyBuff:Has(\"活力苏醒\"), healTarget) if v then return v end \n    --v = SwitchIsOn(\"精华之泉\") and A[\"精华之泉\"]:Cast(healTarget.HealthPercent > 0.45) if v then return v end \n    --v = healTarget.HealthPercent < 0.6 and A[\"禅意波\"]:Cast(nil, healTarget) if v then return v end \n    v = healTarget.HealthPercent > 0.7 and SwitchIsOn(\"攻击敌方\") and run(\"输出\") if v then return v end\n    local mana = player:GetPowerPercent(P[\"法力\"])\n    v = SwitchIsOn(\"法力茶\") and A[\"法力茶\"]:IsReady() and (mana < 0.1 or (healTarget.HealthPercent > 0.8 and mana < 0.75)) and A[\"法力茶\"]:Cast() if v then return v end \n    v = A[\"雷光聚神茶\"]:Cast(healTarget.HealthPercent < 0.7) if v then return v end \nend\n--v = A[\"碧愈疾风\"]:Cast() if v then return v end \n--v = A[\"真气爆裂\"]:Cast(healTarget.HealthPercent < 0.8) if v then return v end \nv = A[\"复苏之雾\"]:Cast(healTarget.HealthPercent < 0.9 or inCombat, healTarget) if v then return v end\n\n--v = A[\"真气波\"]:Cast(healTarget.HealthPercent < 0.85 and vars[\"正在引导的法术\"] ~= \"抚慰之雾\", healTarget) if v then return v end \nv = SwitchIsOn(\"取消施法\") and A[\"抚慰之雾\"]:ShouldCancelChanneling() and A[\"取消施法\"]:Cast() if v then return v end \n\nif talent[\"抚慰之雾\"] then\n    v = A[\"召唤青龙雕像\"]:Cast(healTarget.HealthPercent < 0.9, player) if v then return v end \n    if vars[\"正在引导的法术\"] == \"抚慰之雾\" and A[\"抚慰之雾\"]:IsChannelingOnUnit(healTarget) then\n        --正在对目标施放抚慰之雾\n        v = A[\"氤氲之雾\"]:CastSafely(healTarget.HealthPercent < 0.6, healTarget) if v then return v end \n        v = A[\"活血术\"]:CastSafely(healTarget.HealthPercent < 0.7, healTarget) if v then return v end \n        v = A[\"神龙之赐\"]:CastSafely(healTarget.HealthPercent < 0.7, healTarget) if v then return v end \n    elseif talent[\"青龙之道\"] then\n        v = A[\"抚慰之雾\"]:ForceCast(healTarget.HealthPercent < 0.75, healTarget) if v then return v end \n    else\n        v = A[\"抚慰之雾\"]:Cast(healTarget.HealthPercent < 0.75, healTarget) if v then return v end \n    end\nelseif healTarget.HealthPercent < 0.5 then\n    v = A[\"氤氲之雾\"]:CastSafely(nil, healTarget) if v then return v end \n    v = A[\"活血术\"]:CastSafely(nil, healTarget) if v then return v end \n    v = A[\"神龙之赐\"]:CastSafely(nil, healTarget) if v then return v end \nend\nv = SwitchIsOn(\"预铺复苏\") and run(\"预铺Buff\", A[\"复苏之雾\"]) if v then return v end\n",
            ["输出"] = "--武僧-织雾-输出\nlocal v\n--v = A[\"碧火踏\"]:Cast(player.MyBuff[\"觉醒碧火\"]:GetTimeLeft() < 3) if v then return v end \n--v = A[\"碧火踏\"]:Cast(not player.MyBuff:Has(\"碧火之训\") and not player.MyBuff:Has(\"觉醒碧火\")) if v then return v end \nv = A[\"疾风呼啸踢\"]:Cast() if v then return v end \nv = A[\"轮回之触\"]:Cast(UnitIsPlayer(\"target\") or boss.IsTarget or target.Health >= player.HealthBaseline * 0.3) if v then return v end\n--v = A[\"骨尘酒\"]:Cast() if v then return v end \n--v = SwitchIsOn(\"召唤白虎雕像\") and (A[\"召唤白虎雕像\"]:Cast() or A[\"我_召唤白虎雕像\"]:Cast()) if v then return v end \n--v = A[\"旭日东升踢\"]:Cast(talent[\"升腾迷雾\"]) if v then return v end \nv = A[\"神鹤引项踢\"]:Cast(vars[\"敌方目标数量\"] > 4) if v then return v end \n--v = A[\"旭日东升踢\"]:Cast() if v then return v end \nv = A[\"神鹤引项踢\"]:Cast(vars[\"敌方目标数量\"] > 2) if v then return v end \n--v = A[\"真气波\"]:Cast(player.HealthPercent < 0.95) if v then return v end \n--v = A[\"真气爆裂\"]:Cast(player.HealthPercent < 0.95) if v then return v end \n--v = A[\"碧火踏\"]:Cast() if v then return v end \nlocal count = player.MyBuff[\"禅院教诲\"].Count\nv = A[\"猛虎掌\"]:Cast(count < 4) if v then return v end \nv = A[\"幻灭踢\"]:Cast(count > 3) if v then return v end \nv = A[\"猛虎掌\"]:Cast() if v then return v end \n\n",
        },
        ["踏风"] = {
            ["_专精初始化"] = "--武僧-踏风-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--武僧-踏风-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n\n",
            ["保命"] = "--武僧-踏风-保命\nif not inCombat and battleType == \"野外\" then\n    v = A[\"活血术\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n    v = A[\"活血术\"]:CastSafely(player.HealthPercent < 0.85, player) if v then return v end\n    return\nend\nlocal v\n\nif not player.MyBuff:Has(\"业报之触\") then\n    --v = A[\"散魔功\"]:Cast() if v then return v end\n    v = A[\"壮胆酒\"]:Cast() if v then return v end\n    --v = A[\"躯不坏\"]:Cast() if v then return v end\nend\n\nv = A[\"移花接木\"]:Cast(player.HealthPercent < (inPVE and 0.3 or 0.4)) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"活血术\"]:Cast(player.HealthPercent < (inPVE and 0.3 or 0.4), player) if v then return v end\nv = player.HealthPercent < 0.65 and player.MyBuff:Has(\"活力苏醒\") and A[\"活血术\"]:Cast() if v then return v end\n",
            ["怒雷破_"] = "--武僧-踏风-怒雷破_\nif not SwitchIsOn(\"怒雷破\") then\n    return\nend\nvars[\"怒雷破冷却\"] = A[\"怒雷破\"]:GetCooldown()\nif vars[\"怒雷破冷却\"] > (4 * gcdmax) then\n    return\nend\n--if vars[\"保留真气\"] < 3 then\n--    vars[\"保留真气\"] = 3\n--end\nif vars[\"真气\"] < 3 then\n    return run(\"攒真气\")\nend\nlocal v\nvars[\"怒雷破持续时间\"] = A[\"怒雷破\"]:GetDuration()\nv = A[\"怒雷破\"]:Cast() if v then return v end\n--v = A[\"怒雷破\"]:Cast(vars[\"能量回满时间\"] > (vars[\"怒雷破冷却\"] + vars[\"怒雷破持续时间\"])) if v then return v end\n",
            ["攒真气"] = "--武僧-踏风-攒真气\n--if vars[\"真气差\"] == 1 and vars[\"敌方目标数量\"] == 1 and SwitchIsOn(\"真气爆裂\") then\n--    v = A[\"真气爆裂\"]:Cast() if v then return v end \n--end\nif vars[\"真气差\"] <= 1 then\n    return\nend\n--v = A[\"白虎拳\"]:Cast(vars[\"真气差\"] > 2) if v then return v end \n--v = SwitchIsOn(\"豪能酒\") and A[\"豪能酒\"]:Cast(vars[\"能量\"] < 50 and vars[\"真气\"] < 3) if v then return v end \nif not player.MyBuff:Has(\"组合拳：猛虎掌\") then\n    v = A[\"猛虎掌\"]:Cast() if v then return v end \nelseif not player.MyBuff:Has(\"组合拳：幻灭踢\") then\n    v = A[\"幻灭踢\"]:Cast() if v then return v end \n    --v = A[\"真气波\"]:Cast() if v then return v end \n    --v = A[\"幻灭踢\"]:Cast(vars[\"上一个技能\"] ~= \"幻灭踢\" and player.MyBuff:Has(\"幻灭踢！\")) if v then return v end\n    --v = A[\"移花接木\"]:Cast() if v then return v end \n    --v = A[\"幻灭踢\"]:Cast(vars[\"上一个技能\"] ~= \"幻灭踢\" and vars[\"能量回满时间\"] < 2 * gcdmax) if v then return v end\n    --return 0 --真气未达标，继续下一循环\nend\n",
            ["治疗"] = "--武僧-踏风-治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\nv = A[\"活血术\"]:Cast(target.HealthPercent < 0.7, target) if v then return v end\nv = A[\"活血术\"]:CastSafely(target.HealthPercent < 0.9, target) if v then return v end\n\n",
            ["爆发技能"] = "--武僧-踏风-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nif target.RangeToPlayer > 5 then\n    return\nend\nlocal v\nif talent[\"乾元之巅\"] then\n    if player.MyBuff:Has(\"乾元之巅\") then\n        v = A[\"白虎下凡\"]:Cast() if v then return v end\n        v = talent[\"天神御身\"] and A[\"天神御身\"]:IsActiveSpell() and A[\"天神御身\"]:Cast() if v then return v end\n	    --v = SwitchIsOn(\"骨尘酒\") and A[\"骨尘酒\"]:Cast() if v then return v end \n    end\n    if A[\"怒雷破\"]:GetCooldown() < 8 then\n        local cd = A[\"乾元之巅\"]:GetCooldown()\n        if cd > 2 * gcdmax + 0.4 then\n            return\n        end\n        if vars[\"真气差\"] > 1 then\n            v = run(\"攒真气\") if v then return v end\n        end\n        v = A[\"白虎下凡\"]:Cast() if v then return v end\n        v = not player.MyBuff:Has(\"乾元之巅\") and A[\"乾元之巅\"]:Cast() if v then return run(\"一键爆发\") end\n    end\nelse\n    v = A[\"白虎下凡\"]:Cast() if v then return v end\n    v = talent[\"天神御身\"] and A[\"天神御身\"]:IsActiveSpell() and A[\"天神御身\"]:Cast() if v then return v end\nend\n\n",
            ["输出"] = "--武僧-踏风-输出\nvars[\"真气\"] = player:GetPower(P[\"真气\"])\nvars[\"真气差\"] = player:GetPowerDeficit(P[\"真气\"])\nvars[\"真气最大值\"] = player:GetPowerMax(P[\"真气\"])\nvars[\"能量\"] = player:GetPower(P[\"能量\"])\n--vars[\"能量最大值\"] = player:GetPowerMax(P[\"能量\"])\nvars[\"能量回满时间\"] = player:GetPowerTimeToMax(P[\"能量\"])\n--run(\"取得上一个技能\")\nvars[\"保留真气\"] = 0\n\nlocal v\nv = A[\"轮回之触\"]:Cast(UnitIsPlayer(\"target\") or boss.IsTarget or target.Health >= player.HealthBaseline * 0.3) if v then return v end\n\n--v = A[\"业报之触\"]:Cast(player.HealthWatcher:GetRecentDamagePercent(3) > 0.15) if v then return v end \n--v = A[\"碧火踏\"]:Cast() if v then return v end \nvars[\"幻灭踢！时间\"] = player.MyBuff[\"幻灭踢！\"]:GetTimeLeft()\nv = not player.MyBuff:Has(\"组合拳：幻灭踢\") and A[\"幻灭踢\"]:Cast(vars[\"幻灭踢！时间\"] > 0 and (vars[\"幻灭踢！时间\"] < gcdmax + 0.4)) if v then return v end \n--v = A[\"碧玉疾风\"]:Cast(vars[\"敌方目标数量\"] > 2 and vars[\"上一个技能\"] ~= \"碧玉疾风\") if v then return v end --vars[\"能量\"] > 20,\n--if UnitCastingInfo(\"player\") == \"真气爆裂\" then\n--    vars[\"真气\"] = vars[\"真气\"] + ((vars[\"敌方目标数量\"] < 2) and vars[\"敌方目标数量\"] or 2)\n--    vars[\"真气差\"] = vars[\"真气最大值\"] - vars[\"真气\"]\n--end\n--v = SwitchIsOn(\"召唤白虎雕像\") and (A[\"召唤白虎雕像\"]:Cast() or A[\"我_召唤白虎雕像\"]:Cast()) if v then return v end \n\nv = run(\"爆发技能\") if v then return v end\nv = A[\"风领主之击\"]:Cast() if v then return v end \nv = not player.MyBuff:Has(\"组合拳：神鹤引项踢\") and not A[\"神鹤引项踢\"]:IsChanneling() and player.MyBuff:Has(\"赤精之舞\") and A[\"神鹤引项踢\"]:Cast() if v then return v end\nif talent[\"升龙霸\"] then\n    v = A[\"升龙霸\"]:Cast(target.RangeToPlayer < 5) if v then return v end \n    v = not player.MyBuff:Has(\"组合拳：旭日东升踢\") and A[\"旭日东升踢\"]:Cast(A[\"升龙霸\"]:GetCooldown() < gcdmax * 1.3 and A[\"怒雷破\"]:GetCooldown() > gcdmax * 1.7) if v then return v end \nend\n\n--v = A[\"白虎拳\"]:Cast(vars[\"真气差\"] > 2 and vars[\"能量回满时间\"] < 2 * gcdmax, nil, {LeadCd = gcdmax * 0.8}) if v then return v end \nv = not player.MyBuff:Has(\"组合拳：猛虎掌\") and A[\"猛虎掌\"]:Cast(vars[\"真气差\"] > 1 and vars[\"能量回满时间\"] < 2 * gcdmax) if v then return v end\n--v = A[\"旭日东升踢\"]:Cast(vars[\"上一个技能\"] ~= \"旭日东升踢\" and vars[\"旭日功\"] and player.MyBuff[\"旭日功\"]:GetTimeLeft() < 2) if v then return v end \n\nif vars[\"敌方目标数量\"] > 2 then\n    v = run(\"怒雷破_\") if v then return v end\n    --v = A[\"碧玉疾风\"]:Cast(vars[\"上一个技能\"] ~= \"碧玉疾风\") if v then return v end\n    if not player.MyBuff:Has(\"组合拳：神鹤引项踢\") and not A[\"神鹤引项踢\"]:IsChanneling() then\n        --v = A[\"神鹤引项踢\"]:Cast(player.MyBuff:Has(\"赤精之舞\")) if v then return v end\n        --if vars[\"敌方目标数量\"] > 3 or sv:GetSpellCount(\"神鹤引项踢\") > 1 then\n            if vars[\"真气\"] < 2 then\n                return run(\"攒真气\")\n            end\n            v = A[\"神鹤引项踢\"]:Cast() if v then return v end\n        --end\n    end\n    --v = A[\"真气爆裂\"]:Cast(vars[\"真气差\"] > 1) if v then return v end \n    v = not player.MyBuff:Has(\"组合拳：旭日东升踢\") and A[\"旭日东升踢\"]:Cast() if v then return v end \n    v = not player.MyBuff:Has(\"组合拳：幻灭踢\") and A[\"幻灭踢\"]:Cast((vars[\"真气\"] > 3 or vars[\"幻灭踢！时间\"] > 0 or vars[\"能量回满时间\"] < A[\"旭日东升踢\"]:GetCooldown() + gcdmax)) if v then return v end\n    --v = A[\"白虎拳\"]:Cast(vars[\"真气差\"] > 2) if v then return v end\n    v = not player.MyBuff:Has(\"组合拳：猛虎掌\") and A[\"猛虎掌\"]:Cast(vars[\"真气差\"] > 1) if v then return v end\n    --v = A[\"真气波\"]:Cast(vars[\"上一个技能\"] ~= \"猛虎掌\" and vars[\"能量\"] > 40) if v then return v end\nelse\n    --v = A[\"旭日东升踢\"]:Cast(vars[\"上一个技能\"] ~= \"旭日东升踢\" and vars[\"真气\"] > 4) if v then return v end \n    v = not player.MyBuff:Has(\"组合拳：旭日东升踢\") and A[\"旭日东升踢\"]:Cast() if v then return v end \n    v = run(\"怒雷破_\") if v then return v end\n    --v = A[\"白虎拳\"]:Cast(vars[\"真气差\"] > 2) if v then return v end\n    v = not player.MyBuff:Has(\"组合拳：幻灭踢\") and A[\"幻灭踢\"]:Cast((vars[\"真气\"] > 3 or vars[\"幻灭踢！时间\"] > 0 or vars[\"能量回满时间\"] < A[\"旭日东升踢\"]:GetCooldown() + gcdmax)) if v then return v end\n    --v = A[\"真气爆裂\"]:Cast(vars[\"真气差\"] >= vars[\"敌方目标数量\"]) if v then return v end \n    --v = A[\"真气波\"]:Cast((vars[\"上一个技能\"] == \"猛虎掌\") and vars[\"能量\"] > 40) if v then return v end\n    --v = A[\"幻灭踢\"]:Cast((vars[\"上一个技能\"] == \"猛虎掌\" or vars[\"上一个技能\"] == \"白虎拳\") and vars[\"能量\"] > 40) if v then return v end\n    --v = A[\"真气波\"]:Cast((vars[\"上一个技能\"] == \"猛虎掌\" or vars[\"上一个技能\"] == \"白虎拳\") and vars[\"能量\"] > 40) if v then return v end\n    v = not player.MyBuff:Has(\"组合拳：猛虎掌\") and A[\"猛虎掌\"]:Cast(vars[\"真气差\"] > 1) if v then return v end\n    --if vars[\"能量回满时间\"] < 2 * gcdmax and vars[\"上一个技能\"] ~= \"幻灭踢\" then\n    --v = A[\"猛虎掌\"]:Cast(vars[\"真气差\"] > 1 and vars[\"上一个技能\"] ~= \"猛虎掌\" and vars[\"能量回满时间\"] < gcdmax) if v then return v end\nend\n",
        },
        ["酒仙"] = {
            ["_专精初始化"] = "--武僧-酒仙-_专精初始化\nrun(\"全专精-_专精初始化\")\n\n",
            ["保命"] = "--武僧-酒仙-保命\nlocal v\nif not inCombat and battleType == \"野外\" then\n    v = A[\"活血术\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n    v = A[\"活血术\"]:CastSafely(player.HealthPercent < 0.85, player) if v then return v end\n    return\nend\nv = A[\"玄牛下凡\"]:Cast() if v then return v end\nv = A[\"壮胆酒\"]:Cast() if v then return v end\nv = player.HealthPercent < 0.6 and player.MyBuff:Has(\"活力苏醒\") and A[\"活血术\"]:Cast() if v then return v end\n\n--v = A[\"天神酒\"]:Cast(player.HealthPercent < 0.7 and player.MyBuff:Has(\"净化真气\")) if v then return v end\nv = A[\"天神酒\"]:Cast(player.HealthPercent < 0.6) if v then return v end\nv = A[\"天神灌注\"]:Cast(player.HealthPercent < 0.65) if v then return v end\nvars[\"移花接木数量\"] = A[\"移花接木\"]:GetCount() or 0\nv = A[\"移花接木\"]:Cast(player.HealthPercent < 0.7 and vars[\"移花接木数量\"] > 2) if v then return v end --vars[\"移花接木数量\"] < 5\n\nv = run(\"活血酒\") if v then return v end\n\nv = A[\"真气爆裂\"]:Cast(player.HealthPercent < 0.8) if v then return v end \nv = A[\"移花接木\"]:Cast(player.HealthPercent < 0.7 and vars[\"移花接木数量\"] > 0) if v then return v end --vars[\"移花接木数量\"] < 5\n\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n\n\n",
            ["治疗"] = "--武僧-酒仙-治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\nv = A[\"活血术\"]:Cast(target.HealthPercent < 0.7, target) if v then return v end\nv = A[\"活血术\"]:CastSafely(target.HealthPercent < 0.9, target) if v then return v end\n\n",
            ["活血酒"] = "--武僧-酒仙-活血酒\nvars[\"酒充能\"] = A[\"活血酒\"]:GetChargeInfo()\nvars[\"酒数量\"] = vars[\"酒充能\"].Charges\n\n\nif vars[\"酒数量\"] == 0 then\n    return A[\"玄牛酒\"]:Cast(player.HealthPercent < 0.6 and vars[\"酒充能\"].Cooldown > 2 * gcdmax)\nend\nvars[\"醉拳等级\"] = 0\nif player.MyDebuff:Has(\"轻度醉拳\") then\n    vars[\"醉拳等级\"] = 1\nelseif player.MyDebuff:Has(\"中度醉拳\") then\n    vars[\"醉拳等级\"] = 2\nelseif player.MyDebuff:Has(\"重度醉拳\") then\n    vars[\"醉拳等级\"] = 3\nelse\n    vars[\"醉拳等级\"] = 0\n    return --无醉拳\nend\n--print(\"活血酒\", battleType, inTraining, target.IsEnemy, target.IsTrainDummy, target:GetTrainDummyType())\n--v = A[\"活血酒\"]:Cast(vars[\"醉拳等级\"] == 3 or (vars[\"醉拳等级\"] > (battleType == \"野外\" and 0 or (vars[\"敌方目标数量\"] > 2 and 2 or 1)) and vars[\"酒充能\"]:TimeToCharges() < 2)) if v then return v end\n--print(vars[\"醉拳等级\"], vars[\"敌方目标数量\"],vars[\"敌方目标数量\"] > 2, vars[\"敌方目标数量\"] > 2 and 2 or 1, ((vars[\"敌方目标数量\"] > 2) and 2 or 1), vars[\"醉拳等级\"] > ((vars[\"敌方目标数量\"] > 2) and 2 or 1))\nv = A[\"活血酒\"]:Cast(vars[\"醉拳等级\"] == 3 or (vars[\"醉拳等级\"] > ((vars[\"敌方目标数量\"] > 2) and 2 or 1) and vars[\"酒充能\"]:TimeToCharges() < 2)) if v then  return v end\n\n",
            ["爆发技能"] = "--武僧-酒仙-爆发技能\nlocal v\nif vars[\"爆发强度\"] < 1.5 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nif target.RangeToPlayer > 5 then\n    return\nend\n--if talent[\"精序兵戈\"] then\n--    v = vars[\"醉酿投冷却\"] > 3 and A[\"精序兵戈\"]:Cast() if v then return run(\"一键爆发\") end\n--else\nv = A[\"我_爆炸酒桶\"]:Cast() if v then return run(\"一键爆发\") end \n--end",
            ["输出"] = "--武僧-酒仙-输出\nlocal v\nv = A[\"清空地窖\"]:IsActiveSpell() and A[\"清空地窖\"]:Cast() if v then return run(\"一键爆发\") end\n--v = A[\"清空地窖\"]:IsActiveSpell() and A[\"清空地窖\"]:Cast(nil, nil, {LeadCD=2}) if v then return v end\nv = A[\"轮回之触\"]:Cast(UnitIsPlayer(\"target\") or boss.IsTarget or target.Health >= player.HealthBaseline * 0.3) if v then return v end\nv = A[\"醉酿投\"]:Cast() if v then return v end\nvars[\"醉酿投冷却\"] = A[\"醉酿投\"]:GetCooldown()\n--面前AOE\nv = A[\"火焰之息\"]:Cast(target.RangeToPlayer < 8) if v then return v end\n--v = SwitchIsOn(\"爆炸酒桶\") and (A[\"爆炸酒桶\"]:Cast() or A[\"我_爆炸酒桶\"]:Cast()) if v then return v end \nv = run(\"爆发技能\") if v then return v end\n\n\nv = A[\"幻灭踢\"]:Cast(target.RangeToPlayer < 5) if v then return v end\nv = A[\"碧玉疾风\"]:Cast(target.RangeToPlayer < 8) if v then return v end\n\nv = A[\"真气爆裂\"]:Cast(player.HealthPercent < 0.95) if v then return v end \n\nif player:GetPowerTimeToValue(P[\"能量\"], 65) < vars[\"醉酿投冷却\"] then\n    if vars[\"敌方目标数量\"] < 3 then\n        v = A[\"猛虎掌\"]:Cast() if v then return v end \n    else\n        if A[\"活血酒\"]:GetChargeInfo():TimeToCharges() < 4 then \n            v = A[\"神鹤引项踢\"]:Cast() if v then return v end \n        elseif GetLastSpell(1).Name ~= \"神鹤引项踢\" and not A[\"神鹤引项踢\"]:IsProtected() then\n            v = A[\"神鹤引项踢\"]:Cast() if v then A[\"神鹤引项踢\"]:Protect(gcdmax + 0.4) return v end \n        else\n            v = A[\"猛虎掌\"]:Cast() if v then return v end \n        end\n    end\nend\n\n\n",
        },
    },
    ["死亡骑士"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--死亡骑士-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\nvars[\"灵魂收割条件\"] = \n	function(cachedUnit, unit, ...)\n		if unit:TimeToPercent(0.35) < 4 and A[\"灵魂收割\"]:GetCooldown() < gcdmax * 0.75 then\n			local tm = unit:TimeToDie()\n			local v = ((vars[\"敌方目标数量\"] == 1 and tm > 5) or ((tm > 5 and vars[\"敌方目标数量\"] <= 3 or t28[4] and pet.MyBuff:Has(\"黑暗突变\") and vars[\"敌方目标数量\"] <= 5 and (not target.MyDebuff:Has(\"枯萎凋零\"))))) and A[\"灵魂收割\"]:Cast(nil, unit, {LeadCd = gcdmax * 0.75})\n			if v then\n				return true, true --第二个true表示停止继续找下一个unit\n			else\n				return false\n			end\n		else\n			return false\n		end\n	end\nvars[\"灵界打击条件\"] = \n	function(cachedUnit, unit, ...)\n		if A[\"灵界打击\"]:Cast(nil, unit, NoChangeTarget) then\n			return true, true --第二个true表示停止继续找下一个unit\n		else\n			return false\n		end\n	end\n\nlocal ___runeforges = {\n    [6243] = \"癔狂符文\",--hysteria\n    [3370] = \"冰锋符文\", --razorice\n    [6241] = \"鲜红符文\",--sanguination\n    [6242] = \"护咒符文\",--spellwarding\n    [6245] = \"天启符文\",--apocalypse\n    [3368] = \"堕落十字军符文\",--fallen_crusader\n    [3847] = \"岩肤石像鬼符文\",--stoneskin_gargoyle\n    [6244] = \"无尽渴求符文\",--unending_thirst\n	Update = \n		function(self, slot)\n			local link = GetInventoryItemLink(\"player\", slot)\n			if not link then\n				return false\n			end\n			local enchant = link:match(\"item:%d+:(%d+)\")                    \n			if not enchant then\n				return true\n			end\n			local name = self[tonumber(enchant)]\n			if name then\n				runeforge[name] = true\n			end\n			return true\n		end,\n} \n\nvars[\"更新武器符文类别\"] = \n	function()\n        for k, v in pairs(___runeforges) do\n            --print(k,v)\n            if k ~= \"Update\" then\n                runeforge[v] = false\n            end\n        end\n		___runeforges:Update(16)--主手\n		vars[\"双持\"] = ___runeforges:Update(17)--副手\n	end    \n    \n",
            ["_装备初始化"] = "--死亡骑士-全专精-_装备初始化\nrun(\"全职业-全专精-_装备初始化\")\n\nif vars[\"更新武器符文类别\"] then\n	vars[\"更新武器符文类别\"]()\nend",
            ["基本检查"] = "--死亡骑士-全专精-基本检查\nif (talent[\"告死苍驹\"] or talent[\"死亡冲锋\"]) and player.MyBuff:Has(\"阿彻鲁斯死亡战马\") then --告死苍驹 死亡冲锋\n    return true\nend\nif IsMounted() then --在坐骑上\n    return\nend\nif UnitIsDeadOrGhost(\"player\") then --已死亡\n    return\nend\nif run(\"正在引导法术\") then --正在引导法术\n    return\nend\nif inCombat and IsForceStart() then\n    return true\nend\nif player.MyBuff:Has(\"灵魂变形\") then \n    return\nend\nif ... then --附加check\n    return\nend\nreturn true",
            ["死亡之握_"] = "--死亡骑士-全专精-死亡之握_\nif mouseover.IsEnemy and mouseover.RangeToPlayer > 8 then\n	return A[\"死亡之握\"]:Cast(nil, mouseover)\nelseif target.IsEnemy and target.RangeToPlayer > 8 then\n	return A[\"死亡之握\"]:Cast(nil, target)\nend\n",
            ["输出初始化"] = "--死亡骑士-全专精-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["冰霜"] = {
            ["_专精初始化"] = "--死亡骑士-冰霜-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"冰锋符文条件\"] = \n	function(cachedUnit, unit, ...)\n        if A[\"湮灭\"]:GetMacroText(unit) then\n            if not cachedUnit then\n                return true\n            elseif (unit.MyDebuff[\"锋锐之霜\"].Count + 1) / (unit.MyDebuff[\"锋锐之霜\"]:GetTimeLeft() + 1) > (cachedUnit.MyDebuff[\"锋锐之霜\"].Count + 1) / (cachedUnit.MyDebuff[\"锋锐之霜\"]:GetTimeLeft() + 1) then\n                return true\n            end\n        end\n		return false\n	end\n\n\n",
            ["_脚本初始化"] = "--死亡骑士-冰霜-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n-- variable,name=rw_buffs,value=talent.gathering_storm||conduit.everfrost||runeforge.biting_cold\n-- variable,name=rw_buffs,if=\nvars[\"风暴汇聚\"] = talent[\"风暴汇聚\"] or soulbind[\"永冻之冰\"] or legendary[\"刺骨之寒\"]\n",
            ["保命"] = "--死亡骑士-冰霜-保命\nvars[\"符文能量\"] = player:GetPower(P[\"符文能量\"])\nvars[\"符文能量差\"] = player:GetPowerDeficit(P[\"符文能量\"])\n--vars[\"冰龙吐息\"] = player.MyBuff:Has(\"冰龙吐息\")\nif not inCombat then\n    return\nend\nlocal v\nlocal tm = player.MyBuff[\"黑暗援助\"]:GetTimeLeft()\nv = A[\"灵界打击\"]:Cast(target.RangeToPlayer < 5 and tm > 0 and (tm < 3 or player.HealthPercent < 0.8)) if v then return v end\nif player.HealthPercent > 0.7 then\n    return\nend\nv = A[\"反魔法护罩\"]:Cast() if v then return v end\nv = A[\"冰封之韧\"]:Cast() if v then return v end\nv = A[\"天灾契约\"]:Cast(player.HealthPercent < 0.45) if v then return v end\nv = SwitchIsOn(\"巫妖之躯\") and A[\"巫妖之躯_减伤\"]:Cast() if v then return v end\n\nvars[\"需要灵界打击\"] = player.HealthPercent < (boss.InCombat and 0.4 or (inPVE and 0.5 or 0.7))\nif vars[\"需要灵界打击\"] then\n	v = A[\"灵界打击\"]:CastOnUnitByCondition(nil, 6, 160, vars[\"灵界打击条件\"]) if v then return v end\nend\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n\n",
            ["爆发技能"] = "--死亡骑士-冰霜-爆发技能\nvars[\"爆发技能\"] = false\nif vars[\"爆发强度\"] < 2 or target.RangeToPlayer > 5 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nvars[\"冰霜之柱冷却\"] = A[\"冰霜之柱\"]:GetCooldown()\nvars[\"死神印记冷却\"] = A[\"死神印记\"]:GetCooldown()\nvars[\"冰龙吐息冷却\"] = A[\"冰龙吐息\"]:GetCooldown()\nif vars[\"冰霜之柱\"] then\n    v = A[\"死神印记\"]:Cast() if v then return v end\n    v = A[\"冰龙吐息\"]:Cast() if v then return v end\n    v = A[\"冰霜巨龙之怒\"]:Cast() if v then return v end\nelse\n    if (not SwitchIsOn(\"冰霜之柱\") or vars[\"冰霜之柱冷却\"] > 0.25) then\n        return --没有冰霜之柱\n    end\n    if SwitchIsOn(\"死神印记\") and (runes[2] > 0 or vars[\"死神印记冷却\"] > 0.25) then\n        return\n    end\n    if SwitchIsOn(\"冰龙吐息\") and vars[\"爆发强度\"] > 3 then\n        if vars[\"冰龙吐息冷却\"] > 0.25 and vars[\"冰龙吐息冷却\"] < 25 then\n            return\n        end\n        if vars[\"冰龙吐息冷却\"] < 0.25 and vars[\"符文能量\"] < 60 then\n            return A[\"符文武器增效\"]:Cast()\n        end\n    end\n    v = A[\"冰霜之柱\"]:Cast() if v then vars[\"爆发技能\"] = true return run(\"一键爆发\") end\nend\n",
            ["输出"] = "--死亡骑士-冰霜-输出\nvars[\"白霜\"] = player.MyBuff:Has(\"白霜\") \nvars[\"杀戮机器\"] = player.MyBuff[\"杀戮机器\"].Count\nvars[\"冰霜之柱\"] = player.MyBuff:Has(\"冰霜之柱\")\nvars[\"锋锐之霜\"] = target.MyDebuff[\"锋锐之霜\"].Count\n\nif not vars[\"爆发技能\"] then\n    v = target.RangeToPlayer < 15 and A[\"亡者复生\"]:Cast() if v then return v end\n    v = not talent[\"冰霜统御\"] and A[\"冷酷严冬\"]:Cast() if v then return v end\nend\nv = target.RangeToPlayer < 5 and vars[\"符文能量差\"] > 40 and A[\"符文武器增效\"]:GetChargeInfo():IsReachedOrSoon() and A[\"符文武器增效\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\n\nif vars[\"敌方目标数量\"] > 1 then\n    v = vars[\"符文能量差\"] < 15 and A[\"冰川突进\"]:Cast() if v then return v end\n    v = vars[\"杀戮机器\"] > 1 and A[\"冰霜之镰\"]:Cast() if v then return v end\n    v = vars[\"杀戮机器\"] > 0 and runes[3] == 0 and not vars[\"冰霜之柱\"] and A[\"冰霜之镰\"]:Cast() if v then return v end\n    v = vars[\"白霜\"] and A[\"凛风冲击\"]:Cast() if v then return v end\n    v = A[\"冰霜打击\"]:IsActiveSpellName(\"冰霜灾祸\") and A[\"冰霜打击\"]:Cast() if v then return v end\n    v = A[\"冰川突进\"]:Cast() if v then return v end\n    v = (vars[\"杀戮机器\"] > 0 or not vars[\"冰霜之柱\"]) and A[\"冰霜之镰\"]:Cast() if v then return v end\n    v = vars[\"符文能量\"] < 20 and target.RangeToPlayer < 5 and A[\"符文武器增效\"]:Cast() if v then return v end\n    v = not vars[\"白霜\"] and vars[\"冰霜之柱\"] and A[\"凛风冲击\"]:Cast() if v then return v end\nelse\n    v = vars[\"符文能量差\"] < 15 and A[\"冰霜打击\"]:Cast() if v then return v end\n    v = vars[\"杀戮机器\"] > 1 and A[\"湮灭\"]:Cast() if v then return v end\n    v = vars[\"杀戮机器\"] > 0 and runes[3] == 0 and not vars[\"冰霜之柱\"] and A[\"湮灭\"]:Cast() if v then return v end\n    v = vars[\"白霜\"] and A[\"凛风冲击\"]:Cast() if v then return v end\n    v = (vars[\"锋锐之霜\"] > 4 or A[\"冰霜打击\"]:IsActiveSpellName(\"冰霜灾祸\")) and A[\"冰霜打击\"]:Cast() if v then return v end\n    v = (vars[\"杀戮机器\"] > 0 or not vars[\"冰霜之柱\"]) and A[\"湮灭\"]:Cast() if v then return v end\n    v = A[\"冰霜打击\"]:Cast() if v then return v end\n    v = vars[\"符文能量\"] < 20 and target.RangeToPlayer < 5 and A[\"符文武器增效\"]:Cast() if v then return v end\n    v = not vars[\"白霜\"] and vars[\"冰霜之柱\"] and A[\"凛风冲击\"]:Cast() if v then return v end\nend\n",
        },
