            ["_脚本初始化"] = "--死亡骑士-邪恶-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n--vars[\"溃烂之力\"] = azerite:IsEnabled(\"溃烂之力\") or false\n\n",
            ["保命"] = "--死亡骑士-邪恶-保命\nvars[\"符文能量\"] = player:GetPower(P[\"符文能量\"])\nvars[\"符文能量差\"] = player:GetPowerDeficit(P[\"符文能量\"])\nif not inCombat then\n    v = A[\"亡者复生\"]:Cast() if v then return v end\n    return\nend\nlocal v\nlocal tm = player.MyBuff[\"黑暗援助\"]:GetTimeLeft()\nv = A[\"灵界打击\"]:Cast(target.RangeToPlayer < 5 and tm > 0 and (tm < 3 or player.HealthPercent < 0.8)) if v then return v end\nif player.HealthPercent > 0.7 then\n    v = A[\"亡者复生\"]:Cast() if v then return v end\n    return\nend\nv = SwitchIsOn(\"反魔法护罩\") and A[\"反魔法护罩\"]:Cast() if v then return v end\nv = SwitchIsOn(\"冰封之韧\") and A[\"冰封之韧\"]:Cast() if v then return v end\nv = SwitchIsOn(\"天灾契约\") and A[\"天灾契约\"]:Cast(player.HealthPercent < 0.45) if v then return v end\nv = SwitchIsOn(\"巫妖之躯\") and A[\"巫妖之躯_减伤\"]:Cast() if v then return v end\n\nif player.HealthPercent < (boss.InCombat and 0.4 or (inPVE and 0.5 or 0.7)) then\n	v = A[\"灵界打击\"]:CastOnUnitByCondition(nil, 6, 160, vars[\"灵界打击条件\"]) if v then return v end\nend\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"亡者复生\"]:Cast() if v then return v end\n\n\n\n\n\n",
            ["打断"] = "--死亡骑士-邪恶-打断\nlocal v\nif SwitchIsOn(\"跳跃\") and pet.MyBuff:Has(\"黑暗突变\") and A[\"跳跃\"]:IsReady() then\n	v = pet:GetRangeToUnit(... or target)\n    v = v > 5 and v < 30 and A[\"跳跃\"]:Cast(nil, ...) if v then return v end\nend\nreturn run(\"全专精-打断\", ...)\n",
            ["爆发技能"] = "--死亡骑士-邪恶-爆发技能\nif vars[\"爆发强度\"] < 3 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nif target.RangeToPlayer > 8 then\n    return\nend\nlocal v\nv = A[\"亡者大军\"]:Cast() if v then return run(\"一键爆发\") end\n",
            ["输出"] = "--死亡骑士-邪恶-输出\nlocal v\n-- 优先施放天灾打击，如果吸血鬼打击激活\n--v = A[\"吸血鬼打击\"]:IsActiveSpell() and A[\"天灾打击\"]:Cast() if v then return v end\nv = A[\"我_枯萎凋零\"]:Cast(vars[\"敌方目标数量\"] >= 1 and not player:IsMoving() and target.RangeToPlayer < 3) if v then return v end \nif talent[\"疫疾\"] and A[\"疫疾\"]:IsActiveSpell() then\n    if enemies:GetMyDebuffCount(\"恶性病变\", 30) >= vars[\"敌方目标数量\"] and target.MyDebuff[\"恶性病变\"]:GetTimeLeft() > 1 then\n        v = A[\"疫疾\"]:Cast() if v then return v end\n    else\n        v = A[\"腐化\"]:Cast() if v then return v end\n    end\nelse\n    v = enemies:GetMyDebuffCount(\"恐惧瘟疫\", 30) == 0 and A[\"爆发\"]:Cast() if v then return v end\nend\nv = talent[\"脓疮毒镰\"] and (A[\"脓疮打击\"]:IsActiveSpellName(\"脓疮毒镰\") or target.MyDebuff[\"脓疮毒镰\"]:GetTimeLeft() < 1) and A[\"脓疮打击\"]:Cast() if v then return v end\n--v = A[\"爆发\"]:CastOnMinTime(nil, 20, 90) if v then return v end\nv = run(\"爆发技能\") if v then return v end\nv = A[\"灵魂收割\"]:Cast() if v then return v end\nv = SwitchIsOn(\"黑暗突变\") and vars[\"爆发强度\"] > 1 and A[\"黑暗突变\"]:Cast(UnitExists(\"pet\") and not UnitIsDead(\"pet\")) if v then return v end\nv = (not talent[\"灵魂收割\"] or player.MyBuff:Has(\"亡者指挥官\")) and A[\"腐化\"]:Cast() if v then return v end\nif player.MyBuff:Has(\"禁断知识\") then\n    if vars[\"敌方目标数量\"] > 4 and enemies:GetMyDebuffCount(\"恶性病变\", 30) > 0 then\n        v = A[\"扩散\"]:Cast() if v then return v end\n    else\n        v = A[\"凋零缠绕\"]:Cast() if v then return v end\n    end\nend\nif vars[\"符文能量\"] > 79 or player.MyBuff:Has(\"末日突降\") then\n    --print(vars[\"符文能量\"], vars[\"敌方目标数量\"], enemies:GetMyDebuffCount(\"恶性病变\", 30), A[\"扩散\"]:Cast() and \"扩散\" or false, A[\"凋零缠绕\"]:Cast() and \"凋零缠绕\" or false)\n    if vars[\"敌方目标数量\"] > 2 and enemies:GetMyDebuffCount(\"恶性病变\", 30) > 0 then\n        v = A[\"扩散\"]:Cast() if v then return v end\n    else\n        v = A[\"凋零缠绕\"]:Cast() if v then return v end\n    end\nend\nif player.MyBuff:Has(1254252) then\n    v = A[\"天灾打击\"]:Cast() if v then return v end\nelse\n    v = A[\"脓疮打击\"]:Cast() if v then return v end\nend\nif vars[\"敌方目标数量\"] > 2 and enemies:GetMyDebuffCount(\"恶性病变\", 30) > 0 then\n    v = A[\"扩散\"]:Cast() if v then return v end\nelse\n    v = A[\"凋零缠绕\"]:Cast() if v then return v end\nend\n\n\n",
        },
        ["鲜血"] = {
            ["_专精初始化"] = "--死亡骑士-鲜血-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["保命"] = "--死亡骑士-鲜血-保命\nvars[\"符文能量\"] = player:GetPower(P[\"符文能量\"])\nvars[\"符文能量差\"] = player:GetPowerDeficit(P[\"符文能量\"])\nif not inCombat then\n    return\nend\nlocal v\nif player.HealthPercent > 0.85 then\n    return\nend\nv = A[\"天灾契约\"]:Cast() if v then return v end\nv = A[\"符文刃舞\"]:Cast(not player.MyBuff:Has(\"符文刃舞\")) if v then return v end\nv = A[\"反魔法护罩\"]:Cast() if v then return v end\nv = A[\"吸血鬼之血\"]:Cast() if v then return v end\nv = A[\"冰封之韧\"]:Cast() if v then return v end\nv = A[\"巫妖之躯_减伤\"]:Cast() if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"亡者复生\"]:Cast() if v then return v end\n\n\n\n\n\n",
            ["灵界打击_"] = "--死亡骑士-鲜血-灵界打击_\n--将黑暗的力量灌注到武器中，造成1,753点物理伤害，并为你恢复之前5秒内所受伤害的25%，至少恢复7%的最大生命值。\nlocal v = ... or 1\n--if player.HealthPercent < ((talent[\"浮空城意志\"] and player.MyBuff:Has(\"符文刃舞\")) and 0.3 or 0.4) then\n--    return A[\"灵界打击\"]:Cast()\n--end\nif vars[\"符文能量差\"] <= 30 and player.HealthPercent <= v then --防止溢出\n    return A[\"灵界打击\"]:Cast()\nend\n--local injure = player.HealthWatcher:GetRecentDamagePercent(5) * 0.25 / player.HealthBaseline\n\n--if injure > 0.2 and player.HealthPercent < 0.75 then\n--	return A[\"灵界打击\"]:CastOnUnitByCondition(nil, 6, 160, vars[\"灵界打击条件\"])\n--end\n\nif player.HealthPercent < 0.75 then\n	return A[\"灵界打击\"]:CastOnUnitByCondition(nil, 6, 160, vars[\"灵界打击条件\"])\nend\n\n",
            ["爆发技能"] = "--死亡骑士-鲜血-爆发技能\nif vars[\"爆发强度\"] < 2 then\n    return\nend\n--v = SwitchIsOn(\"憎恶附肢\") and A[\"憎恶附肢\"]:Cast() if v then return v end\nif not SwitchIsOn(\"输出爆发\") or not player.BurstSpell then\n    return\nend\n--runes[5] > 0 and vars[\"符文能量差\"] > 5 and \nv = A[player.BurstSpell]:Cast() if v then return run(\"一键爆发\") end\n",
            ["输出"] = "--死亡骑士-鲜血-输出\nlocal v\nvars[\"符文刃舞时间\"] = player.MyBuff[\"符文刃舞\"]:GetTimeLeft()\nif player.HealthPercent < ((talent[\"浮空城意志\"] and vars[\"符文刃舞时间\"] > 0) and 0.3 or 0.4) then\n	v = A[\"灵界打击\"]:CastOnUnitByCondition(nil, 6, 160, vars[\"灵界打击条件\"]) if v then return v end\nend\nv = A[\"死神印记\"]:Cast() if v then return v end\n--if t28[2] and vars[\"符文刃舞时间\"] > 0 then\n--	v = A[\"骨髓分裂\"]:Cast(player.MyBuff[\"白骨之盾\"]:GetTimeLeft() < 5 and player.MyBuff[\"白骨之盾\"].Count < 8) if v then return v end\n--	v = A[\"心脏打击\"]:Cast() if v then return v end\n--end\nv = totems:GetTimeLeft(\"食尸鬼\", true)\n\nv = SwitchIsOn(\"灵界打击\") and run(\"灵界打击_\") if v then return v end\nv = run(\"爆发技能\") if v then return v end\nif target.RangeToPlayer < 8 and A[\"血液沸腾\"]:IsReady() then\n    v = A[\"血液沸腾\"]:GetChargeInfo():IsReachedOrSoon() and A[\"血液沸腾\"] if v then return v end\n    v = vars[\"敌方目标数量\"] - enemies:GetMyDebuffCount(\"血之疫病\", 10) > 1 and A[\"血液沸腾\"] if v then return v end\n    --v = A[\"血液沸腾\"]:Cast() if v then return v end\nend\nvars[\"赤色天灾时间\"] = 0\nif target.RangeToPlayer < 5 and SwitchIsOn(A[\"枯萎凋零\"].ActionName) and A[\"枯萎凋零\"]:IsReady() then\n    vars[\"赤色天灾时间\"] = player.MyBuff[\"赤色天灾\"]:GetTimeLeft()\n	if vars[\"赤色天灾时间\"] > 0 and vars[\"赤色天灾时间\"] < 4 then\n		v = A[\"我_枯萎凋零\"]:Cast() if v then return v end\n		--v = A[\"枯萎凋零\"]:Cast() or A[\"我_枯萎凋零\"]:Cast() if v then return v end\n	elseif vars[\"赤色天灾时间\"] > 0 or (vars[\"敌方目标数量\"] > 2 and runes[4] == 0 and enemies:GetMyDebuffCount(\"枯萎凋零\", 10) == 0) then\n		v = A[\"我_枯萎凋零\"]:Cast() if v then return v end\n		--v = A[\"枯萎凋零\"]:Cast() or A[\"我_枯萎凋零\"]:Cast() if v then return v end\n	end\nend\n--if t28[2] and vars[\"符文刃舞时间\"] > 0 then\n--	if player.MyBuff[\"白骨之盾\"]:GetTimeLeft() < 5 and player.MyBuff[\"白骨之盾\"].Count < 8 then\n--		v = A[\"骨髓分裂\"]:Cast() if v then return v end\n--		v = A[\"血液沸腾\"]:GetChargeInfo():IsReachedOrSoon() or vars[\"敌方目标数量\"] > 7 and A[\"血液沸腾\"] if v then return v end\n--        v = vars[\"符文能量差\"] <= 30 and A[\"灵界打击\"]:Cast() if v then return v end\n--	else\n--		v = A[\"心脏打击\"]:Cast() if v then return v end\n--	end\n--end\n\nv = A[\"精髓分裂\"]:Cast(vars[\"符文能量差\"] >= 20 and (player.MyBuff[\"白骨之盾\"]:GetTimeLeft() < 3 or player.MyBuff[\"白骨之盾\"].Count < 8)) if v then return v end\nv = A[\"吞噬\"]:Cast(player.HealthPercent < 0.95) if v then return v end\nv = A[\"吸血鬼打击\"]:IsActiveSpell() and A[\"心脏打击\"]:Cast() if v then return v end\n\nv = A[\"心脏打击\"]:Cast(vars[\"符文能量差\"] >= 15 and runes[3] == 0) if v then return v end\nif vars[\"赤色天灾时间\"] > 0 and vars[\"赤色天灾时间\"] < 10 then\n	v = A[\"我_枯萎凋零\"]:Cast() if v then return v end\n	--v = A[\"枯萎凋零\"]:Cast() or A[\"我_枯萎凋零\"]:Cast() if v then return v end\nend\n\nv = A[\"死神的抚摩\"]:Cast(target.RangeToPlayer > 10 and (not UnitAffectingCombat(\"target\") or (runes[4] == 0 and not target.MyDebuff:Has(\"血之疫病\")))) if v then return v end\n",
        },
