            ["保命"] = "--法师-全专精-保命\nlocal v\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nvars[\"爆发技能时间\"] = player.MyBuff[A[\"爆发技能\"].ActionName]:GetTimeLeft()\n--vars[\"能量符文时间\"] = player.MyBuff[\"能量符文\"]:GetTimeLeft()\nv = SwitchIsOn(A[\"护盾技能\"].ActionName) and not inTraining and A[\"护盾技能\"]:Cast(player.HealthPercent < 0.3 or (vars[\"爆发技能时间\"] == 0)) if v then return v end\nif not inCombat then\n    v = A[\"奥术智慧\"]:Cast() if v then return v end\n    v = SwitchIsOn(A[\"召宠\"].ActionName) and A[\"召宠\"]:Cast() if v then return v end\n    return \nend\nv = SwitchIsOn(\"寒冰屏障\") and A[\"寒冰屏障\"]:Cast() if v then return v end\nv = A[\"奥术智慧\"]:Cast() if v then return v end\nv = SwitchIsOn(A[\"召宠\"].ActionName) and A[\"召宠\"]:Cast() if v then return v end\n\n",
            ["冰霜新星"] = "--法师-全专精-冰霜新星\nv = A[\"冰霜新星\"]:Cast(not A[\"冰霜新星\"]:SucceededIn(3) and (enemies:GetNearbyCount(player, 12) > 0)) if v then return v end\n",
        },
        ["冰霜"] = {
            ["_专精初始化"] = "--法师-冰霜-_专精初始化\nrun(\"全专精-_专精初始化\")\n\nvars[\"冰川尖刺伤害\"] = 0\nvars[\"冰川尖刺施法时间\"] = 9999\nvars[\"冰刺数量\"] = 0\nvars[\"寒冰指最大层数\"] = 2\n\n",
            ["打爆炸物"] = "--法师-冰霜-打爆炸物\nlocal v\nv = A[\"冰枪术\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--法师-冰霜-爆发技能\nif vars[\"爆发强度\"] < 2 or not SwitchIsOn(\"输出爆发\") then\n	return\nend\nlocal v = A[\"冰霜射线\"]:IsActiveSpell() and A[\"冰霜射线\"]:Cast() if v then return A[\"镜像\"]:Cast() or run(\"一键爆发\") end\n",
            ["输出"] = "--法师-冰霜-输出\nlocal v\nv = not inCombat and A[\"暴风雪\"]:Cast() if v then return v end\n\nv = A[\"冰风暴\"]:GetChargeInfo():IsReachedOrSoon() and A[\"冰风暴\"]:Cast() if v then return v end\nvars[\"冰冷智慧\"] = player.MyBuff:Has(\"冰冷智慧\")\nv = not vars[\"冰冷智慧\"] and vars[\"爆发强度\"] > 1 and not player:IsMoving() and A[\"寒冰宝珠\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\nv = talent[\"彗星风暴\"] and A[\"彗星风暴\"]:IsActiveSpell() and not player:IsMoving() and not target:IsMoving() and A[\"彗星风暴\"]:Cast() if v then return v end\n\nvars[\"冰冻之雨\"] = player.MyBuff:Has(\"冰冻之雨\")\nv = vars[\"冰冻之雨\"] and vars[\"敌方目标数量\"] > 2 and A[\"暴风雪\"]:Cast() if v then return v end\nv = player.MyBuff:Has(\"霜火增效\") and A[\"寒冰箭\"]:Cast() if v then return v end\n\nvars[\"冻结\"] = target.MyDebuff[\"冻结\"].Count\nvars[\"寒冰指\"] = player.MyBuff:Has(\"寒冰指\")\nv = vars[\"冻结\"] > (vars[\"寒冰指\"] and 5 or 9) and player.MyBuff:Has(\"热能真空\") and A[\"冰枪术\"]:Cast() if v then return v end\nv = A[\"冰川尖刺\"]:IsActiveSpell() and A[\"冰川尖刺\"]:Cast() if v then return v end\nv = vars[\"冰冻之雨\"] and vars[\"敌方目标数量\"] > 1 and A[\"暴风雪\"]:Cast() if v then return v end\nv = vars[\"冰冷智慧\"] and A[\"冰风暴\"]:Cast() if v then return v end\nv = vars[\"敌方目标数量\"] > 2 and A[\"暴风雪\"]:Cast() if v then return v end\nv = vars[\"冻结\"] > 5 and A[\"冰枪术\"]:Cast() if v then return v end\nv = A[\"冰风暴\"]:Cast() if v then return v end\n--if talent[\"霜火之箭\"] then\n--    v = A[\"霜火之箭\"]:Cast() if v then return v end\n--else\n    v = A[\"寒冰箭\"]:Cast() if v then return v end\n--end\nv = player:IsMoving() and A[\"冰枪术\"]:Cast() if v then return v end\n",
        },
        ["奥术"] = {
            ["_专精初始化"] = "--法师-奥术-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"奥术齐射最大层数\"] = talent[\"咒焰齐射\"] and 25 or 20",
            ["唤醒"] = "--法师-奥术-唤醒\nlocal castTo, params = ...\nreturn run(\"安全引导\", \"唤醒\", player, params)\n",
            ["打爆炸物"] = "--法师-奥术-打爆炸物\nlocal v\nv = A[\"奥术弹幕\"]:Cast() if v then return v end\nv = A[\"奥术冲击\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--法师-奥术-爆发技能\nif vars[\"爆发强度\"] < 2.5 or not SwitchIsOn(\"输出爆发\") then\n	return\nend\nlocal v\nif (vars[\"奥术齐射\"] < vars[\"奥术齐射最大层数\"] or vars[\"奥术充能\"] < 4) and vars[\"法力百分比\"] > 0.3 then\n    return\nend\nvars[\"大法师之触CD\"] = A[\"大法师之触\"]:GetCooldown()\nif vars[\"大法师之触CD\"] < 0.5 or vars[\"大法师之触CD\"] > 15 then\n    v = A[\"奥术涌动\"]:Cast() if v then return A[\"镜像\"]:Cast() or run(\"一键爆发\") end\nend\n",
            ["输出"] = "--法师-奥术-输出\nlocal v\nvars[\"法力不足\"] = select(2, IsUsableSpell(talent[\"奥术脉冲\"] and \"奥术脉冲\" or \"奥术冲击\"))\nv = vars[\"法力不足\"] and talent[\"唤醒\"] and run(\"唤醒\") if v then return v end\n\nvars[\"法力百分比\"] = player:GetPowerPercent(P[\"法力\"])\nvars[\"奥术充能\"] = player:GetPower(P[\"奥术充能\"])\nvars[\"奥术齐射\"] = A[\"奥术弹幕\"]:GetCount()\nvars[\"大法师之触时间\"] = target.MyDebuff[\"大法师之触\"]:GetTimeLeft()\nvars[\"奥术涌动时间\"] = player.MyBuff[\"奥术涌动\"]:GetTimeLeft()\nvars[\"奥术涌动CD\"] = A[\"奥术涌动\"]:GetCooldown()\nlocal spell, tm = player:GetCastingSpell()\nif spell == \"奥术冲击\" or spell == \"奥术脉冲\" then\n    v = SwitchIsOn(\"取消奥冲\") and tm > (spell == \"奥术脉冲\" and 0.8 or 1) and vars[\"大法师之触时间\"] == 0 and vars[\"奥术涌动时间\"] == 0 and vars[\"法力百分比\"] < 0.7 and vars[\"奥术充能\"] >= 4 and vars[\"奥术齐射\"] >= vars[\"奥术齐射最大层数\"] and A[\"取消施法\"]:Cast() if v then return v end \n    if vars[\"奥术充能\"] < 4 and vars[\"正在奥冲\"] then\n        vars[\"奥术充能\"] = vars[\"奥术充能\"] + (talent[\"奥能动力\"] and 2 or 1)\n    end\n    if vars[\"奥术齐射\"] < vars[\"奥术齐射最大层数\"] and talent[\"心智洞开\"] then\n        vars[\"奥术齐射\"] = vars[\"奥术齐射\"] + 2\n    end\nend\n\nv = run(\"爆发技能\") if v then return v end\n\nv = (vars[\"奥术涌动时间\"] > 10 or vars[\"奥术涌动CD\"] > 35) and A[\"大法师之触\"]:Cast() if v then return v end\nvars[\"奥术弹幕\"] = A[\"奥术弹幕\"]:CastedIn(1)\nv = not vars[\"奥术弹幕\"] and vars[\"奥术齐射\"] >= vars[\"奥术齐射最大层数\"] and vars[\"奥术充能\"] >= 4 and A[\"奥术弹幕\"]:Cast() if v then return v end\nif not vars[\"奥术弹幕\"] and vars[\"奥术齐射\"] > 14 and ((vars[\"奥术涌动时间\"] > 0.2 and vars[\"奥术涌动时间\"] < gcdmax + 0.2) or (vars[\"大法师之触时间\"] > 0.2 and vars[\"大法师之触时间\"] < gcdmax + 0.2)) then\n    v = A[\"奥术弹幕\"]:Cast() if v then return v end\nend\nv = A[\"奥术宝珠\"]:GetChargeInfo():IsReachedOrSoon() and A[\"奥术宝珠\"]:Cast() if v then return v end\nvars[\"节能施法时间\"] = player.MyBuff[\"节能施法\"]:GetTimeLeft()\nv = (not talent[\"法球精通\"] or (talent[\"法球精通\"] and vars[\"节能施法时间\"] > 0)) and vars[\"奥术齐射\"] < 15 and A[\"奥术宝珠\"]:Cast() if v then return v end\nv = not talent[\"法球精通\"] and vars[\"奥术齐射\"] < 13 and A[\"奥术飞弹\"]:Cast() if v then return v end\n\nv = not vars[\"奥术弹幕\"] and talent[\"法力专家\"] and vars[\"法力百分比\"] < 0.3 and vars[\"奥术充能\"] > 0 and A[\"奥术弹幕\"]:Cast() if v then return v end\n\nv = vars[\"大法师之触时间\"] > 8 and A[\"气定神闲\"]:Cast() if v then return v end\nv = player.MyBuff:Has(\"气定神闲\") and A[\"奥术冲击\"]:Cast() if v then return v end\n\nv = vars[\"敌方目标数量\"] > 1 and A[\"奥术脉冲\"]:Cast() if v then return v end\nv = A[\"奥术冲击\"]:Cast() if v then return v end\n\nv = A[\"寒冰新星\"]:Cast() if v then return v end\nv = A[\"冰锥术\"]:Cast() if v then return v end\nv = (SwitchIsOn(\"行走弹幕\") or vars[\"法力不足\"]) and A[\"奥术弹幕\"]:Cast() if v then return v end\n\n\n\n",
        },
        ["火焰"] = {
            ["_专精初始化"] = "--法师-火焰-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["打爆炸物"] = "--法师-火焰-打爆炸物\nlocal v\nv = run(\"补炽热连击\") if v and v ~= 0 then return v end\nv = A[\"灼烧\"]:Cast() if v then return v end\n",
            ["显示燃烧期间技能"] = "--法师-火焰-显示燃烧期间技能\nif vars[\"燃烧时间\"] > 0 then\n    if not vars[\"燃烧开始时间\"] or vars[\"燃烧开始时间\"] < GetTime() - 20 then\n        vars[\"燃烧开始时间\"] = GetTime()\n    end\nelse\n    if vars[\"燃烧开始时间\"] then\n        vars[\"燃烧期间技能\"] = {}\n        for i = 1, 30 do\n            v = GetLastSpell(i)\n            if v.Time < vars[\"燃烧开始时间\"] then\n                break\n            end\n            --if v.Name ~= \"能量符文\" then\n                vars[\"燃烧期间技能\"][v.Name] = (vars[\"燃烧期间技能\"][v.Name] or 0) + 1\n            --end\n        end\n        local s = \"燃烧期间共施放\"\n        for k, v in pairs(vars[\"燃烧期间技能\"]) do\n            s = s .. v .. \"个\" .. k .. \" \"\n        end\n        Print(s)\n        vars[\"燃烧开始时间\"] = false\n    end\nend\n",
            ["火焰冲击_"] = "--法师-火焰-火焰冲击_\nif vars[\"炽热连击\"] then\n    return 0\nend\nvars[\"火焰冲击充能\"] = A[\"火焰冲击\"]:GetChargeInfo()\nvars[\"火焰冲击数量\"] = vars[\"火焰冲击充能\"].Charges\nvars[\"火焰冲击总数\"] = vars[\"火焰冲击充能\"].MaxCharges\n\nif not A[\"火焰冲击\"]:IsReady(0.6) then\n    return\nend\nif A[\"火焰冲击\"]:SucceededIn(0.8) then\n    return\nend\nif vars[\"燃烧时间\"] > 0 then --燃烧中直接补\n    return A[\"火焰冲击\"]:Cast()\nend\n\n--燃烧外\nlocal tm = vars[\"火焰冲击充能\"]:TimeToCharges()\nif vars[\"燃烧CD\"] + (talent[\"自燃\"] and 0 or vars[\"火焰冲击充能\"].Duration) + 2 > tm then\n    return A[\"火焰冲击\"]:Cast()\nend\nif vars[\"爆发强度\"] < 2 and vars[\"爆发强度\"] > 0.8 and vars[\"火焰冲击数量\"] > 1 then\n    return A[\"火焰冲击\"]:Cast()\nend\nif not inInstance and not inTraining and vars[\"火焰冲击数量\"] > 1 and (not (SwitchIsOn(\"输出爆发\") and vars[\"爆发强度\"] > 1)) then\n    return A[\"火焰冲击\"]:Cast()\nend\n",
            ["爆发技能"] = "--法师-火焰-爆发技能\nif vars[\"爆发强度\"] < 2 or not SwitchIsOn(\"输出爆发\") then\n	return\nend\nlocal v = A[\"燃烧\"]:Cast() if v then return A[\"镜像\"]:Cast() or run(\"一键爆发\") end\n",
            ["补炽热连击"] = "--法师-火焰-补炽热连击\nif vars[\"炽热连击\"] then\n    return 0\nend\nif not vars[\"热力迸发\"] then\n    return\nend\nlocal v\nv = run(\"火焰冲击_\") if v then return v end\nif vars[\"燃烧时间\"] > 0 then\n    return A[\"灼烧\"]:CastSafely()\nend\nv = A[\"灼烧\"]:Cast(talent[\"灼烧之触\"] and target.HealthPercent < 0.3) if v then return v end \n\n\n\n",
            ["输出"] = "--法师-火焰-输出\nlocal v\nvars[\"正在施放的法术\"], vars[\"剩余施法时间\"] = player:GetCastingSpell()\nvars[\"烈焰风暴施法时间\"] = A[\"烈焰风暴\"]:GetCurrentCastingTime()\nvars[\"炽热连击\"] = player.MyBuff:Has(\"炽热连击！\") or (vars[\"烈焰风暴施法时间\"] == 0)\nvars[\"热力迸发\"] = player.MyBuff:Has(\"热力迸发\")\nvars[\"燃烧CD\"] = A[\"燃烧\"]:GetCooldown()\nvars[\"燃烧时间\"] = player.MyBuff[\"燃烧\"]:GetTimeLeft()\nif A[\"燃烧\"]:CastedIn(0.8) and not vars[\"炽热连击\"] then\n    if vars[\"正在施放的法术\"] == \"灼烧\" then\n        if vars[\"热力迸发\"] then\n            vars[\"炽热连击\"] = true\n            vars[\"热力迸发\"] = false\n        else\n            vars[\"热力迸发\"] = true\n        end\n    end\nend\nvars[\"火焰冲撞\"] = player.MyBuff:Has(\"火焰冲撞\")\n\nrun(\"显示燃烧期间技能\")\n--取消意外的读条\nif inCombat and vars[\"剩余施法时间\"] > 1 then\n    if vars[\"正在施放的法术\"] == \"烈焰风暴\" or vars[\"正在施放的法术\"] == \"炎爆术\" then\n        if not vars[\"火焰冲撞\"] then --非瞬发的炎爆术或烈焰风暴造成的伤害提高225%\n            return A[\"取消施法\"]\n        end\n    elseif vars[\"正在施放的法术\"] == \"火球术\" or vars[\"正在施放的法术\"] == \"灼烧\" or vars[\"正在施放的法术\"] == \"霜火之箭\" then\n        if vars[\"炽热连击\"] then\n            return A[\"取消施法\"]\n        end\n    end\nend\nv = (vars[\"燃烧CD\"] > 28 or vars[\"燃烧CD\"] < gcdmax or vars[\"燃烧时间\"] > 1) and A[\"流星\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\nif vars[\"燃烧时间\"] > 0 then--燃烧中\n    v = vars[\"炽热连击\"] and (A[\"烈焰风暴\"]:Cast() or A[\"炎爆术\"]:Cast()) if v then return v end \n    v = run(\"补炽热连击\") if v then return v end\n    if talent[\"灼烧\"] then\n        v = A[\"灼烧\"]:CastSafely() if v then return v end\n    elseif talent[\"霜火之箭\"] then\n        v = A[\"霜火之箭\"]:CastSafely() if v then return v end\n    else\n        v = A[\"火球术\"]:CastSafely() if v then return v end\n    end\nelse--燃烧以外\n    v = (vars[\"炽热连击\"] or vars[\"火焰冲撞\"]) and (A[\"烈焰风暴\"]:Cast() or A[\"炎爆术\"]:Cast()) if v then return v end \n    v = run(\"补炽热连击\") if v then return v end\n    if talent[\"灼烧\"] then\n        v = (target.HealthPercent < 0.3 or vars[\"燃烧时间\"] > gcdmax or A[\"灼烧\"]:GetCurrentCastingTime() == 0) and A[\"灼烧\"]:Cast() if v then return v end \n    elseif talent[\"霜火之箭\"] then\n        v = A[\"霜火之箭\"]:Cast() if v then return v end\n    else\n        v = A[\"火球术\"]:Cast() if v then return v end\n    end\n    v = A[\"灼烧\"]:Cast() if v then return v end\nend\n\n\n",
        },
    },
    ["潜行者"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--潜行者-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["保命"] = "--潜行者-全专精-保命\nvars[\"潜行中\"] = player.MyBuff:Has(\"潜行\") or player.MyBuff:Has(\"消失\")\n\nlocal v\nif not inCombat then\n    v = run(\"自动涂药膏\") if v then return v end\n    v = player.HealthPercent < 0.8 and A[\"猩红之瓶\"]:Cast() if v then return v end\n	v = A[\"潜行\"]:Cast(not player.MyBuff:Has(\"潜行\") and IsForceStart() and not A[\"潜行\"]:SucceededIn(2)) if v then return v end\n	return \nend\n\nvars[\"非装死中\"] = not talent[\"装死\"] or (not player.MyBuff:Has(\"装死\") and player.MyDebuff:Has(\"装死\"))\nv = SwitchIsOn(\"保命消失\") and player.HealthPercent < 0.05 and vars[\"非装死中\"] and A[\"消失\"]:IsReady() and A[\"消失\"]:ForceCast() if v then return v end\n--if player.HealthPercent < 0.4 or not talent[\"飘忽不定\"] or not player.MyBuff:Has(\"佯攻\") then\nv = player.HealthPercent < 0.4 and A[\"闪避\"]:Cast() if v then return v end\nv = player.HealthPercent < 0.4 and A[\"暗影斗篷\"]:Cast() if v then return v end\n--end\n\n--v = SwitchIsOn(\"佯攻\") and A[\"佯攻\"]:Cast(not player.MyBuff:Has(\"佯攻\") and player.AllInjure > (talent[\"飘忽不定\"] and 0.15 or 0.1)) if v then return v end\nv = not player.MyBuff:Has(\"佯攻\") and player.HealthPercent < 0.5 and A[\"佯攻\"]:Cast() if v then return v end\nv = A[\"猩红之瓶\"]:Cast((((boss.TargetingYouCount > 0 or not inPVE or not UnitExists(\"party1\")) and player.HealthPercent < 0.75) or player.HealthPercent < 0.5 or player.HealthPercent < 0.3)) if v then return v end\nv = player.HealthPercent < 0.4 and A[\"纳鲁的赐福\"]:Cast() if v then return v end\nv = SwitchIsOn(\"保命消失\") and player.HealthPercent < 0.1 and vars[\"非装死中\"] and A[\"消失\"]:IsReady() and A[\"消失\"]:ForceCast()  if v then return v end\nv = vars[\"爆发强度\"] > 0.4 and player:GetPower(P[\"能量\"]) < 30 and A[\"菊花茶\"]:Cast() if v then return v end\n\n",
            ["嫁祸诀窍"] = "--潜行者-全专精-嫁祸诀窍\nif inTraining then\n    return\nend\nif not A[\"嫁祸诀窍\"]:IsReady() then\n    return\nend\nlocal v, u\nif inParty or inRaid then\n	if focus.IsFriend and focus:IsAlive() and focus:GetDuty() == \"TANK\" then\n		u = focus\n	else\n		u = friends:GetTank()\n    end\n	if u and (combatTime > 5 or not inCombat) then --仅战斗开始5秒内误导T\n		return\n	end\nend\nif u and u.RangeToPlayer < 60 then\n	v = A[\"嫁祸诀窍\"]:Cast(nil, u) if v then return v end\nend\n",
            ["搜索"] = "--潜行者-全专精-搜索\nif not SwitchIsOn(\"搜索\") then\n    return\nend\nif inPvpCombat then\n    return\nend\nif boss.IsTarget then\n    return\nend\nif A[\"搜索\"]:SucceededOnUnit(target, 10) then\n    return\nend\nif A[\"搜索\"]:FailedOnUnit(target, 10) then\n    local s = A[\"搜索\"].FailReason\n    if s == \"没有物品可以拿取\" or s == \"无效的目标\" then\n        --print(\"**********没有物品可以拿取\")\n        return\n    end\nend\n\nreturn A[\"搜索\"]:Cast()\n",
            ["暗影步"] = "--潜行者-全专精-暗影步\nreturn A[\"暗影步\"]:Cast(target.RangeToPlayer > 8)\n",
            ["消失"] = "--潜行者-全专精-消失\nlocal v = A[\"消失\"]:Cast() \nif v then SetForceStart() return v end\n",
            ["潜行起手"] = "--潜行者-全专精-潜行起手\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nvars[\"连击点差\"] = player:GetPowerDeficit(P[\"连击点\"])\n\nif player.MyBuff:Has(\"潜行\") or player.MyBuff:Has(\"消失\") then\n    v = not inCombat and run(\"搜索\") if v then return v end\n	if vars[\"爆发强度\"] > 2 and target.RangeToPlayer < vars[\"潜行起手距离\"] then\n		--v = A[\"切割\"]:Cast() if v then return v end\n		--v = SwitchIsOn(\"死亡标记\") and A[\"死亡标记\"]:Cast(vars[\"连击点\"] < 2) if v then return v end\n		--v = legendary[\"刺客大师印记\"] and run(\"爆发技能\") if v then return v end\n	end\n    v = A[\"偷袭\"]:Cast(target.IsPlayer or not vars[\"潜行起手技能\"].IsValid) if v then return v end\n    v = vars[\"潜行起手技能\"]:ForceCast() if v then return v end\nelseif not inCombat and not player.MyBuff:Has(\"消失\") then\n    v = A[\"潜行\"]:Cast(not A[\"潜行\"]:SucceededIn(2)) if v then return v end\nend\n",
            ["猩红之瓶"] = "--潜行者-全专精-猩红之瓶\nreturn A[\"猩红之瓶\"]:Cast(player.HealthPercent < 0.85)\n",
            ["肾击_"] = "--潜行者-全专精-肾击_\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nreturn A[\"肾击\"]:Cast(vars[\"连击点\"] > 2)",
            ["自动涂药膏"] = "--潜行者-全专精-自动涂药膏\nlocal v\nlocal count = 0\n--v = not player.MyBuff:HasAny(\"速效药膏\", \"致伤药膏\") and A[\"致命药膏\"]:Cast() if v then return v end\n--v = not player.MyBuff:HasAny(\"减速药膏\", \"迟钝药膏\", \"萎缩药膏\") and A[\"非致命药膏\"]:Cast() if v then return v end\nif talent[\"强化致伤药膏\"] then\n    vars[\"致伤药膏\"] = player.MyBuff[\"致伤药膏\"]:GetTimeLeft()\n    if vars[\"致伤药膏\"] > 0 then count = count + 1 end\n    v = vars[\"致伤药膏\"] > 0 and vars[\"致伤药膏\"] < 300 and A[\"致伤药膏\"]:Cast() if v then return v end\nelse\n    vars[\"速效药膏\"] = player.MyBuff[\"速效药膏\"]:GetTimeLeft()\n    if vars[\"速效药膏\"] > 0 then count = count + 1 end\n    v = vars[\"速效药膏\"] > 0 and vars[\"速效药膏\"] < 300 and A[\"速效药膏\"]:Cast() if v then return v end\nend\nif count < 1 then\n    if talent[\"强化致伤药膏\"] then\n        v = vars[\"致伤药膏\"] < 300 and A[\"致伤药膏\"]:Cast() if v then return v end\n    else\n        v = vars[\"速效药膏\"] < 300 and A[\"速效药膏\"]:Cast() if v then return v end\n    end\nend\n\ncount = 0\nvars[\"萎缩药膏\"] = player.MyBuff[\"萎缩药膏\"]:GetTimeLeft() \nif vars[\"萎缩药膏\"] > 0 then count = count + 1 end\nv = vars[\"萎缩药膏\"] > 0 and vars[\"萎缩药膏\"] < 300 and A[\"萎缩药膏\"]:Cast() if v then return v end\nvars[\"迟钝药膏\"] = player.MyBuff[\"迟钝药膏\"]:GetTimeLeft()\nif vars[\"迟钝药膏\"] > 0 then count = count + 1 end\nv = vars[\"迟钝药膏\"] > 0 and vars[\"迟钝药膏\"] < 300 and A[\"迟钝药膏\"]:Cast() if v then return v end\nvars[\"减速药膏\"] = player.MyBuff[\"减速药膏\"]:GetTimeLeft()\nif vars[\"减速药膏\"] > 0 then count = count + 1 end\nv = vars[\"减速药膏\"] > 0 and vars[\"减速药膏\"] < 300 and A[\"减速药膏\"]:Cast() if v then return v end\nif count < 1 then\n    v = vars[\"萎缩药膏\"] < 300 and A[\"萎缩药膏\"]:Cast() if v then return v end\n    v = vars[\"迟钝药膏\"] < 300 and A[\"迟钝药膏\"]:Cast() if v then return v end\n    v = vars[\"减速药膏\"] < 300 and A[\"减速药膏\"]:Cast() if v then return v end\nend\n",
            ["输出初始化"] = "--潜行者-全专精-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", player, 8)\n\n",
            ["输出前"] = "--潜行者-全专精-输出前\nlocal v = SwitchIsOn(\"嫁祸诀窍\") and run(\"嫁祸诀窍\") if v then return v end\nv = A[\"毒刃\"]:Cast(target:HasEnrageBuff()) if v then return v end\n",
        },
        ["奇袭"] = {
            ["_专精初始化"] = "--潜行者-奇袭-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"潜行起手技能\"] = A[\"锁喉\"]\nvars[\"潜行起手距离\"] = 15\nif not vars[\"诡诈锁喉结束时间\"] then vars[\"诡诈锁喉结束时间\"] = 0 end\n",
            ["打爆炸物"] = "--潜行者-奇袭-打爆炸物\nlocal v\nv = A[\"侧袭\"]:Cast() if v then return v end\nv = A[\"毁伤\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--潜行者-奇袭-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nv = A[\"死亡印记\"]:Cast(target.RangeToPlayer < 5 and vars[\"连击点差\"] < 4 and (not SwitchIsOn(\"诡诈消失\") or A[\"消失\"]:IsReady(3) or A[\"消失\"]:GetCooldown() > 20)) if v then return run(\"一键爆发\") end\nif player.MyBuff[\"死亡印记\"]:GetTimeLeft() < 10 then\n    return\nend\nv = A[\"君王之灾\"]:Cast() if v then return run(\"一键爆发\") or v end\n",
            ["自动涂药膏"] = "--潜行者-奇袭-自动涂药膏\nlocal v\nlocal count = 0\nvars[\"夺命药膏\"] = player.MyBuff[\"夺命药膏\"]:GetTimeLeft() \nif vars[\"夺命药膏\"] > 0 then count = count + 1 end\nv = vars[\"夺命药膏\"] > 0 and vars[\"夺命药膏\"] < 300 and A[\"夺命药膏\"]:Cast() if v then return v end\nvars[\"增效药膏\"] = player.MyBuff[\"增效药膏\"]:GetTimeLeft()\nif vars[\"增效药膏\"] > 0 then count = count + 1 end\nv = vars[\"增效药膏\"] > 0 and vars[\"增效药膏\"] < 300 and A[\"增效药膏\"]:Cast() if v then return v end\nvars[\"致伤药膏\"] = player.MyBuff[\"致伤药膏\"]:GetTimeLeft()\nif vars[\"致伤药膏\"] > 0 then count = count + 1 end\nv = vars[\"致伤药膏\"] > 0 and vars[\"致伤药膏\"] < 300 and A[\"致伤药膏\"]:Cast() if v then return v end\nvars[\"速效药膏\"] = player.MyBuff[\"速效药膏\"]:GetTimeLeft()\nif vars[\"速效药膏\"] > 0 then count = count + 1 end\nv = vars[\"速效药膏\"] > 0 and vars[\"速效药膏\"] < 300 and A[\"速效药膏\"]:Cast() if v then return v end\nif count < (talent[\"龙淬之锋\"] and 2 or 1) then\n    v = vars[\"夺命药膏\"] < 300 and A[\"夺命药膏\"]:Cast() if v then return v end\n    v = vars[\"增效药膏\"] < 300 and A[\"增效药膏\"]:Cast() if v then return v end\n    if talent[\"强化致伤药膏\"] then\n        v = vars[\"致伤药膏\"] < 300 and A[\"致伤药膏\"]:Cast() if v then return v end\n    end\n    v = vars[\"速效药膏\"] < 300 and A[\"速效药膏\"]:Cast() if v then return v end\nend\n\ncount = 0\nvars[\"萎缩药膏\"] = player.MyBuff[\"萎缩药膏\"]:GetTimeLeft() \nif vars[\"萎缩药膏\"] > 0 then count = count + 1 end\nv = vars[\"萎缩药膏\"] > 0 and vars[\"萎缩药膏\"] < 300 and A[\"萎缩药膏\"]:Cast() if v then return v end\nvars[\"迟钝药膏\"] = player.MyBuff[\"迟钝药膏\"]:GetTimeLeft()\nif vars[\"迟钝药膏\"] > 0 then count = count + 1 end\nv = vars[\"迟钝药膏\"] > 0 and vars[\"迟钝药膏\"] < 300 and A[\"迟钝药膏\"]:Cast() if v then return v end\nvars[\"减速药膏\"] = player.MyBuff[\"减速药膏\"]:GetTimeLeft()\nif vars[\"减速药膏\"] > 0 then count = count + 1 end\nv = vars[\"减速药膏\"] > 0 and vars[\"减速药膏\"] < 300 and A[\"减速药膏\"]:Cast() if v then return v end\nif count < (talent[\"龙淬之锋\"] and 2 or 1) then\n    v = vars[\"萎缩药膏\"] < 300 and A[\"萎缩药膏\"]:Cast() if v then return v end\n    v = vars[\"迟钝药膏\"] < 300 and A[\"迟钝药膏\"]:Cast() if v then return v end\n    v = vars[\"减速药膏\"] < 300 and A[\"减速药膏\"]:Cast() if v then return v end\nend\n",
            ["诡诈"] = "--潜行者-奇袭-诡诈\n--脱离潜行状态后的3秒内，原本需要潜行的技能仍可继续使用。同时使锁喉造成的伤害提高80%，且在潜行状态下和脱离潜行之后的3秒内使用时不会产生冷却时间。\nlocal v\n--vars[\"诡诈锁喉中\"] = false\nif not talent[\"诡诈\"] then\n    return\nend\n--诡诈锁喉\nlocal gztm = player.MyBuff[\"诡诈\"]:GetTimeLeft()\n--print(\"诡诈时间\", gztm, vars[\"锁喉时间\"])\nif gztm > 0.5 then\n    if vars[\"锁喉时间\"] == 0 then\n        return A[\"锁喉\"]:ForceCast()\n    end\n    if gztm < 1.6 then\n        return A[\"锁喉\"]:ForceCast()\n    end\nend\nif gztm > 0 and vars[\"锁喉时间\"] > 0 then --在诡诈期间的锁喉，都认为是大锁喉，切换目标可能会导致时间不准确（保存最大的时间）\n    local tm = GetTime() + vars[\"锁喉时间\"]\n    if tm > vars[\"诡诈锁喉结束时间\"] then\n        vars[\"诡诈锁喉结束时间\"] = tm\n    end\nend\nif not SwitchIsOn(\"诡诈消失\") or not A[\"消失\"]:IsReady() then\n    return\nend\n--诡诈消失\nif vars[\"目标强度\"] > 0.5 and A[\"宿敌\"]:GetCooldown() > 70 or player.MyBuff[\"宿敌\"]:GetTimeLeft() > 4 then\n    v = A[\"消失\"]:Cast() if v then SetForceStart() return v end\nend\n",
            ["输出"] = "--潜行者-奇袭-输出\nlocal v\nvars[\"能量\"] = player:GetPower(P[\"能量\"])\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nv = run(\"潜行起手\") if v then return v end\nif not inCombat then\n    return\nend\n\n\nvars[\"锁喉时间\"] = target.MyDebuff[\"锁喉\"]:GetTimeLeft()\n\nv = run(\"诡诈\") if v then return v end\n--v = A[\"死亡标记\"]:Cast(vars[\"连击点差\"] > 3) if v then return v end\nv = run(\"锯齿骨刺_\") if v then return v end\n\nv = run(\"爆发技能\") if v then return v end\nv = A[\"锁喉\"]:Cast(vars[\"连击点差\"] > 0 and vars[\"诡诈锁喉结束时间\"] < GetTime()) if v then return v end\nif vars[\"敌方目标数量\"] > 2 then\n    --AOE\n    v = A[\"猩红风暴\"]:Cast(vars[\"连击点差\"] == 0) if v then return v end\n    v = A[\"刀扇\"]:Cast(vars[\"连击点差\"] > 0) if v then return v end\n    if A[\"猩红风暴\"].IsValid then return end\nend\n--单体\n--终结技\nvars[\"割裂时间\"] = UnitIsPlayer(\"target\") and 30 or target.MyDebuff[\"割裂\"]:GetTimeLeft()\nvars[\"深谋远虑时间\"] = player.MyBuff[\"深谋远虑\"]:GetTimeLeft()\nvars[\"补深谋远虑\"] = talent[\"深谋远虑\"] and vars[\"深谋远虑时间\"] < 0.2\nv = not UnitIsPlayer(\"target\") and A[\"割裂\"]:Cast(vars[\"补深谋远虑\"] or vars[\"割裂时间\"] < gcdmax * 2, nil, {RefillTime=((vars[\"连击点\"]) + 1) * 4 * 0.3}) if v then return v end\nv = A[\"毒伤\"]:Cast((vars[\"连击点差\"] < 2) and (vars[\"补深谋远虑\"] or (vars[\"深谋远虑时间\"] > 0.2 and vars[\"深谋远虑时间\"] < gcdmax) or target.MyDebuff[\"毒伤\"]:GetTimeLeft() < gcdmax)) if v then return v end\nv = A[\"刺骨\"].IsValid and A[\"刺骨\"]:Cast(vars[\"连击点\"] == 5 or (A[\"刺骨\"]:GetDamage() * vars[\"连击点\"]) >= target.Health) if v then return v end --被毒伤代替\n--连击点\nif vars[\"连击点差\"] > 1 and player.MyBuff:Has(\"侧袭\") then\n    v = A[\"伏击\"]:Cast() if v then return v end\nend\n--v = A[\"淬毒之刃\"]:Cast(vars[\"连击点差\"] > 0 and player:GetPowerTimeToValue(P[\"能量\"], 60) < gcdmax) if v then return v end\nv = A[\"抽血\"]:Cast(vars[\"锁喉时间\"] > 0 and vars[\"割裂时间\"] > 0) if v then return v end --无连击点\n--v = A[\"侧袭\"]:Cast(vars[\"连击点差\"] > 0 and player:GetPowerTimeToValue(P[\"能量\"], 75) < gcdmax) if v then return v end\nv = A[\"毁伤\"]:Cast(vars[\"连击点差\"] > 1 and player:GetPowerTimeToValue(P[\"能量\"], 90) < gcdmax) if v then return v end\nv = A[\"影袭\"].IsValid and A[\"影袭\"]:Cast(vars[\"能量\"] >= 75 or A[\"影袭\"]:GetDamage() >= target.Health) if v then return v end\n\nv = A[\"暗影步\"]:Cast(target.RangeToPlayer > 8 and SwitchIsOn(\"暗影步\")) if v then return v end\nv = A[\"剧毒之刃\"]:Cast(SwitchIsOn(\"剧毒之刃\") and vars[\"能量\"] >= 70 and target.RangeToPlayer > 9) if v then return v end\n",
            ["锯齿骨刺_"] = "--潜行者-奇袭-锯齿骨刺_\n--潜行者-奇袭-锯齿骨刺\nif not SwitchIsOn(\"锯齿骨刺\") then\n    return\nend\nif not A[\"锯齿骨刺\"].IsValid then\n    return\nend\n\n--vars[\"锯齿骨刺数量\"], vars[\"敌方人数\"] = enemies:GetMyDebuffCount(\"锯齿骨刺\", 15)\n--if vars[\"连击点差\"] <= vars[\"锯齿骨刺数量\"] then\n--    return\n--end\nif vars[\"连击点差\"] < 1 then\n    return\nend\nif target.MyDebuff:Has(\"锯齿骨刺\") then\n    return\n    --if vars[\"锯齿骨刺数量\"] == vars[\"敌方人数\"] then\n    --    v = A[\"锯齿骨刺\"]:Cast() if v then return v end\n    --end\nelse\n    v = A[\"锯齿骨刺\"]:Cast() if v then return v end \nend\n",
        },
        ["敏锐"] = {
            ["_专精初始化"] = "--潜行者-敏锐-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"潜行起手技能\"] = A[\"暗影打击\"]\nvars[\"潜行起手距离\"] = 28\n\n",
            ["打爆炸物"] = "--潜行者-敏锐-打爆炸物\nlocal v\nv = A[\"暗影打击\"]:Cast() if v then return v end\nv = A[\"背刺\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--潜行者-敏锐-爆发技能\nif vars[\"爆发强度\"] < 2.5 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v = A[\"影分身\"]:GetCooldown() < 6 and A[\"暗影之刃\"]:Cast() and A[\"暗影之舞\"]:Cast() if v then return run(\"一键爆发\") end\n",
            ["补刀"] = "--潜行者-敏锐-补刀\nlocal v\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nv = A[\"暗影打击\"]:Cast(A[\"暗影打击\"]:GetDamage() >= target.Health) if v then return v end\nv = A[\"背刺\"]:Cast(A[\"背刺\"]:GetDamage() >= target.Health) if v then return v end\nv = A[\"刺骨\"]:Cast(A[\"刺骨\"]:GetDamage() * vars[\"连击点\"] >= target.Health) if v then return v end\n",
            ["输出"] = "--潜行者-敏锐-输出\nlocal v\n\nv = run(\"潜行起手\") if v then return v end\nif not inCombat then\n    return\nend\nv = run(\"爆发技能\") if v then return v end\n\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nvars[\"连击点差\"] = player:GetPowerDeficit(P[\"连击点\"])\n--vars[\"能量回满时间\"] = player:GetPowerTimeToMax(P[\"能量\"])\n--vars[\"能量差\"] = player:GetPowerDeficit(P[\"能量\"])\n--vars[\"能量\"] = player:GetPower(P[\"能量\"])\n\nv = vars[\"连击点差\"] < 2 and not player.MyBuff:Has(\"切割\") and A[\"刺骨\"]:Cast() if v then return v end\nvars[\"暗影之舞\"] = player.MyBuff:Has(\"暗影之舞\") or player.MyBuff:Has(\"诡诈\")\nv = not vars[\"暗影之舞\"] and vars[\"爆发强度\"] > 0.8 and A[\"影分身\"]:GetCooldown() < 6 and (A[\"暗影之刃\"]:GetCooldown() > 20 or A[\"暗影之舞\"]:GetChargeInfo():IsReachedOrSoon()) and A[\"暗影之舞\"]:Cast() if v then return v end\nv = vars[\"暗影之舞\"] and vars[\"连击点差\"] > 3 and A[\"赤喉之咬\"]:Cast() if v then return v end\nif talent[\"隐秘之刃\"] then\n    if vars[\"连击点\"] > 4 or vars[\"连击点差\"] < 2 then\n        vars[\"惊慌\"] = target.MyDebuff:Has(\"惊慌\")\n        if talent[\"致命一击\"] then\n            v = vars[\"惊慌\"] and A[\"刺骨\"]:IsActiveSpellName(\"致命一击\") and A[\"刺骨\"]:Cast() if v then return v end\n            v = vars[\"暗影之舞\"] and (not vars[\"惊慌\"] or not A[\"刺骨\"]:IsActiveSpellName(\"致命一击\")) and A[\"影分身\"]:Cast() if v then return v end\n            if vars[\"连击点差\"] < 2 then\n                if vars[\"敌方目标数量\"] > 3 then\n                    v = A[\"黑火药\"]:Cast() if v then return v end\n                else\n                    v = A[\"刺骨\"]:Cast() if v then return v end\n                end\n            end\n        elseif vars[\"连击点差\"] < 2 then\n            v = vars[\"连击点差\"] < 2 and A[\"黑火药\"]:Cast() if v then return v end\n            v = vars[\"惊慌\"] and A[\"刺骨\"]:Cast() if v then return v end\n            v = vars[\"暗影之舞\"] and A[\"影分身\"]:Cast() if v then return v end\n            v = A[\"刺骨\"]:Cast() if v then return v end\n        end\n    end\nelse\n    if talent[\"至黑之夜\"] and player.MyBuff:Has(\"至黑之夜\") then\n        if vars[\"连击点差\"] == 0 then\n            v = A[\"刺骨\"]:Cast() if v then return v end\n        else\n            vars[\"连击点\"] = 0 --防止不打袖剑风暴和暗影打击\n        end\n    elseif vars[\"连击点差\"] < 2 then\n        v = vars[\"暗影之舞\"] and A[\"影分身\"]:Cast() if v then return v end\n        if vars[\"敌方目标数量\"] > 3 then\n            v = A[\"黑火药\"]:Cast() if v then return v end\n        else\n            v = A[\"刺骨\"]:Cast() if v then return v end\n        end\n    end\nend\nif vars[\"连击点\"] < 5 or vars[\"连击点差\"] > 1 then\n    if vars[\"敌方目标数量\"] > 3 or (talent[\"见者尽灭\"] and not vars[\"暗影之舞\"]) then\n        v = A[\"袖剑风暴\"]:Cast() if v then return v end\n    else\n        v = A[\"暗影打击\"]:Cast() or (player:GetPower(P[\"能量\"]) >= 50 and A[\"背刺\"]:Cast()) if v then return v end\n    end\nend\nv = target.RangeToPlayer > 8 and A[\"暗影步\"]:Cast() if v then return v end\n\n\n\n",
        },
        ["狂徒"] = {
            ["_专精初始化"] = "--潜行者-狂徒-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"潜行起手技能\"] = A[\"伏击\"]\nvars[\"潜行起手距离\"] = 15\nvars[\"攻击距离\"] = talent[\"杂耍打击\"] and 8 or 5\nvars[\"敌方目标距离\"] = talent[\"杂耍打击\"] and 10 or 8\nvars[\"命运骨骰Buff\"] = \n{\n    [\"残忍精准\"] = 0,     --正中眉心爆击几率提高60%，其他技能提高20%。\n    [\"大乱斗\"] = 0,        --攻击速度提高55%。吸血提高25%\n    [\"骷髅黑帆\"] = 0,        --影袭触发额外攻击提高30%。\n    [\"强势连击\"] = 0,        --你的攻击获得1个额外的连击点数。且伤害提高20%\n    [\"埋藏的宝藏\"] = 0,   --每秒能量恢复提高4点\n    [\"精准定位\"] = 0,        --终结技会使你的许多技能冷却时间缩短，每花费一个连击点数可缩短1秒。\n}\n\n--AddCommonSwitch(\"AOE\", \"JAOE\", \"剑刃乱舞\")\n--AddPriorMacro(\"正中眉心\")\n--AddPriorMacro(\"冲动\")\n--AddPriorMacro(\"剑刃乱舞\")\n--AddSpellSwitch(\"剑刃乱舞\", nil, \"剑舞\")\n--AddSpellSwitch(\"消失\")\n--AddSpellSwitch(\"佯攻\")\n--AddSpellSwitch(\"猩红之瓶\")\n--AddSpellSwitch(\"还击\")\n--if talent[\"刀锋冲刺\"] then\n--    AddSpellSwitch(\"刀锋冲刺\")\n--end\n--AddSpellSwitch(\"仇敌之血\")\n",
            ["_脚本初始化"] = "--潜行者-狂徒-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n",
            ["命运骨骰_"] = "--潜行者-狂徒-命运骨骰_\nif not SwitchIsOn(\"命运骨骰\") then\n    return\nend\n--if vars[\"暗影之舞\"] then\n--    return\n--end\n--if vars[\"连击点差\"] > 1 then\n--    return\n--end\nlocal action = A[\"命运骨骰\"]:Cast()\nif target.RangeToPlayer > (inCombat and vars[\"潜行起手距离\"] or (vars[\"潜行起手距离\"] + 3)) then\n	return\nend\nif vars[\"爆发强度\"] < 0.6 then\n	return\nend\nif boss.IsTarget and vars[\"目标死亡时间\"] < 5 then\n	return\nend\n\n--当拥有5个连击点数且命运骨骰所带来的战斗增益BUFF≤3秒且目标存活时间>20秒时施放命运骨骰以消耗连击点数\n--单BUFF时除了暴击攻速以外都Reroll，双buff除了回能减cd都不reroll\n--vars[\"命运骨骰Buff\"] = \n--{\n--    \"残忍精准\",     --正中眉心爆击几率提高60%，其他技能提高20%。\n--    \"大乱斗\",        --攻击速度提高55%。吸血提高25%\n--    \"骷髅黑帆\",        --影袭触发额外攻击提高30%。\n--    \"强势连击\",        --你的攻击获得1个额外的连击点数。且伤害提高20%\n--    \"埋藏的宝藏\",   --每秒能量恢复提高4点\n--    \"精准定位\",        --终结技会使你的许多技能冷却时间缩短，每花费一个连击点数可缩短1秒。\n--}\nlocal count = 0\nlocal minTime = 50\nlocal buffTime = 0\nlocal s = \"\"\n--print(\"-------\")\nfor k, v in pairs(vars[\"命运骨骰Buff\"]) do\n    buffTime = player.MyBuff[k]:GetTimeLeft()\n    vars[\"命运骨骰Buff\"][k] = buffTime\n    --print(k, vars[\"命运骨骰Buff\"][k])\n    if buffTime > 0 then\n        --2个以上\n        if count >= 2 then --已经有2个了\n            return\n        end\n        count = count + 1\n        if minTime > buffTime then\n            minTime = buffTime\n        end\n        s = s .. k .. \" \"\n    end\n    --buffTime = player.MyBuff[v]:GetTimeLeft()\n    --if buffTime > 0 then\n    --    return\n    --end\nend\nif count > 0 then\n    -- keep_it_rolling,if=!variable.rtb_reroll&(buff.broadside.up+buff.true_bearing.up+buff.skull_and_crossbones.up+buff.ruthless_precision.up)>2&(buff.shadow_dance.down||rtb_buffs>=6)\n    -- keep_it_rolling,if=not (variable.rtb_reroll) and (buff.broadside.up + buff.true_bearing.up + buff.skull_and_crossbones.up + buff.ruthless_precision.up) > 2 and (buff.shadow_dance.down or rtb_buffs >= 6)\n    v = SwitchIsOn(\"时运继延\") and A[\"时运继延\"]:Cast(count >= 5 and ((vars[\"命运骨骰Buff\"][\"强势连击\"] and 1 or 0) + (vars[\"命运骨骰Buff\"][\"精准定位\"] and 1 or 0) + (vars[\"命运骨骰Buff\"][\"骷髅黑帆\"] and 1 or 0) + (vars[\"命运骨骰Buff\"][\"残忍精准\"] and 1 or 0)) > 2) if v then return v end\n    if not action then\n        return\n    end\n\n    --- 骰子中有强势连击\n    if vars[\"命运骨骰Buff\"][\"强势连击\"] > 0 then\n        return\n    end\n    --- 如果使用提神影尘橙,骰子中有精准定位\n    if talent[\"提神影尘\"] and vars[\"命运骨骰Buff\"][\"精准定位\"] > 0 then\n        return\n    end\n    --- 如果使用迅捷短枪橙,骰子中有骷髅黑帆\n    if talent[\"迅疾连射\"] and vars[\"命运骨骰Buff\"][\"骷髅黑帆\"] > 0 then\n        return\n    end\n    --- 骰子中Roll出了2个或以上Buff,除了大乱斗+埋藏的宝藏.\n    if count == 2 and (vars[\"命运骨骰Buff\"][\"大乱斗\"] == 0 or vars[\"命运骨骰Buff\"][\"埋藏的宝藏\"] == 0) then\n        return\n    end \nend\n\n\n--if vars[\"剑刃乱舞中\"] and vars[\"敌方目标数量\"] > 1 then\n--    print(\"剑刃乱舞中\")\n--    return\n--end\n\n--local needRefill = (not vars[\"剑刃乱舞中\"]) and boss.Exists and not UnitIsPlayer(\"target\") \n--if needRefill then\n--    needRefill = vars[\"敌方目标数量\"] < 2\n--    if needRefill and vars[\"连击点差\"] > 1 then\n--        return\n--    end\n--end\nif not talent[\"灌铅骰子\"] or player.MyBuff:Has(\"冲动\") or A[\"冲动\"]:GetCooldown() > 20 then \n    --print(\"reroll\", s)\n    return action\nend\n\n--if vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n--    return action\n--end\n",
            ["打爆炸物"] = "--潜行者-狂徒-打爆炸物\nlocal v\nvars[\"连击点差\"] = player:GetPowerDeficit(P[\"连击点\"])\nv = A[\"手枪射击\"]:Cast(vars[\"连击点差\"] >= (talent[\"快速拔枪\"] and 2 or 1) and player.MyBuff:Has(\"可乘之机\")) if v then return v end\nv = A[\"影袭\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--潜行者-狂徒-爆发技能\n\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\n--v = SwitchIsOn(\"影舞步\") and A[\"影舞步\"]:Cast() if v then return v end\nlocal tm = player.MyBuff[\"冲动\"]:GetTimeLeft()\nv = A[\"冲动\"]:Cast(target.RangeToPlayer < 5 and vars[\"能量回满时间\"] > gcdmax and tm == 0) if v then return run(\"一键爆发\") end\nif player.MyBuff[\"冲动\"]:GetTimeLeft() < 10 then\n    return\nend\n--v = A[\"鬼魅攻击\"]:Cast() if v then return v end\n\n-- variable,name=shadow_dance_condition,value=talent.shadow_dance&(!stealthed.all||talent.count_the_odds&!variable.stealthed_cto)&debuff.between_the_eyes.up&(!talent.ghostly_strike||debuff.ghostly_strike.up)&(!talent.dreadblades||!cooldown.dreadblades.ready)\n-- variable,name=shadow_dance_condition,if=\n--if talent[\"暗影之舞\"] and target.MyDebuff:Has(\"正中眉心\") and (not talent[\"鬼魅攻击\"] or target.MyDebuff:Has(\"鬼魅攻击\")) and (not talent[\"恐惧之刃\"] or not (A[\"恐惧之刃\"]:IsReady())) then\n--    -- shadow_dance,if=!talent.keep_it_rolling&variable.shadow_dance_condition&buff.slice_and_dice.up&(variable.finish_condition||talent.hidden_opportunity)\n--    -- shadow_dance,if=not (talent.keep_it_rolling.enabled) and variable.shadow_dance_condition and buff.slice_and_dice.up and (variable.finish_condition or talent.hidden_opportunity.enabled)\n--    v = A[\"暗影之舞\"]:Cast(not talent[\"时运继延\"] and player.MyBuff:Has(\"切割\") and (vars[\"连击点差\"] < 2 or talent[\"藏锋寻时\"])) if v then return v end\n--    -- shadow_dance,if=talent.keep_it_rolling&variable.shadow_dance_condition&(cooldown.keep_it_rolling.remains<=30||cooldown.keep_it_rolling.remains>120&(variable.finish_condition||talent.hidden_opportunity))\n--    -- shadow_dance,if=talent.keep_it_rolling.enabled and variable.shadow_dance_condition and (cooldown.keep_it_rolling.remains <= 30 or cooldown.keep_it_rolling.remains > 120 and (variable.finish_condition or talent.hidden_opportunity.enabled))\n--    v = A[\"暗影之舞\"]:Cast(talent[\"时运继延\"] and (A[\"时运继延\"]:GetCooldown() <= 30 or A[\"时运继延\"]:GetCooldown() > 120 and (vars[\"连击点差\"] < 2 or talent[\"藏锋寻时\"]))) if v then return v end\n--end\n\n--v = SwitchIsOn(\"恐惧之刃\") and A[\"恐惧之刃\"]:Cast(vars[\"连击点\"] < 2) if v then return v end\n",
            ["输出"] = "--潜行者-狂徒-输出\nlocal v\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nvars[\"连击点差\"] = player:GetPowerDeficit(P[\"连击点\"])\nvars[\"剑刃乱舞中\"] = player.MyBuff:Has(\"剑刃乱舞\")\nvars[\"恐惧之刃\"] = player.MyDebuff:Has(\"恐惧之刃\")\n--vars[\"暗影之舞\"] = player.MyBuff:Has(\"暗影之舞\")\n\n--v = A[\"伏击\"]:Cast(vars[\"暗影之舞\"]) if v then return v end\n\nv = not vars[\"恐惧之刃\"] and run(\"命运骨骰_\") if v then return v end\n--v = A[\"命运骨骰\"]:Cast() if v then return v end\nv = run(\"切割_\") if v then return v end\nif talent[\"裂额射击\"] and A[\"正中眉心\"]:Cast(nil, nil, {LeadCd=1.2}) then\n    vars[\"潜行起手技能\"] = A[\"正中眉心\"]\nelse\n    vars[\"潜行起手技能\"] = A[\"伏击\"]\nend\nv = run(\"潜行起手\") if v then return v end\n\nif not inCombat then\n    return\nend\n--if vars[\"暗影之舞\"] then\n--    v = SwitchIsOn(\"剑刃乱舞\") and A[\"剑刃乱舞\"]:Cast(vars[\"敌方目标数量\"] > 1 and vars[\"爆发强度\"] > 0.6 and target.RangeToPlayer < vars[\"攻击距离\"] + 2 and not player.MyBuff:Has(\"剑刃乱舞\")) if v then return v end\n--    v = A[\"斩击\"]:Cast(vars[\"连击点\"] > 3) if v then return v end\n--    v = A[\"伏击\"]:Cast() if v then return v end\n--    return 0\n--end\n\nv = SwitchIsOn(\"消失\") and (inParty or inRaid or inTraining) and vars[\"目标强度\"] > 0.5 and vars[\"连击点差\"] > 2 and not player.MyBuff:Has(\"潜行\") and A[\"消失\"]:Cast() if v then SetForceStart() return v end\n\nv = A[\"偷袭\"]:Cast(UnitIsPlayer(\"target\") or not A[\"伏击\"].IsValid) if v then return v end\n--v = A[\"伏击\"]:Cast() if v then return v end\nv = A[\"伏击\"]:Cast(vars[\"连击点差\"] > 2 or player.MyBuff:Has(\"潜行\") or player.MyBuff:Has(\"消失\")) if v then return v end\n\n\n--v = A[\"死亡标记\"]:Cast(vars[\"连击点差\"] > 3) if v then return v end\nv = SwitchIsOn(\"剑刃乱舞\") and A[\"剑刃乱舞\"]:Cast(vars[\"敌方目标数量\"] > 1 and vars[\"爆发强度\"] > 0.6 and target.RangeToPlayer < vars[\"攻击距离\"] + 2) if v then return v end --not vars[\"剑刃乱舞中\"] and \n    v = A[\"毒刃\"]:Cast(UnitIsPlayer(\"target\")) if v then return v end --PVP\n\nvars[\"能量差\"] = player:GetPowerDeficit(P[\"能量\"])\nvars[\"能量回满时间\"] = player:GetPowerTimeToMax(P[\"能量\"])\n\n-- Blade Flurry on 2+ enemies\n-- blade_flurry,if=spell_targets>=2&!buff.blade_flurry.up&!stealthed.rogue,description=Blade Flurry on 2+ enemies\n-- blade_flurry,if=spell_targets.any >= 2 and not (buff.blade_flurry.up) and not (stealthed.rogue)\nv = SwitchIsOn(\"剑刃乱舞\") and A[\"剑刃乱舞\"]:Cast(vars[\"敌方目标数量\"] > 1 and vars[\"爆发强度\"] > 0.6 and target.RangeToPlayer < vars[\"攻击距离\"] + 2 and not player.MyBuff:Has(\"剑刃乱舞\")) if v then return v end\n-- vanish,if=!runeforge.invigorating_shadowdust&(!stealthed.all||talent.count_the_odds&!variable.stealthed_cto)&!buff.take_em_by_surprise.up&((talent.find_weakness&debuff.find_weakness.down||talent.hidden_opportunity||settings.ambush_anyway)&variable.ambush_condition||!talent.find_weakness&talent.count_the_odds&variable.finish_condition)&(!talent.shadow_dance||!cooldown.shadow_dance.ready)\n-- vanish,if=not (runeforge.invigorating_shadowdust.enabled) and (not (stealthed.all) or talent.count_the_odds.enabled and not (variable.stealthed_cto)) and not (buff.take_em_by_surprise.up) and ((talent.find_weakness.enabled and debuff.find_weakness.down or talent.hidden_opportunity.enabled or settings.ambush_anyway) and variable.ambush_condition or not (talent.find_weakness.enabled) and talent.count_the_odds.enabled and variable.finish_condition) and (not (talent.shadow_dance.enabled) or not (cooldown.shadow_dance.ready))\n--v = A[\"消失\"]:Cast(not (legendary[\"提神影尘\"]) and (not (stealthed.all$) or talent[\"潜伏胜机\"] and not (vars[\"stealthed_cto\"])) and not (player.MyBuff:Has(\"攻其不备\")) and ((talent[\"洞悉弱点\"] and (not target.MyDebuff:Has(\"洞悉弱点\")) or talent[\"藏锋寻时\"] or @settings not found@) and vars[\"ambush_condition\"] or not (talent[\"洞悉弱点\"]) and talent[\"潜伏胜机\"] and vars[\"finish_condition\"]) and (not (talent[\"暗影之舞\"]) or not (A[\"暗影之舞\"]:IsReady()))) if v then return v end\n-- adrenaline_rush,if=!buff.adrenaline_rush.up&(!talent.improved_adrenaline_rush||combo_points<=2)\n-- adrenaline_rush,if=not (buff.adrenaline_rush.up) and (not (talent.improved_adrenaline_rush.enabled) or combo_points.current <= 2)\nv = run(\"爆发技能\") if v then return v end\n--v = A[\"冲动\"]:Cast(not (player.MyBuff:Has(\"冲动\")) and (not (@talent.improved_adrenaline_rush.enabled#improved_adrenaline_rush not found@) or player:GetPower(P[\"连击点\"]) <= 2)) if v then return v end\n-- dreadblades,if=!stealthed.all&combo_points<=2&(!talent.marked_for_death||!cooldown.marked_for_death.ready)&target.time_to_die>=10\n-- dreadblades,if=not (stealthed.all) and combo_points.current <= 2 and (not (talent.marked_for_death.enabled) or not (cooldown.marked_for_death.ready)) and target.time_to_die >= 10\nv = SwitchIsOn(\"恐惧之刃\") and vars[\"爆发强度\"] > 2 and A[\"恐惧之刃\"]:Cast(vars[\"连击点\"] <= 2) if v then return v end\n-- Fleshcraft for Pustule Eruption if not stealthed and not with Blade Flurry\n-- If adds are up, snipe the one with lowest TTD. Use when dying faster than CP deficit or without any CP.\n-- If no adds will die within the next 30s, use MfD on boss without any CP.\n-- marked_for_death,if=raid_event.adds.in>30-raid_event.adds.duration&combo_points.deficit>=cp_max_spend-1&!debuff.dreadblades.up,description=If no adds will die within the next 30s; use MfD on boss without any CP.\n-- marked_for_death,if=raid_event.adds.in > 30 - raid_event.adds.duration and combo_points.deficit >= cp_max_spend - 1 and not (debuff.dreadblades.up)\n--v = vars[\"爆发强度\"] > 0.4 and A[\"死亡标记\"]:Cast(vars[\"连击点差\"] >= 5 and not vars[\"恐惧之刃\"]) if v then return v end\n-- Use in 1-2T if BtE is up and won't cap Energy, or at 3T+\n-- killing_spree,if=variable.blade_flurry_sync&!stealthed.rogue&(debuff.between_the_eyes.up&debuff.dreadblades.down&energy.base_deficit>(energy.regen*2+15)||spell_targets.blade_flurry>2),description=Use in 1-2T if BtE is up and won't cap Energy; or at 3T+\n-- killing_spree,if=variable.blade_flurry_sync and not (stealthed.rogue) and (debuff.between_the_eyes.up and debuff.dreadblades.down and energy.base_deficit > (energy.regen * 2 + 15) or spell_targets.blade_flurry > 2)\nv = SwitchIsOn(\"影舞步\") and A[\"影舞步\"]:Cast(target.MyDebuff:Has(\"正中眉心\") and (not vars[\"恐惧之刃\"]) and vars[\"能量回满时间\"] > 2.5 or vars[\"敌方目标数量\"] > 2) if v then return v end\n-- blade_rush,if=variable.blade_flurry_sync&(energy.base_time_to_max>2&!debuff.dreadblades.up||energy<=30||spell_targets>2)\n-- blade_rush,if=variable.blade_flurry_sync and (energy.base_time_to_max > 2 and not (debuff.dreadblades.up) or energy.current <= 30 or spell_targets.any > 2)\n\nv = vars[\"目标强度\"] > 0.3 and vars[\"连击点\"] > 4 and A[\"正中眉心\"]:Cast((target.MyDebuff[\"正中眉心\"]:GetTimeLeft() < 4 or talent[\"绿皮船长的柳枝\"] and not player.MyBuff:Has(\"绿皮船长的柳枝\") or not talent[\"绿皮船长的柳枝\"] and player.MyBuff:Has(\"残忍精准\"))) if v then return v end\nif vars[\"连击点差\"] == 0 and vars[\"能量回满时间\"] > A[\"正中眉心\"]:GetCooldown() then\n    return 0\nend\n\n\nv = SwitchIsOn(\"刀锋冲刺\") and vars[\"能量回满时间\"] > gcdmax and target.RangeToPlayer < 4 and not player.MyBuff:Has(\"冲动\") and A[\"刀锋冲刺\"]:Cast() if v then return v end\n\n\n\nv = A[\"斩击\"]:Cast((vars[\"连击点差\"] < 2) or (not inPVE and (A[\"斩击\"]:GetDamage() * vars[\"连击点\"]) >= target.Health)) if v then return v end\nv = A[\"斩击\"]:Cast(vars[\"剑刃乱舞中\"] and vars[\"敌方目标数量\"] > 2 and (vars[\"连击点差\"] < 2)) if v then return v end\n\n\n\nv = A[\"手枪射击\"]:Cast(player.MyBuff:Has(\"绿皮船长的柳枝\") and (not talent[\"迅疾连射\"] and player.MyBuff:Has(\"可乘之机\") or player.MyBuff[\"绿皮船长的柳枝\"]:GetTimeLeft() < 1.5)) if v then return v end\n-- With Fan the Hammer, consume Opportunity at max stacks or if we will get 4+ CP and Dreadblades is not up\n-- pistol_shot,if=talent.fan_the_hammer&buff.opportunity.up&(buff.opportunity.stack>=buff.opportunity.max_stack||buff.opportunity.remains<2),description=With Fan the Hammer; consume Opportunity at max stacks or if we will get 4+ CP and Dreadblades is not up\n-- pistol_shot,if=talent.fan_the_hammer.enabled and buff.opportunity.up and (buff.opportunity.stack >= buff.opportunity.max_stack or buff.opportunity.remains < 2)\nv = A[\"手枪射击\"]:Cast(talent[\"迅疾连射\"] and player.MyBuff:Has(\"可乘之机\") and (player.MyBuff[\"可乘之机\"].Count >= 6 or player.MyBuff[\"可乘之机\"]:GetTimeLeft() < 2)) if v then return v end\n-- pistol_shot,if=talent.fan_the_hammer&buff.opportunity.up&combo_points.deficit>((1+talent.quick_draw)*talent.fan_the_hammer.rank)&!buff.dreadblades.up&(!talent.hidden_opportunity||!buff.subterfuge.up&!buff.shadow_dance.up)\n-- pistol_shot,if=talent.fan_the_hammer.enabled and buff.opportunity.up and combo_points.deficit > ((1 + talent.quick_draw.enabled) * talent.fan_the_hammer.rank) and not (buff.dreadblades.up) and (not (talent.hidden_opportunity.enabled) or not (buff.subterfuge.up) and not (buff.shadow_dance.up))\nv = A[\"手枪射击\"]:Cast(talent[\"迅疾连射\"] and player.MyBuff:Has(\"可乘之机\") and vars[\"连击点差\"] > ((1 + (talent[\"快速拔枪\"] or 0)) * (talent[\"迅疾连射\"] or 0)) and not vars[\"恐惧之刃\"] and (not talent[\"藏锋寻时\"] or not player.MyBuff:Has(\"诡诈\"))) if v then return v end\n-- pool_resource,for_next=1\n-- pool_resource,if=\n--v = A[\"pool_resource$11\"]:Cast() if v then return v end\n-- ambush,if=settings.ambush_anyway||talent.hidden_opportunity||talent.find_weakness&debuff.find_weakness.down\n-- ambush,if=settings.ambush_anyway or talent.hidden_opportunity.enabled or talent.find_weakness.enabled and debuff.find_weakness.down\n--v = A[\"伏击\"]:Cast(@settings not found@ or talent[\"藏锋寻时\"] or talent[\"洞悉弱点\"] and (not target.MyDebuff:Has(\"洞悉弱点\"))) if v then return v end\n-- Apply SBS to all targets without a debuff as priority, preferring targets dying sooner after the primary target\n-- serrated_bone_spike,if=!dot.serrated_bone_spike_dot.ticking,description=Apply SBS to all targets without a debuff as priority; preferring targets dying sooner after the primary target\n-- serrated_bone_spike,if=not (dot.serrated_bone_spike_dot.ticking)\n--v = A[\"锯齿骨刺\"]:Cast(not target.MyDebuff:Has(\"锯齿骨刺\")) if v then return v end\n-- serrated_bone_spike,cycle_targets=1,