            ["输出初始化"] = "--潜行者-狂徒-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", player, vars[\"敌方目标距离\"])\n\n",
            ["输出前1"] = "--潜行者-狂徒-输出前1\n--潜行者-狂徒-输出前\nlocal v = SwitchIsOn(\"嫁祸诀窍\") and run(\"嫁祸诀窍\") if v then return v end\nv = A[\"毒刃\"]:Cast(target:HasEnrageBuff()) if v then return v end\nv = player:GetPower(P[\"连击点\"]) > 2 and player.MyBuff:Has(\"诡诈\") and A[\"正中眉心\"]:Cast() if v then return v end\n",
