            ["_暗言术：灭"] = "--牧师-全专精-_暗言术：灭\nif not SwitchIsOn(\"暗言术：灭\") then\n    return\nend\nlocal v = A[\"暗言术：灭\"]:Cast()\nif not v then return end\n--if target.HealthPercent >= 0.2 then\n--    return\n--end\n\nlocal dmg = A[\"暗言术：灭\"]:GetDamage()\nif player.Health < dmg * 3 then\n    return\nend\n--if dmg > target.Health then\n--    return v\n--end\nreturn v\n--if target.HealthPercent < 0.2 or target:IsBigGuy() then\n--    return v\n--end\n",
