        ["戒律"] = {
            ["_专精初始化"] = "--牧师-戒律-_专精初始化\nrun(\"全专精-_专精初始化\")\nEnableSwitch(\"心灵震爆\")\nEnableSwitch(\"苦修\")\n",
            ["_脚本初始化"] = "--牧师-戒律-_脚本初始化\nrun(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--牧师-戒律-保命\nlocal v\nif not inCombat then\n--	v = A[\"真言术：盾\"]:Cast(player.HealthPercent < 0.9 and not player.MyBuff:Has(\"进食\"), player) if v then return v end\n    v = A[\"快速治疗\"]:Cast(player.HealthPercent < 0.6, player) if v then return v end\n    v = A[\"快速治疗\"]:CastSafely(player.HealthPercent < 0.8, player) if v then return v end\n    v = A[\"真言术：韧\"]:Cast() if v then return v end\n    return \nend\n--v = A[\"真言术：命\"]:Cast(player.HealthPercent < 0.35, player) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"真言术：盾\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\nv = A[\"绝望祷言\"]:Cast() if v then return v end\nv = not player.AllBuff:Has(\"痛苦压制\") and A[\"痛苦压制\"]:Cast() if v then return v end\nv = A[\"真言术：韧\"]:Cast() if v then return v end\n\n\n",
            ["治疗"] = "--牧师-戒律-治疗\nlocal v\n\nvars[\"救赎时间\"] = healTarget.MyBuff[\"救赎\"]:GetTimeLeft()\nif inCombat then\n    v = SwitchIsOn(\"取消施法\") and A[\"快速治疗\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    --v = player.MyBuff:Has(\"全神贯注\") and A[\"真言术：盾\"]:Cast(nil, healTarget) if v then return v end\n    v = A[\"快速治疗\"]:Cast(healTarget.HealthPercent < 0.45 and player.MyBuff:Has(\"圣光涌动\"), healTarget) if v then return v end\n    --v = A[\"真言术：命\"]:Cast(healTarget.HealthPercent < 0.35, healTarget) if v then return v end\n    v = A[\"真言术：盾\"]:Cast(healTarget.HealthPercent < 0.4 and vars[\"救赎时间\"] < 2, healTarget) if v then return v end\n    v = healTarget.HealthPercent < 0.5 and talent[\"双重视界\"] and A[\"苦修\"]:Cast(nil, healTarget) if v then return v end\n    v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    if not healTarget.AllBuff:Has(\"痛苦压制\") then\n        v = A[\"痛苦压制\"]:Cast(healTarget.HealthPercent < 0.4, healTarget) if v then return v end\n    end\n    v = SwitchIsOn(\"终极苦修\") and run(\"终极苦修\") if v then return v end\n    vars[\"总救赎数量\"], vars[\"总友方人数\"], vars[\"低血量救赎数量\"], vars[\"低血量友方人数\"], vars[\"低血量救赎数量2\"], vars[\"低血量友方人数2\"] = friends:GetMyBuffCount(\"救赎\", 80, 0.85, 0.65)\n    v = vars[\"低血量友方人数\"] > 2 and vars[\"低血量救赎数量\"] < vars[\"低血量友方人数\"] and A[\"真言术：耀\"]:Cast(nil, healTarget) if v then return v end\n    v = vars[\"低血量友方人数2\"] > 1 and A[player.BurstSpell]:Cast() if v then return run(\"一键爆发\") or v end\n    v = (vars[\"低血量救赎数量\"] > 2 or vars[\"低血量救赎数量2\"] > 1) and A[\"心灵震爆\"]:Cast() if v then return v end\n    if healTarget.HealthPercent < 0.65 then\n        v = A[\"苦修\"]:Cast(nil, healTarget) if v then return v end\n    end\n\n    v = A[\"福音\"]:Cast((vars[\"总友方人数\"] > 2 and vars[\"总救赎数量\"] >= vars[\"总友方人数\"] * 0.7) or vars[\"总救赎数量\"] == vars[\"总友方人数\"]) if v then return v end\n    --v = A[\"神圣之星\"]:Cast() if v then return v end\n    --v = A[\"苦修\"]:Cast(healTarget.HealthPercent < 0.7 or (healTarget.HealthPercent < 0.8 and (talent[\"幡然悔悟\"] and vars[\"救赎数量\"] > 3) or player.MyBuff:Has(\"阴暗面之力\")), healTarget) if v then return v end\n    v = A[\"快速治疗\"]:Cast(healTarget.HealthPercent < 0.5, healTarget) if v then return v end\n    v = A[\"快速治疗\"]:CastSafely(healTarget.HealthPercent < 0.75, healTarget) if v then return v end\n    v = run(\"_暗言术：灭\") if v then return v end\n    v = A[\"暗言术：痛\"]:Cast() if v then return v end\n    v = not SwitchIsOn(\"仅单体\") and enemies:GetNearbyCount(player, 12) > 2 and A[\"神圣新星\"]:Cast() if v then return v end\n    --v = UnitExists(\"mouseover\") and SwitchIsOn(\"鼠指痛\") and A[\"暗言术：痛\"]:Cast(nil, mouseover) if v then return v end\n    --v = GetSpellInfo(\"惩击\") == \"虚空冲击\" and A[\"惩击\"]:Cast() if v then return v end\n--    v = (not talent[\"暗影盟约\"] or A[player.BurstSpell]:GetCooldown() > 10) and A[\"苦修\"]:Cast() if v then return v end\nend\nv = A[\"快速治疗\"]:CastSafely(healTarget.HealthPercent < 0.75, healTarget) if v then return v end\nv = player:IsMoving() and healTarget.HealthPercent < 0.7 and A[\"恳求\"]:Cast(nil, healTarget) if v then return v end\nv = SwitchIsOn(\"预铺盾\") and run(\"预铺Buff\", A[\"真言术：盾\"]) if v then return v end\n\n\n",
            ["爆发技能"] = "--牧师-戒律-爆发技能\nif vars[\"爆发强度\"] < 3 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v = A[\"能量灌注\"]:Cast(nil, player) if v then return run(\"一键爆发\") end\n--if focus.IsFriend then\n--    v = A[\"能量灌注\"]:Cast(nil, focus) if v then return v end\n--else\n--    v = A[\"能量灌注\"]:Cast(nil, player) if v then return v end\n--end\n\n--if not SwitchIsOn(\"输出爆发\") then\n--    return\n--end\n--v = player.MyBuff[\"能量灌注\"]:GetTimeLeft() > 10 and run(\"一键爆发\") if v then return v end\n\n",
