            ["输出"] = "--牧师-戒律-输出\nlocal v\n\n--v = vars[\"目标强度\"] > 0.7 and A[\"心灵震爆\"]:Cast() if v then return v end\n--v = not inCombat and battleType ~= \"野外\" and not A[\"惩击\"]:CastedIn(3) and A[\"惩击\"]:Cast() if v then return v end\n\nv = run(\"爆发技能\") if v then return v end\nv = SwitchIsOn(\"输出苦修\") and talent[\"双重视界\"] and A[\"苦修\"]:Cast() if v then return v end\nv = run(\"_暗言术：灭\") if v then return v end\n--v = inCombat and vars[\"爆发强度\"] > 1.5 and SwitchIsOn(\"圣光之怒\") and A[\"圣光之怒\"]:Cast((vars[\"友方人数\"] > 2 and vars[\"救赎数量\"] >= vars[\"友方人数\"] * 0.7) or vars[\"救赎数量\"] == vars[\"友方人数\"]) if v then return v end\n\n--v = A[\"真言术：慰\"]:Cast(player:GetPowerPercent(P[\"法力\"]) < 0.95) if v then return v end\nv = A[\"暗言术：痛\"]:Cast() if v then return v end\nv = not SwitchIsOn(\"仅单体\") and enemies:GetNearbyCount(player, 12) > 2 and A[\"神圣新星\"]:Cast() if v then return v end\nv = (battleType == \"野外\" or SwitchIsOn(\"输出心爆\") or inTraining) and A[\"心灵震爆\"]:Cast() if v then return v end\n--if UnitExists(\"mouseover\") and SwitchIsOn(\"鼠指痛\") and not sv:UnitIsUnit(\"target\", \"mouseover\") then\n--    v = A[\"暗言术：痛\"]:Cast(nil, mouseover) if v then return v end\n--end\nv = A[\"驱散魔法\"]:Cast() if v then return v end\n--v = A[\"真言术：慰\"]:Cast() if v then return v end\n--vars[\"救赎数量\"] = friends:GetMyBuffCount(\"救赎\", 80)\nv = SwitchIsOn(\"输出苦修\") and A[\"苦修\"]:Cast((not inPVE and player.HealthPercent > 0.9) or (inCombat and vars[\"总救赎数量\"] > 3) or player.MyBuff:Has(\"阴暗面之力\")) if v then return v end\nv = A[\"惩击\"]:Cast() if v then return v end\n",
        },
        ["暗影"] = {
            ["_专精初始化"] = "--牧师-暗影-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_暗言术：灭"] = "--牧师-暗影-_暗言术：灭\n--if not SwitchIsOn(\"暗言术：灭\") then\n--    return\n--end\nif not A[\"暗言术：灭\"]:IsReady() then return end\n\nlocal v, unit\nif target.HealthPercent < 0.2 then\n    v = A[\"暗言术：灭\"]:Cast() if v then return v end\nend\n\nif vars[\"敌方目标数量\"] > 1 then\n    for _, unit in pairs(enemies.Units) do\n        if unit.NeedAttack and unit.HealthPercent < 0.2 and unit:IsInFrontOfPlayer(40, 50) then\n            v = A[\"暗言术：灭\"]:Cast(nil, unit) if v then return v end\n	    end\n    end\nend\n\nif player.Health > A[\"暗言术：灭\"]:GetDamage() * 2.5 then\n    v = A[\"暗言术：灭\"]:Cast() if v then return v end\nend\n\n",
            ["保命"] = "--牧师-暗影-保命\nlocal v\nvars[\"虚空形态中\"] = player.MyBuff:Has(\"虚空形态\")\nv = A[\"暗影形态\"]:Cast(not vars[\"虚空形态中\"] and not player.MyBuff:Has(\"暗影形态\")) if v then return v end\nif not inCombat then\n	v = SwitchIsOn(\"自己套盾\") and A[\"真言术：盾\"]:Cast(player.HealthPercent < 0.9 and not player.MyBuff:Has(\"进食\"), player) if v then return v end\n    if battleType == \"野外\" then\n        v = A[\"快速治疗\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n        v = A[\"快速治疗\"]:CastSafely(player.HealthPercent < 0.8, player) if v then return v end\n    end\n    v = A[\"真言术：韧\"]:Cast() if v then return v end\n    return \nend\n\n--v = A[\"真言术：命\"]:Cast(player.HealthPercent < 0.35, player) if v then return v end\nv = SwitchIsOn(\"自己套盾\") and A[\"真言术：盾\"]:Cast(player.HealthPercent < (battleType == \"团队\" and 0.3 or 0.6), player) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"绝望祷言\"]:Cast() if v then return v end\nif inPVE then\n    v = A[\"吸血鬼的拥抱\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nelse\n    v = A[\"吸血鬼的拥抱\"]:Cast(player.HealthPercent < 0.5) if v then return v end\n    v = not inTraining and A[\"快速治疗\"]:Cast(player.HealthPercent <= 0.5 and player:GetPowerPercent(P[\"法力\"]) > 0.3, player) if v then return v end\nend\nv = A[\"消散\"]:Cast() if v then return v end\nv = A[\"真言术：韧\"]:Cast() if v then return v end\n",
            ["取得中间的怪"] = "--牧师-暗影-取得中间的怪\n----牧师-暗影-取得中间的怪\n----尽量找中间的怪施放\n--if vars[\"中间的怪\"] then\n--    return vars[\"中间的怪\"]\n--end\n--local nearbyInfo, unit, maxUnit\n--local maxCount = 0\n--local maxRange = 1000\n--for _, unit in pairs(enemies.Units) do\n--    if unit.NeedAttack and unit:IsInFrontOfPlayer(40, 50) then\n--        nearbyInfo = enemies:GetNearbyInfo(unit, 12)\n--        --print(unit.UnitId, nearbyInfo[\"数量\"], maxCount, nearbyInfo[\"总距离\"], maxRange)\n--        if nearbyInfo[\"数量\"] >= maxCount and nearbyInfo[\"总距离\"] < maxRange and A[\"精神灼烧\"]:Cast(nil, unit) then\n--            maxCount = nearbyInfo[\"数量\"]\n--            maxRange = nearbyInfo[\"总距离\"]\n--            maxUnit = unit\n--            --print(\"中间的怪变更\", unit.UnitId, maxCount, maxRange)\n--        end\n--	end\n--end\n--if maxUnit then\n--    vars[\"中间的怪\"] = maxUnit\n----print(\"中间的怪\", maxUnit.UnitId, maxCount, maxRange)\n--end\n--return maxUnit\n\n\n",
            ["正在引导法术"] = "--牧师-暗影-正在引导法术\nvars[\"正在引导的法术\"] = player:GetChannelingSpell()\n\nif not vars[\"正在引导的法术\"] then\n    return\nend\nif (vars[\"正在引导的法术\"] == \"精神鞭笞\") then -- and UnitSpellHaste(\"player\") < 50 or vars[\"正在引导的法术\"] == \"精神灼烧\"\n    return\nend\nreturn true",
            ["治疗"] = "--牧师-暗影-治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\n--v = A[\"真言术：命\"]:Cast(target.HealthPercent < 0.35, target) if v then return v end\nv = A[\"真言术：盾\"]:Cast(not inCombat or target.HealthPercent < 0.95, target) if v then return v end\nv = A[\"快速治疗\"]:Cast(target.HealthPercent <= 0.5 and player:GetPowerPercent(P[\"法力\"]) > 0.3, target) if v then return v end\n",
            ["爆发技能"] = "--牧师-暗影-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nif player.BurstSpell then\n    v = A[player.BurstSpell]:IsActiveSpell() and A[player.BurstSpell]:Cast() if v then return run(\"一键爆发\") end\nelse\n    return run(\"一键爆发\")\nend\n",
            ["补痛触"] = "--牧师-暗影-补痛触\n----牧师-暗影-补痛触\n--local castTo = ...\n\n--if talent[\"哀难\"] then --吸血鬼之触还会对目标施加暗言术：痛。此时无视暗言术：痛\n--    return A[\"吸血鬼之触\"]:Cast(nil, castTo)\n--end\n\n----if talent[\"黑暗虚空\"] then --在目标周围引爆黑暗能量，对附近所有敌人施加暗言术：痛\n----    --优先施放黑暗虚空，无论是否需要补痛\n----    v = A[\"黑暗虚空\"]:Cast(nil, castTo) if v then return v end\n----    if A[\"黑暗虚空\"]:GetCooldown() > 6 then --黑暗虚空还有一段时间才好，先补暗言术：痛\n----        v = A[\"暗言术：痛\"]:Cast(nil, castTo) if v then return v end\n----    end\n----    return A[\"吸血鬼之触\"]:Cast(nil, castTo)\n----end\n\n--v = A[\"吸血鬼之触\"]:Cast(nil, castTo) if v then return v end\n--v = A[\"暗言术：痛\"]:Cast(nil, castTo) if v then return v end\n",
            ["输出"] = "--牧师-暗影-输出\nlocal v\n\nvars[\"狂乱值\"] = player:GetPower(P[\"狂乱\"])\nvars[\"狂乱差值\"] = player:GetPowerDeficit(P[\"狂乱\"])\nvars[\"吸血鬼之触时间\"] = target.MyDebuff[\"吸血鬼之触\"]:GetTimeLeft()\n\nv = vars[\"吸血鬼之触时间\"] < 7 and A[\"触须猛击\"]:CastSafely() if v then return v end\n\nv = not talent[\"触须猛击\"] and A[\"吸血鬼之触\"]:CastOnMinTime(nil, 40, 60) if v then return v end\nv = not talent[\"触须猛击\"] and not talent[\"哀难\"] and A[\"暗言术：痛\"]:CastOnMinTime(nil, 40, 60) if v then return v end\nv = A[\"光晕\"]:Cast() if v then return v end\nv = A[\"虚空齐射\"]:IsActiveSpell() and A[\"虚空齐射\"]:Cast() if v then return v end\nv = A[\"暗言术：癫\"]:Cast() if v then return v end\nv = vars[\"敌方目标数量\"] < 3 and A[\"心灵震爆\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\nv = GetSpellInfo(\"心灵震爆\") == \"虚空冲击\" and A[\"心灵震爆\"]:Cast() if v then return v end\nv = run(\"_暗言术：灭\") if v then return v end\nv = A[\"虚空洪流\"]:Cast() if v then return v end\nv = A[\"心灵震爆\"]:Cast() if v then return v end\nv = A[\"精神鞭笞\"]:Cast() if v then return v end\n",
            ["输出初始化"] = "--牧师-暗影-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", target, 15)\n\n",
        },
        ["神圣"] = {
            ["_专精初始化"] = "--牧师-神圣-_专精初始化\nrun(\"全专精-_专精初始化\")\n\n",
            ["_脚本初始化"] = "--牧师-神圣-_脚本初始化\nrun(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--牧师-神圣-保命\nlocal v\nif player:HasBuff(\"救赎之魂\") then\n    return\nend\nif not inCombat then\n    v = A[\"快速治疗\"]:Cast(player.HealthPercent < 0.8, player) if v then return v end\n    v = A[\"快速治疗\"]:CastSafely(player.HealthPercent < 0.9, player) if v then return v end\n    v = A[\"真言术：韧\"]:Cast() if v then return v end\n    return \nend\n--v = A[\"真言术：命\"]:Cast(player.HealthPercent < 0.35, player) if v then return v end\nv = A[\"绝望祷言\"]:Cast() if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"守护之魂\"]:Cast(player.HealthPercent < 0.35, player) if v then return v end\nv = A[\"真言术：韧\"]:Cast() if v then return v end\n",
            ["治疗"] = "--牧师-神圣-治疗\nlocal v\nif healTarget == player and player:HasBuff(\"救赎之魂\") then\n    return\nend\n\nv = SwitchIsOn(\"取消施法\") and A[\"快速治疗\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \nif inCombat then\n    v = A[\"圣言术：静\"]:Cast(healTarget.HealthPercent < 0.5, healTarget) if v then return v end\n    v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    v = A[\"守护之魂\"]:Cast(healTarget.HealthPercent < 0.4, healTarget) if v then return v end\n    v = SwitchIsOn(\"神圣赞美诗\") and run(\"神圣赞美诗\") if v then return v end\n    v = A[\"神圣化身\"]:Cast() if v then return v end\n    v = A[\"快速治疗\"]:Cast(healTarget.HealthPercent < 0.3 or (healTarget.HealthPercent < 0.5 and player.MyBuff:Has(\"圣光涌动\")), healTarget) if v then return v end\n    v = A[\"光晕\"]:Cast() if v then return v end\n    v = A[\"圣言术：灵\"]:Cast() if v then return v end\nend\nv = A[\"愈合祷言\"]:Cast(healTarget.HealthPercent >= 0.5 and friends:GetMyBuffCount(\"愈合祷言\", 100) == 0 and sv:UnitName(\"target\") ~= \"枯萎之种\", healTarget) if v then return v end\nv = A[\"治疗祷言\"]:Cast(nil, healTarget) if v then return v end\n\n\nif inRaid then\n    v = A[\"快速治疗\"]:Cast(healTarget.HealthPercent < 0.75, healTarget) if v then return v end\n    v = A[\"快速治疗\"]:CastSafely(healTarget.HealthPercent < 0.8 or (healTarget.HealthPercent < 0.85 and (talent[\"光明尾迹\"] or player.MyBuff[\"圣光涌动\"].Count == 2)), healTarget) if v then return v end\nelse\n    v = A[\"快速治疗\"]:Cast(healTarget.HealthPercent < 0.65, healTarget) if v then return v end\n    v = A[\"快速治疗\"]:CastSafely(healTarget.HealthPercent < 0.75 or (healTarget.HealthPercent < 0.8 and (talent[\"光明尾迹\"] or player.MyBuff[\"圣光涌动\"].Count == 2)), healTarget) if v then return v end\nend\n",
            ["爆发技能"] = "--牧师-神圣-爆发技能\nif vars[\"爆发强度\"] < 3 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v = A[\"能量灌注\"]:Cast(nil, player) if v then return run(\"一键爆发\") end\n--if focus.IsFriend then\n--    v = A[\"能量灌注\"]:Cast(nil, focus) if v then return v end\n--else\n--    v = A[\"能量灌注\"]:Cast(nil, player) if v then return v end\n--end\n\n--if not SwitchIsOn(\"输出爆发\") then\n--    return\n--end\n--v = player.MyBuff[\"能量灌注\"]:GetTimeLeft() > 10 and run(\"一键爆发\") if v then return v end\n\n",
            ["神圣赞美诗"] = "--牧师-神圣-神圣赞美诗\nlocal castTo, params = ...\n--if not castTo then \n--    castTo = (UnitExists(\"target\") and target or player)\n--end\nreturn run(\"安全引导\", \"神圣赞美诗\", castTo, params)\n\n\n",
            ["输出"] = "--牧师-神圣-输出\nlocal v\nif player:HasBuff(\"救赎之魂\") then\n    return\nend\nv = vars[\"爆发强度\"] > 3 and focus.IsFriend and A[\"能量灌注\"]:Cast(nil, focus) if v then return v end\nv = run(\"_暗言术：灭\") if v then return v end\nv = A[\"驱散魔法\"]:Cast() if v then return v end\nv = A[\"神圣之火\"]:CastOnMinTime(nil, 40, 60) if v then return v end\nv = player.MyBuff:Has(\"苍穹之焰\") and A[\"神圣之火\"]:ForceCast() if v then return v end\n--v = SwitchIsOn(\"苍穹之焰\") and A[\"苍穹之焰\"]:Cast() if v then return v end\n\nv = A[\"惩击\"]:Cast(not inCombat and not A[\"惩击\"]:CastedIn(3) and not A[\"神圣之火\"]:CastedIn(3)) if v then return v end\nv = A[\"圣言术：罚\"]:Cast() if v then return v end\nv = A[\"神圣新星\"]:Cast(not SwitchIsOn(\"仅单体\") and enemies:GetNearbyCount(player, 12) > 2) if v then return v end\nv = A[\"暗言术：痛\"]:Cast() if v then return v end\n--if UnitExists(\"mouseover\") and SwitchIsOn(\"鼠指痛\") and not sv:UnitIsUnit(\"target\", \"mouseover\") then\n--    v = A[\"暗言术：痛\"]:Cast(nil, mouseover) if v then return v end\n--end\nv = A[\"惩击\"]:Cast() if v then return v end\n",
        },
    },
    ["猎人"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--猎人-全专精-_专精初始化\n--print(\"猎人-全专精-_专精初始化\")\n\nrun(\"全职业-全专精-_专精初始化\")\n\n",
            ["保命"] = "--猎人-全专精-保命\nif player.MyBuff:Has(\"假死\") then\n    return 0\nend\nif inCombat then\n	v = SwitchIsOn(\"意气风发\") and A[\"意气风发\"]:Cast(player.HealthPercent < 0.5) if v then return v end\n	v = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n    v = SwitchIsOn(\"优胜劣汰\") and A[\"优胜劣汰\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"灵龟守护\") and (not A[\"灵龟守护\"]:IsProtected()) and A[\"灵龟守护\"]:Cast() if v then A[\"灵龟守护\"]:Protect(1, 0) return v end\nend\nv = run(\"治疗复活宠物\") if v then return v end\n\n",
            ["假死"] = "--猎人-全专精-假死_优先\nif player.MyBuff:Has(\"假死\") then\n    return 0\nend\nlocal v = A[\"假死\"]:Cast()\nif not v then\n    return\nend\nStop()\nreturn v\n--if not A[\"假死\"]:IsProtected() then\n--    A[\"假死\"]:Protect(3)\n--    return A[\"假死\"]:Cast()\n--else\n--    Stop()\n--    return 0\n--end\n",
            ["基本检查"] = "--猎人-全专精-基本检查\nif not player.MyBuff:Has(\"假死\") then\n    --print(GetTime(), \"猎人-全专精-基本检查\", run(\"全职业-全专精-基本检查\"))\n    return run(\"全职业-全专精-基本检查\")\nend\n",
            ["智能误导"] = "--猎人-全专精-智能误导\nif inTraining then\n    return\nend\nif not SwitchIsOn(\"智能误导\") then\n    return\nend\nif not A[\"误导\"]:IsReady() then\n    return\nend\nlocal v, u\nif inParty or inRaid then\n	if focus.IsFriend and focus:IsAlive() and focus:GetDuty() == \"TANK\" then\n		u = focus\n	else\n		u = friends:GetTank()\n    end\n	if u and combatTime > 5 then --仅战斗开始5秒内误导T\n		return\n	end\nend\nif not u and UnitExists(\"pet\") and not UnitIsDead(\"pet\") then\n	u = pet\nend\nif u and u.RangeToPlayer < 60 then\n	v = A[\"误导\"]:Cast(nil, u) if v then return v end\nend\n",
            ["治疗复活宠物"] = "--猎人-全专精-治疗复活宠物\n        --print(\"111\", UnitExists(\"pet\"), UnitIsDead(\"pet\"), A[\"复活宠物\"].ActionName, A[\"复活宠物\"].ID, A[\"复活宠物\"].BindingInfo.BindingKeyCode, A[\"治疗宠物\"].ActionName, A[\"治疗宠物\"].ID)\nif UnitLevel(\"player\") < 3 then\n    return\nend\nif SwitchIsOn(\"召唤宠物\") and A[\"召唤宠物\"].IsValid then\n    if UnitIsDead(\"pet\") then\n        --print(\"111\", UnitExists(\"pet\"), UnitIsDead(\"pet\"), A[\"复活宠物\"].ActionName, A[\"复活宠物\"].ID, A[\"复活宠物\"]:GetCooldown(), gcdmax, A[\"复活宠物\"]:IsCasting())\n        --if(A[\"复活宠物\"]:GetCooldown() < gcdmax) and not A[\"复活宠物\"]:IsCasting() then\n        if not A[\"复活宠物\"]:IsCasting() then\n            return A[\"复活宠物\"]:Cast()\n        end\n        return 0\n    elseif not UnitExists(\"pet\") then --not exist\n		local v = A[\"召唤宠物\"]:Cast(not A[\"召唤宠物\"]:IsProtected()) if v then A[\"召唤宠物\"]:Protect(3) return v end\n\n		--v = A[\"复活宠物\"]:Cast() if v then return v end\n			--print(\"222\", UnitExists(\"pet\"), UnitIsDead(\"pet\"), A[\"复活宠物\"].ActionName, A[\"复活宠物\"].ID, A[\"复活宠物\"]:GetCooldown(), gcdmax, A[\"复活宠物\"]:IsCasting())\n		--if(A[\"复活宠物\"]:GetCooldown() < gcdmax) and not A[\"复活宠物\"]:IsCasting() then\n		if not A[\"复活宠物\"]:IsCasting() then\n			return A[\"复活宠物\"]:Cast(not A[\"复活宠物\"]:FailedIn(5, \"你的宠物还未死亡\"))\n		end\n		return 0\n	end\nend\n--治疗宠物\nif A[\"治疗宠物\"].IsValid then\n    if UnitExists(\"pet\") and not UnitIsDead(\"pet\") then --IsPetActive()\n        local petHealthPercent = pet.HealthPercent\n        if petHealthPercent < 0.9 then\n            local boss1 = boss:GetBoss1()\n            if boss1 then\n                if sv:UnitIsUnit(boss1.UnitId .. \"target\", \"pet\") then\n                    if(A[\"治疗宠物\"]:GetCooldown() < 0.4) then\n                        return A[\"治疗宠物\"]:Cast()\n                    end\n                else\n                    if petHealthPercent < 0.5 then\n                        if(A[\"治疗宠物\"]:GetCooldown() < 0.4) then\n                            return A[\"治疗宠物\"]:Cast()\n                        end\n                    end\n                end\n            elseif petHealthPercent < 0.65 or not (inInstance and UnitExists(\"party1\")) then\n                --print(\"222\", UnitExists(\"pet\"), UnitIsDead(\"pet\"), A[\"复活宠物\"].ActionName, A[\"复活宠物\"].ID, A[\"治疗宠物\"].ActionName, A[\"治疗宠物\"].ID)\n                --print(A[\"治疗宠物\"]:IsReady(gcdmax), A[\"治疗宠物\"]:GetCooldown(), A[\"治疗宠物\"].ActionName)\n                if(A[\"治疗宠物\"]:GetCooldown() < 0.4) then\n                    return A[\"治疗宠物\"]:Cast()\n                end\n                --return A[\"治疗宠物\"]:Cast(nil, nil, {LeadCd=gcdmax})\n            end\n        end\n    end\nend\n",
            ["猎人印记_"] = "--猎人-全专精-猎人印记_\nlocal v\nif target.IsPlayer then\n    v = UnitClass(\"target\")\n    if v == \"潜行者\" or v == \"德鲁伊\" or v == \"法师\" or UnitRace(\"player\") == \"暗夜精灵\" then\n        v = enemies:GetMyDebuffCount(\"猎人印记\", 60) == 0 and A[\"猎人印记\"]:Cast() if v then return v end \n    end\nelseif not inCombat then\n    v = enemies:GetMyDebuffCount(\"猎人印记\", 60) == 0 and A[\"猎人印记\"]:Cast() if v then return v end \nend\n",
            ["输出前"] = "--猎人-全专精-输出前\nlocal v\n--v = A[\"夺命射击\"]:Cast(target.IsPlayer) if v then return v end \nv = A[\"宁神射击\"]:Cast(target:HasEnrageBuff()) if v then return v end\nv = run(\"猎人印记_\") if v then return v end\nv = run(\"智能误导\") if v then return v end\n",
        },
        ["射击"] = {
            ["_专精初始化"] = "--猎人-射击-_专精初始化\nrun(\"全专精-_专精初始化\")\n--vars[\"子弹风暴最大数量\"] = talent[\"燃炎弹药\"] and 20 or 15\n",
            ["打爆炸物"] = "--猎人-射击-打爆炸物\nlocal v = A[\"奥术射击\"]:Cast() if v then return v end\n",
            ["爆发技能"] = "--猎人-射击-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v = gcd < 0.6 and A[\"百发百中\"]:IsActiveSpellName() and A[\"百发百中\"]:Cast() \nif v then \n    if vars[\"敌方目标数量\"] < 2 then\n        return (not player:IsMoving() and run(\"一键爆发\"))\n    elseif target.MyDebuff:Has(\"哨兵印记\") then\n	    return A[\"选择目标\"]:TargetFrontEnemy() or (not player:IsMoving() and run(\"一键爆发\"))\n    elseif enemies:GetMyDebuffCount(\"哨兵印记\", 50) > 0 then\n        return (not player:IsMoving() and run(\"一键爆发\"))\n    end\nend\n",
            ["补刀"] = "--猎人-射击-补刀\nlocal v\nv = A[\"夺命射击\"]:Cast() if v then return v end \nv = A[\"奥术射击\"]:Cast(A[\"奥术射击\"]:GetDamage() > target.Health) if v then return v end\n",
            ["输出"] = "--猎人-射击-输出\nlocal v, v1\n--vars[\"集中值\"] = player:GetPower(P[\"集中\"])\nvars[\"集中差值\"] = player:GetPowerDeficit(P[\"集中\"])\n--vars[\"子弹风暴数量\"] = player.MyBuff[\"子弹风暴\"].Count\nvars[\"月光战轮\"] = player.MyBuff[\"月光战轮\"]:GetTimeLeft()\nv = vars[\"月光战轮\"] > 0 and vars[\"月光战轮\"] < 3 and A[\"月光战轮\"]:Cast() if v then return v end\n\nif vars[\"敌方目标数量\"] > 2 and talent[\"技巧射击\"] then --AOE\n    v = run(\"爆发技能\") if v then return v end\n    v = GetLastSpell().Name\n    vars[\"技巧射击\"] = player.MyBuff:Has(\"技巧射击\") or v == \"多重射击\" or (talent[\"幽影之触\"] and v == \"黑蚀箭\") or v == \"乱射\"\n    if vars[\"技巧射击\"] then\n        --v = A[\"瞄准射击\"]:GetChargeInfo():IsReachedOrSoon() and A[\"瞄准射击\"]:Cast() if v then return v end\n        v = A[\"急速射击\"]:Cast() if v then return v end\n        v = A[\"瞄准射击\"]:Cast() if v then return v end\n    else\n        v = talent[\"幽影之触\"] and A[\"黑蚀箭\"]:AutoCastOnMinTime() if v then return v end\n        v = (player.MyBuff:Has(\"弹无虚发\") or A[\"急速射击\"]:IsReady(1) or A[\"瞄准射击\"]:IsReady(1)) and A[\"多重射击\"]:Cast() if v then return v end\n    end\n    v = not player:IsMoving() and A[\"乱射\"]:Cast() if v then return v end\n    v = A[\"哀恸箭\"]:IsActiveSpell() and A[\"哀恸箭\"]:Cast() if v then return v end\n    v = vars[\"月光战轮\"] > 0 and A[\"月光战轮\"]:Cast() if v then return v end\n    v = vars[\"集中差值\"] >= 35 and A[\"稳固射击\"]:Cast() if v then return v end\nelse--单体\n    v = A[\"乱射\"]:Cast() if v then return v end\n    v = A[\"急速射击\"]:Cast() if v then return v end\n    v = talent[\"弹无虚发\"] and (player.MyBuff:Has(\"弹无虚发\") or (GetLastSpell() == \"瞄准射击\" or A[\"瞄准射击\"]:IsCasting())) and A[\"奥术射击\"]:Cast() if v then return v end\n    v = run(\"爆发技能\") if v then return v end\n    v = (A[\"瞄准射击\"]:GetCurrentCastingTime() == 0 or A[\"瞄准射击\"]:GetChargeInfo():IsReachedOrSoon()) and A[\"瞄准射击\"]:Cast() if v then return v end--荷枪实弹或快满\n    v = talent[\"黑蚀箭\"] and A[\"黑蚀箭\"]:Cast(vars[\"目标死亡时间\"] > 12) if v then return v end\n    v = not talent[\"黑蚀箭\"] and A[\"夺命射击\"]:Cast() if v then return v end\n    v = A[\"哀恸箭\"]:IsActiveSpell() and A[\"哀恸箭\"]:Cast() if v then return v end\n    v = vars[\"月光战轮\"] > 0 and A[\"月光战轮\"]:Cast() if v then return v end\n    v = A[\"瞄准射击\"]:Cast() if v then return v end\n    v = vars[\"集中差值\"] < 30 and A[\"奥术射击\"]:Cast() if v then return v end\n    v = vars[\"集中差值\"] >= 35 and A[\"稳固射击\"]:Cast() if v then return v end\nend\n",
        },
        ["生存"] = {
            ["_专精初始化"] = "--猎人-生存-_专精初始化\n--vars[\"补毒蛇钉刺条件\"] = function(unit) return not unit.MyDebuff:Has(\"信息素炸弹\") end\nrun(\"全专精-_专精初始化\")\n\nvars[\"猫鼬撕咬AOE条件\"] = \n	function(cachedUnit, unit, ...)\n		if unit.MyDebuff[\"潜藏毒素\"].Count > 8 and A[\"猫鼬撕咬\"]:Cast(nil, unit) then\n			return true, true --第二个true表示停止继续找下一个unit\n		else\n			return false\n		end\n	end\n",
            ["打爆炸物"] = "--猎人-生存-打爆炸物\nlocal v\nv = A[\"杀戮命令\"]:Cast() if v then return v end \n--v = A[\"毒蛇钉刺\"]:Cast(nil, nil, NoCheck) if v then return v end\n",
            ["爆发技能"] = "--猎人-生存-爆发技能\nif vars[\"爆发强度\"] < 1.5 or not SwitchIsOn(\"输出爆发\") then\n	return\nend\nif vars[\"集中差值\"] < 25 then\n	return\nend\nif vars[\"哨兵印记\"] then\n	return\nend\nif talent[\"双生利牙\"] and vars[\"利矛之刃\"] > 1 then\n	return\nend\nlocal v = A[\"狩魂一击\"]:IsActiveSpellName() and A[\"狩魂一击\"]:Cast() if v then return run(\"一键爆发\") end\n",
            ["补刀"] = "--猎人-生存-补刀\nlocal v\nv = A[\"猛禽一击\"]:Cast(A[\"猛禽一击\"]:GetDamage() > target.Health) if v then return v end \nv = A[\"杀戮命令\"]:Cast(A[\"杀戮命令\"]:GetDamage() > target.Health) if v then return v end \n",
            ["输出"] = "--猎人-生存-输出\nlocal v\n--vars[\"集中值\"] = player:GetPower(P[\"集中\"])\nvars[\"集中差值\"] = player:GetPowerDeficit(P[\"集中\"])\nvars[\"哨兵印记\"] = target.MyDebuff:Has(\"哨兵印记\")\nvars[\"利矛之刃\"] = player.MyBuff[\"利矛之刃\"].Count\n\nv = A[\"野火炸弹\"]:GetChargeInfo():IsReachedOrSoon() and A[\"野火炸弹\"]:Cast() if v then return v end\nv = A[\"爆裂火铳\"]:Cast() if v then return v end\nv = A[\"燎焰沥青\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\nif vars[\"敌方目标数量\"] > 2 then --AOE\n    v = vars[\"集中差值\"] > 25 and (vars[\"利矛之刃\"] == 0 or A[\"杀戮命令\"]:GetChargeInfo():IsReachedOrSoon()) and A[\"杀戮命令\"]:Cast() if v then return v end\nelse--单体\n    v = vars[\"利矛之刃\"] == 0 and A[\"杀戮命令\"]:Cast() if v then return v end\nend\nv = vars[\"哨兵印记\"] and A[\"野火炸弹\"]:Cast() if v then return v end\nv = vars[\"利矛之刃\"] > 0 and A[\"月光战轮\"]:IsActiveSpell() and A[\"月光战轮\"]:Cast() if v then return v end\nv = vars[\"利矛之刃\"] > 0 and talent[\"猪突猛进\"] and player.MyBuff:Has(\"猪突猛进\") and A[\"投掷手斧\"]:Cast() if v then return v end\nv = vars[\"利矛之刃\"] > 0 and A[\"猛禽一击\"]:Cast() if v then return v end\nv = vars[\"集中差值\"] > 25 and A[\"杀戮命令\"]:Cast() if v then return v end\nv = vars[\"利矛之刃\"] > 0 and A[\"野火炸弹\"]:Cast() if v then return v end\nv = A[\"猛禽一击\"]:Cast() if v then return v end\n\nv = target.RangeToPlayer >= 10 and A[\"雄鹰守护\"]:Cast() if v then return v end \nv = A[\"鱼叉猛刺\"]:Cast() if v then return v end\n",
            ["输出初始化1"] = "--猎人-生存-输出初始化1\nreturn run(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["野兽控制"] = {
            ["_专精初始化"] = "--猎人-野兽控制-_专精初始化\nrun(\"全专精-_专精初始化\")\n\n",
            ["_脚本初始化"] = "--猎人-野兽控制-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n",
            ["爆发技能"] = "--猎人-野兽控制-爆发技能\nif vars[\"爆发强度\"] < 1 or not SwitchIsOn(\"输出爆发\") then\n	return\nend\nlocal v\nv = A[\"狂野怒火\"]:IsActiveSpellName() and A[\"狂野怒火\"]:Cast() if v then return run(\"一键爆发\") end\n",
            ["补刀"] = "--猎人-野兽控制-补刀\nlocal v\nv = A[\"眼镜蛇射击\"]:Cast(A[\"眼镜蛇射击\"]:GetDamage() > target.Health) if v then return v end \nv = A[\"杀戮命令\"]:Cast(A[\"杀戮命令\"]:GetDamage() > target.Health) if v then return v end \n",
            ["输出"] = "--猎人-野兽控制-输出\nlocal v\n--vars[\"集中值\"] = player:GetPower(P[\"集中\"])\nvars[\"集中差值\"] = player:GetPowerDeficit(P[\"集中\"])\nv = A[\"黑蚀箭\"]:AutoCastOnMinTime() if v then return v end\nv = A[\"哀恸箭\"]:IsActiveSpell() and A[\"哀恸箭\"]:Cast() if v then return v end\nv = A[\"倒刺射击\"]:GetChargeInfo():IsReachedOrSoon() and A[\"倒刺射击\"]:AutoCastOnMinTime() if v then return v end\nv = run(\"爆发技能\") if v then return v end\nv = vars[\"敌方目标数量\"] > 1 and A[\"狂野鞭笞\"]:Cast() if v then return v end\nv = A[\"杀戮命令\"]:Cast() if v then return v end\nv = A[\"倒刺射击\"]:AutoCastOnMinTime() if v then return v end\nv = vars[\"集中差值\"] < 30 and A[\"眼镜蛇射击\"]:Cast() if v then return v end\nv = A[\"黑蚀箭\"]:ForceCast() if v then return v end\n\n--v = A[\"倒刺射击\"]:GetChargeInfo():IsReachedOrSoon() and A[\"倒刺射击\"]:AutoCastOnMinTime() if v then return v end\n--v = run(\"爆发技能\") if v then return v end\n--v = vars[\"敌方目标数量\"] > 1 and A[\"狂野鞭笞\"]:Cast() if v then return v end\n--v = A[\"杀戮命令\"]:Cast() if v then return v end\n--v = A[\"哀恸箭\"]:IsActiveSpell() and A[\"哀恸箭\"]:Cast() if v then return v end\n--v = A[\"黑蚀箭\"]:AutoCastOnMinTime() if v then return v end\n--v = A[\"倒刺射击\"]:AutoCastOnMinTime() if v then return v end\n--v = vars[\"集中差值\"] < 30 and A[\"眼镜蛇射击\"]:Cast() if v then return v end\n--v = A[\"黑蚀箭\"]:ForceCast() if v then return v end\n",
        },
    },
    ["萨满祭司"] = {
        ["元素"] = {
            ["_专精初始化"] = "--萨满祭司-元素-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"引雷针条件\"] = \n	function(cachedUnit, unit, ...)\n		if not unit.MyDebuff:Has(\"引雷针\") and unit:TimeToDie() > 4 then\n			return true, true --第二个true表示停止继续找下一个unit\n		else\n			return false\n		end\n	end\n\n",
            ["保命"] = "--萨满祭司-元素-保命\n--local _, _, _, mainHandEnchantID, _, _, _, offHandEnchantId = GetWeaponEnchantInfo()\nif SwitchIsOn(\"武器附魔\") then\n    local hasMainHandEnchant, _, _, _, hasOffHandEnchant = GetWeaponEnchantInfo()\n    if not hasMainHandEnchant and GetInventoryItemLink(\"player\", 16) then--主手\n        v = A[\"火舌武器\"]:Cast() if v then return v end\n    end\n    if not hasOffHandEnchant and talent[\"雷霆打击结界\"] then--副手\n        v = GetInventoryItemLink(\"player\", 17)\n        if v and select(7, GetItemInfo(v)) == \"盾牌\" then\n            v = A[\"雷霆打击结界\"]:Cast() if v then return v end\n        end\n    end\nend\nlocal v\nif not inCombat then\n    if battleType == \"野外\" then\n        v = A[\"治疗之涌\"]:Cast(player.HealthPercent < 0.6, player) if v then return v end\n        v = A[\"治疗之涌\"]:CastSafely(player.HealthPercent < 0.8, player) if v then return v end\n    end\n    v = run(\"护盾\") if v then return v end\n    v = A[\"天怒\"]:Cast() if v then return v end\n    return\nend\n--v = A[\"石壁图腾\"]:Cast(player.HealthPercent < 0.5) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"星界转移\"]:Cast() if v then return v end\n--v = A[\"先祖指引\"]:ForceCast(player.HealthPercent < 0.5) if v then return v end\nv = A[\"治疗之涌\"]:Cast(player.HealthPercent < (inPVE and 0.3 or 0.4), player) if v then return v end\nv = run(\"护盾\") if v then return v end\nv = A[\"天怒\"]:Cast() if v then return v end\nv = run(\"虚空裂隙\") if v then return v end\n",
            ["打爆炸物"] = "--萨满祭司-元素-打爆炸物\nlocal v\nv = A[\"冰霜震击\"]:Cast() if v then return v end\n",
            ["治疗"] = "--萨满祭司-元素-治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\nv = SwitchIsOn(\"治疗之涌\") and A[\"治疗之涌\"]:Cast(target.HealthPercent < 0.7, target) if v then return v end\nv = SwitchIsOn(\"治疗之涌\") and A[\"治疗之涌\"]:CastSafely(target.HealthPercent < 0.9, target) if v then return v end\n--v = SwitchIsOn(\"大地之盾\") and (not target.MyBuff:Has(\"闪电之盾\") and not target.MyBuff:Has(\"大地之盾\")) and A[\"大地之盾\"]:Cast(not focus:CanBeAssisted() and friends:GetMyBuffCount(\"大地之盾\", 60) == 0, target) if v then return v end\n\n",
            ["爆发技能"] = "--萨满祭司-元素-爆发技能\nif not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nv = A[\"风暴守护者\"]:Cast() if v then return v end\nv = vars[\"爆发强度\"] > 4 and A[\"升腾\"]:Cast() if v then return run(\"一键爆发\") end\nv = vars[\"爆发强度\"] > 4 and A[\"土元素\"]:Cast(not UnitExists(\"pet\")) if v then return v end\n\n",
            ["补刀"] = "--萨满祭司-元素-补刀\nlocal v, v1\nv = A[\"冰霜震击\"]:Cast(vars[\"敌方目标数量\"] == 1 and A[\"冰霜震击\"]:GetDamage() > target.Health) if v then return v end --收割\n",
            ["输出"] = "--萨满祭司-元素-输出\nlocal v, v1\n--vars[\"漩涡值\"] = player:GetPower(P[\"漩涡\"])\n--vars[\"漩涡差值\"] = player:GetPowerDeficit(P[\"漩涡\"])\n\nv = A[\"烈焰震击\"]:CastOnMinTime(nil, 40, 60) if v then return v end\n--v = A[\"流电炽焰\"]:CastOnMinTime(nil, 40, 60) if v then return v end\nv = A[\"流电炽焰\"]:Cast() if v then return v end\nv = run(\"爆发技能\") if v then return v end\nv = A[\"先祖迅捷\"]:Cast() if v then return v end\nv = A[\"自然迅捷\"]:Cast() if v then return v end\nif not talent[\"元素宗师\"] or player.MyBuff:Has(\"元素宗师\") then\n    --print(\"元素宗师\", player.MyBuff[\"元素宗师\"]:GetTimeLeft())\n    if vars[\"敌方目标数量\"] > 2 then\n        if A[\"狂风怒号\"]:IsActiveSpell() then\n            v = talent[\"传导能量\"] and A[\"狂风怒号\"]:CastOnNoDebuff(\"引雷针\", 40, 60) or A[\"狂风怒号\"]:Cast() if v then return v end\n        end\n        v = talent[\"引雷针\"] and A[\"地震术\"]:CastOnNoDebuff(\"引雷针\", 40, 60) or A[\"地震术\"]:Cast() if v then return v end\n    else\n        v = talent[\"引雷针\"] and A[\"元素冲击\"]:CastOnNoDebuff(\"引雷针\", 40, 60) or A[\"元素冲击\"]:Cast() if v then return v end\n        v = talent[\"引雷针\"] and A[\"大地震击\"]:CastOnNoDebuff(\"引雷针\", 40, 60) or A[\"大地震击\"]:Cast() if v then return v end\n        if A[\"狂风怒号\"]:IsActiveSpell() then\n            v = talent[\"传导能量\"] and A[\"狂风怒号\"]:CastOnNoDebuff(\"引雷针\", 40, 60) or A[\"狂风怒号\"]:Cast() if v then return v end\n        end\n    end\nelse\n    v = GetLastSpell() ~= \"熔岩爆裂\" and A[\"熔岩爆裂\"]:Cast() if v then return v end\nend\nif vars[\"敌方目标数量\"] > 2 then\n    v = talent[\"传导能量\"] and A[\"闪电链\"]:CastOnNoDebuff(\"引雷针\", 40, 60) or A[\"闪电链\"]:Cast() if v then return v end\nelse\n    v = talent[\"传导能量\"] and A[\"闪电箭\"]:CastOnNoDebuff(\"引雷针\", 40, 60) or A[\"闪电箭\"]:Cast() if v then return v end\nend\nv = A[\"冰霜震击\"]:Cast() if v then return v end\nif UnitLevel(\"player\") < 10 then\n    v = A[\"根源打击\"]:Cast() if v then return v end\nend\n\nv = inCombat and vars[\"爆发强度\"] > 0.5 and player:IsMoving() and A[\"灵魂行者的恩赐\"]:Cast() if v then return v end\n\n",
        },
        ["全专精"] = {
            ["_专精初始化"] = "--萨满祭司-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["基本检查"] = "--萨满祭司-全专精-基本检查\nreturn run(\"全职业-全专精-基本检查\", player.MyBuff:Has(\"幽魂之狼\"))\n",
            ["大地之盾2"] = "--萨满祭司-全专精-大地之盾2\n--萨满祭司-全专精-大地之盾\nif not SwitchIsOn(\"大地之盾\") then\n    return\nend\nif friends:GetMyBuffCount(\"大地之盾\", 60) > 0 then\n    return\nend\nif healTarget.UnitId and sv:UnitIsUnit(healTarget.UnitId, \"focus\") then\n    if not healTarget.MyBuff:Has(\"大地之盾\") then\n        v = A[\"大地之盾\"]:Cast(nil, healTarget, IgnoreSwitch) if v then return v end\n    end\nend\nif inParty or inRaid then\n    if healTarget:GetDuty() == \"TANK\" then\n        --print(UnitName(healTarget.UnitId), healTarget:GetDuty())\n        v = A[\"大地之盾\"]:Cast(nil, healTarget, IgnoreSwitch) if v then return v end\n    end\n--else\n--    v = A[\"大地之盾\"]:Cast(not player.MyBuff:Has(\"水之护盾\") or not player.MyBuff:Has(\"闪电之盾\"), player) if v then return v end\nend\n",
            ["护盾"] = "--萨满祭司-全专精-护盾\nlocal v\nlocal sz = player.MyBuff:Has(\"水之护盾\")\nlocal sd = player.MyBuff:Has(\"闪电之盾\")\nlocal dd = player.MyBuff:Has(\"大地之盾\")\nif talent[\"元素环绕\"] then\n    v = not sz and (not dd or not sd) and A:Has(\"水之护盾\") and A[\"水之护盾\"]:Cast() if v then return v end\n    v = not sd and (not dd or not sz) and A[\"闪电之盾\"]:Cast() if v then return v end\n    v = not dd and (not sd or not sz) and (SwitchIsOn(\"自己地盾\") or SwitchIsOn(\"全员地盾\")) and A[\"大地之盾\"]:Cast(nil, player) if v then return v end\nelseif not sd and not dd and not sz then\n    v = A:Has(\"水之护盾\") and A[\"水之护盾\"]:Cast() if v then return v end\n    v = A[\"闪电之盾\"]:Cast() if v then return v end\n    v = (SwitchIsOn(\"自己地盾\") or (SwitchIsOn(\"全员地盾\") and battleType == \"野外\")) and A[\"大地之盾\"]:Cast(nil, player) if v then return v end\nend\n\nif SwitchIsOn(\"全员地盾\") then\n    --if inParty or inRaid then\n    v = friends:GetTank()\n    if v then\n        --print(UnitName(healTarget.UnitId), healTarget:GetDuty())\n            v = A[\"大地之盾\"]:Cast(nil, v, IgnoreSwitch) if v then return v end\n    end\n    if focus.IsFriend then\n        v = A[\"大地之盾\"]:Cast(nil, focus, IgnoreSwitch) if v then return v end\n    elseif friends:GetMyBuffCount(\"大地之盾\", 60) < ((talent[\"元素环绕\"] and dd) and 2 or 1) then\n        v = friends:GetOtherMinHealthPercentUnit()\n        if v and v.IsPlayer and (UnitInParty(v.UnitId) or UnitInRaid(v.UnitId)) then\n            --print(UnitName(healTarget.UnitId), healTarget:GetDuty())\n            v = A[\"大地之盾\"]:Cast(nil, v, IgnoreSwitch) if v then return v end\n        end\n    end\nend\n\n",
            ["虚空裂隙"] = "--萨满祭司-全专精-虚空裂隙\nlocal v = A[\"清毒图腾\"]:Cast()\nif v and friends:GetAllDebuffCount(\"虚空裂隙\", 50) > 0 then\n    return v\nend\n",
        },
        ["增强"] = {
            ["_专精初始化"] = "--萨满祭司-增强-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["保命"] = "--萨满祭司-增强-保命\nlocal v\nif SwitchIsOn(\"武器附魔\") then\n    local hasMainHandEnchant, _, _, _, hasOffHandEnchant = GetWeaponEnchantInfo()\n    if not hasMainHandEnchant and GetInventoryItemLink(\"player\", 16) then--主手\n        v = talent[\"风怒武器\"] and A[\"风怒武器\"]:Cast() or A[\"火舌武器\"]:Cast() if v then return v end\n    end\n    if not hasOffHandEnchant and GetInventoryItemLink(\"player\", 17) and talent[\"风怒武器\"] then--副手\n        v = A[\"火舌武器\"]:Cast() if v then return v end\n    end\nend\nif not inCombat then\n    if battleType == \"野外\" then\n        v = A[\"治疗之涌\"]:Cast(player.HealthPercent < 0.6, player) if v then return v end\n        v = A[\"治疗之涌\"]:CastSafely(player.HealthPercent < 0.8, player) if v then return v end\n    end\n    v = run(\"护盾\") if v then return v end\n    v = A[\"天怒\"]:Cast() if v then return v end\n    return\nend\n--v = A[\"石壁图腾\"]:Cast(player.HealthPercent < 0.5) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"星界转移\"]:Cast() if v then return v end\nv = A[\"治疗之涌\"]:GetCurrentCastingTime() == 0 and A[\"治疗之涌\"]:Cast(player.HealthPercent < (battleType == \"野外\" and 0.7 or (inPVE and 0.3 or 0.6)), player) if v then return v end\n--v = A[\"先祖指引\"]:ForceCast(player.HealthPercent < 0.5) if v then return v end\nv = run(\"护盾\") if v then return v end\nv = A[\"天怒\"]:Cast() if v then return v end\nv = run(\"虚空裂隙\") if v then return v end\n",
            ["打爆炸物"] = "--萨满祭司-增强-打爆炸物\nlocal v\nv = A[\"毁灭闪电\"]:Cast(vars[\"敌方目标数量\"] > 1 and not player.MyBuff:Has(\"毁灭闪电\")) if v then return v end\nv = SwitchIsOn(\"裂地术\") and A[\"裂地术\"]:Cast(target.RangeToPlayer < 5 and vars[\"敌方目标数量\"] > 2) if v then return v end\nv = A[\"毁灭闪电\"]:Cast(vars[\"敌方目标数量\"] > 2) if v then return v end\n--v = A[\"霜刃打击\"]:Cast() if v then return v end\nv = A[\"熔岩猛击\"]:Cast() if v then return v end\n",
            ["治疗"] = "--萨满祭司-增强-治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\nv = A[\"治疗链\"]:Cast(target.HealthPercent < 0.9 and target.HealthPercent > 0.7, target) if v then return v end\nv = A[\"治疗之涌\"]:Cast(target.HealthPercent < 0.7, target) if v then return v end\nv = A[\"治疗之涌\"]:CastSafely(target.HealthPercent < 0.9, target) if v then return v end\n--v = SwitchIsOn(\"大地之盾\") and (not target.MyBuff:Has(\"闪电之盾\") and not target.MyBuff:Has(\"大地之盾\")) and A[\"大地之盾\"]:Cast(not focus:CanBeAssisted() and friends:GetMyBuffCount(\"大地之盾\", 60) == 0, target) if v then return v end\n",
            ["爆发技能"] = "--萨满祭司-增强-爆发技能\n\nlocal v\n\n--v = talent[\"巫医血统\"] and vars[\"爆发强度\"] > 0.8 and vars[\"爆发强度\"] < 2 and A[\"野性狼魂\"]:Cast() if v then return v  end\nif vars[\"爆发强度\"] < 2 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nif target.RangeToPlayer > 8 then\n    return\nend\n\nif talent[\"升腾\"] then\n    if vars[\"爆发强度\"] > 3 and A[\"升腾\"]:Cast() then\n        v = vars[\"爆发强度\"] > 4 and A[\"土元素\"]:Cast() if v then return v end\n        --v = A[\"野性狼魂\"]:Cast() if v then return v end\n        return run(\"一键爆发\")\n    end\nelse\n    v = vars[\"爆发强度\"] > 4 and A[\"土元素\"]:Cast() if v then return v end\n    v = A[\"毁灭之风\"]:Cast() if v then return run(\"一键爆发\") end\nend\n",
            ["输出"] = "--萨满祭司-增强-输出\nlocal v, v1\nvars[\"漩涡武器数\"] = player.MyBuff[\"漩涡武器\"].Count\nvars[\"升腾\"] = player.MyBuff:Has(\"升腾\")-- or player.MyBuff:Has(\"毁灭之风\")\n\n--v = talent[\"大地奔涌\"] and totems:GetTimeLeft(\"涌动图腾\") > 0 and A[\"裂地术\"]:ForceCast() if v then return v end\nv = A[\"烈焰震击\"]:Cast() if v then return v end\nv = A[\"流电炽焰\"]:Cast() if v then return v end\nif target.RangeToPlayer < 3 then\n    v = A[\"我_涌动图腾\"]:Cast() if v then return v end\n    v = A[\"裂地术\"]:IsActiveSpell() and A[\"裂地术\"]:ForceCast() if v then return v end\nend\n\nv = run(\"爆发技能\") if v then return v end\n--v = A[\"烈焰震击\"]:CastOnMinTime(nil, 40, 60) if v then return v end\nif vars[\"升腾\"]then\n    v = A[\"毁灭闪电\"]:Cast() if v then return v end\n    v = A[\"风切\"]:Cast() if v then return v end\nend\nif vars[\"漩涡武器数\"] > (talent[\"暴怒漩涡\"] and 8 or 4) and A[\"闪电链\"]:GetCurrentCastingTime() == 0 then\n    v = talent[\"始源风暴\"] and A[\"始源风暴\"]:IsActiveSpell() and A[\"始源风暴\"]:Cast() if v then return v end\n    v = talent[\"传导能量\"] and A[\"狂风怒号\"]:IsActiveSpell() and A[\"狂风怒号\"]:CastOnNoDebuff(\"引雷针\", 40, 60) or A[\"狂风怒号\"]:Cast() if v then return v end\n    if vars[\"敌方目标数量\"] > 2 then\n        v = talent[\"传导能量\"] and A[\"闪电链\"]:CastOnNoDebuff(\"引雷针\", 40, 60) or A[\"闪电链\"]:Cast() if v then return v end\n    else\n        v = talent[\"传导能量\"] and A[\"闪电箭\"]:CastOnNoDebuff(\"引雷针\", 40, 60) or A[\"闪电箭\"]:Cast() if v then return v end\n    end\nend\nv = A[\"毁灭闪电\"]:Cast() if v then return v end\nv = A[\"风暴打击\"]:GetChargeInfo():IsReachedOrSoon() and A[\"风暴打击\"]:Cast() if v then return v end\nv = A[\"熔岩猛击\"]:Cast() if v then return v end\nv = A[\"风暴打击\"]:Cast() if v then return v end\nv = A[\"冰霜震击\"]:Cast() if v then return v end\nif UnitLevel(\"player\") < 10 then\n    v = A[\"根源打击\"]:Cast() if v then return v end\nend\nv = A[\"狂野扑击\"]:Cast() if v then return v end\n",
            ["输出初始化"] = "--萨满祭司-增强-输出初始化\nreturn run(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["恢复"] = {
            ["_专精初始化"] = "--萨满祭司-恢复-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--萨满祭司-恢复-_脚本初始化\nrun(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--萨满祭司-恢复-保命\nlocal v\nif SwitchIsOn(\"武器附魔\") then\n    local hasMainHandEnchant, _, _, _, hasOffHandEnchant = GetWeaponEnchantInfo()\n    if not hasMainHandEnchant and GetInventoryItemLink(\"player\", 16) then--主手\n        v = talent[\"大地生命武器\"] and A[\"大地生命武器\"]:Cast() if v then return v end\n    end\n    if not hasOffHandEnchant and talent[\"辅助灌魔\"] then--副手\n        v = GetInventoryItemLink(\"player\", 17)\n        if v and select(7, GetItemInfo(v)) == \"盾牌\" then\n            v = A[\"唤潮者的护卫\"]:Cast() if v then return v end\n        end\n    end\nend\nif not inCombat then\n    v = run(\"护盾\") if v then return v end\n    v = A[\"天怒\"]:Cast() if v then return v end\n    return\nend\n--v = A[\"石壁图腾\"]:Cast(player.HealthPercent < 0.5) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"星界转移\"]:Cast() if v then return v end\nv = run(\"护盾\") if v then return v end\n--v = A[\"法力之潮图腾\"]:Cast(player:GetPowerPercent(P[\"法力\"]) < 0.2) if v then return v end\n--v = A[\"法力之泉图腾\"]:Cast() if v then return v end\nv = A[\"天怒\"]:Cast() if v then return v end\nv = run(\"虚空裂隙\") if v then return v end --词缀\n",
            ["打爆炸物"] = "--萨满祭司-恢复-打爆炸物\nlocal v\nv = A[\"闪电链\"]:GetCurrentCastingTime() == 0 and A[\"闪电链\"]:Cast() if v then return v end\nv = A[\"冰霜震击\"]:Cast() if v then return v end\nv = A[\"熔岩爆裂\"]:Cast(player.MyBuff:Has(\"熔岩奔腾\")) if v then return v end\nv = A[\"闪电链\"]:Cast() if v then return v end\nv = A[\"闪电箭\"]:Cast() if v then return v end\n",
            ["治疗"] = "--萨满祭司-恢复-治疗\nlocal v\nif inCombat then\n    v = SwitchIsOn(\"取消施法\") and A[\"治疗波\"]:ShouldCancelCasting(0.85) and A[\"取消施法\"]:Cast() if v then return v end \n    v = SwitchIsOn(\"取消施法\") and A[\"治疗链\"]:ShouldCancelCasting(0.85) and A[\"取消施法\"]:Cast() if v then return v end \n    v = A[\"灵魂链接图腾\"]:Cast() if v then return v end\n    v = A[\"治疗之潮图腾\"]:Cast(player.MyBuff[\"升腾\"]:GetTimeLeft() < 1) if v then return v end\n    v = A[\"升腾\"]:Cast() if v then return run(\"一键爆发\") end\n    v = healTarget.HealthPercent < 0.5 and (A[\"自然迅捷\"]:Cast() or A[\"先祖迅捷\"]:Cast()) if v then return v end\n    v = A[\"治疗链\"]:GetCurrentCastingTime() == 0 and A[\"治疗链\"]:Cast(healTarget.HealthPercent < 0.8 and healTarget.HealthPercent > 0.3, healTarget) if v then return v end\n    v = A[\"生命释放\"]:Cast(healTarget.HealthPercent < 0.6, healTarget) if v then return v end\n    v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    v = A[\"激流\"]:Cast(healTarget.HealthPercent < 0.6, healTarget) if v then return v end\n    v = A[\"治疗链\"]:GetCurrentCastingTime() == 0 and A[\"治疗链\"]:Cast(healTarget.HealthPercent < 0.8 and healTarget.HealthPercent > 0.35, healTarget) if v then return v end\n    v = (not talent[\"治疗之潮图腾\"] or totems:GetTimeLeft(\"治疗之潮图腾\") < 0.5) and totems:GetTimeLeft(\"治疗之泉图腾\") < 0.5 and A[\"治疗之泉图腾\"]:Cast() if v then return v end\n    v = A[\"倾盆大雨\"]:IsActiveSpell() and A[\"倾盆大雨\"]:Cast() if v then return v end\n    v = not talent[\"涌动图腾\"] and A[\"治疗之雨\"]:Cast() if v then return v end\n    v = talent[\"涌动图腾\"] and A[\"涌动图腾\"]:Cast() if v then return v end\n--    v = talent[\"涌动图腾\"] and A[\"我_涌动图腾\"]:Cast() if v then return v end\nend\n\nv = A[\"激流\"]:Cast(healTarget.HealthPercent < 0.9, healTarget) if v then return v end\nv = A[\"生命释放\"]:Cast(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\nv = A[\"治疗链\"]:Cast(healTarget.HealthPercent < 0.8 and healTarget.HealthPercent > 0.35, healTarget) if v then return v end\n\nif SwitchIsOn(\"治疗波\") then\n    v = A[\"治疗波\"]:Cast(healTarget.HealthPercent < 0.6, healTarget) if v then return v end\n    v = not A[\"治疗波\"]:IsCasting() and A[\"治疗波\"]:CastSafely(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\nend\n\nv = inCombat and healTarget.HealthPercent < 0.5 and player:IsMoving() and A[\"灵魂行者的恩赐\"]:Cast() if v then return v end\nv = SwitchIsOn(\"预铺激流\") and run(\"预铺Buff\", A[\"激流\"]) if v then return v end\n",
            ["输出"] = "--萨满祭司-恢复-输出\nlocal v\nif not inCombat then\n    if vars[\"敌方目标数量\"] > 2  then\n        v = A[\"闪电链\"]:Cast(not A[\"闪电链\"]:CastedIn(3)) if v then return v end\n    else\n        v = A[\"熔岩爆裂\"]:Cast(not A[\"熔岩爆裂\"]:CastedIn(3)) if v then return v end\n        v = A[\"闪电箭\"]:Cast(not A[\"闪电箭\"]:CastedIn(3) and not A[\"熔岩爆裂\"]:CastedIn(3)) if v then return v end\n    end\nend\nv = A[\"烈焰震击\"]:Cast() if v then return v end\nv = A[\"净化术\"]:Cast() if v then return v end\nv = A[\"熔岩爆裂\"]:Cast(player.MyBuff:Has(\"熔岩奔腾\")) if v then return v end\n--v = vars[\"爆发强度\"] > 1.3 and SwitchIsOn(\"风暴守护者\") and A[\"风暴守护者\"]:Cast() if v then return v end\nv = A[\"闪电链\"]:Cast() if v then return v end\nv = A[\"熔岩爆裂\"]:Cast() if v then return v end\nv = A[\"闪电箭\"]:Cast() if v then return v end\n\nv = SwitchIsOn(\"鼠指烈焰\") and A[\"烈焰震击\"]:Cast(nil, mouseover) if v then return v end\nv = A[\"根源打击\"]:Cast() if v then return v end\n",
        },
    },
}
JAutoActionV3_DefaultScripts_Classic = 
{
    ["全职业"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--全职业-全专精-_专精初始化\n--如果2者同时启用，则仅【需要打断的法术列表】生效\n--vars[\"需要打断的法术列表\"]:Enable()\n--vars[\"需要打断的法术列表\"]:Clear()\n--vars[\"需要打断的法术列表\"]:Add(\"心灵震爆\")\n\n--vars[\"无需打断的法术列表\"]:Enable()\n--vars[\"无需打断的法术列表\"]:Clear()\n--vars[\"无需打断的法术列表\"]:Add(\"心灵震爆\")\n\n--AddCommonPriorMacro(\"J项链技能\", 3, \"艾泽拉斯之心精华\", \"项链技能\")\nvars[\"PVP爆发阈值\"] = 0.5\nvars[\"敌方目标距离\"] = 8\n\n--自定义宏的写法如下, 注意名字不要和现有的重复!!! 可以自己加上特殊的前后缀之类的\n--AddMacro(\"MY自定义宏名字\", \"/say 我的自定义宏第一行\\n/say 我的自定义宏第二行\") --\\n是换行符\n--使用时与其他技能用法相同\n--v = A[\"MY自定义宏名字\"]:Cast() if v then return v end\n\n\n",
            ["_脚本初始化"] = "--全职业-全专精-_脚本初始化\n--脚本开始时执行\nrun(\"更新爆发饰品\")\nreturn",
            ["_装备初始化"] = "--全职业-全专精-_装备初始化\nreturn",
            ["一键爆发"] = "--全职业-全专精-一键爆发\nif A[\"一键爆发\"]:IsProtected() then\n    return\nend\nif gcd > 0.5 then\n    return 0\nend\nlocal p\nif inTraining then\n    p = SwitchIsOn(\"Boss药水\") and \"BP\" or (SwitchIsOn(\"副本药水\") and \"FP\")\nelseif inPVE then\n    if boss.IsTarget then\n       p = SwitchIsOn(\"Boss药水\") and \"BP\"\n    else\n       p = SwitchIsOn(\"副本药水\") and \"FP\"\n    end\nelseif inPVP then\n    p = SwitchIsOn(\"PVP药水\") and \"PP\"\nend\nif not p then\n    p = \"\"\nend\nlocal s = \"\"\nlocal cd = 9999\nif SwitchIsOn(\"饰品1\") and vars[\"爆发饰品1\"] then\n    s = \"S1\"\n    cd = vars[\"爆发饰品1\"]:GetCooldown() or 0\nend\nif SwitchIsOn(\"饰品2\") and vars[\"爆发饰品2\"] then\n    s = s .. \"S2\"\n    cd = math.min(vars[\"爆发饰品2\"]:GetCooldown(), cd)\nend\nif cd > 0.2 and cd < 10 then\n    return\nend\n--print(\"一键爆发\" .. s .. p, A[\"一键爆发\" .. s .. p])\nlocal v = A[\"一键爆发\" .. s .. p]\nif not v or A[\"一键爆发\"]:IsProtected() then\n    return\nend\nif not UnitCastingInfo(\"player\") and not UnitChannelInfo(\"player\") then\n    A[\"一键爆发\"]:Protect(3, 0.3)\nend\nreturn v:Cast()\n",
            ["使用饰品"] = "--全职业-全专精-使用饰品\n\n--如果饰品可用,则立即使用\n--用法 v = run(\"使用饰品\", \"饰品名\") if v then return v end\n--或者 v = run(\"使用饰品\", \"饰品名\", 额外条件, 目标) if v then return v end\nlocal name, condition, castTo, leadCd = ...\nif condition == false then\n	return\nend\nlocal v\nif SwitchIsOn(\"饰品1\") and A[\"饰品1\"]:IsItem(name) then\n	v = A[\"饰品1\"]:Cast(nil, castTo) if v then return v end\nelseif SwitchIsOn(\"饰品2\") and A[\"饰品2\"]:IsItem(name) then\n	v = A[\"饰品2\"]:Cast(nil, castTo) if v then return v end\nend\n",
            ["保命"] = "--全职业-全专精-保命\nreturn",
            ["发送按键"] = "--全职业-全专精-发送按键\n--用法：创建一个宏，内容是： /jaa 发送按键 key interval\n--x为你想要发送的按键, 数字和字母直接写, 如果要发送F1-F12， 需要写 KEY_F1 \n--例如： /jaa 发送按键 P 60         会每隔60秒发送一个P按键\nlocal key, interval = ...\nif tonumber(interval) then\n    if not vars[\"上次发送按键时间\"] or (GetTime() - vars[\"上次发送按键时间\"] > tonumber(interval)) then\n        vars[\"上次发送按键时间\"] = GetTime()\n        return key \n    end\nelse\n    return key \nend\n",
            ["取得嗜血剩余时间"] = "--全职业-全专精-取得嗜血剩余时间\nlocal v\nv = player.AllBuff[\"嗜血\"]\nif v.SpellID == 2825 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"远古狂乱\"]\nif v.SpellID == 90355 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"英勇\"]\nif v.SpellID == 32182 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"时间扭曲\"]\nif v.SpellID == 80353 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"虚空之风\"]\nif v.SpellID == 160452 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"原始暴怒\"]\nif v.SpellID == 264667 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nv = player.AllBuff[\"死亡凶蛮战鼓\"]\nif v.SpellID == 309658 then\n	vars[\"嗜血剩余时间\"] = v:GetTimeLeft()\n	if vars[\"嗜血剩余时间\"] > 0 then\n		return\n	end\nend\nvars[\"嗜血剩余时间\"] = 0\n",
            ["取得爆发强度"] = "--全职业-全专精-取得爆发强度\nif boss.Exists and not boss.InCombat then\n    --print(\"boss存在但不在战斗\")\n    return 0 --不爆发\nend\nif target.IsTrainDummy then\n    return 99\nend\nif inPvpCombat then\n	if target.IsPlayer then\n		return target.HealthPercent <= (vars[\"PVP爆发阈值\"] or 0.5) and 5 or 1\n	else\n		return 0\n	end\nend\n\nif boss.Exists then -- boss战\n    if target.IsBoss then\n        if inRaid then --团本boss\n            return 98\n        elseif inParty then --5人本boss\n            if target:TimeToDie() > 15 then\n                return 88\n            else\n                return target.Health / (player.HealthBaseline * inParty)\n            end\n        else --野外boss\n            if target:TimeToDie() > 15 then\n                return 50\n            else\n                return target.Health / (player.HealthBaseline * inRaid)\n            end\n        end\n    elseif inPVE then\n        return target.Health / (player.HealthBaseline * (inParty and (inParty * 2) or (inRaid * 2)))\n    end\nelseif inRaid then -- 团本小怪,无boss\n	return vars[\"敌方目标总血量\"] / (player.HealthBaseline * inRaid * 0.6)\nelseif battleType == \"小队\" then -- 小队小怪,无boss\n	return vars[\"敌方目标总血量\"] / (player.HealthBaseline * inParty * 0.6)\nelse --野外\n	return vars[\"敌方目标总血量\"] / (player.HealthBaseline * 0.7)\nend\nreturn 0\n\n",
            ["取得目标强度"] = "--全职业-全专精-取得目标强度\nlocal unit = ... or target\nif unit.IsTrainDummy then\n    return 99\nend\nif inPvpCombat then\n	if unit.IsPlayer then\n		return unit.HealthPercent <= (vars[\"PVP爆发阈值\"] or 0.5) and 5 or 2\n	else\n		return 0\n	end\nend\n--if unit.IsBoss then\n--    return inParty and 4.1 or 5\n--end\n\nif inRaid then -- 团本小怪,无boss\n	return unit.Health / (player.HealthBaseline * inRaid * 0.5)\nelseif battleType == \"小队\" then -- 小队小怪,无boss\n	return unit.Health / (player.HealthBaseline * inParty * 0.6)\nelse --野外\n	return unit.Health / (player.HealthBaseline * 0.7)\nend\nreturn 0\n\n",
            ["基本检查"] = "--全职业-全专精-基本检查\nif IsMounted() then --在坐骑上\n    return\nend\nif UnitIsDeadOrGhost(\"player\") then --已死亡\n    return\nend\nif run(\"正在引导法术\") then --正在引导法术\n    return\nend\nif inCombat and IsForceStart() then\n    return true\nend\nif  player.MyBuff:Has(\"灵魂变形\") then \n    return\nend\nif ... then --附加check\n    return\nend\nreturn true",
            ["安全嘲讽"] = "--全职业-全专精-安全嘲讽\nif player.TauntSpell then\n    return player.TauntSpell:Cast()\nend\n",
            ["安全引导"] = "--全职业-全专精-安全引导\nlocal actionName, castTo, params = ...\nlocal v = A[actionName]:Cast(nil, castTo, params)\nif v then\n	A[actionName]:Protect(1.5)\n	--print(1, A[actionName]:Cast(nil, castTo) or 0, GetTime())\n	return v\nelseif A[actionName]:IsProtected() then\n	v = A[actionName]:GetCooldown()\n	if v > 10 and v < select(2, GetSpellCooldown(actionName)) - 2 then\n		--print(\"安全引导1\", actionName, GetTime())\n		return\n	else\n		--print(\"安全引导2\", actionName, GetTime())\n		return 0\n	end\nelse\n	--print(4, v, GetTime())\nend\n\n\n",
            ["强制执行"] = "--全职业-全专精-强制执行\nreturn",
            ["打断"] = "--全职业-全专精-打断\nif player.InterruptSpell then\n    return player.InterruptSpell:Cast(nil, ...)\nend\n",
            ["智能上马"] = "--全职业-全专精-智能上马\nif A[\"召唤随机坐骑\"]:IsProtected() then\n    return -1 ----停止优先宏\nend\nlocal v\nlocal cls = UnitClass(\"player\")\nif cls == \"德鲁伊\" then\n    if IsIndoors() then\n        if not player.MyBuff:Has(\"猎豹形态\") then\n            return A[\"猎豹形态\"]:Cast()\n        else\n            A[\"召唤随机坐骑\"]:Protect(1, 0)\n            return A[\"取消猎豹形态\"]:Cast()\n        end\n    end\n    if player.MyBuff:Has(\"旅行形态\") then\n        A[\"召唤随机坐骑\"]:Protect(1, 0)\n        return A[\"取消旅行形态\"]:Cast()\n    end\n    if not IsMounted() and (player:IsMoving() or inCombat) then\n        return A[\"旅行形态\"]:Cast()\n    end\nelseif cls == \"萨满祭司\" then\n    if IsIndoors() then\n        if not player.MyBuff:Has(\"幽魂之狼\") then\n            return A[\"幽魂之狼\"]:Cast()\n        else\n            A[\"召唤随机坐骑\"]:Protect(1, 0)\n            return A[\"取消幽魂之狼\"]:Cast()\n        end\n    end\nend\nif IsMounted() and not player.MyBuff:Has(\"神圣马驹\") then\n    Dismount()\n    return -1\nend\nif C_Map.GetBestMapForUnit(\"player\")==1543 then \n    C_MountJournal.SummonByID(1442)\nelse\n    C_MountJournal.SummonByID(0)\n    --return A[\"召唤随机坐骑\"]:Cast()\nend\nreturn -1\n",
            ["更新治疗饰品"] = "--全职业-全专精-更新治疗饰品\nvars[\"可用治疗饰品\"] = vars[\"可用治疗饰品\"] or {\"法缚威镜\", \"焖燃飞羽绒簇\"}\nvars[\"治疗饰品1\"] = false\nvars[\"治疗饰品2\"] = false\n\nfor _, v in pairs(vars[\"可用治疗饰品\"]) do\n    if A[\"饰品1\"]:IsItem(v) then\n        vars[\"治疗饰品1\"] = A[\"饰品1\"]\n    elseif A[\"饰品2\"]:IsItem(v) then\n        vars[\"治疗饰品2\"] = A[\"饰品2\"]\n    end\nend\n",
            ["更新爆发饰品"] = "--全职业-全专精-更新爆发饰品\nif not vars[\"无效饰品\"] then\n    vars[\"无效饰品\"] = \n    {\n        \"帕库冠羽\",\n        \"噩兆多彩精华\",\n    }\n    if vars[\"可用治疗饰品\"] then\n        for _, v in pairs(vars[\"可用治疗饰品\"]) do\n            table.insert(vars[\"无效饰品\"], v)\n        end\n    end\nend\nvars[\"爆发饰品1\"] = A[\"饰品1\"]:CanBeUsedInBurstMacro() and A[\"饰品1\"]\nvars[\"爆发饰品2\"] = A[\"饰品2\"]:CanBeUsedInBurstMacro() and A[\"饰品2\"]\n\nfor _, v in pairs(vars[\"无效饰品\"]) do\n    if A[\"饰品1\"]:IsItem(v) then\n        vars[\"爆发饰品1\"] = false\n    elseif A[\"饰品2\"]:IsItem(v) then\n        vars[\"爆发饰品2\"] = false\n    end\nend\n",
            ["正在引导法术"] = "--全职业-全专精-正在引导法术\n--可重载\nreturn player:GetChannelingSpell() --正在引导法术\n",
            ["治疗"] = "--全职业-全专精-治疗\nreturn",
            ["爆发技能"] = "--全职业-全专精-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n	return\nend\nreturn run(\"一键爆发\")\n",
            ["目标已无敌"] = "--全职业-全专精-目标已无敌\nlocal v\nif target.AllBuff:Has(\"圣盾术\") or target.AllBuff:Has(\"寒冰屏障\") or target.AllBuff:Has(\"灵龟守护\") then\n    return 0\nend\n",
            ["立即一键爆发"] = "--全职业-全专精-立即一键爆发\n--if A[\"一键爆发\"]:IsProtected() then\n--    return\n--end\n--if gcd > 0.5 then\n--    return 0\n--end\nlocal p\nif inTraining then\n    p = SwitchIsOn(\"Boss药水\") and \"BP\" or (SwitchIsOn(\"副本药水\") and \"FP\")\nelseif inPVE then\n    if boss.IsTarget then\n       p = SwitchIsOn(\"Boss药水\") and \"BP\"\n    else\n       p = SwitchIsOn(\"副本药水\") and \"FP\"\n    end\nelseif inPVP then\n    p = SwitchIsOn(\"PVP药水\") and \"PP\"\nend\nif not p then\n    p = \"\"\nend\nlocal s = \"\"\nif SwitchIsOn(\"饰品1\") and vars[\"爆发饰品1\"] then\n    s = \"S1\"\nend\nif SwitchIsOn(\"饰品2\") and vars[\"爆发饰品2\"] then\n    s = s .. \"S2\"\nend\n--print(\"一键爆发\" .. s .. p, A[\"一键爆发\" .. s .. p])\nlocal v = A[\"一键爆发\" .. s .. p]\nif not v then\n    return\nend\nif player.BurstSpell then\n    p = A[player.BurstSpell]\n    if p and p:CastedIn(gcdmax) then\n        return false\n    end\nend\n--if not UnitCastingInfo(\"player\") and not UnitChannelInfo(\"player\") then\n--    A[\"一键爆发\"]:Protect(3, 0.3)\n--end\nreturn v:Cast()\n",
            ["补刀"] = "--全职业-全专精-补刀\nreturn\n",
            ["输出"] = "--全职业-全专精-输出\nPrint(\"当前专精没有内置输出脚本, 请打开Hekili开关\")\nreturn",
            ["输出初始化"] = "--全职业-全专精-输出初始化\nlocal unit, rangeLimit = ...\nvars[\"敌方目标\"] = enemies:GetNearbyInfo(unit or target, rangeLimit or 8)\nvars[\"敌方目标数量\"] = SwitchIsOn(\"仅单体\") and 1 or vars[\"敌方目标\"][\"数量\"]\nvars[\"敌方不动目标数量\"] = SwitchIsOn(\"仅单体\") and 1 or vars[\"敌方目标\"][\"不动数量\"]\nvars[\"敌方目标总血量\"] = vars[\"敌方目标\"][\"总剩余血量\"]\nvars[\"爆发强度\"] = run(\"取得爆发强度\")\nvars[\"目标强度\"] = run(\"取得目标强度\")\nvars[\"目标死亡时间\"] = target:TimeToDie()\nrun(\"取得嗜血剩余时间\")\n\n",
            ["输出前"] = "--全职业-全专精-输出前\nreturn",
            ["输出流程"] = "--全职业-全专精-输出流程\nlocal v\n--v = (battleType == \"小队\") and A[\"打爆炸物\"]:Cast() if v then return v end --\n--v = run(\"远程拾取器\") if v then return v end\n--v = A[\"打爆炸物\"]:Cast() if v then return v end --\n--v = A[\"虚体生物\"]:Cast() if v then return v end --\n--print(SwitchIsOn(\"切换敌方\") and inCombat and not target.IsEnemy)\nif inCombat and not target.IsEnemy then --SwitchIsOn(\"切换敌方\") and \n	return A[\"选择目标\"]:TargetFrontEnemy()\nend\n\nif not target.IsEnemy then\n	return A[\"停止攻击\"]:Cast()\nend\nif not IsForceStart() then\n    if not inCombat then\n        --Debug(\"防止误开怪\")\n        --pauseHekili()\n		return A[\"停止攻击\"]:Cast()\n        --return 0\n    end\n    if not target.NeedAttack then\n        Debug(\"目标不在战斗中\")\n		return A[\"停止攻击\"]:Cast()\n        --return 0\n    end\nend\nv = SwitchIsOn(\"打断焦点\") and focus.IsEnemy and run(\"打断\", focus) if v then return v end\nv = SwitchIsOn(\"打断目标\") and run(\"打断\") if v then return v end\n--目标已无敌\nif target.IsPlayer and target.PhysicalReduce == 1 and target.MagicReduce == 1 then \n    Debug(\"目标已无敌\")\n	return 0\nend\n\nv = A[\"宠物攻击\"]:Cast() if v then return v end\n--local isAoe, count = run(\"取得目标数\", battleType)\n--v = run(battleType .. \"输出\" .. (isAoe and \"AOE\" or \"单体\"), count) if v then return v end\n--v = run(\"Simc\") if v then return v end\n--run(\"输出初始化\")\nv = run(\"输出初始化\") if v then return v end\n--v = A[\"自动攻击\"]:Cast() if v then return v end\nv = vars[\"敌方目标数量\"] == 1 and run(\"补刀\") if v then return v end\nv = run(\"输出前\") if v then return v end\nif SwitchIsOn(\"内置一键\") then-- and not player.IsHealer\n    v = hekili() if v then return v end\nelse\n    v = run(\"输出\") if v then return v end\nend\n--if inCombat then\n--    return A[\"自动攻击\"]:Cast()\n--end\n",
            ["远程拾取器"] = "--全职业-全专精-远程拾取器\nlocal v\nif inInstance or not SwitchIsOn(\"远程拾取器\") then\n    return\nend\nif not A[\"远程拾取器\"]:IsReady() then\n    return\nend\nif A[\"远程拾取器\"]:IsProtected() then\n    return\nend\nA[\"远程拾取器\"]:Protect(60)\nError(\"警告:长时间使用[远程拾取器]自动挂机有可能导致封号, 使用此功能后果自负!!!\")\nreturn A[\"远程拾取器\"]:Cast()\n",
            ["选择治疗目标"] = "--全职业-全专精-选择治疗目标\nlocal v = friends:GetMinHealthPercentUnit()\n--if v and v.UnitId then\n	--print(\"选择治疗目标\", UnitName(v.UnitId), v.HealthPercent)\n--end\nreturn v\n",
            ["防暂离"] = "--全职业-全专精-防暂离\nlocal t = GetTime() - (vars[\"上次时间\"] or 0)\nif t > 10 then\n    if t > 15 then\n        vars[\"上次时间\"] = GetTime()\n    end\n    return \"A\"\nend",
            ["饰品治疗"] = "--全职业-全专精-饰品治疗\nlocal castTo = ...\nlocal v\nv = vars[\"治疗饰品1\"] and vars[\"治疗饰品1\"]:Cast(nil, castTo) if v then return v end \nv = vars[\"治疗饰品2\"] and vars[\"治疗饰品2\"]:Cast(nil, castTo) if v then return v end \n",
            ["默认"] = "--全职业-全专精-默认\n--通过run函数执行子脚本的时候，如果存在当前执行主脚本的名字作为前缀的脚本，则会优先执行\n--例如在执行主脚本【默认】时，如果存在子脚本【默认初始化】，则该脚本会优先被执行\nreturn run(\"默认流程\")",
            ["默认流程"] = "--全职业-全专精-默认流程\nlocal v\n--if SwitchIsOn(\"强制驱散\") then\n--	--优先驱散列表中的debuff\n--    v = ForceDispelFriend() if v then return v end --\"优先驱散友方\" \n--end\n\n--v = A[\"治疗石\"]:Cast(player.HealthPercent < (battleType == \"野外\" and 0.55 or 0.35) and SwitchIsOn(\"治疗石\") and A[\"治疗石\"]:GetCount() > 0 and not A[\"治疗石\"]:FailedIn(10, \"物品还没有准备好\")) if v then return v end\n\n--自己保命\nhealTarget = player --保命内脚本应该是直接使用player, 此处为了保险起见, 设置为player\nv = run(\"保命\") if v then return v end\nv = SwitchIsOn(\"驱散友方\") and DispelFriend() if v then return v end\n\n--治疗目标\nif target.IsFriend and target.HealReduce < 0.9 then\n	healTarget = target\n	--healTarget:UpdateReduceV3()\n    v = run(\"治疗\") if v then return v end\nend\n\nif player.IsHealer then\n	--v = (battleType == \"小队\") and A[\"打爆炸物\"]:Cast() if v then return v end --\n	--治疗专精\n	if focus.IsFriend and focus.HealReduce < 0.9 then\n		healTarget = focus\n		--healTarget:UpdateReduceV3()\n		v = run(\"治疗\") if v then return v end\n	end\n    if SwitchIsOn(\"切换友方\") then\n        healTarget = run(\"选择治疗目标\") or false\n		if healTarget then\n			--healTarget:UpdateReduceV3()\n			v = run(\"治疗\") if v then return v end\n		end\n    end\n    if SwitchIsOn(\"打断焦点\") and focus.IsEnemy then\n        v = run(\"打断\", focus) if v then return v end\n    elseif SwitchIsOn(\"打断目标\") then\n        v = run(\"打断\") if v then return v end\n    end\n    if not target.IsFriend and SwitchIsOn(\"攻击敌方\") then\n        v = run(\"输出流程\") if v then return v end\n    end\nelseif not target.IsFriend then\n	--非治疗专精\n    v = run(\"输出流程\") if v then return v end\nend\n",
        },
    },
    ["圣骑士"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--圣骑士-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["保命"] = "--圣骑士-全专精-保命\nlocal v\nlocal sds = player.MyBuff:Has(\"圣盾术\")\nif sds then\n    v = SwitchIsOn(\"无敌闪现\") and A[\"圣光闪现\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n    v = SwitchIsOn(\"无敌闪现\") and A[\"圣光闪现\"]:CastSafely(player.HealthPercent < 0.8, player) if v then return v end\n    return \nend\nif not inCombat then\n    v = SwitchIsOn(\"圣光闪现\") and A[\"圣光闪现\"]:Cast(player.HealthPercent < 0.7, player) if v then return v end\n    v = SwitchIsOn(\"圣光闪现\") and A[\"圣光闪现\"]:CastSafely(player.HealthPercent < 0.8, player) if v then return v end\n    v = run(\"祝福\") if v then return v end\n    v = run(\"圣印\") if v then return v end\n    return \nend\n\nif not player.AllBuff:Has(\"自律\") and not A[\"复仇之怒\"]:SucceededIn(30) then\n    v = SwitchIsOn(\"圣佑术\") and A[\"圣佑术\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"圣盾术\") and A[\"圣盾术\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"圣疗术\") and A[\"圣疗术\"]:Cast(player.HealthPercent < ((player.AllReduce > 0.2) and 0.2 or 0.25), player) if v then return v end\nend\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n\nv = run(\"祝福\") if v then return v end\nv = run(\"圣印\") if v then return v end\n\n\n\n\n",
            ["圣印"] = "--圣骑士-全专精-圣印\nlocal v\nif SwitchIsOn(\"命令圣印\") and A[\"命令圣印\"].IsValid then\n    v = A[\"命令圣印\"]:Cast(nil, player) if v then return v end\nelseif SwitchIsOn(\"腐蚀圣印\") and A[\"腐蚀圣印\"].IsValid then\n    v = A[\"腐蚀圣印\"]:Cast(nil, player) if v then return v end\nelseif SwitchIsOn(\"光明圣印\") and A[\"光明圣印\"].IsValid then\n    v = A[\"光明圣印\"]:Cast(nil, player) if v then return v end\nelseif SwitchIsOn(\"智慧圣印\") and A[\"智慧圣印\"].IsValid then\n    v = A[\"智慧圣印\"]:Cast(nil, player) if v then return v end\nelseif SwitchIsOn(\"公正圣印\") and A[\"公正圣印\"].IsValid then\n    v = A[\"公正圣印\"]:Cast(nil, player) if v then return v end\nelseif SwitchIsOn(\"正义圣印\") and A[\"正义圣印\"].IsValid then\n    v = A[\"正义圣印\"]:Cast(nil, player) if v then return v end\nend\n",
            ["基本检查"] = "--圣骑士-全专精-基本检查\nif IsMounted() and not player.MyBuff:Has(\"神圣马驹\") then --在坐骑上\n    return\nend\nif UnitIsDeadOrGhost(\"player\") then --已死亡\n    return\nend\nif run(\"正在引导法术\") then --正在引导法术\n    return\nend\nif inCombat and IsForceStart() then\n    return true\nend\nif  player.MyBuff:Has(\"灵魂变形\") then \n    return\nend\nif ... then --附加check\n    return\nend\nreturn true",
            ["审判"] = "--圣骑士-全专精-审判\nlocal v\nif SwitchIsOn(\"圣光审判\") and A[\"圣光审判\"].IsValid then\n    v = A[\"圣光审判\"]:Cast() if v then return v end\nelseif SwitchIsOn(\"智慧审判\") and A[\"智慧审判\"].IsValid then\n    v = A[\"智慧审判\"]:Cast() if v then return v end\nelseif SwitchIsOn(\"公正审判\") and A[\"公正审判\"].IsValid then\n    v = A[\"公正审判\"]:Cast() if v then return v end\nend\n",
            ["祝福"] = "--圣骑士-全专精-祝福\nlocal v\nif SwitchIsOn(\"力量祝福\") and A[\"力量祝福\"].IsValid then\n    v = A[\"力量祝福\"]:Cast(nil, player) if v then return v end\nelseif SwitchIsOn(\"智慧祝福\") and A[\"智慧祝福\"].IsValid then\n    v = A[\"智慧祝福\"]:Cast(nil, player) if v then return v end\nelseif SwitchIsOn(\"王者祝福\") and A[\"王者祝福\"].IsValid then\n    v = A[\"王者祝福\"]:Cast(nil, player) if v then return v end\nelseif SwitchIsOn(\"庇护祝福\") and A[\"庇护祝福\"].IsValid then\n    v = A[\"庇护祝福\"]:Cast(nil, player) if v then return v end\nend\n",
            ["输出初始化"] = "--圣骑士-全专精-输出初始化\nrun(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["惩戒"] = {
            ["_专精初始化"] = "--圣骑士-惩戒-_专精初始化\nrun(\"全专精-_专精初始化\")\n\n",
        },
        ["神圣"] = {
            ["_专精初始化"] = "--圣骑士-神圣-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--圣骑士-神圣-_脚本初始化\nrun(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n",
            ["圣光道标"] = "--圣骑士-神圣-圣光道标\nif not SwitchIsOn(\"圣光道标\") then\n    return\nend\nif friends:GetMyBuffCount(\"圣光道标\", 60) > 0 then\n    return\nend\nif healTarget.UnitId and UnitIsUnit(healTarget.UnitId, \"focus\") then\n    if not healTarget.MyBuff:Has(\"圣光道标\") then\n        v = A[\"圣光道标\"]:Cast(nil, healTarget) if v then return v end\n    end\nend\nif inParty or inRaid then\n    if healTarget:GetDuty() == \"TANK\" then\n        --print(UnitName(healTarget.UnitId), healTarget:GetDuty())\n        v = A[\"圣光道标\"]:Cast(nil, healTarget) if v then return v end\n    end\nelseif inPVP then\n    v = A[\"圣光道标\"]:Cast(nil, player) if v then return v end\nend",
            ["圣洁护盾"] = "--圣骑士-神圣-圣洁护盾\nif not SwitchIsOn(\"圣洁护盾\") then\n    return\nend\nif friends:GetMyBuffCount(\"圣洁护盾\", 60) > 0 then\n    return\nend\n--if healTarget.UnitId and UnitExists(\"focus\") and UnitExists(healTarget.UnitId) and UnitIsUnit(healTarget.UnitId, \"focus\") then\nif healTarget.UnitId and UnitIsUnit(healTarget.UnitId, \"focus\") then\n    if not healTarget.MyBuff:Has(\"圣洁护盾\") then\n        v = A[\"圣洁护盾\"]:Cast(nil, healTarget) if v then return v end\n    end\nend\nif inParty or inRaid then\n    if healTarget:GetDuty() == \"TANK\" then\n        --print(UnitName(healTarget.UnitId), healTarget:GetDuty())\n        v = A[\"圣洁护盾\"]:Cast(nil, healTarget) if v then return v end\n    end\nelse\n    v = A[\"圣洁护盾\"]:Cast(nil, player) if v then return v end\nend",
            ["治疗"] = "--圣骑士-神圣-治疗\nlocal v\nif inCombat then\n    vars[\"光之优雅\"] = talent[\"光之优雅\"] and player.MyBuff[\"光之优雅\"]:GetTimeLeft() or 99\n    v = A[\"圣光闪现\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    v = A[\"圣光术\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n\n    v = SwitchIsOn(\"圣疗术\") and A[\"圣疗术\"]:Cast(healTarget.HealthPercent < 0.2, healTarget) if v then return v end\n    v = SwitchIsOn(\"神恩术\") and healTarget.HealthPercent < 0.5 and A[\"神恩术\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"神圣恳求\") and healTarget.HealthPercent > 0.85 and player:GetPowerPercent(P[\"法力\"]) < 0.7 and A[\"神圣恳求\"]:Cast() if v then return v end\n    v = A[\"神圣震击\"]:Cast(healTarget.HealthPercent < 0.65, healTarget) if v then return v end\n    v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    v = run(\"圣洁护盾\") if v then return v end\n    v = run(\"圣光道标\") if v then return v end\n    if inCombat and target.NeedAttack and healTarget.HealthPercent > 0.65 and target.IsEnemy then\n        v = SwitchIsOn(\"圣光审判\") and A[\"圣光审判\"]:Cast() if v then return v end\n    end\n    vars[\"无敌中\"] = player.MyBuff:Has(\"圣盾术\")\n    v = SwitchIsOn(\"牺牲之手\") and A[\"牺牲之手\"]:Cast(inPVE and healTarget.HealthPercent < 0.4 and not UnitIsUnit(healTarget.UnitId, \"player\") and (player.HealthPercent > 0.6 or vars[\"无敌中\"]), healTarget) if v then return v end\n    v = SwitchIsOn(\"复仇之怒\") and A[\"复仇之怒\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"光环掌握\") and A[\"光环掌握\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"神启\") and player:GetPowerPercent(P[\"法力\"]) < 0.75 and A[\"神启\"]:Cast() if v then return v end\n\n    if SwitchIsOn(\"圣光术\") and talent[\"光之优雅\"] then\n        if healTarget.HealthPercent < 0.8 or (healTarget.HealthPercent < 0.9 and vars[\"光之优雅\"] < 5) then\n            v = A[\"圣光术\"]:Cast(nil, healTarget) if v then return v end\n        end\n    end\n    v = A[\"神圣震击\"]:Cast(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\n    if player.MyBuff:Has(\"圣光灌注\") then\n        if SwitchIsOn(\"圣光闪现\") then\n            v = A[\"圣光闪现\"]:CastSafely(healTarget.HealthPercent > 0.5 and healTarget.HealthPercent < 0.75, healTarget) if v then return v end\n        elseif SwitchIsOn(\"圣光术\") then\n            v = A[\"圣光术\"]:Cast(healTarget.HealthPercent > 0.5 and healTarget.HealthPercent < 0.75, healTarget) if v then return v end\n        end\n    end\n    if healTarget.HealthPercent < 0.5 then\n        v = SwitchIsOn(\"圣光闪现\") and A[\"圣光闪现\"]:Cast(nil, healTarget) if v then return v end\n    end\nend\n\nif inRaid then\n    if SwitchIsOn(\"圣光术\") then\n        v = A[\"圣光术\"]:Cast(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\n    elseif SwitchIsOn(\"圣光闪现\") then\n        v = A[\"圣光闪现\"]:CastSafely(healTarget.HealthPercent < 0.5, healTarget) if v then return v end\n    end\nelse\n    if SwitchIsOn(\"圣光术\") then\n        v = A[\"圣光术\"]:Cast(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\n    elseif SwitchIsOn(\"圣光闪现\") then\n        v = A[\"圣光闪现\"]:CastSafely(healTarget.HealthPercent < 0.45, healTarget) if v then return v end\n    end\nend\n\n",
            ["输出"] = "--圣骑士-神圣-输出\nlocal v\nv = A[\"愤怒之锤\"]:Cast() if v then return v end\nv = A[\"奉献\"]:Cast(target.RangeToPlayer < 2 and enemies:GetMyDebuffCount(\"奉献\") == 0) if v then return v end\nv = run(\"审判\") if v then return v end\nv = A[\"神圣震击\"]:Cast() if v then return v end\nv = A[\"正义盾击\"]:Cast() if v then return v end\n",
            ["选择治疗目标"] = "--圣骑士-神圣-选择治疗目标\n\n--为圣光道标重写的GetHealTarget\nif talent[\"圣光道标\"] and friends:GetMyBuffCount(\"圣光道标\", 60) > 0 then\n    local sgdb\n    return friends:GetUnitByCondition(player, 40, false, false,\n        function(cachedUnit, unit)\n			if unit.HealReduce > 0.9 then\n				--print(\"HealReduce\", unit.HealReduce, unit.UnitId)\n				return false\n			end\n			--print(unit.UnitId, unit.HealReduce)\n			if cachedUnit and unit.HealthPercent > cachedUnit.HealthPercent then\n				--print(\"HealReduce2\", unit.HealReduce, unit.UnitId)\n				return false\n			end\n            if unit.MyBuff:Has(\"圣光道标\") then\n                sgdb = unit\n				return false\n            end\n			if inRaid then\n				--print(\"inRaid\", UnitInRaid(unit.UnitId), unit.UnitId)\n				return UnitInRaid(unit.UnitId) or UnitIsUnit(unit.UnitId, \"player\")\n			elseif inParty then\n				--print(\"inParty\", UnitInParty(unit.UnitId), unit.UnitId)\n				return UnitInParty(unit.UnitId) or UnitIsUnit(unit.UnitId, \"player\")\n			else\n				--print(\"UnitIsPlayer\", UnitIsPlayer(unit.UnitId), UnitIsUnit(unit.UnitId, \"pet\"), unit.UnitId)\n				return UnitIsPlayer(unit.UnitId) or UnitIsUnit(unit.UnitId, \"pet\")\n			end\n        end\n    ) or sgdb\nelse\n    return friends:GetMinHealthPercentUnit()\nend\n",
        },
        ["防护"] = {
            ["_专精初始化"] = "--圣骑士-防护-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["保命"] = "--圣骑士-防护-保命\nlocal v\nv = run(\"圣骑士-全专精-保命\") if v then return v end\n\nif not inCombat then\n    return \nend\n\nv = A[\"神圣之盾\"]:Cast() if v then return v end\nv = player:GetPowerPercent(P[\"法力\"]) < 0.7 and A[\"神圣恳求\"]:Cast() if v then return v end\n\n\n\n\n\n",
            ["爆发技能"] = "--圣骑士-防护-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\nif player.BurstSpell then\n    v = A[player.BurstSpell]:Cast() if v then return run(\"一键爆发\") end\n    if player.MyBuff[player.BurstSpell]:GetTimeLeft() < 10 then\n        return\n    end\nelse\n    v = run(\"一键爆发\") if v then return v end\nend\n\n",
            ["输出"] = "--圣骑士-防护-输出\n\nlocal v\nv = run(\"爆发技能\") if v then return v end\nv = A[\"愤怒之锤\"]:Cast() if v then return v end\nv = A[\"复仇者之盾\"]:Cast() if v then return v end\nv = A[\"正义之锤\"]:Cast(target.RangeToPlayer < 5) if v then return v end\nv = A[\"奉献\"]:Cast(target.RangeToPlayer < 2) if v then return v end\nv = run(\"审判\") if v then return v end\nv = A[\"正义盾击\"]:Cast() if v then return v end\n\n",
        },
    },
    ["德鲁伊"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--德鲁伊-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\nvars[\"下次月蚀可用时间\"] = 0\nvars[\"下次日蚀可用时间\"] = 0\n",
            ["保命"] = "--德鲁伊-全专精-保命\nif not inCombat then\n    v = SwitchIsOn(\"荆棘术\") and A[\"荆棘术\"]:Cast(nil, player) if v then return v end --还要给T\n    v = SwitchIsOn(\"野性印记\") and A[\"野性赐福\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"荆棘术\") and target.IsFriend and A[\"荆棘术\"]:Cast(nil, target) if v then return v end\n    return \nend\nlocal v\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"树皮术\") and A[\"树皮术\"]:Cast() if v then return v end\nv = SwitchIsOn(\"自然之握\") and A[\"自然之握\"]:Cast() if v then return v end\nv = SwitchIsOn(\"野性印记\") and A[\"野性赐福\"]:Cast() if v then return v end\nv = SwitchIsOn(\"荆棘术\") and target.IsFriend and A[\"荆棘术\"]:Cast(nil, target) if v then return v end\n--if player.MyBuff:Has(\"猎豹形态\") or player.MyBuff:Has(\"熊形态\") or player.MyBuff:Has(\"巨熊形态\") then\n--    v = SwitchIsOn(\"精灵之火\") and A[\"精灵之火（野性）\"]:Cast() if v then return v end\n--else\n--    v = SwitchIsOn(\"精灵之火\") and A[\"精灵之火\"]:Cast() if v then return v end\n--end\n",
            ["变熊狂回"] = "--德鲁伊-全专精-变熊狂回\n--local v = A[\"熊形态\"]:Cast(not player.MyBuff:Has(\"熊形态\")) if v then return v end\nlocal v = A[\"熊形态\"]:Cast() if v then return v end\nv = A[\"狂暴回复\"]:Cast(player.HealthPercent < 0.9, nil, FreeToCast) if v then return v end\n\n\n\n",
            ["基本检查"] = "--德鲁伊-全专精-基本检查\nreturn run(\"全职业-全专精-基本检查\", player.MyBuff:Has(\"旅行形态\"))\n",
            ["旅行形态保命"] = "--德鲁伊-全专精-旅行形态保命\nif not inCombat then\n    return\nend\nif player.HealthPercent > 0.6 then\n    return \nend\nlocal v\n--v = A[\"生存本能\"] and SwitchIsOn(\"生存本能\") and A[\"生存本能\"]:Cast() if v then return v end\nv = SwitchIsOn(\"树皮术\") and A[\"树皮术\"]:Cast() if v then return v end\n",
            ["枭兽形态保命"] = "--德鲁伊-全专精-枭兽形态保命\nlocal v\nif not inCombat then\n	v = SwitchIsOn(\"保命愈合\") and A[\"愈合\"]:ForceCast(player.HealthPercent < 0.4) if v then return v end\n	v = SwitchIsOn(\"野性印记\") and A[\"野性赐福\"]:Cast() if v then return v end\n    return \nend\nlocal v\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"树皮术\") and A[\"树皮术\"]:Cast() if v then return v end\nif SwitchIsOn(\"保命愈合\") then\n	v = A[\"愈合\"]:ForceCast(player.HealthPercent < 0.2) if v then return v end\n	v = A[\"愈合\"]:CastSafely(player.HealthPercent < 0.3) if v then return v end\nend\nv = SwitchIsOn(\"野性印记\") and A[\"野性赐福\"]:Cast() if v then return v end\n",
            ["枭兽形态治疗"] = "--德鲁伊-全专精-枭兽形态治疗\nlocal v\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\n--愈合可在枭首形态下使用\n--v = A[\"愈合\"]:CastSafely(healTarget.HealthPercent < 0.85, healTarget) if v then return v end\nv = A[\"愈合\"]:ForceCast(target.HealthPercent < 0.6, target) if v then return v end\nif target.HealthPercent < 0.9 then\n    if IsForceStart() then\n        v = A[\"愈合\"]:ForceCast(nil, target) if v then return v end\n    else\n        v = A[\"愈合\"]:CastSafely(nil, target) if v then return v end\n    end\nend\n\n--血量过低时，会尝试使用恢复亲和，此时会切换到人形态\n--if target.HealthPercent < 0.7 then\n--    v = run(\"恢复亲和\") if v then return v end\n--end\n\n",
            ["枭兽形态输出"] = "--德鲁伊-全专精-枭兽形态输出\nvars[\"自然之赐时间\"] = player.MyBuff[\"自然之赐\"]:GetTimeLeft()\nvars[\"月蚀时间\"] = player.MyBuff[\"月蚀\"]:GetTimeLeft()\nif vars[\"月蚀时间\"] > 0 and vars[\"下次月蚀可用时间\"] < GetTime() then\n    vars[\"下次月蚀可用时间\"] = GetTime() + vars[\"月蚀时间\"] + 30\nend\nvars[\"日蚀时间\"] = player.MyBuff[\"日蚀\"]:GetTimeLeft()\nif vars[\"日蚀时间\"] > 0 and vars[\"下次日蚀可用时间\"] < GetTime() then\n    vars[\"下次日蚀可用时间\"] = GetTime() + vars[\"日蚀时间\"] + 30\nend\n\nif not inCombat then-- and vars[\"敌方目标数量\"] == 1\n    if A[\"星火术\"].IsValid then\n        v = A[\"星火术\"]:CastSafely() if v then return v end --not A[\"星火术\"]:IsCasting()\n    else\n        v = A[\"愤怒\"]:CastSafely() if v then return v end -- not A[\"愤怒\"]:IsCasting()\n    end\nend\nv = SwitchIsOn(\"精灵之火\") and (talent[\"强化精灵之火\"] or battleType == \"小队\" or battleType == \"团队\") and A[\"精灵之火\"]:Cast() if v then return v end\n\nv = SwitchIsOn(\"激活\") and player:GetPowerPercent(P[\"法力\"]) < 0.3 and A[\"激活\"]:Cast(nil, player) if v then return v end\n\n--v = vars[\"敌方目标数量\"] > 3 and run(\"爆发技能\") if v then return v end\nv = SwitchIsOn(\"星辰坠落\") and vars[\"爆发强度\"] > 2 and enemies:GetNearbyCount(player, 30, true) > 2 and A[\"星辰坠落\"]:Cast() if v then return v end\nv = SwitchIsOn(\"自然之力\") and vars[\"爆发强度\"] > 1.5 and A[\"自然之力\"]:Cast() if v then return v end\n-- typhoon,if=active_enemies>1&target.distance<30\n-- typhoon,if=active_enemies > 1 and target.distance < 30\nv = SwitchIsOn(\"台风\") and vars[\"敌方目标数量\"] > 1 and A[\"台风\"]:Cast() if v then return v end\n-- hurricane,if=active_enemies>1\n-- hurricane,if=active_enemies > 1\nv = SwitchIsOn(\"飓风\") and A[\"飓风\"]:Cast(vars[\"敌方目标数量\"] > 1) if v then return run(\"安全引导\", \"飓风\") end\n\n--v = vars[\"月蚀时间\"] > 8 and run(\"爆发技能\") if v then return v end\nif vars[\"月蚀时间\"] > A[\"星火术\"]:GetCurrentCastingTime() then\n    v = A[\"星火术\"]:Cast() if v then return v end\nelseif vars[\"日蚀时间\"] > A[\"愤怒\"]:GetCurrentCastingTime() then\n    v = A[\"愤怒\"]:Cast() if v then return v end\nend\nv = A[\"虫群\"]:Cast() if v then return v end\nv = A[\"月火术\"]:Cast() if v then return v end\n--print((GetTime() > vars[\"下次日蚀可用时间\"] - A[\"星火术\"]:GetCurrentCastingTime()) and \"日蚀可用\" or \"\", (GetTime() > vars[\"下次月蚀可用时间\"] - A[\"愤怒\"]:GetCurrentCastingTime()) and \"月蚀可用\" or \"\")\nv = vars[\"自然之赐时间\"] > 0.3 and A[\"星火术\"]:Cast() if v then return v end\nv = (GetTime() > vars[\"下次月蚀可用时间\"] - A[\"愤怒\"]:GetCurrentCastingTime()) and A[\"愤怒\"]:Cast() if v then return v end\nv = (GetTime() > vars[\"下次日蚀可用时间\"] - A[\"星火术\"]:GetCurrentCastingTime()) and A[\"星火术\"]:Cast() if v then return v end\nv = A[\"愤怒\"]:Cast() if v then return v end\nv = A[\"月火术\"]:ForceCast() if v then return v end\n",
            ["治疗"] = "--德鲁伊-全专精-治疗\nlocal v\n--if not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n--    return\n--end\n--v = run(\"恢复亲和\") if v then return v end\nv = A[\"愈合\"]:Cast(target.HealthPercent < 0.6 or ((target.HealthPercent < 0.9 or IsForceStart()) and A[\"愈合\"]:IsSafeToCast() and not target.MyBuff:Has(\"愈合\")), target)\n--if SwitchIsOn(\"切换友方\") then\n--    v = run(\"切换治疗目标\") if v then return v end\n--end\n",
            ["熊形态保命"] = "--德鲁伊-全专精-熊形态保命\nlocal v\nif not inCombat then\n	v = SwitchIsOn(\"野性印记\") and A[\"野性赐福\"]:Cast() if v then return v end\n    return \nend\nlocal v\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"树皮术\") and A[\"树皮术\"]:Cast() if v then return v end\nv = A[\"狂暴回复\"] and SwitchIsOn(\"狂暴回复\") and A[\"狂暴回复\"]:Cast(player.HealthPercent < 0.7) if v then return v end\nv = SwitchIsOn(\"铁鬃\") and A[\"铁鬃\"]:Cast(nil, nil, player.MyBuff:Has(\"野性之心\") and {MaxCount=(player.HealthPercent < 0.75 and 5 or 1),RefillTime=10} ) if v then return v end\nv = SwitchIsOn(\"野性印记\") and A[\"野性赐福\"]:Cast() if v then return v end\n",
            ["熊形态治疗"] = "--德鲁伊-全专精-熊形态治疗\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\n--if target.HealthPercent < 0.9 then\n--    return run(\"恢复亲和\")\n--end\n",
            ["熊形态输出"] = "--德鲁伊-全专精-熊形态输出\nlocal v\nv = A[\"裂伤\"]:Cast() if v then return v end\nlocal count = SwitchIsOn(\"仅单体\") and 1 or enemies:GetNearbyCount(player, 6)\n--print(A[\"痛击\"].ActionName, A[\"痛击\"].ID, A[\"痛击\"]:IsReady(), A[\"痛击\"].IsValid, vars[\"目标数\"], A[\"痛击\"]:Cast(vars[\"目标数\"] > 0, nil, {MaxCount=3}))\nv = A[\"痛击\"] and A[\"痛击\"]:Cast(count > 0, nil, {MaxCount=3}) if v then return v end\n--v = A[\"月火术\"]:Cast() if v then return v end\nv = A[\"横扫\"] and A[\"横扫\"]:Cast(count > 0) if v then return v end\nv = A[\"痛击\"] and A[\"痛击\"]:Cast(count > 0, nil, {MaxCount=10}) if v then return v end\n\nv = SwitchIsOn(\"野性冲锋\") and A[\"野性冲锋\"]:Cast() if v then return v end\n--v = A[\"月火术\"]:ForceCast() if v then return v end\n",
            ["猎豹形态保命"] = "--德鲁伊-全专精-猎豹形态保命\nif not inCombat then\n	v = SwitchIsOn(\"野性印记\") and A[\"野性赐福\"]:Cast() if v then return v end\n    return \nend\nlocal v\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"生存本能\") and A[\"生存本能\"] and A[\"生存本能\"]:Cast() if v then return v end\nv = SwitchIsOn(\"树皮术\") and A[\"树皮术\"]:Cast() if v then return v end\nv = SwitchIsOn(\"野性印记\") and A[\"野性赐福\"]:Cast() if v then return v end\n",
            ["猎豹形态治疗"] = "--德鲁伊-全专精-猎豹形态治疗\nif not SwitchIsOn(\"治疗友方\") or not target.IsFriend then\n    return\nend\n--if target.HealthPercent < 0.7 then\n--    return run(\"恢复亲和\")\n--end\n",
            ["猎豹形态输出"] = "--德鲁伊-全专精-猎豹形态输出\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nvars[\"能量\"] = player:GetPower(P[\"能量\"])\n\nlocal v\nif vars[\"连击点\"] > 3 then\n    v = A[\"割裂\"]:Cast() if v then return v end\n    v = A[\"凶猛撕咬\"]:Cast() if v then return v end\nelse\n    local count = SwitchIsOn(\"仅单体\") and 1 or enemies:GetNearbyCount(player, 6)\n--print(A[\"痛击_豹\"].ActionName, A[\"痛击_豹\"].ID, A[\"痛击_豹\"]:IsReady(), A[\"痛击_豹\"].IsValid, count, A[\"痛击_豹\"]:Cast(count > 0))\n    v = A[\"痛击_豹\"] and A[\"痛击_豹\"]:Cast(count > 2) if v then return v end\n    v = A[\"横扫_豹\"] and A[\"横扫_豹\"]:Cast(count > 2 and vars[\"能量\"] > 50) if v then return v end\n    v = A[\"斜掠\"] and A[\"斜掠\"]:Cast() if v then return v end\n    v = A[\"撕碎\"]:Cast(vars[\"能量\"] > 60) if v then return v end\nend\nv = SwitchIsOn(\"野性冲锋\") and A[\"野性冲锋\"]:Cast() if v then return v end\n\n",
            ["输出"] = "--德鲁伊-全专精-输出\nif vars[\"专精形态\"] == \"\" or not A[vars[\"专精形态\"]].IsValid then\n    return run(\"德鲁伊-恢复-输出\")\nend\n",
            ["输出前"] = "--德鲁伊-全专精-输出前\nif vars[\"专精形态\"] ~= \"\" and player.Stance == \"\" and A[vars[\"专精形态\"]].IsValid and player.Stance ~= vars[\"专精形态\"] then\n    return A[vars[\"专精形态\"]]:Cast()\nend\n\n",
        },
        ["守护"] = {
            ["_专精初始化"] = "--德鲁伊-守护-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"专精形态\"] = \"熊形态\"\n",
        },
        ["平衡"] = {
            ["_专精初始化"] = "--德鲁伊-平衡-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"专精形态\"] = \"枭兽形态\"\n\n",
            ["枭兽形态输出"] = "--德鲁伊-平衡-枭兽形态输出\nvars[\"自然之赐时间\"] = player.MyBuff[\"自然之赐\"]:GetTimeLeft()\nvars[\"月蚀时间\"] = player.MyBuff[\"月蚀\"]:GetTimeLeft()\nif vars[\"月蚀时间\"] > 0 and vars[\"下次月蚀可用时间\"] < GetTime() then\n    vars[\"下次月蚀可用时间\"] = GetTime() + vars[\"月蚀时间\"] + 30\nend\nvars[\"日蚀时间\"] = player.MyBuff[\"日蚀\"]:GetTimeLeft()\nif vars[\"日蚀时间\"] > 0 and vars[\"下次日蚀可用时间\"] < GetTime() then\n    vars[\"下次日蚀可用时间\"] = GetTime() + vars[\"日蚀时间\"] + 30\nend\n\nif not inCombat then-- and vars[\"敌方目标数量\"] == 1\n    if A[\"星火术\"].IsValid then\n        v = A[\"星火术\"]:CastSafely() if v then return v end --not A[\"星火术\"]:IsCasting()\n    else\n        v = A[\"愤怒\"]:CastSafely() if v then return v end -- not A[\"愤怒\"]:IsCasting()\n    end\nend\nv = SwitchIsOn(\"精灵之火\") and (talent[\"强化精灵之火\"] or battleType == \"小队\" or battleType == \"团队\") and A[\"精灵之火\"]:Cast() if v then return v end\nv = SwitchIsOn(\"激活\") and player:GetPowerPercent(P[\"法力\"]) < 0.3 and A[\"激活\"]:Cast(nil, player) if v then return v end\n\nv = vars[\"敌方目标数量\"] > 3 and run(\"爆发技能\") if v then return v end\nv = SwitchIsOn(\"星辰坠落\") and vars[\"爆发强度\"] > 2 and enemies:GetNearbyCount(player, 30, true) > 2 and A[\"星辰坠落\"]:Cast() if v then return v end\nv = SwitchIsOn(\"自然之力\") and vars[\"爆发强度\"] > 1.5 and A[\"自然之力\"]:Cast() if v then return v end\n-- typhoon,if=active_enemies>1&target.distance<30\n-- typhoon,if=active_enemies > 1 and target.distance < 30\nv = SwitchIsOn(\"台风\") and vars[\"敌方目标数量\"] > 1 and A[\"台风\"]:Cast() if v then return v end\n-- hurricane,if=active_enemies>1\n-- hurricane,if=active_enemies > 1\nv = SwitchIsOn(\"飓风\") and A[\"飓风\"]:Cast(vars[\"敌方目标数量\"] > 1) if v then return run(\"安全引导\", \"飓风\") end\n\nv = vars[\"月蚀时间\"] > 8 and run(\"爆发技能\") if v then return v end\nif vars[\"月蚀时间\"] > A[\"星火术\"]:GetCurrentCastingTime() then\n    v = A[\"星火术\"]:Cast() if v then return v end\nelseif vars[\"日蚀时间\"] > A[\"愤怒\"]:GetCurrentCastingTime() then\n    v = A[\"愤怒\"]:Cast() if v then return v end\nend\nv = A[\"虫群\"]:Cast() if v then return v end\nv = A[\"月火术\"]:Cast() if v then return v end\n--print((GetTime() > vars[\"下次日蚀可用时间\"] - A[\"星火术\"]:GetCurrentCastingTime()) and \"日蚀可用\" or \"\", (GetTime() > vars[\"下次月蚀可用时间\"] - A[\"愤怒\"]:GetCurrentCastingTime()) and \"月蚀可用\" or \"\")\nv = vars[\"自然之赐时间\"] > 0.3 and A[\"星火术\"]:Cast() if v then return v end\nv = (GetTime() > vars[\"下次月蚀可用时间\"] - A[\"愤怒\"]:GetCurrentCastingTime()) and A[\"愤怒\"]:Cast() if v then return v end\nv = (GetTime() > vars[\"下次日蚀可用时间\"] - A[\"星火术\"]:GetCurrentCastingTime()) and A[\"星火术\"]:Cast() if v then return v end\nv = A[\"愤怒\"]:Cast() if v then return v end\nv = A[\"月火术\"]:ForceCast() if v then return v end\n",
            ["爆发技能"] = "--德鲁伊-平衡-爆发技能\nif vars[\"爆发强度\"] < 2 or not SwitchIsOn(\"输出爆发\") then\n	return\nend\nlocal v\nv = run(\"一键爆发\") if v then return v end\n--v = A[\"超凡之盟\"]:Cast() if v then return run(\"一键爆发\") end\n--if A[\"超凡之盟\"]:GetCooldown() < 20 then\n--   return\n--end\n----v = player.MyBuff[A[\"超凡之盟\"].ActionName]:GetTimeLeft()\n----if v > 0 and v < 3 then\n----   return\n----end\n--v = SwitchIsOn(\"万灵之召\") and run(\"万灵之召\") if v then return v end\n\n",
        },
        ["恢复"] = {
            ["_专精初始化"] = "--德鲁伊-恢复-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"专精形态\"] = \"生命之树\"\n",
            ["_脚本初始化"] = "--德鲁伊-恢复-_脚本初始化\nrun(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--德鲁伊-恢复-保命\nlocal v\nv = run(\"德鲁伊-全专精-保命\") if v then return v end\n",
            ["宁静"] = "--德鲁伊-恢复-宁静\nlocal castTo, params = ...\n--if not castTo then \n--    castTo = (UnitExists(\"target\") and target or player)\n--end\nreturn run(\"安全引导\", \"宁静\", castTo, params)\n\n",
            ["枭兽形态治疗"] = "--德鲁伊-恢复-枭兽形态治疗\nlocal v\nif healTarget.HealthPercent < 0.7 then\n    return run(\"德鲁伊-恢复-治疗\")\nend\n--愈合可在枭首形态下使用\nv = A[\"愈合\"]:CastSafely(healTarget.HealthPercent < 0.85, healTarget) if v then return v end\n\n",
            ["治疗"] = "--德鲁伊-恢复-治疗\nreturn run(\"生命之树治疗\")",
            ["生命之树治疗"] = "--德鲁伊-恢复-生命之树治疗\nlocal v\nv = A[\"滋养\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n\nif inCombat then\n    --v = run(\"使用饰品\", \"流水脉动之心\", healTarget.HealthPercent < 0.55) if v then return v end\n    v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    v = run(\"宁静\") if v then return v end\n    vars[\"迅捷治愈\"] = healTarget.MyBuff:Has(\"愈合\") or healTarget.MyBuff:Has(\"回春术\")\n    v = vars[\"迅捷治愈\"] and A[\"迅捷治愈\"]:Cast(healTarget.HealthPercent < 0.75, healTarget) if v then return v end\n    v = A[\"激活\"]:ForceCast(player:GetPowerPercent(P[\"法力\"]) < 0.15, player) if v then return v end\n    if vars[\"迅捷治愈\"] and healTarget.HealthPercent < 0.5 then\n        v = A[\"迅捷治愈\"]:Cast(nil, healTarget) if v then return v end\n    end\n    v = SwitchIsOn(\"自然迅捷\") and A[\"自然迅捷\"]:Cast(healTarget.HealthPercent < 0.4) if v then return v end\n    v = healTarget.MyBuff[\"生命绽放\"]:GetTimeLeft()\n    v = A[\"生命绽放\"]:Cast(healTarget.HealthPercent < 0.7, healTarget) if v then return v end\nend\nv = A[\"滋养\"]:Cast(healTarget.HealthPercent < 0.3, healTarget) if v then return v end\nv = SwitchIsOn(\"野性成长\") and A[\"野性成长\"]:Cast(nil, healTarget) if v then return v end\nv = A[\"回春术\"]:Cast(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\nif talent[\"滋养\"] and not player:IsMoving() then\n    v = A[\"愈合\"]:CastSafely(healTarget.HealthPercent < 0.7, healTarget) if v then return v end\n    v = A[\"滋养\"]:Cast(healTarget.HealthPercent < 0.6, healTarget) if v then return v end\n    v = A[\"滋养\"]:CastSafely(healTarget.HealthPercent < 0.7, healTarget) if v then return v end\nelse\n    v = A[\"愈合\"]:CastSafely(healTarget.HealthPercent < 0.7, healTarget) if v then return v end\n    v = A[\"治疗之触\"]:CastSafely(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\nend\n",
            ["生命之树输出"] = "--德鲁伊-恢复-生命之树输出\nreturn",
            ["输出"] = "--德鲁伊-恢复-输出\nlocal v\nif not inCombat then\n    if vars[\"敌方目标数量\"] == 1 then\n        v = A[\"星火术\"]:CastSafely() if v then return v end\n    end\n    v = A[\"愤怒\"]:CastSafely() if v then return v end\nend\nv = SwitchIsOn(\"枭兽形态\") and A[\"枭兽形态\"]:Cast() if v then return v end\n\nif vars[\"敌方目标数量\"] > 1 then\n	v = A[\"虫群\"]:CastOnMinTime(nil, 40, 60) if v then return v end\n	v = A[\"月火术\"]:CastOnMinTime(nil, 40, 60) if v then return v end\n    v = A[\"星火术\"]:Cast() if v then return v end\nelse\n	v = A[\"虫群\"]:Cast() if v then return v end\n	v = A[\"月火术\"]:Cast() if v then return v end\nend\nv = A[\"愤怒\"]:Cast() if v then return v end\nv = A[\"月火术\"]:ForceCast() if v then return v end\n\n\n",
        },
        ["野性战斗"] = {
            ["_专精初始化"] = "--德鲁伊-野性战斗-_专精初始化\n--德鲁伊-野性-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"专精形态\"] = \"猎豹形态\"\nif talent[\"月之灵\"] then\n    vars[\"血腥爪击可用技能_单体\"] = {[1]=\"斜掠\", [2]=\"月火术\", [3]=\"撕碎\", [4]=\"痛击\", [\"施放技能名\"] = {[1]=\"斜掠\", [2]=\"强制月火术\", [3]=\"撕碎\", [4]=\"痛击_豹\"}}\n    vars[\"血腥爪击可用技能_AOE\"] = {[1]=\"痛击\", [2]=(talent[\"野蛮挥砍\"] and \"野蛮挥砍\" or \"横扫\"), [3]=\"斜掠\", [4]=\"月火术\", [\"施放技能名\"] = {[1]=\"痛击_豹\", [2]=\"横扫_豹\", [3]=\"斜掠\", [4]=\"强制月火术\"}}\nelse\n    vars[\"血腥爪击可用技能_单体\"] = {[1]=\"斜掠\", [2]=\"撕碎\", [3]=\"痛击\", [\"施放技能名\"] = {[1]=\"斜掠\", [2]=\"撕碎\", [3]=\"痛击_豹\"}}\n    vars[\"血腥爪击可用技能_AOE\"] = {[1]=\"痛击\", [2]=(talent[\"野蛮挥砍\"] and \"野蛮挥砍\" or \"横扫\"), [3]=\"斜掠\", [\"施放技能名\"] = {[1]=\"痛击_豹\", [2]=\"横扫_豹\", [3]=\"斜掠\"}}\nend\n",
