            ["输出"] = "--战士-武器-输出\n--战士-武器-_输出\nlocal v\nvars[\"怒气\"] = player:GetPower(P[\"怒气\"])\n\nv = A[\"撕裂\"]:Cast() if v then return v end\nv = A[\"雷霆一击\"]:Cast() if v then return v end\nv = UnitLevel(\"player\") < 10 and A[\"英勇打击\"]:Cast(vars[\"怒气\"] > 70) if v then return v end\nv = SwitchIsOn(\"冲锋\") and A[\"冲锋\"]:Cast(target.RangeToPlayer < 25 and target.RangeToPlayer > 8) if v then return v end\n",
