    ["术士"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--术士-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["保命"] = "--术士-全专精-保命\nlocal v\nv = GetSpellInfo(\"恶魔掌控\")\nif v == \"巨斧投掷\" then\n	vars[\"宠物类型\"] = \"恶魔卫士\"\nelseif v == \"法术封锁\" then\n	vars[\"宠物类型\"] = \"地狱猎犬\"\nelseif v == \"暗影壁垒\" then\n	vars[\"宠物类型\"] = \"虚空行者\"\nelseif v == \"诱惑\" then\n	vars[\"宠物类型\"] = \"魅魔\"\nelseif v == \"烧灼驱魔\" then\n	vars[\"宠物类型\"] = \"小鬼\"\nelse\n	vars[\"宠物类型\"] = \"\"\nend\nif not inCombat then\n    vars[\"痛苦无常连发\"] = false\nend\nif SwitchIsOn(\"恶魔皮肤\") then\n    v = A[\"恶魔皮肤\"]:Cast() if v then return v end\nelseif SwitchIsOn(\"邪甲术\") then\n    v = A[\"邪甲术\"]:Cast() if v then return v end\nelseif SwitchIsOn(\"魔甲术\") then\n    v = A[\"魔甲术\"]:Cast() if v then return v end\nend\n\nif not inCombat then\n    v = run(\"召唤宠物\") if v then return v end\n    v = SwitchIsOn(\"生命通道\") and A[\"生命通道\"]:Cast(UnitExists(\"pet\") and not UnitIsDead(\"pet\") and pet.HealthPercent < (inPVE and 0.4 or 0.6)) if v then return v end\n    v = SwitchIsOn(\"制造治疗石\") and A[\"制造治疗石\"]:Cast(not inInstance and not inTraining and A[\"治疗石\"]:GetCount() == 0) if v then return v end\n	v = SwitchIsOn(\"灵魂石\") and A[\"灵魂石\"]:Cast(not inInstance and not inTraining, player) if v then return v end\n    return\nend\n\n",
            ["召唤宠物"] = "--术士-全专精-召唤宠物\nlocal v\nif not A[\"召唤小鬼\"]:IsProtected() then\n	A[\"召唤小鬼\"]:Protect(4, 1.5)\n	return\nend\nif GetSpecialization() == 2 and SwitchIsOn(\"召唤卫士\") then\n    v = A[\"召唤恶魔卫士\"]:Cast()\nelseif SwitchIsOn(\"召唤小鬼\") then\n    v = A[\"召唤小鬼\"]:Cast()\nelseif SwitchIsOn(\"召唤蓝胖\") then\n    v = A[\"召唤虚空行者\"]:Cast()\nelseif SwitchIsOn(\"召唤猎犬\") then\n    v = A[\"召唤地狱猎犬\"]:Cast()\nelseif SwitchIsOn(\"召唤魅魔\") then\n    v = A[\"召唤魅魔\"]:Cast()\nend\nif v then\n	--if inCombat and SwitchIsOn(\"邪能统御\") then\n	--	return A[\"邪能统御\"]:Cast() or v\n	--else\n		return v\n	--end\nend",
            ["打断"] = "--术士-全专精-打断\nif vars[\"宠物类型\"] == \"恶魔卫士\" then\n    return A[\"巨斧投掷\"]:Cast(nil, ...)\nelseif vars[\"宠物类型\"] == \"地狱猎犬\" then\n    return A[\"法术封锁\"]:Cast(nil, ...)\nend\n",
