            ["更新灵魂碎片数量"] = "--术士-恶魔学识-更新灵魂碎片数量\nvars[\"灵魂碎片\"] = player:GetPower(P[\"灵魂碎片\"])\n\nlocal name = UnitCastingInfo(\"player\")\nif name == \"暗影箭\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] + 1\nelseif name == \"恶魔之箭\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] + 2\nelseif name == \"召唤恶魔暴君\" then    \n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] + 5\nelseif name == \"召唤恐惧猎犬\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] - 2\nelseif name == \"古尔丹之手\" then\n    if vars[\"灵魂碎片\"] > 3 then\n        vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] - 3\n		vars[\"小鬼数量\"] = vars[\"小鬼数量\"] + 3\n    else\n        vars[\"灵魂碎片\"] = 0\n		vars[\"小鬼数量\"] = vars[\"小鬼数量\"] + vars[\"灵魂碎片\"]\n    end\nend\n\nif vars[\"灵魂碎片\"] > 5 then\n    vars[\"灵魂碎片\"] = 5\nend",
        },
        ["毁灭"] = {
            ["_专精初始化"] = "--术士-毁灭-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["更新灵魂碎片数量"] = "--术士-毁灭-更新灵魂碎片数量\nif player.MyBuff:Has(\"毁灭仪式\") then\n	vars[\"灵魂碎片裂片\"] = 40\nelse\n	vars[\"灵魂碎片裂片\"] = player:GetPower(P[\"灵魂碎片\"], true)\n	local name = UnitCastingInfo(\"player\")\n	if name == \"混乱之箭\" then\n		vars[\"灵魂碎片裂片\"] = vars[\"灵魂碎片裂片\"] - 20\n	elseif name == \"烧尽\" then\n		vars[\"灵魂碎片裂片\"] = vars[\"灵魂碎片裂片\"] + 2\n	elseif name == \"灵魂之火\" then\n		vars[\"灵魂碎片裂片\"] = vars[\"灵魂碎片裂片\"] + 10\n	end\n	if vars[\"灵魂碎片裂片\"] > 50 then\n		vars[\"灵魂碎片裂片\"] = 50\n	end\nend\nvars[\"灵魂碎片\"] = vars[\"灵魂碎片裂片\"] / 10",
        },
        ["痛苦"] = {
            ["_专精初始化"] = "--术士-痛苦-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["更新灵魂碎片数量"] = "--术士-痛苦-更新灵魂碎片数量\nvars[\"灵魂碎片\"] = player:GetPower(P[\"灵魂碎片\"])\nlocal name = UnitCastingInfo(\"player\")\nif name == \"灾难狂欢\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] - 1\nelseif name == \"腐蚀之种\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] - 1\nelseif name == \"邪恶污染\" then\n    vars[\"灵魂碎片\"] = vars[\"灵魂碎片\"] - 1\nend\n",
            ["输出"] = "--术士-痛苦-输出\nif vars[\"爆发强度\"] > 1 then\n	v = SwitchIsOn(\"灵魂腐化\") and A[\"灵魂腐化\"]:Cast() if v then return v end\nend\nif SwitchIsOn(\"吸取生命\") and enemies:GetMyDebuffCount(\"灵魂腐化\", 50) > 1 then\n    v = A[\"吸取生命\"]:Cast() if v then return v end\nend\nrun(\"更新灵魂碎片数量\")\nvars[\"攒死亡之箭碎片\"] = false\n--if not UnitIsPlayer(\"target\") then\n--end\nlocal v\nvars[\"攒碎片\"] = vars[\"攒死亡之箭碎片\"]\nif vars[\"敌方目标数量\"] > 2 then\n    v = A[\"腐蚀之种\"]:Cast(vars[\"灵魂碎片\"] > 0 and not vars[\"攒碎片\"]) if v then return v end\n    v = A[\"诡异魅影\"]:Cast() if v then return v end\n    --v = A[\"邪恶污染\"]:Cast(vars[\"灵魂碎片\"] > 0 and not vars[\"攒碎片\"]) if v then return v end\nend\nvars[\"鼠标目标数\"] = SwitchIsOn(\"仅单体\") and 1 or enemies:GetNearbyCount(mouseover, 10)\nv = SwitchIsOn(\"鼠指减益\") and A[\"腐蚀之种\"]:Cast(vars[\"灵魂碎片\"] > 0 and not vars[\"攒碎片\"] and vars[\"鼠标目标数\"] > 2, mouseover) if v then return v end\n\nv = A[\"诡异魅影\"]:Cast() if v then return v end\nv = A[\"生命虹吸\"]:Cast() if v then return v end\nv = A[\"痛楚\"]:Cast() if v then return v end\nv = A[\"痛苦无常\"]:Cast() if v then return v end\n\nv = A[\"献祭\"]:Cast() if v then return v end\nv = A[\"腐蚀术\"]:Cast(vars[\"敌方目标数量\"] < 3 or not A[\"腐蚀之种\"].IsValid) if v then return v end\n\nv = SwitchIsOn(\"鼠指减益\") and A[\"痛楚\"]:Cast(nil, mouseover) if v then return v end\nv = SwitchIsOn(\"鼠指减益\") and A[\"痛苦无常\"]:Cast(nil, mouseover) if v then return v end\nv = SwitchIsOn(\"鼠指减益\") and A[\"生命虹吸\"]:Cast(nil, mouseover) if v then return v end\nv = SwitchIsOn(\"鼠指减益\") and A[\"腐蚀术\"]:Cast(vars[\"敌方目标数量\"] < 3 or not A[\"腐蚀之种\"].IsValid, mouseover) if v then return v end\nv = run(\"爆发技能\") if v then return v end\n\nv = A[\"吸取灵魂\"]:Cast(vars[\"灵魂碎片\"] < 5 and vars[\"目标死亡时间\"] < 3 and not (boss.IsTarget and boss.LivingCount == 1)) if v then return v end\nv = A[\"鬼影缠身\"]:Cast() if v then return v end\nv = A[\"暗影箭\"]:Cast(player.MyBuff:Has(\"夜幕\")) if v then return v end\n--v = A[\"邪恶污染\"]:Cast(vars[\"灵魂碎片\"] > 0 and not vars[\"攒碎片\"]) if v then return v end\n--if vars[\"目标死亡时间\"] > 6 and not vars[\"攒碎片\"] then --普通怪\n--    if talent[\"死亡之箭\"] then\n--        v = A[\"痛苦无常\"]:Cast(vars[\"灵魂碎片\"] == 5) if v then return v end\n--    end\n--end\nv = SwitchIsOn(\"吸取生命\") and A[\"吸取生命\"]:Cast(player.MyBuff[\"大难临头\"].Count >= 35) if v then return v end\nv = SwitchIsOn(\"灾难狂欢\") and A[\"灾难狂欢\"]:Cast(vars[\"灵魂碎片\"] > 3 or not vars[\"攒碎片\"]) if v then return v end\nv = A[\"吸取灵魂\"]:Cast() if v then return v end\nv = A[\"暗影箭\"]:Cast() if v then return v end\n\n",
        },
