    ["死亡骑士"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--死亡骑士-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\nvars[\"灵界打击条件\"] = \n	function(cachedUnit, unit, ...)\n		if A[\"灵界打击\"]:Cast(nil, unit, NoChangeTarget) then\n            local count  = 0\n            if unit.MyDebuff:Has(\"冰霜疫病\") then\n                count = count + 1\n            end\n            if unit.MyDebuff:Has(\"血之疫病\") then\n                count = count + 1\n            end\n			return count > 0, count == 2 --第二个true表示停止继续找下一个unit\n		else\n			return false\n		end\n	end\n\nlocal ___runeforges = {\n    [6243] = \"癔狂符文\",--hysteria\n    [3370] = \"冰锋符文\", --razorice\n    [6241] = \"鲜红符文\",--sanguination\n    [6242] = \"护咒符文\",--spellwarding\n    [6245] = \"天启符文\",--apocalypse\n    [3368] = \"堕落十字军符文\",--fallen_crusader\n    [3847] = \"岩肤石像鬼符文\",--stoneskin_gargoyle\n    [6244] = \"无尽渴求符文\",--unending_thirst\n	Update = \n		function(self, slot)\n			local link = GetInventoryItemLink(\"player\", slot)\n			if not link then\n				return false\n			end\n			local enchant = link:match(\"item:%d+:(%d+)\")                    \n			if not enchant then\n				return true\n			end\n			local name = self[tonumber(enchant)]\n			if name then\n				runeforge[name] = true\n			end\n			return true\n		end,\n} \n\nvars[\"更新武器符文类别\"] = \n	function()\n        for k, v in pairs(___runeforges) do\n            --print(k,v)\n            if k ~= \"Update\" then\n                runeforge[v] = false\n            end\n        end\n		___runeforges:Update(16)--主手\n		vars[\"双持\"] = ___runeforges:Update(17)--副手\n	end    \n    \n",
            ["_装备初始化"] = "--死亡骑士-全专精-_装备初始化\nrun(\"全职业-全专精-_装备初始化\")\n\nif vars[\"更新武器符文类别\"] then\n	vars[\"更新武器符文类别\"]()\nend",
            ["输出初始化"] = "--死亡骑士-全专精-输出初始化\nrun(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["冰霜"] = {
            ["_专精初始化"] = "--死亡骑士-冰霜-_专精初始化\nrun(\"全专精-_专精初始化\")\n\n",
            ["_脚本初始化"] = "--死亡骑士-冰霜-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n",
