        ["邪恶"] = {
            ["_专精初始化"] = "--死亡骑士-邪恶-_专精初始化\nrun(\"全专精-_专精初始化\")\n--vars[\"灵魂收割条件\"] = \n--	function(cachedUnit, unit, ...)\n--		if unit:TimeToPercent(0.35) < 4 and A[\"灵魂收割\"]:GetCooldown() < gcdmax * 0.75 then\n--			local tm = unit:TimeToDie()\n--			local v = ((vars[\"敌方目标数量\"] == 1 and tm > 5) or ((tm > 5 and vars[\"敌方目标数量\"] <= 3 or t28[4] and pet.MyBuff:Has(\"黑暗突变\") and vars[\"敌方目标数量\"] <= 5 and (not target.MyDebuff:Has(\"枯萎凋零\") or covenant == \"法夜\")))) and A[\"灵魂收割\"]:Cast(nil, unit, {LeadCd = gcdmax * 0.75})\n--			if v then\n--				return true, true --第二个true表示停止继续找下一个unit\n--			else\n--				return false\n--			end\n--		else\n--			return false\n--		end\n--	end\n",
            ["_脚本初始化"] = "--死亡骑士-邪恶-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n\n",
            ["保命"] = "--死亡骑士-邪恶-保命\nvars[\"符文能量\"] = player:GetPower(P[\"符文能量\"])\nvars[\"符文能量差\"] = player:GetPowerDeficit(P[\"符文能量\"])\n--if not inCombat then\n--    v = SwitchIsOn(\"亡者复生\") and A[\"亡者复生\"]:Cast() if v then return v end\n--    return\n--end\nlocal v\n--local tm = player.MyBuff[\"黑暗援助\"]:GetTimeLeft()\n--v = A[\"灵界打击\"]:Cast(target.RangeToPlayer < 5 and tm > 0 and (tm < 3 or player.HealthPercent < 0.8)) if v then return v end\n--if player.HealthPercent > 0.7 then\n--    v = SwitchIsOn(\"亡者复生\") and A[\"亡者复生\"]:Cast() if v then return v end\n--    return\n--end\nv = SwitchIsOn(\"反魔法护罩\") and A[\"反魔法护罩\"]:Cast() if v then return v end\nv = SwitchIsOn(\"冰封之韧\") and A[\"冰封之韧\"]:Cast() if v then return v end\nv = SwitchIsOn(\"天灾契约\") and A[\"天灾契约\"]:Cast(player.HealthPercent < 0.45) if v then return v end\n--v = SwitchIsOn(\"巫妖之躯\") and A[\"巫妖之躯_减伤\"]:Cast() if v then return v end\nvars[\"冰霜疫病时间\"] = target.MyDebuff[\"冰霜疫病\"]:GetTimeLeft()\nvars[\"血之疫病时间\"] = target.MyDebuff[\"血之疫病\"]:GetTimeLeft()\n\nif player.HealthPercent < (boss.InCombat and 0.4 or (inPVE and 0.5 or 0.7)) then\n	v = vars[\"冰霜疫病时间\"] > 0 and vars[\"血之疫病时间\"] > 0 and A[\"灵界打击\"]:Cast() if v then return v end\n	v = A[\"灵界打击\"]:CastOnUnitByCondition(nil, 6, 160, vars[\"灵界打击条件\"]) if v then return v end\nend\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = (not UnitExists(\"pet\") or UnitIsDead(\"pet\")) and SwitchIsOn(\"亡者复生\") and A[\"亡者复生\"]:Cast() if v then return v end\n\n\n\n\n\n",
            ["爆发技能"] = "--死亡骑士-邪恶-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nif target.RangeToPlayer > 10 then\n    return\nend\nlocal v\nv = SwitchIsOn(\"亡者大军\") and A[\"亡者大军\"]:Cast() if v then return v end\nv = SwitchIsOn(\"召唤石像鬼\") and A[\"召唤石像鬼\"]:Cast() if v then return run(\"一键爆发\") end\n--print(runes.Count, vars[\"符文能量\"], A[\"符文武器增效\"]:Cast())\nv = SwitchIsOn(\"符文武器增效\") and runes.Count < 1 and vars[\"符文能量\"] <= 60 and A[\"符文武器增效\"]:Cast() if v then return v end\n\n",
            ["补刀"] = "--死亡骑士-邪恶-补刀\nlocal v\nv = A[\"凋零缠绕\"]:Cast(A[\"凋零缠绕\"]:GetDamage() > target.Health) if v then return v end \nv = A[\"天灾打击\"]:Cast(A[\"天灾打击\"]:GetDamage() > target.Health) if v then return v end \nv = A[\"鲜血打击\"]:Cast(A[\"鲜血打击\"]:GetDamage() > target.Health) if v then return v end \n",
            ["输出"] = "--死亡骑士-邪恶-输出\nlocal v\n\nv = SwitchIsOn(\"白骨之盾\") and not player.MyBuff:Has(\"白骨之盾\") and A[\"白骨之盾\"]:Cast() if v then return v end\nif not inCombat then\n    v = vars[\"符文能量\"] <= 85 and A[\"寒冬号角\"]:Cast() if v then return v end\nend\nv = run(\"爆发技能\") if v then return v end\n--凋零缠绕 邪爆\nif vars[\"符文能量\"] >= 80 then\n    if vars[\"敌方目标数量\"] > 2 and SwitchIsOn(\"邪爆\") and talent[\"邪爆\"] and not A[\"邪爆\"]:IsProtected() then\n        v = A[\"邪爆\"]:Cast() if v then A[\"邪爆\"]:Protect(3) return v end\n    else\n        v = A[\"凋零缠绕\"]:Cast() if v then return v end\n    end\nend\n\n--保持冰霜疫病和血之疫病\nv = vars[\"冰霜疫病时间\"] < 4 and A[\"冰冷触摸\"]:Cast() if v then return v end\nv = vars[\"血之疫病时间\"] < 4 and A[\"暗影打击\"]:Cast() if v then return v end\n--保持孤寂buff\nv = A[\"孤寂\"]:Cast() if v then return v end\n\n--枯萎凋零\nv = SwitchIsOn(A[\"枯萎凋零\"].ActionName) and (A[\"枯萎凋零\"]:Cast() or A[\"我_枯萎凋零\"]:Cast()) if v then return v end\n\n--保持食尸鬼狂乱buff\nv = pet:IsAlive() and pet.MyBuff[\"食尸鬼狂乱\"]:GetTimeLeft() < 5 and A[\"食尸鬼狂乱\"]:Cast() if v then return v end\n--天灾打击\nv = A[\"天灾打击\"]:Cast() if v then return v end\n--冰触暗打  --血沸（双持）\nif vars[\"敌方目标数量\"] > 2 then\n    if vars[\"冰霜疫病时间\"] > 1 and vars[\"血之疫病时间\"] > 1 and (enemies:GetMyDebuffCount(\"冰霜疫病\") < vars[\"敌方目标数量\"] or enemies:GetMyDebuffCount(\"血之疫病\") < vars[\"敌方目标数量\"]) then\n        v = A[\"传染\"]:Cast() if v then return v end\n    end\n    v = A[\"血液沸腾\"]:Cast() if v then return v end\nelse\n    v = A[\"鲜血打击\"]:Cast() if v then return v end\nend\n--凋零缠绕 邪爆\nif vars[\"符文能量\"] >= 70 then\n    if vars[\"敌方目标数量\"] > 2 and SwitchIsOn(\"邪爆\") and talent[\"邪爆\"] and not A[\"邪爆\"]:FailedIn(3) then\n        v = A[\"邪爆\"]:Cast() if v then return v end\n    else\n        v = A[\"凋零缠绕\"]:Cast() if v then return v end\n    end\nend\n--寒冬号角\nv = vars[\"符文能量\"] <= 85 and A[\"寒冬号角\"]:Cast() if v then return v end\n\n\n\n\n--双持邪\n--保持冰霜疫病和血之疫病\n--保持孤寂buff\n--枯萎凋零\n--保持食尸鬼狂乱buff\n--冰触暗打血沸\n--凋零缠绕\n--寒冬号角\n--简单的理解就是把6个符文分成三组\n--一组符文是冰触暗打血打为起手组\n--然后是枯萎凋零为一组\n--最后是冰触 食尸鬼狂乱 血沸为循环组\n--爆发技能为召唤天鬼和符文武器增效 天鬼是持当前人物角色的属性快照的\n--起手先切城邪恶灵气15%攻速----->倒数20秒寒冬号角+骨盾2%额外伤害----->倒数10秒召唤大军----->倒数1秒持加速药水----->冰触暗打血打----->凋零----->符文武器增效----->天鬼----->切回红脸----->食尸鬼狂乱----->冰触----->血沸 开始循环一组凋零 一组起手 一组凋零 这样交替循环\n\n--双手邪\n--保持冰霜疫病和血之疫病\n--保持孤寂buff\n--枯萎凋零\n--天灾打击\n--冰触暗打\n--凋零缠绕\n--寒冬号角\n--简单的理解就是把符文分成两组\n--冰触 暗打 血打 血打 天打（多目标可以将血打换成传染）为一组\n--冰触 暗打 血打 枯萎凋零为二组\n--爆发技能为召唤天鬼和符文武器增效 天鬼是持当前人物角色的属性快照的\n--起手先切城邪恶灵气15%攻速----->倒数20秒寒冬号角+骨盾2%额外伤害----->倒数10秒召唤大军----->倒数1秒持加速药水----->冰触暗打血打血打----->天打----->符文武器增效----->天鬼----->切回红脸----->血打----->天打----->天打 开始循环一组冰触暗打血打血打天打 后 二组冰触暗打血打枯萎凋零 这样交替循环循环\n",
        },
        ["鲜血"] = {
            ["_专精初始化"] = "--死亡骑士-鲜血-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
        },
    },
    ["法师"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--法师-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["保命"] = "--法师-全专精-保命\nlocal v\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nvars[\"爆发技能时间\"] = player.MyBuff[A[\"爆发技能\"].ActionName]:GetTimeLeft()\nv = A[\"寒冰屏障\"]:Cast() if v then return v end\nv = A[\"寒冰护体\"]:Cast() if v then return v end\nv = A[\"法力护盾\"]:Cast() if v then return v end\nv = A[\"防护冰霜结界\"]:Cast() if v then return v end\nif SwitchIsOn(\"霜甲术\") then\n    v = A[\"霜甲术\"]:Cast() if v then return v end\nelseif SwitchIsOn(\"冰甲术\") then\n    v = A[\"冰甲术\"]:Cast() if v then return v end\nelseif SwitchIsOn(\"法师护甲\") then\n    v = A[\"法师护甲\"]:Cast() if v then return v end\nelseif SwitchIsOn(\"熔岩护甲\") then\n    v = A[\"熔岩护甲\"]:Cast() if v then return v end\nend\nv = SwitchIsOn(\"奥术智慧\") and A[\"奥术光辉\"]:Cast() if v then return v end\nv = SwitchIsOn(A[\"召宠\"].ActionName) and A[\"召宠\"]:Cast() if v then return v end\n\n\n\n",
            ["冰霜新星"] = "--法师-全专精-冰霜新星\nv = A[\"冰霜新星\"]:Cast(not A[\"冰霜新星\"]:SucceededIn(3) and (enemies:GetNearbyCount(player, 12) > 0)) if v then return v end\n",
        },
        ["冰霜"] = {
            ["_专精初始化"] = "--法师-冰霜-_专精初始化\nrun(\"全专精-_专精初始化\")\n\nvars[\"冰川尖刺伤害\"] = 0\nvars[\"冰川尖刺施法时间\"] = 9999\nvars[\"冰刺数量\"] = 0\nvars[\"寒冰指最大层数\"] = 2\n\n",
        },
        ["奥术"] = {
            ["_专精初始化"] = "--法师-奥术-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
        },
        ["火焰"] = {
            ["_专精初始化"] = "--法师-火焰-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"瞬发烈焰风暴起始数量\"] = talent[\"烈焰之地\"] and 2 or 4\nvars[\"读条烈焰风暴起始数量\"] = talent[\"烈焰之地\"] and 3 or 6\nvars[\"燃烧中烈焰风暴起始数量\"] = talent[\"烈焰之地\"] and 3 or 6\nvars[\"燃烧CD阈值\"] = talent[\"薪火\"] and 50 or 38\n",
        },
    },
    ["潜行者"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--潜行者-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["保命"] = "--潜行者-全专精-保命\nvars[\"潜行中\"] = player.MyBuff:Has(\"潜行\") or player.MyBuff:Has(\"消失\")\n\nlocal v\nif not inCombat then\n	v = A[\"潜行\"]:Cast(not player.MyBuff:Has(\"潜行\") and IsForceStart() and not A[\"潜行\"]:SucceededIn(2)) if v then return v end\n	return \nend\n\nv = SwitchIsOn(\"保命消失\") and player.HealthPercent < 0.1 and A[\"消失\"]:Cast() if v then return v end\n--if player.HealthPercent < 0.4 or not talent[\"飘忽不定\"] or not player.MyBuff:Has(\"佯攻\") then\nv = SwitchIsOn(A[\"保命技能\"].ActionName) and player.HealthPercent < 0.4 and A[\"保命技能\"]:Cast() if v then return v end\nv = SwitchIsOn(\"暗影斗篷\") and player.HealthPercent < 0.4 and A[\"暗影斗篷\"]:Cast() if v then return v end\n--end\n\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = SwitchIsOn(\"保命消失\") and player.HealthPercent < 0.1 and vars[\"非装死中\"] and A[\"消失\"]:Cast() if v then return v end\n\n",
            ["切割"] = "--潜行者-全专精-切割\nif not SwitchIsOn(\"切割\") then\n	return\nend\nif vars[\"连击点\"] == 0 then\n	return\nend\nif target.RangeToPlayer > (inCombat and vars[\"潜行起手距离\"] or (vars[\"潜行起手距离\"] + 5)) then\n	return\nend\nif vars[\"爆发强度\"] < 1 and vars[\"目标死亡时间\"] < 8 then\n	return\nend\nif boss.IsTarget and vars[\"目标死亡时间\"] < 8 then\n	return\nend\nif not talent[\"穷追猛砍\"] or not player.MyBuff:Has(\"切割\") then\n    return A[\"切割\"]:Cast(nil, nil, {RefillTime = (vars[\"连击点\"] + 1) * 1.8})\nend\n",
            ["嫁祸诀窍"] = "--潜行者-全专精-嫁祸诀窍\nif inTraining then\n    return\nend\nif not A[\"嫁祸诀窍\"]:IsReady() then\n    return\nend\nlocal v, u\nif inParty or inRaid then\n	if focus.IsFriend and focus:IsAlive() and focus:GetDuty() == \"TANK\" then\n		u = focus\n	else\n		u = friends:GetTank()\n    end\n	if u and combatTime > 5 then --仅战斗开始5秒内误导T\n		return\n	end\nend\nif u and u.RangeToPlayer < 60 then\n	v = A[\"嫁祸诀窍\"]:Cast(nil, u) if v then return v end\nend\n",
            ["搜索"] = "--潜行者-全专精-搜索\nif not SwitchIsOn(\"搜索\") then\n    return\nend\nif inPvpCombat then\n    return\nend\nif boss.IsTarget then\n    return\nend\nif A[\"搜索\"]:SucceededOnUnit(target, 10) then\n    return\nend\nif A[\"搜索\"]:FailedOnUnit(target, 10) then\n    local s = A[\"搜索\"].FailReason\n    if s == \"没有物品可以拿取\" or s == \"无效的目标\" then\n        --print(\"**********没有物品可以拿取\")\n        return\n    end\nend\n\nreturn A[\"搜索\"]:Cast()\n",
            ["暗影步"] = "--潜行者-全专精-暗影步\nreturn A[\"暗影步\"]:Cast(target.RangeToPlayer > 8)\n",
            ["潜行起手"] = "--潜行者-全专精-潜行起手\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nvars[\"连击点差\"] = player:GetPowerDeficit(P[\"连击点\"])\n\nif player.MyBuff:Has(\"潜行\") then\n    v = run(\"搜索\") if v then return v end\n	if vars[\"爆发强度\"] > 2 and target.RangeToPlayer < vars[\"潜行起手距离\"] then\n		v = vars[\"连击点\"] > 0 and A[\"切割\"]:Cast() if v then return v end\n		v = SwitchIsOn(\"死亡标记\") and A[\"死亡标记\"]:Cast(vars[\"连击点\"] < 2) if v then return v end\n		v = legendary[\"刺客大师印记\"] and run(\"爆发技能\") if v then return v end\n	end\n    v = A[\"偷袭\"]:Cast(target.IsPlayer or not vars[\"潜行起手技能\"].IsValid) if v then return v end\n    v = vars[\"潜行起手技能\"]:ForceCast() if v then return v end\nelseif not inCombat and not player.MyBuff:Has(\"消失\") then\n    v = A[\"潜行\"]:Cast(not A[\"潜行\"]:SucceededIn(2)) if v then return v end\nend\n",
            ["肾击"] = "--潜行者-全专精-肾击\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nreturn A[\"肾击\"]:Cast(vars[\"连击点\"] > 2)",
            ["输出初始化"] = "--潜行者-全专精-输出初始化\nrun(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["奇袭"] = {
            ["_专精初始化"] = "--潜行者-奇袭-_专精初始化\nrun(\"全专精-_专精初始化\")\n--vars[\"潜行起手技能\"] = A[\"强制锁喉\"]\nvars[\"潜行起手距离\"] = 15\n--if not vars[\"诡诈锁喉结束时间\"] then vars[\"诡诈锁喉结束时间\"] = 0 end\n",
            ["爆发技能"] = "--潜行者-奇袭-爆发技能\nif vars[\"爆发强度\"] < 4 or not SwitchIsOn(\"输出爆发\") then\n    return\nend\nlocal v\n--v = A[\"宿敌\"]:Cast(target.RangeToPlayer < 5 and vars[\"连击点差\"] < 4 and (not SwitchIsOn(\"诡诈消失\") or A[\"消失\"]:IsReady(3) or A[\"消失\"]:GetCooldown() > 20)) if v then return run(\"一键爆发\") end\n--if player.MyBuff[\"宿敌\"]:GetTimeLeft() < 10 then\n--    return\n--end\n",
            ["补刀"] = "--潜行者-奇袭-补刀\nlocal v\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nv = A[\"毁伤\"]:Cast(A[\"毁伤\"]:GetDamage() >= target.Health) if v then return v end \nv = A[\"影袭\"]:Cast(A[\"影袭\"]:GetDamage() >= target.Health) if v then return v end \nif A[\"毒伤\"].IsValid then\n    v = A[\"影袭\"]:Cast(A[\"影袭\"]:GetDamage() * vars[\"连击点\"] >= target.Health) if v then return v end \nelse\n    v = A[\"刺骨\"]:Cast(A[\"刺骨\"]:GetDamage() * vars[\"连击点\"] >= target.Health) if v then return v end\nend\n",
            ["输出"] = "--潜行者-奇袭-输出\nlocal v\nvars[\"连击点\"] = player:GetPower(P[\"连击点\"])\nvars[\"连击点差\"] = player:GetPowerDeficit(P[\"连击点\"])\nv = SwitchIsOn(\"嫁祸诀窍\") and run(\"嫁祸诀窍\") if v then return v end\n--v = run(\"潜行起手\") if v then return v end\nif player.MyBuff:Has(\"潜行\") then\n    v = run(\"搜索\") if v then return v end\n	if vars[\"爆发强度\"] > 2 and target.RangeToPlayer < vars[\"潜行起手距离\"] then\n		v = vars[\"连击点\"] > 0 and A[\"切割\"]:Cast() if v then return v end\n	end\n    if vars[\"敌方目标数量\"] < 3 then\n        if A[\"锁喉\"].IsValid then\n            v = A[\"锁喉\"]:Cast() if v then return v end\n            v = A[\"伏击\"]:Cast() if v then return v end\n        else\n            v = A[\"偷袭\"]:Cast() if v then return v end\n        end\n    end\nelseif not inCombat and not player.MyBuff:Has(\"消失\") then\n    v = A[\"潜行\"]:Cast(not A[\"潜行\"]:SucceededIn(2)) if v then return v end\nend\nif not inCombat and A[\"潜行\"].IsValid and A[\"锁喉\"].IsValid then\n    return\nend\n\n\n--1.潜行起手：潜行、嫁祸T==》绞喉起手(有流血可以直接疾跑毁伤起手)==》切割==》血之饥渴==》毁伤==》毒伤==》进入循环(可视情况选择3+循环或者4+循环)(冷血可用给刀扇或高星毒伤)\n--2.非潜行起手：在条件不允许潜行起手的时候，进战斗前偷速度药水、嫁祸T==》毁伤起手==》割裂(如队友可挂流血则使用切割)==》[血之饥渴]==》[毁伤]==》切割(如上一个终结技使用了[切割]则这里使用[毒伤])==》[毁伤]==》[毒伤]进入循环 (冷血可用给刀扇或高星毒伤)\n--3.多目标场合：超过3目标的战斗请使用[刀扇]，起手嫁祸T之后连续两个刀扇可以迅速建立T的群拉仇恨，如果预计AOE时间较长，则尽量维持切割buff和血之饥渴debuff，同时持续使用刀扇直到目标小于3.\n--4.进阶技巧：在平缓期(没有其他Buff触发的时候)的规则1：高位留能70-80打毒伤，毒伤之后立即打毁伤。规则2：如果经常遇到毒伤还没完能量就要满了，可以降低留能的值。\n--在buff触发期：无论有多少能量，在前一个毒伤结束之后马上打下一个毒伤，尽量维持毒伤的高覆盖率，同时在爆发期尽量连击点到了3星或以上就打毒伤。\n--20221021补充：关于佯攻：(由国外大佬simonize发现)听说了以后，我进行了实测，确定佯攻可以正确触发毒药，因此在配合雕文的时候，可以把佯攻作为填充技能使用，并尽量打在毒伤buff中，25人团队状态时，可粗略认为每个佯攻期望收益1000伤害左右。固定团队收益不如嫁祸雕文，但是个人boss冲榜的时候是最优选择。\n--如果你是一个新上手的刺杀贼，推荐你使用3+毒伤循环[即连击点大于等于3就使用毒伤]此循环操作简单、易于上手，与4+毒伤循环[即连击点大于等于4就使用毒伤]DPS差距极低；最后，请不要使用5+毒伤循环[即只有连击点等于5才使用毒伤]，5星毒伤循环(1-4不打毒伤，只打五星毒伤)低于3+毒伤循环(1-2不打毒伤，3-5打毒伤)≈4+毒伤循环(1-3不打毒伤，4-5打毒伤)。不同场景下，3+循环和4+循环互有胜负，也就是说打3+打4+都可以。\n--5.其他内容：[血之饥渴]持续时间一分钟，带雕文单体增伤8%，需要目标身上有流血效果，因此在血之饥渴时间快到的时候，要注意观察目标状态(推荐使用WA字符串)，如果没有其他队友(野德、战士)可以上流血效果，就需要提前补[割裂]以免断血渴效果；\n--如果团队里没有战士、猎人等其他职业提供20%的破甲debuff，刺杀贼要不要打[破甲]？如果团队里仅有自己一名菜刀，不要打；如果团队里有其他菜刀，即使只有两个人，也是正收益，那就打[破甲]；\n--[消失]可以触发[灭绝]并提供约60点能量，请记得将消失安排到输出循环中，作为一个buff技能使用。另外，由于[佯攻]改版后可降低50%的AOE伤害，善用[暗影斗篷]和佯攻规避伤害可大幅度增加生存能力。\n\n--v = run(\"爆发技能\") if v then return v end\nv = A[\"血之饥渴\"]:Cast() if v then return v end\n\nv = A[\"割裂\"]:Cast(not player.MyBuff:Has(\"血之饥渴\")) if v then return v end\n \nv = run(\"切割_\") if v then return v end\nvars[\"能量\"] = player:GetPower(P[\"能量\"])\nv = vars[\"能量\"] < 30 and SwitchIsOn(\"输出消失\") and (vars[\"敌方目标数量\"] > 2 or A[\"锁喉\"]:Cast()) and A[\"消失\"]:Cast() if v then return v end\nif vars[\"敌方目标数量\"] > 2 then\n    --AOE 只打刀扇\n    v = A[\"刀扇\"]:Cast() \n    if v then \n        return SwitchIsOn(\"冷血\") and A[\"冷血\"]:Cast() or v \n    end\n    return\nend\n--单体\n--终结技\nif vars[\"连击点差\"] < 2 then\n    v = SwitchIsOn(\"破甲\") and A[\"破甲\"]:Cast() if v then return v end\n    if A[\"毒伤\"].IsValid then\n        v = vars[\"能量\"] > 75 and A[\"毒伤\"]:Cast() \n        if v then \n            if vars[\"连击点差\"] == 0 and SwitchIsOn(\"冷血\") then\n                return A[\"冷血\"]:Cast() or v\n            else\n                return v \n            end\n        end\n    else\n        v = A[\"刺骨\"]:Cast() if v then return v end\n    end\nend\n--连击点\nif A[\"毁伤\"].IsValid then\n    v = vars[\"连击点差\"] > 1 and A[\"毁伤\"]:Cast() if v then return v end \nelse\n    v = SwitchIsOn(\"背刺\") and not A[\"背刺\"]:FailedIn(2, \"你必须位于目标背后。\") and A[\"背刺\"]:Cast() if v then return v end\n    v = vars[\"能量\"] > 60 and A[\"影袭\"]:Cast() if v then return v end\nend\nv = SwitchIsOn(\"佯攻\") and A[\"佯攻\"]:Cast() if v then return v end\n\nv = SwitchIsOn(\"暗影步\") and target.RangeToPlayer > 8 and A[\"暗影步\"]:Cast() if v then return v end\n\n\n",
        },
        ["战斗"] = {
            ["_专精初始化"] = "--潜行者-战斗-_专精初始化\nrun(\"全专精-_专精初始化\")\nvars[\"潜行起手技能\"] = A[\"伏击\"]\nvars[\"潜行起手距离\"] = 15\nvars[\"攻击距离\"] = talent[\"杂耍打击\"] and 8 or 5\nvars[\"敌方目标距离\"] = talent[\"杂耍打击\"] and 10 or 8\nvars[\"命运骨骰Buff\"] = \n{\n    [\"残忍精准\"] = 0,     --正中眉心爆击几率提高60%，其他技能提高20%。\n    [\"大乱斗\"] = 0,        --攻击速度提高55%。吸血提高25%\n    [\"骷髅黑帆\"] = 0,        --影袭触发额外攻击提高30%。\n    [\"强势连击\"] = 0,        --你的攻击获得1个额外的连击点数。且伤害提高20%\n    [\"埋藏的宝藏\"] = 0,   --每秒能量恢复提高4点\n    [\"精准定位\"] = 0,        --终结技会使你的许多技能冷却时间缩短，每花费一个连击点数可缩短1秒。\n}\n\n--AddCommonSwitch(\"AOE\", \"JAOE\", \"剑刃乱舞\")\n--AddPriorMacro(\"正中眉心\")\n--AddPriorMacro(\"冲动\")\n--AddPriorMacro(\"剑刃乱舞\")\n--AddSpellSwitch(\"剑刃乱舞\", nil, \"剑舞\")\n--AddSpellSwitch(\"消失\")\n--AddSpellSwitch(\"佯攻\")\n--AddSpellSwitch(\"猩红之瓶\")\n--AddSpellSwitch(\"还击\")\n--if talent[\"刀锋冲刺\"] then\n--    AddSpellSwitch(\"刀锋冲刺\")\n--end\n--AddSpellSwitch(\"仇敌之血\")\n",
            ["_脚本初始化"] = "--潜行者-战斗-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n",
            ["输出初始化"] = "--潜行者-战斗-输出初始化\nrun(\"全职业-全专精-输出初始化\", player, vars[\"敌方目标距离\"])\n\n",
