    ["牧师"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--牧师-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["_暗言术：灭"] = "--牧师-全专精-_暗言术：灭\nif not SwitchIsOn(\"暗言术：灭\") then\n    return\nend\nlocal v = A[\"暗言术：灭\"]:Cast()\nif not v then return end\n--if target.HealthPercent >= 0.2 then\n--    return\n--end\n\nlocal dmg = A[\"暗言术：灭\"]:GetDamage()\nif target.Health <= A[\"暗言术：灭\"]:GetDamage() then\n    return v\nend\n",
            ["希望圣歌"] = "--牧师-全专精-希望圣歌\nlocal castTo, params = ...\n--if not castTo then \n--    castTo = (UnitExists(\"target\") and target or player)\n--end\nreturn run(\"安全引导\", \"希望圣歌\", castTo, params)\n\n\n",
            ["神圣赞美诗"] = "--牧师-全专精-神圣赞美诗\nlocal castTo, params = ...\n--if not castTo then \n--    castTo = (UnitExists(\"target\") and target or player)\n--end\nreturn run(\"安全引导\", \"神圣赞美诗\", castTo, params)\n\n",
