        ["戒律"] = {
            ["_专精初始化"] = "--牧师-戒律-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--牧师-戒律-_脚本初始化\nrun(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--牧师-戒律-保命\nlocal v\nif not inCombat then\n    v = A[\"强效治疗术\"]:CastSafely(player.HealthPercent < 0.8, player) if v then return v end\n    v = SwitchIsOn(\"真言术：韧\") and A[\"坚韧祷言\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"神圣之灵\") and A[\"精神祷言\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"暗影防护\") and A[\"暗影防护祷言\"]:Cast() if v then return v end\n    v = A[\"心灵之火\"]:Cast() if v then return v end\n	v = A[\"真言术：盾\"]:Cast(player.HealthPercent < 0.9 and not player.AllDebuff:Has(\"虚弱灵魂\") and not player.MyBuff:Has(\"进食\"), player) if v then return v end\n    return \nend\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"真言术：盾\"]:Cast(player.HealthPercent < 0.7 and not player.AllDebuff:Has(\"虚弱灵魂\") and not player.MyBuff:Has(\"进食\"), player) if v then return v end\nv = SwitchIsOn(\"绝望祷言\") and A[\"绝望祷言\"]:Cast() if v then return v end\nv = SwitchIsOn(\"痛苦压制\") and A[\"痛苦压制\"]:Cast() if v then return v end\n\n\n\n\n",
            ["治疗"] = "--牧师-戒律-治疗\nlocal v\n\nvars[\"虚弱灵魂\"] = healTarget.AllDebuff:Has(\"虚弱灵魂\")\nif inCombat then\n    v = A[\"快速治疗\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    v = A[\"强效治疗术\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    v = healTarget.HealthPercent < 0.9 and A[\"真言术：盾\"]:Cast(not vars[\"虚弱灵魂\"], healTarget) if v then return v end\n    v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    v = A[\"痛苦压制\"]:Cast(healTarget.HealthPercent < 0.4, healTarget) if v then return v end\n    v = A[\"能量灌注\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"神圣赞美诗\") and run(\"安全引导\", \"神圣赞美诗\") if v then return v end\n    v = healTarget.HealthPercent > 0.3 and A[\"治疗之环\"]:Cast(nil, healTarget) if v then return v end\n    if healTarget.HealthPercent < (inRaid and 0.8 or 0.6) then\n        v = A[\"苦修\"]:Cast(nil, healTarget) if v then return v end\n        v = A[\"联结治疗\"]:Cast(not UnitIsUnit(healTarget.UnitId, \"player\") and player.HealthPercent < 0.85, healTarget) if v then return v end\n        if healTarget.HealthPercent < 0.5 then\n            v = A[\"快速治疗\"]:Cast(nil, healTarget) if v then return v end\n            v = SwitchIsOn(\"治疗术\") and A[\"强效治疗术\"]:Cast(nil, healTarget) if v then return v end\n        elseif not inRaid then\n            v = SwitchIsOn(\"治疗术\") and A[\"强效治疗术\"]:Cast(nil, healTarget) if v then return v end\n            v = A[\"快速治疗\"]:Cast(nil, healTarget) if v then return v end\n        end\n    end\n    v = A[\"光明之泉\"]:Cast(nil, player) if v then return v end\n    if player:GetPowerPercent(P[\"法力\"]) < 0.35 then\n        v = target.IsEnemy and A[\"暗影恶魔\"]:Cast() if v then return v end\n        v = SwitchIsOn(\"希望圣歌\") and run(\"安全引导\", \"希望圣歌\") if v then return v end\n    end\n\n\nend\n\nv = healTarget.HealthPercent < 0.8 and A[\"苦修\"]:Cast(nil, healTarget) if v then return v end\nv = healTarget.HealthPercent < (inRaid and 0.75 or 0.85) and SwitchIsOn(\"恢复\") and A[\"恢复\"]:Cast(nil, healTarget) if v then return v end\nv = A[\"愈合祷言\"]:Cast(healTarget.HealthPercent < 0.95 and friends:GetMyBuffCount(\"愈合祷言\", 100) == 0, healTarget) if v then return v end\nv = SwitchIsOn(\"治疗术\") and healTarget.HealthPercent < (inRaid and 0.5 or 0.7) and A[\"强效治疗术\"]:Cast(nil, healTarget) if v then return v end\nv = SwitchIsOn(\"快速治疗\") and healTarget.HealthPercent < (inRaid and 0.5 or 0.8) and A[\"快速治疗\"]:Cast(nil, healTarget) if v then return v end\nif UnitExists(\"mouseover\") then\n    v = mouseover.HealthPercent < 0.9 and not vars[\"虚弱灵魂\"] and A[\"真言术：盾\"]:Cast(nil, mouseover) if v then return v end\nend\n",
            ["输出"] = "--牧师-戒律-输出\nlocal v\nv = SwitchIsOn(\"驱敌魔法\") and A[\"驱散魔法_敌方\"]:Cast() if v then return v end\n--v = A[\"吸血鬼之触\"]:Cast() if v then return v end\n--神圣之火	11		78	2秒施法时间	30码距离	10秒冷却时间		12法力值			神圣的烈焰吞噬敌人，对其造成890到1130点神圣伤害，并在7秒内造成350点额外的神圣伤害。												\nv = A[\"神圣之火\"]:Cast() if v then return v end\n--心灵震爆	13		79	1.5秒施法时间	30码距离	8秒冷却时间		18法力值			用暗影魔法冲击敌人，对其造成992到1048点暗影伤害。												\nv = A[\"心灵震爆\"]:Cast() if v then return v end\nv = enemies:GetMyDebuffCount(\"噬灵疫病\", 60) == 0 and A[\"噬灵疫病\"]:Cast() if v then return v end\nv = A[\"暗言术：痛\"]:Cast() if v then return v end\nv = SwitchIsOn(\"神圣新星\") and not SwitchIsOn(\"仅单体\") and A[\"神圣新星\"]:Cast(enemies:GetNearbyCount(player, 12) > 2) if v then return v end\n\nv = SwitchIsOn(\"暗言术：灭\") and A[\"暗言术：灭\"]:Cast() if v and target.Health <= A[\"暗言术：灭\"]:GetDamage() then return v end\n\nif SwitchIsOn(\"鼠指痛\") and UnitExists(\"mouseover\") and not UnitIsUnit(\"target\", \"mouseover\") then\n    v = A[\"暗言术：痛\"]:Cast(nil, mouseover) if v then return v end\nend\nv = SwitchIsOn(\"输出苦修\") and A[\"苦修\"]:Cast() if v then return v end\nv = A[\"惩击\"]:Cast() if v then return v end\n",
