            ["_暗言术：灭"] = "--牧师-暗影-_暗言术：灭\nif not SwitchIsOn(\"暗言术：灭\") then\n    return\nend\nif not A[\"暗言术：灭\"]:IsReady() then return end\n\nlocal v, unit\nif target.HealthPercent < 0.2 then\n    v = A[\"暗言术：灭\"]:Cast() if v then return v end\nend\n\nif vars[\"敌方目标数量\"] > 1 then\n    for _, unit in pairs(enemies.Units) do\n        if unit.NeedAttack and unit.HealthPercent < 0.2 and unit:IsInFrontOfPlayer(40, 50) then\n            v = A[\"暗言术：灭\"]:Cast(nil, unit) if v then return v end\n	    end\n    end\nend\n\nif vars[\"暗影烈焰棱镜\"] and player.Health > A[\"暗言术：灭\"]:GetDamage() * 2.5 then\n    v = A[\"暗言术：灭\"]:Cast() if v then return v end\nend\n\n",
