            ["_专精初始化"] = "--牧师-神圣-_专精初始化\nrun(\"全专精-_专精初始化\")\n\n",
            ["_脚本初始化"] = "--牧师-神圣-_脚本初始化\nrun(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--牧师-神圣-保命\nlocal v\nv = SwitchIsOn(\"真言术：盾\") and A[\"真言术：盾\"]:Cast(player.HealthPercent < 0.9 and not player.AllDebuff:Has(\"虚弱灵魂\") and not player.MyBuff:Has(\"进食\"), player) if v then return v end\nif not inCombat then\n    v = A[\"快速治疗\"]:Cast(player.HealthPercent < 0.8, player) if v then return v end\n    v = A[\"快速治疗\"]:CastSafely(player.HealthPercent < 0.9, player) if v then return v end\n    v = SwitchIsOn(\"真言术：韧\") and A[\"坚韧祷言\"]:Cast() if v then return v end\n    return \nend\nv = A[\"真言术：盾\"]:Cast(player.HealthPercent < 0.7 and not player.AllDebuff:Has(\"虚弱灵魂\") and not player.MyBuff:Has(\"进食\"), player) if v then return v end\nv = A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\nv = A[\"绝望祷言\"]:Cast() if v then return v end\nv = A[\"守护之魂\"]:Cast(player.HealthPercent < 0.35, player) if v then return v end\nv = A[\"希望象征\"]:Cast(player:GetPowerPercent(P[\"法力\"]) < 0.2) if v then return v end\nv = A[\"真言术：韧\"]:Cast() if v then return v end\n",
            ["治疗"] = "--牧师-神圣-治疗\nlocal v\nvars[\"快速专注\"] = player.MyBuff[\"快速专注\"]\nlocal fillkszz = legendary[\"快速专注\"] and (vars[\"快速专注\"].Count < 5 or vars[\"快速专注\"]:GetTimeLeft() < 5)\nif inCombat then\n    v = A[\"快速治疗\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    v = A[\"治疗术\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    v = A[\"真言术：盾\"]:Cast(healTarget.HealthPercent < 0.95 and not healTarget.AllDebuff:Has(\"虚弱灵魂\"), healTarget) if v then return v end\n    --v = SwitchIsOn(\"控心术\") and A[\"控心术\"]:Cast(healTarget.HealthPercent < 0.6 and target.IsEnemy) if v then return v end\n    if healTarget.HealthPercent > 0.25 and fillkszz then\n        v = A[\"快速治疗\"]:CastSafely(nil, healTarget) if v then return v end\n    end\n\n    v = A[\"圣言术：静\"]:Cast(healTarget.HealthPercent < 0.5, healTarget) if v then return v end\n    v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    v = A[\"守护之魂\"]:Cast(healTarget.HealthPercent < 0.35, healTarget) if v then return v end\n    --v = run(\"使用饰品\", \"释魂红玉\", target.IsEnemy and hoe:Need(), target) if v then return v end\n    v = A[\"圣言术：赎\"]:Cast() if v then return v end\n    v = A[\"能量灌注\"]:Cast() if v then return run(\"一键爆发\") end\n    v = run(\"神圣赞美诗\") if v then return v end\n    v = A[\"神圣化身\"]:Cast() if v then return v end\n    if vars[\"快速专注\"].Count == 5 then\n        if healTarget.HealthPercent < 0.4 then\n            v = A[\"治疗术\"]:Cast(nil, healTarget) if v then return v end\n        elseif healTarget.HealthPercent < 0.6 then\n            v = A[\"治疗术\"]:CastSafely(nil, healTarget) if v then return v end\n        end\n    end\n    v = A[\"快速治疗\"]:Cast(healTarget.HealthPercent < 0.3 or (healTarget.HealthPercent < 0.5 and player.MyBuff:Has(\"圣光涌动\")), healTarget) if v then return v end\n    if player.MyBuff:Has(\"晋升者之赐\") then\n        v = A[\"晋升新星_治疗\"]:Cast() if v then return v end\n    end\n    v = A[\"光晕\"]:Cast() if v then return v end\n    v = A[\"圣言术：灵\"]:Cast() if v then return v end\n    v = A[\"治疗之环\"]:Cast(nil, healTarget) if v then return v end\n    v = A[\"神圣之星\"]:Cast() if v then return v end\nelse\n    if healTarget.HealthPercent > 0.25 and fillkszz then\n        v = A[\"快速治疗\"]:CastSafely(nil, healTarget) if v then return v end\n    end\nend\nv = A[\"联结治疗\"]:Cast(not UnitIsUnit(healTarget.UnitId, \"player\") and healTarget.HealthPercent < 0.9 and player.HealthPercent < 0.9, healTarget) if v then return v end\nv = A[\"愈合祷言\"]:Cast(healTarget.HealthPercent >= 0.5 and friends:GetMyBuffCount(\"愈合祷言\", 100) == 0 and UnitName(\"target\") ~= \"枯萎之种\", healTarget) if v then return v end\nv = A[\"治疗祷言\"]:Cast(nil, healTarget) if v then return v end\nv = A[\"恢复\"]:Cast(healTarget.HealthPercent >= 0.5 and healTarget.HealthPercent < 0.95, healTarget) if v then return v end\n\n\nif inRaid then\n    if vars[\"快速专注\"].Count == 5 then\n        if healTarget.HealthPercent < 0.85 then\n            v = A[\"治疗术\"]:CastSafely(nil, healTarget) if v then return v end\n        end\n    else\n        if SwitchIsOn(\"治疗术\") then\n            v = A[\"快速治疗\"]:Cast(healTarget.HealthPercent < 0.6, healTarget) if v then return v end\n            v = A[\"快速治疗\"]:CastSafely(healTarget.HealthPercent < 0.7 or (healTarget.HealthPercent < 0.85 and (talent[\"光明尾迹\"] or player.MyBuff[\"圣光涌动\"].Count == 2)), healTarget) if v then return v end\n            v = A[\"治疗术\"]:CastSafely(healTarget.HealthPercent < 0.87, healTarget) if v then return v end\n        else\n            v = A[\"快速治疗\"]:Cast(healTarget.HealthPercent < 0.75, healTarget) if v then return v end\n            v = A[\"快速治疗\"]:CastSafely(healTarget.HealthPercent < 0.8 or (healTarget.HealthPercent < 0.85 and (talent[\"光明尾迹\"] or player.MyBuff[\"圣光涌动\"].Count == 2)), healTarget) if v then return v end\n        end\n    end\nelse\n    if vars[\"快速专注\"].Count == 5 then\n        if healTarget.HealthPercent < 0.86 then\n            v = A[\"治疗术\"]:CastSafely(nil, healTarget) if v then return v end\n        end\n    else\n        v = A[\"快速治疗\"]:Cast(healTarget.HealthPercent < 0.75, healTarget) if v then return v end\n        v = A[\"快速治疗\"]:CastSafely(healTarget.HealthPercent < 0.82 or (healTarget.HealthPercent < 0.86 and (talent[\"光明尾迹\"] or player.MyBuff[\"圣光涌动\"].Count == 2)), healTarget) if v then return v end\n        v = SwitchIsOn(\"治疗术\") and A[\"治疗术\"]:CastSafely(healTarget.HealthPercent < 0.86, healTarget) if v then return v end\n    end\nend\nv = A[\"恢复\"]:Cast(healTarget.HealthPercent < 0.95, healTarget) if v then return v end\n\nif SwitchIsOn(\"真言术：盾\") and UnitExists(\"mouseover\") then\n    v = A[\"真言术：盾\"]:Cast(mouseover.HealthPercent < 0.95 and not mouseover.AllDebuff:Has(\"虚弱灵魂\"), mouseover) if v then return v end\nend\n",
            ["输出"] = "--牧师-神圣-输出\nlocal v\nif player:HasBuff(\"救赎之魂\") then\n    return\nend\nv = run(\"虚空幽灵玺戒\") if v then return v end\nif player.MyBuff:Has(\"晋升者之赐\") then\n    v = A[\"晋升新星_伤害\"]:Cast() if v then return v end\n    v = A[\"晋升冲击\"]:Cast() if v then return v end\nend\nv = run(\"_暗言术：灭\") if v then return v end\nv = A[\"驱散魔法\"]:Cast() if v then return v end\nv = A[\"神圣之火\"]:Cast() if v then return v end\nv = A[\"惩击\"]:Cast(not inCombat and not A[\"惩击\"]:CastedIn(3) and not A[\"神圣之火\"]:CastedIn(3)) if v then return v end\nv = A[\"圣言术：罚\"]:Cast() if v then return v end\nv = A[\"神圣新星\"]:Cast() if v then return v end\nv = A[\"暗言术：痛\"]:Cast() if v then return v end\nif UnitExists(\"mouseover\") and SwitchIsOn(\"鼠指痛\") and not UnitIsUnit(\"target\", \"mouseover\") then\n    v = A[\"暗言术：痛\"]:Cast(nil, mouseover) if v then return v end\nend\nv = A[\"惩击\"]:Cast() if v then return v end\n",
        },
    },
    ["猎人"] = {
        ["全专精"] = {
            ["_专精初始化"] = "--猎人-全专精-_专精初始化\n--print(\"猎人-全专精-_专精初始化\")\n\nrun(\"全职业-全专精-_专精初始化\")\n\n",
            ["保命"] = "--猎人-全专精-保命\nif player.MyBuff:Has(\"假死\") then\n    return 0\nend\nif inCombat then\n	--v = SwitchIsOn(\"意气风发\") and A[\"意气风发\"]:Cast(player.HealthPercent < 0.35) if v then return v end\n	v = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n    --v = SwitchIsOn(\"优胜劣汰\") and A[\"优胜劣汰\"]:Cast() if v then return v end\n    --v = SwitchIsOn(\"灵龟守护\") and (not A[\"灵龟守护\"]:IsProtected()) and A[\"灵龟守护\"]:Cast() if v then A[\"灵龟守护\"]:Protect(1, 0) return v end\n    v = A[\"威慑\"]:Cast() if v then return v end\nend\nv = run(\"治疗复活宠物\") if v then return v end\n\n",
            ["假死"] = "--猎人-全专精-假死_优先\nif player.MyBuff:Has(\"假死\") then\n    return 0\nend\nreturn A[\"假死\"]:Cast()\n",
            ["智能误导"] = "--猎人-全专精-智能误导\nif inTraining then\n    return\nend\nif not SwitchIsOn(\"智能误导\") then\n    return\nend\nif not A[\"误导\"]:IsReady() then\n    return\nend\nlocal v, u\nif inParty or inRaid then\n	if focus.IsFriend and focus:IsAlive() and focus:GetDuty() == \"TANK\" then\n		u = focus\n	else\n		u = friends:GetTank()\n    end\n	if u and combatTime > 5 then --仅战斗开始5秒内误导T\n		return\n	end\nend\nif not u and UnitExists(\"pet\") and not UnitIsDead(\"pet\") then\n	u = pet\nend\nif u and u.RangeToPlayer < 60 then\n	v = A[\"误导\"]:Cast(nil, u) if v then return v end\nend\n",
            ["治疗复活宠物"] = "--猎人-全专精-治疗复活宠物\n        --print(\"111\", UnitExists(\"pet\"), UnitIsDead(\"pet\"), A[\"复活宠物\"].ActionName, A[\"复活宠物\"].ID, A[\"复活宠物\"].BindingInfo.BindingKeyCode, A[\"治疗宠物\"].ActionName, A[\"治疗宠物\"].ID)\nif UnitLevel(\"player\") < 3 then\n    return\nend\nif SwitchIsOn(\"召唤宠物\") then\n    if UnitIsDead(\"pet\") then\n        --print(\"111\", UnitExists(\"pet\"), UnitIsDead(\"pet\"), A[\"复活宠物\"].ActionName, A[\"复活宠物\"].ID, A[\"复活宠物\"]:GetCooldown(), gcdmax, A[\"复活宠物\"]:IsCasting())\n        --if(A[\"复活宠物\"]:GetCooldown() < gcdmax) and not A[\"复活宠物\"]:IsCasting() then\n        if not A[\"复活宠物\"]:IsCasting() then\n            return A[\"复活宠物\"]:Cast()\n        end\n        return 0\n    elseif not UnitExists(\"pet\") then --not exist\n		local v\n		if GetSpecialization() == 1 then\n			v = A[\"兽王召唤宠物\"]:Cast(not A[\"兽王召唤宠物\"]:IsProtected()) if v then A[\"兽王召唤宠物\"]:Protect(3) return v end\n		else\n			v = A[\"其他召唤宠物\"]:Cast(not A[\"其他召唤宠物\"]:IsProtected()) if v then A[\"其他召唤宠物\"]:Protect(3) return v end\n		end\n\n		--v = A[\"复活宠物\"]:Cast() if v then return v end\n			--print(\"222\", UnitExists(\"pet\"), UnitIsDead(\"pet\"), A[\"复活宠物\"].ActionName, A[\"复活宠物\"].ID, A[\"复活宠物\"]:GetCooldown(), gcdmax, A[\"复活宠物\"]:IsCasting())\n		--if(A[\"复活宠物\"]:GetCooldown() < gcdmax) and not A[\"复活宠物\"]:IsCasting() then\n		if not A[\"复活宠物\"]:IsCasting() then\n			return A[\"复活宠物\"]:Cast(not A[\"复活宠物\"]:FailedIn(5, \"你的宠物还未死亡\"))\n		end\n		return 0\n	end\nend\n--治疗宠物\nif UnitExists(\"pet\") and not UnitIsDead(\"pet\") then --IsPetActive()\n    local petHealthPercent = pet.HealthPercent\n    if petHealthPercent < 0.9 then\n        if UnitExists(\"boss1\") then\n            if UnitIsUnit(\"boss1target\", \"pet\") then\n                if(A[\"治疗宠物\"]:GetCooldown() < 0.4) then\n                    return A[\"治疗宠物\"]:Cast()\n                end\n            else\n                if petHealthPercent < 0.5 then\n                    if(A[\"治疗宠物\"]:GetCooldown() < 0.4) then\n                        return A[\"治疗宠物\"]:Cast()\n                    end\n                end\n            end\n        elseif petHealthPercent < 0.65 or not (inInstance and UnitExists(\"party1\")) then\n            --print(\"222\", UnitExists(\"pet\"), UnitIsDead(\"pet\"), A[\"复活宠物\"].ActionName, A[\"复活宠物\"].ID, A[\"治疗宠物\"].ActionName, A[\"治疗宠物\"].ID)\n            --print(A[\"治疗宠物\"]:IsReady(gcdmax), A[\"治疗宠物\"]:GetCooldown(), A[\"治疗宠物\"].ActionName)\n            if(A[\"治疗宠物\"]:GetCooldown() < 0.4) then\n                return A[\"治疗宠物\"]:Cast()\n            end\n            --return A[\"治疗宠物\"]:Cast(nil, nil, {LeadCd=gcdmax})\n        end\n    end\nend\n",
            ["猎人印记_"] = "--猎人-全专精-猎人印记_\nif not target.IsPlayer then\n    return\nend\nlocal v = UnitClass(\"target\")\nif v == \"潜行者\" or v == \"德鲁伊\" or v == \"法师\" or UnitRace(\"player\") == \"暗夜精灵\" then\n    v = A[\"猎人印记\"]:Cast(not target.AllDebuff:Has(\"猎人印记\")) if v then return v end \nend\n",
        },
        ["射击"] = {
            ["_专精初始化"] = "--猎人-射击-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
        },
        ["生存"] = {
            ["_专精初始化"] = "--猎人-生存-_专精初始化\n--vars[\"补毒蛇钉刺条件\"] = function(unit) return not unit.MyDebuff:Has(\"信息素炸弹\") end\nrun(\"全专精-_专精初始化\")\n",
            ["输出初始化"] = "--猎人-生存-输出初始化\nrun(\"全职业-全专精-输出初始化\", player, 8)\n\n",
        },
        ["野兽控制"] = {
            ["_专精初始化"] = "--猎人-野兽控制-_专精初始化\nprint(\"猎人-野兽控制-_专精初始化\")\nrun(\"全专精-_专精初始化\")\n\n",
            ["_脚本初始化"] = "--猎人-野兽控制-_脚本初始化\nrun(\"全专精-_脚本初始化\")\n",
        },
    },
    ["萨满祭司"] = {
        ["元素"] = {
            ["_专精初始化"] = "--萨满祭司-元素-_专精初始化\nrun(\"全专精-_专精初始化\")\n\n",
        },
        ["全专精"] = {
            ["_专精初始化"] = "--萨满祭司-全专精-_专精初始化\nrun(\"全职业-全专精-_专精初始化\")\n",
            ["基本检查"] = "--萨满祭司-全专精-基本检查\nreturn run(\"全职业-全专精-基本检查\", player.MyBuff:Has(\"幽魂之狼\"))\n",
            ["大地之盾"] = "--萨满祭司-全专精-大地之盾\nif not SwitchIsOn(\"大地之盾\") then\n    return\nend\nif friends:GetMyBuffCount(\"大地之盾\", 60) > 0 then\n    return\nend\nif UnitIsUnit(healTarget.UnitId, \"focus\") then\n    if not healTarget.MyBuff:Has(\"大地之盾\") then\n        v = A[\"大地之盾\"]:Cast(nil, healTarget) if v then return v end\n    end\nend\nif inParty or inRaid then\n    if healTarget:GetDuty() == \"TANK\" then\n        --print(UnitName(healTarget.UnitId), healTarget:GetDuty())\n        v = A[\"大地之盾\"]:Cast(nil, healTarget) if v then return v end\n    end\nelse\n    v = A[\"大地之盾\"]:Cast(not player.MyBuff:Has(\"水之护盾\") and not player.MyBuff:Has(\"闪电之盾\"), player) if v then return v end\nend\n",
        },
        ["增强"] = {
            ["_专精初始化"] = "--萨满祭司-增强-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
        },
        ["恢复"] = {
            ["_专精初始化"] = "--萨满祭司-恢复-_专精初始化\nrun(\"全专精-_专精初始化\")\n",
            ["_脚本初始化"] = "--萨满祭司-恢复-_脚本初始化\n--run(\"更新治疗饰品\")\nrun(\"全专精-_脚本初始化\")\n",
            ["保命"] = "--萨满祭司-恢复-保命\nif not GetWeaponEnchantInfo() and GetInventoryItemLink(\"player\", 16) then--主手\n    v = SwitchIsOn(\"大地生命武器\") and A[\"大地生命武器\"]:Cast() if v then return v end\nend\nlocal v\nif not inCombat then\n    v = SwitchIsOn(\"水之护盾\") and A[\"水之护盾\"]:Cast(not player.MyBuff:Has(\"大地之盾\") and not player.MyBuff:Has(\"闪电之盾\")) if v then return v end\n    v = SwitchIsOn(\"闪电之盾\") and A[\"闪电之盾\"]:Cast(not player.MyBuff:Has(\"大地之盾\") and not player.MyBuff:Has(\"水之护盾\")) if v then return v end\n    --v = SwitchIsOn(\"大地之盾\") and not player.MyBuff:Has(\"闪电之盾\") and not player.MyBuff:Has(\"水之护盾\") and A[\"大地之盾\"]:Cast(not focus:CanBeAssisted() and friends:GetMyBuffCount(\"大地之盾\", 60) == 0, player) if v then return v end\n    return\nend\nv = SwitchIsOn(\"纳鲁的赐福\") and A[\"纳鲁的赐福\"]:Cast(player.HealthPercent < 0.4) if v then return v end\n--v = SwitchIsOn(\"星界转移\") and A[\"星界转移\"]:Cast() if v then return v end\nv = SwitchIsOn(\"水之护盾\") and A[\"水之护盾\"]:Cast(not player.MyBuff:Has(\"大地之盾\") and not player.MyBuff:Has(\"闪电之盾\")) if v then return v end\nv = SwitchIsOn(\"闪电之盾\") and A[\"闪电之盾\"]:Cast(not player.MyBuff:Has(\"大地之盾\") and not player.MyBuff:Has(\"水之护盾\")) if v then return v end\n--v = SwitchIsOn(\"大地之盾\") and not player.MyBuff:Has(\"闪电之盾\") and not player.MyBuff:Has(\"水之护盾\") and A[\"大地之盾\"]:Cast(not focus:CanBeAssisted() and friends:GetMyBuffCount(\"大地之盾\", 60) == 0, player) if v then return v end\nv = SwitchIsOn(\"法力之潮图腾\") and A[\"法力之潮图腾\"]:Cast(player:GetPowerPercent(P[\"法力\"]) < 0.2) if v then return v end\n",
            ["治疗"] = "--萨满祭司-恢复-治疗\nlocal v\nif inCombat then\n    v = A[\"次级治疗波\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    v = A[\"治疗波\"]:ShouldCancelCasting() and A[\"取消施法\"]:Cast() if v then return v end \n    v = SwitchIsOn(\"治疗链\") and A[\"治疗链\"]:GetCurrentCastingTime() == 0 and A[\"治疗链\"]:Cast(healTarget.HealthPercent < 0.86 and healTarget.HealthPercent > 0.4, healTarget) if v then return v end\n    --v = healTarget.HealthPercent < 0.5 and run(\"饰品治疗\", healTarget) if v then return v end\n    v = A[\"激流\"]:Cast(healTarget.HealthPercent < 0.6, healTarget) if v then return v end\n    v = SwitchIsOn(\"潮汐之力\") and A[\"潮汐之力\"]:Cast() if v then return v end\n    v = SwitchIsOn(\"自然迅捷\") and A[\"自然迅捷\"]:Cast(healTarget.HealthPercent < 0.4) if v then return v end\n    v = SwitchIsOn(\"治疗链\") and A[\"治疗链\"]:Cast(healTarget.HealthPercent < 0.86 and healTarget.HealthPercent > 0.4, healTarget) if v then return v end\n    if healTarget.HealthPercent < 0.6 and player.MyBuff[\"波涛汹涌\"].Count > 0 then\n        v = SwitchIsOn(\"治疗波\") and A[\"治疗波\"]:CastSafely(nil, healTarget) if v then return v end\n        v = SwitchIsOn(\"次级治疗波\") and A[\"次级治疗波\"]:CastSafely(nil, healTarget) if v then return v end\n    end\n    v = SwitchIsOn(\"次级治疗波\") and A[\"次级治疗波\"]:Cast(healTarget.HealthPercent < 0.35, healTarget) if v then return v end\nend\nv = run(\"大地之盾\") if v then return v end\n\nv = A[\"激流\"]:Cast(healTarget.HealthPercent < 0.85, healTarget) if v then return v end\n\nv = SwitchIsOn(\"治疗链\") and A[\"治疗链\"]:Cast(healTarget.HealthPercent < 0.86 and healTarget.HealthPercent > 0.4, healTarget) if v then return v end\n\n--if inRaid then\n    if SwitchIsOn(\"治疗波\") then\n        v = SwitchIsOn(\"次级治疗波\") and A[\"次级治疗波\"]:Cast(healTarget.HealthPercent < 0.6, healTarget) if v then return v end\n        v = SwitchIsOn(\"次级治疗波\") and A[\"次级治疗波\"]:CastSafely(healTarget.HealthPercent < 0.7, healTarget) if v then return v end\n        v = A[\"治疗波\"]:Cast(healTarget.HealthPercent < 0.85 and healTarget.HealthPercent > (SwitchIsOn(\"次级治疗波\") and 0.69 or 0), healTarget) if v then return v end\n    else\n        v = SwitchIsOn(\"次级治疗波\") and A[\"次级治疗波\"]:Cast(healTarget.HealthPercent < 0.65, healTarget) if v then return v end\n        v = SwitchIsOn(\"次级治疗波\") and A[\"次级治疗波\"]:CastSafely(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\n    end\n--else\n--    v = SwitchIsOn(\"次级治疗波\") and A[\"次级治疗波\"]:Cast(healTarget.HealthPercent < 0.75, healTarget) if v then return v end\n--    v = SwitchIsOn(\"次级治疗波\") and A[\"次级治疗波\"]:CastSafely(healTarget.HealthPercent < 0.8, healTarget) if v then return v end\n--    v = SwitchIsOn(\"治疗波\") and A[\"治疗波\"]:Cast(healTarget.HealthPercent < 0.86 and healTarget.HealthPercent > (SwitchIsOn(\"次级治疗波\") and 0.69 or 0), healTarget) if v then return v end\n--end\n\n",
            ["输出"] = "--萨满祭司-恢复-输出\nlocal v\nif not inCombat then\n    if vars[\"敌方目标数量\"] > 2  then\n        v = A[\"闪电链\"]:CastSafely() if v then return v end\n    else\n        v = A[\"熔岩爆裂\"]:CastSafely() if v then return v end\n        v = A[\"闪电箭\"]:CastSafely(not A[\"熔岩爆裂\"]:CastedIn(3)) if v then return v end\n    end\nend\nv = A[\"烈焰震击\"]:Cast() if v then return v end\nv = SwitchIsOn(\"净化术\") and A[\"净化术\"]:Cast() if v then return v end\n--v = A[\"熔岩爆裂\"]:Cast(player.MyBuff:Has(\"熔岩奔腾\")) if v then return v end\nv = A[\"闪电链\"]:Cast() if v then return v end\nv = A[\"熔岩爆裂\"]:Cast() if v then return v end\nv = A[\"闪电箭\"]:Cast() if v then return v end\n\nv = SwitchIsOn(\"鼠指烈焰\") and A[\"烈焰震击\"]:Cast(nil, mouseover) if v then return v end\n--v = A[\"冰霜震击\"]:Cast() if v then return v end\n",
        },
    },
}
